(()=>{const {q,c,add,R,n,nr,o,pk,f3,fs}=DA;add(c('error_two_step','误差两步法｜规则、补位与例子',[
q('q43','第一步',['技巧'],()=>R('速算误差两步法第一步是什么？','截三位做差',['截三位做差','直接背答案','先看全文','只算尾数','把分母倒过来'],'误差速算两步：第一步截三位做差，第二步差 ÷ 基数前两位。','题干问第一步，所以答案是截三位做差。')),
q('q44','截三位',['技巧'],()=>R('速算误差两步法中，截三位做差的正确操作是？','直接截取前三位，无需四舍五入',['四舍五入保留三位有效数字','直接截取前三位，无需四舍五入','向上取整到第三位','向下取整到第三位','保留全部位数做差'],'误差口算追求速度，无需额外做四舍五入处理。','截三位直接截取前三位即可，不用四舍五入，目的是快速口算误差，减少多余步骤。')),
q('qx_pad_three_digits','不足三位补 0',['技巧','误差速算','划线法'],()=>{const x=nr(12,89,[24]),pad=x*10,low=pad-n(3,9),high=pad+n(6,18);return R('速算误差截三位时，如果目标骨架不足三位，应如何处理？','补 0 成三位后再做差',['补 0 成三位后再做差','直接只看一位','必须四舍五入','改用尾数法','忽略这个数不算误差'],'截三位的目的是统一口算尺度，不足三位要补位。',`例如 ${x} 应看成 ${pad}，再和 ${low}、${high} 等三位骨架做差；这样才能继续用“差值 ÷ 基数前两位”估算百分比误差。`)}),
q('q45','例子',['技巧'],()=>{const a=n(3000,9300),p=n(2,8),dir=pk([-1,1]),b=Math.round(a*(1+dir*p/100)/10)*10,realPct=Math.max(1,Math.round(Math.abs(b-a)/a*100)),word=b>a?'上升':'下降',ans=`${word}约 ${realPct}%`,a3=f3(a),b3=f3(b),diff=Math.abs(Number(b3)-Number(a3)),base=fs(a3);return R(`${a} 变成 ${b}，误差大约是？`,ans,o(ans,[`${word==='上升'?'下降':'上升'}约 ${realPct}%`,`${word}约 ${Math.max(1,realPct-1)}%`,`${word}约 ${realPct+2}%`,`${word==='上升'?'下降':'上升'}约 ${realPct+3}%`]),`${a}→${a3}，${b}→${b3}，差 ${diff}。`,`差 ${diff} ÷ ${base} ≈ ${realPct}%，目标数变${b>a?'大':'小'}，所以是${ans}。`)}),
q('q48','精度量级',['技巧'],()=>R('速算误差两步法中，“x% 多”的“多”通常代表什么量级的误差？','千分之几',['百分之几十','百分之十几','千分之几','万分之几','完全为 0'],'本方法的整体精度远高于市面常规估算方法。','“x% 多”的“多”仅代表零点几个百分点，对应千分之几的误差，整体精度远高于常规估算方法。'))
],'sequence'));})();

