(()=>{const {q,c,add,R}=DA;add(c('error_control_training','误差控制｜原则与训练',[
q('q46','控制原则',['基础'],()=>R('单个改数误差通常尽量不要超过多少？','10%',['1%','5%','10%','20%','50%'],'单个误差过大，口算修正会变慢且不稳。','本课原则：单个改数误差尽量不要超过 10%。')),
q('q47','日常训练',['技巧'],()=>R('日常想要练习误差口算能力，以下哪种方式最便捷？','利用车牌号、随机数字练习改数误差',['每天做 100 道精算题','背诵所有小数','利用车牌号、随机数字练习改数误差','只看理论不练习','反复誊写公式'],'训练目标是 3 秒内判断任意改数的误差，重在熟练度。','利用生活中的数字（如车牌号、商品价格）练习改数误差，碎片化可练，能快速提升误差口算速度。'))
]));})();

