(function(){
  const {op,R,Q,C,add,coverage}=EX;
  const lineMain=Q('choice_line_main','划线法主线',['运用'],()=>R('普通A÷B、A÷B×C、A÷B×C÷D连乘连除，优先用什么？','划线法',op('划线法',['两个分数做差专项','完整竖式','只背公式','材料定位法']),'本课主线是乘除速算。','普通乘除结构中，划线法不限两数三数四数，是本课第一优先级。'),coverage());
  const splitAux=Q('choice_split_aux','拆分法辅助',['运用'],()=>R('拆分法在本课方法体系中的位置是什么？','A÷B时可辅助，三数以上不做主线',op('A÷B时可辅助，三数以上不做主线',['所有题第一优先','专门解决两个分数做差','完全不能用','只适合文字理解题']),'拆分法适合单分数。','拆分法处理A÷B很顺手；多个数连乘连除时会变复杂。'),coverage());
  const dislocBackup=Q('choice_disloc_backup','错位法备选',['运用'],()=>R('错位加减法在本课方法体系中的位置是什么？','划线法不熟时的备选工具',op('划线法不熟时的备选工具',['永远替代划线法','完全不能使用','只用于三不看','只用于单位换算']),'它能用，但不是最终主线。','错位法适合习惯写步骤的人；三数四数普通乘除中，熟练划线通常更快。'),coverage());
  const fractionDiff=Q('boundary_fraction_diff','两个分数和差',['基础'],()=>R('遇到A÷B - C÷D这类两个分数做差，为什么不能无脑大幅划线？','做差会放大误差，要用后续专项方法或精修',op('做差会放大误差，要用后续专项方法或精修',['因为这是纯乘法','因为选项永远很远','因为百分号可直接删','因为分母不能改']),'差值小时误差尤其敏感。','两个分数做和差不是本课普通乘除主场，误差可能被放大，后续比重差、混合原理等会处理。'),coverage());
  const plusBoundary=Q('boundary_plus_structure','加减结构',['基础'],()=>R('遇到含有1+增长率、两个量相减等加减结构时，正确态度是什么？','先处理加减结构，再对纯乘除部分使用划线法',op('先处理加减结构，再对纯乘除部分使用划线法',['所有符号直接三不看','完全不能估算','只看最大数','直接把加号当乘号']),'边界在于加减不是占位。','小数点、百分号能暂不看是乘除内部的规则；有加减时必须先还原结构。'),coverage());
  const laterTopics=Q('boundary_later_topics','后续专项边界',['基础'],()=>R('比重差、平均数变化、增长量极小等题，为什么不能只靠本节普通划线法？','它们常含加减或差值放大，需要后续专项技巧',op('它们常含加减或差值放大，需要后续专项技巧',['它们都没有数字','它们只考常识','它们永远选最大','它们不属于资料分析']),'本节讲纯乘除主线，不包打天下。','后续增长、比重、平均数会继续用乘除基础，但遇到差值、混合、加减结构时要切换专项方法。'),coverage());
  const closeOption=Q('boundary_close_option','选项极近',['运用'],()=>R('选项极近时，本课速算还要额外注意什么？','不能只看粗范围，要补方向和小误差',op('不能只看粗范围，要补方向和小误差',['永远只看首位','永远选最大','直接不做','误差越大越好']),'选项决定精度。','选项远则粗，选项近则精；极近时要补“多”、方向，必要时换更精细方法。'),coverage());
  const finalFlow=Q('choice_final_flow','四步总流程',['运用'],()=>R('第二课普通乘除速算的总流程是什么？','分清结构 → 划舒服数 → 合并误差 → 结合选项',op('分清结构 → 划舒服数 → 合并误差 → 结合选项',['先背例题 → 照搬数字 → 放弃误差 → 选最大','先精算 → 再看结构 → 再看选项 → 再划线','只看材料 → 不看式子 → 不看选项 → 盲选','先错位 → 再拆分 → 再竖式 → 再计算器']),'这是本课主线闭环。','先判断A÷B、A÷B×C还是四数结构；再把不舒服数据划成舒服数；合并误差方向；最后根据选项决定精度。'),coverage());
  const priority=C('choice_priority_module','方法优先级',['运用'],[lineMain,splitAux,dislocBackup],'sequence',coverage({progressScope:'node_children',progressLabel:'局部掌握'}));
  const boundaries=C('choice_boundaries_module','不适用边界',['基础'],[fractionDiff,plusBoundary,laterTopics,closeOption],'sequence',coverage({progressScope:'node_children',progressLabel:'局部掌握'}));
  add(C('method_choice_card','方法取舍与边界｜主线、备选、禁区',['运用'],[priority,boundaries,finalFlow],'sequence',coverage({routeSchema:'recursive_route_tree_v1',routeDepth:'3',progressScope:'card_children',progressLabel:'题卡掌握',localProgressLabel:'局部掌握'})));
})();

// ----- lessons/data_analysis_speed_02/17_ordinary_multiply_and_addition_edge.js -----
(function(){
  const {n,op,R,Q,C,add,coverage,parameter}=EX;

  const twoFactor=Q('mul_two_factor_basic','两数乘法',['技巧'],()=>{
    const a=n(21,89);
    const b=n(31,49);
    const aa=Math.round(a/10)*10;
    const bb=Math.round(b/10)*10;
    const ans='先把两数划成舒服数，再看误差是否需要补';
    return R(
      `${a}×${b} 这类普通乘法，划线法的第一步是什么？`,
      ans,
      op(ans,['必须从个位竖式相乘','只能用错位加减法','先拆成两个分数','直接放弃估算']),
      '普通乘法也是纯乘除的一部分。',
      `例如可先看成 ${aa}×${bb} 的骨架，再判断 ${a}、${b} 分别是划大还是划小；乘法内部按同向叠加、异向抵消处理。`,
      parameter()
    );
  });

  const multiFactor=Q('mul_multi_factor_chain','多项连乘',['技巧'],()=>{
    const a=n(31,39), b=n(97,104), c=n(118,126);
    const ans='先找能互相抵消误差的因子，再出基准值';
    return R(
      `${a}×${b}×${c} 这类多项连乘，优先怎么划？`,
      ans,
      op(ans,['每个数都强行保留三位','先把所有数精确相乘','只看最后一个因子','把乘号全部改成除号']),
      '多项连乘不是新公式，仍是乘法误差合并。',
      `多项连乘时，不必死算 ${a}、${b}、${c} 的真实乘积；优先让某些因子上升、某些因子下降，使误差抵消。`,
      parameter()
    );
  });

  const multiplyModule=C('mul_ordinary_module','普通乘法与连乘',['技巧'],[twoFactor,multiFactor],'sequence',coverage({progressScope:'node_children',progressLabel:'局部掌握'}));

  const fifteenSkeleton=Q('sensitive_15_skeleton','15骨架',['技巧'],()=>R(
    '看到分母约为15时，为什么常能想到“3×5”，并把5转到分子侧处理？',
    '15=3×5，除以5可转成乘以2的骨架，方便配合三不看和误差修正',
    op('15=3×5，除以5可转成乘以2的骨架，方便配合三不看和误差修正',['15只能精确长除','15与分数转化无关','看到15必须改成1/7','15只能用于加法']),
    '这是分数转化和划线的联动。',
    '把分母改到15附近时，可把15拆成3×5；除以5相当于乘0.2，骨架上常转成“乘2再回位”，让运算更轻。'
  ),coverage());

  const oneEighteen=Q('sensitive_one_eighteen','1/18骨架',['技巧'],()=>R(
    '1/18 的速算骨架可以怎样由 5/9 联想到？',
    '1/18 = 0.0555…，可看成5/9骨架555前面补0并调整数量级',
    op('1/18 = 0.0555…，可看成5/9骨架555前面补0并调整数量级',['1/18等于0.18','1/18必须背成142857','1/18只能用错位加减法','1/18不能估算']),
    '课程例题里用过1/18和5/9的联动。',
    '因为1/9=0.111…，1/18是其一半，即0.0555…；所以可以抓555骨架，再用数量级回位。'
  ),coverage());

  const sensitiveModule=C('sensitive_edge_module','敏感骨架补充',['技巧'],[fifteenSkeleton,oneEighteen],'all',coverage({progressScope:'node_children',progressLabel:'局部掌握'}));

  const highAdd=Q('addition_high_first','高位叠加',['基础'],()=>R(
    '多位数加法如果只是后续题里的辅助计算，通常从哪边先看？',
    '从高位往低位看，必要时结合进位判断范围',
    op('从高位往低位看，必要时结合进位判断范围',['像小学竖式一样必须从个位开始','直接套三不看原则','把加号看成乘号','只看最后一位']),
    '这是课程里的旁支提示，不是本节主训练。',
    '多位数加法一般先看高位累加，低位只负责是否进位；资料分析里常不必把每一位都算到极精。'
  ),coverage());

  const tailDigit=Q('addition_tail_digit','尾数法提示',['基础'],()=>R(
    '资料分析中遇到多项加法，除了高位叠加，课程还提示过哪类辅助判断？',
    '尾数法',
    op('尾数法',['错位加减法专门化一','七分数循环节','增长率做差','百分号三不看']),
    '这是加法旁支。',
    '当选项尾数差异明显时，可以用尾数法；但这不是本节乘除速算的主线，只作为后续遇题时的辅助。'
  ),coverage());

  const addModule=C('addition_edge_module','加法旁支提示',['基础'],[highAdd,tailDigit],'all',coverage({progressScope:'node_children',progressLabel:'局部掌握'}));

  add(C('ordinary_multiply_and_edges_card','普通乘法与旁支提示｜纯乘法、敏感数与高位加法',['运用'],[multiplyModule,sensitiveModule,addModule],'all',coverage({routeSchema:'recursive_route_tree_v1',routeDepth:'3',progressScope:'card_children',progressLabel:'题卡掌握',localProgressLabel:'局部掌握'})));
})();

