// ----- lessons/data_analysis_speed_03/01_growth_framework.js -----
(function(){
  const {R,Q,C,add,op}=DA3;
  const map=Q('framework_three_blocks','三大块识别',['基础'],()=>{
    const ans='增长、比重、平均数';
    return R('资料分析的大方向，本节课先放进哪三大块框架里理解？',ans,op(ans,['增长、利润、工程','速度、浓度、行程','比重、概率、排列组合']),'先建立课程地图。','资料分析的大方向分为增长、比重、平均数；本节重点展开增长，同时提醒后续还会讲比重和平均数。');
  });
  const flow=Q('framework_process','做题流程',['基础'],()=>{
    const ans='识别题型 → 列公式 → 带数据 → 结合估算和选项';
    return R('本课处理资料分析题的主流程是？',ans,op(ans,['先精算到底 → 再读题','只背公式，不看选项','先看材料全文 → 再随便代数']),'公式不是终点，选项意识也要进入流程。','先根据问法识别增长、比重或平均数；再列式带数；最后结合估算、误差和选项范围决定算到哪里。');
  });
  const unit=Q('framework_unit','单位识别',['基础'],()=>{
    const ans='带单位多为增长量，百分号多为增长率';
    return R('一道题问“比上年增长多少”，选项全是“亿元/万吨/万辆”。这通常说明它问的是？',ans,op(ans,['一定是增长率','一定是百分点','一定是同比时间']),'看选项单位。','增长量是绝对量，通常带单位；增长率是相对量，通常写成百分号。');
  });
  add(C('growth_framework','增长框架｜题型、公式与选项',['基础'],[map,flow,unit],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/02_section_percent_base_time.js -----
DA3.sec('基础概念｜百分点、基期现期、同比环比');

// ----- lessons/data_analysis_speed_03/03_percent_point.js -----
(function(){
  const {n,rn,op,R,Q,C,add,fmt,pct,pp}=DA3;
  const abs=Q('pp_abs_relative','绝对量比较',['基础'],()=>{
    const b=n(40,90), d=n(5,20), a=b+d;
    const rel=fmt(d/b*100,1)+'%';
    const ans='既可以做差，也可以做比';
    return R(`${a} 比 ${b} 多多少？这两个数都是绝对量，正确处理是？`,ans,op(ans,[`只能说多 ${d}`,'只能读作百分点','只能做除法']),'绝对量比较有两种读法。',`${a}-${b}=${d} 是绝对差；${d}÷${b}≈${rel} 是相对差。绝对量可以做差，也可以做比。`);
  });
  const rule=Q('pp_rule','百分数规则',['基础'],()=>{
    const ans='百分数之间原则上只做加减，结果读作百分点';
    return R('两个增长率、两个比重这类百分数比较时，核心规则是？',ans,op(ans,['百分数之间优先相乘','百分数做差后仍读百分号','百分数之间必须先除后减']),'百分数本身就是相对量。','百分数是相对量。两个相对量比较，规范做法是做差，且结果读作百分点。');
  });
  const industry=Q('pp_industry_added_value','产业增加值',['基础'],()=>{
    const names=['第一产业','第二产业','第三产业','工业','服务业'];
    const name=names[n(0,names.length-1)];
    const value=rn(120.5,980.5,1);
    const ans='具体指标值，不是增长量';
    return R(`材料说“${name}增加值为${value}亿元”。这里的“增加值”应理解为？`,ans,op(ans,['增长量，必须套增长量公式','百分点','同比增长率']),'这是经济统计名词。',`“${name}增加值”是一个具体经济指标值，可近似当成产值/量来处理，不要因为有“增加”二字就误判为增长量。`);
  });
  const standard=Q('pp_train_standard','规范差值变量',['技巧'],()=>{
    const b=rn(4,18,1), d=rn(2,12,1), a=Number((b+d).toFixed(1));
    const ans=pp(d);
    return R(`甲增长率为 ${pct(a)}，乙增长率为 ${pct(b)}。甲比乙高多少？`,ans,op(ans,[pct(d),pct(d/b*100),pp(d+1),pp(Math.max(0.1,d-1))]),'两个百分数做差，读成百分点。',`${pct(a)}-${pct(b)}=${pct(d)}，读作 ${ans}。`);
  });
  const noDivide=Q('pp_train_no_divide','不要先除变量',['技巧'],()=>{
    const b=n(4,12), d=n(2,6), a=b+d;
    const wrong=fmt(d/b*100,1)+'%';
    const ans=pp(d);
    return R(`${a}% 比 ${b}% 高多少？`,ans,op(ans,[wrong,pct(d),pp(d+1)]),'不是绝对量比较，不能优先做相对差。',`两个百分数比较，先做 ${a}%-${b}%=${d}%，结果读作 ${ans}；${wrong} 是把百分数又当绝对量做比。`);
  });
  const irregular=Q('pp_train_irregular','异常选项变量',['运用'],()=>{
    const b=n(5,15), d=n(3,9), a=b+d;
    const ans=`选数值为 ${d} 的差值项`;
    return R(`题目问 ${a}% 比 ${b}% 高多少。规范应为 ${d} 个百分点，但选项全写成百分号。考场应优先怎么办？`,ans,op(ans,['直接放弃此题','先算相对差','把两个百分数相乘']),'先按规范差值找答案。',`规范计算是 ${a}%-${b}%=${d} 个百分点。若只有 ${d}% 这类书面选项，仍优先选差值项；若差值完全没有，再考虑不规范的相对差。`);
  });
  const train=C('pp_variable','变量训练',['技巧'],[standard,noDivide,irregular],'all');
  add(C('percent_point','百分数与百分点｜读法、陷阱与变量训练',['基础'],[abs,rule,industry,train],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/04_base_current.js -----
(function(){
  const {n,op,R,Q,C,add,fmt}=DA3;
  const formula=Q('base_formula','基期公式',['基础'],()=>{
    const ans='基期 = 现期 ÷ (1+增长率)';
    return R('已知现期和“现期相对于基期”的增长率，求过去的量，应使用哪个公式？',ans,op(ans,['现期 = 基期 ÷ (1+增长率)','增长量 = 现期 + 基期','增长率 = 现期 + 基期 - 1']),'过去的量是基期。','由 基期×(1+r)=现期 得：基期=现期÷(1+r)。');
  });
  const current=Q('current_formula','现期公式',['基础'],()=>{
    const ans='现期 = 基期 × (1+增长率)';
    return R('已知过去的量和增长率，求现在的量，应使用哪个公式？',ans,op(ans,['基期 = 现期 × (1+增长率)','现期 = 基期 ÷ (1+增长率)','增长率 = 现期 ÷ 增长量']),'基期向现期推进，要乘。','现期比基期增长 r，因此现期=基期×(1+r)。');
  });
  const direct=Q('base_train_direct','一年基期变量',['技巧'],()=>{
    const cur=n(800,2600), r=n(8,35);
    const ans=`${cur} ÷ (1+${r}%)`;
    return R(`2022年某产量为 ${cur} 万吨，比2021年增长 ${r}%。求2021年产量，正确列式是？`,ans,op(ans,[`${cur} × (1+${r}%)`,`${cur} ÷ ${r}%`,`${cur} × ${r}%`]),'2021年是过去，求基期。',`2022年是现期，2021年是基期，所以用现期÷(1+r)：${ans}。`);
  });
  const yearTrap=Q('base_train_year_trap','去年前年陷阱变量',['运用'],()=>{
    const cur=n(900,3200), r1=n(6,18), r2=n(20,45);
    const ans=`${cur} ÷ (1+${r2}%)`;
    return R(`2022年产量为 ${cur}，比去年增长 ${r1}%，比前年增长 ${r2}%。求2020年产量，列式是？`,ans,op(ans,[`${cur} ÷ (1+${r1}%)`,`${cur} × (1+${r2}%)`,`${cur} ÷ (1+${r1}%+${r2}%)`]),'求2020年，就要找2022相对2020的增长率。',`前年是2020年。题干直接给出“2022比前年增长${r2}%”，所以用 ${ans}。${r1}% 是求2021年时才用。`);
  });
  const chain=Q('base_train_chain','连续基期变量',['技巧'],()=>{
    const cur=n(1000,5000), r10=n(20,60), delta=n(5,15); const r09=r10-delta;
    const ans=`${cur} ÷ (1+${r10}%) ÷ (1+${r09}%)`;
    return R(`2010年某值为 ${cur}，2010年增长率 ${r10}%，增幅同比提高 ${delta} 个百分点。求2008年值，列式是？`,ans,op(ans,[`${cur} ÷ (1+${r09}%)`,`${cur} ÷ (1+${r10}%+${r09}%)`,`${cur} × (1+${r10}%) × (1+${r09}%)`]),'先求2009，再求2008。',`2010增长率属于2010年，即2010相对2009；2009增长率=${r10}%-${delta}个百分点=${r09}%。所以2008=${ans}。`);
  });
  const train=C('base_variable','变量训练',['技巧'],[direct,yearTrap,chain],'all');
  add(C('base_current','基期与现期｜公式、时间与增长率匹配',['基础'],[formula,current,train],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/05_time_terms.js -----
(function(){
  const {n,op,R,Q,C,add}=DA3;
  const rateBelong=Q('time_rate_belong','增长率归属',['基础'],()=>{
    const ans='2010年的增长率，表示2010年相对于2009年';
    return R('“2010年比2009年增长55.6%”这句话可以简写为？',ans,op(ans,['2009年的增长率，表示2009年相对于2010年','2009年的增长率，表示2009年相对于2008年','2010和2009共同的增长率']),'增长率归属于后面的那个年份。','“2010年增长率55.6%”就是2010年相对于2009年的增长率；“2009年增长率”才是2009年相对于2008年。');
  });
  const increase=Q('time_increase_meaning','增幅同比',['基础'],()=>{
    const ans='增幅就是增长率，同比提高是与上一同比期的增长率做差';
    return R('“增幅同比提高20个百分点”中的“增幅”应理解为？',ans,op(ans,['增长量','现期量','基期量']),'增幅不是增长量。','增幅=增长率。同比提高20个百分点，表示本期增长率比同比期增长率高20个百分点。');
  });
  const month=Q('time_month','年月口径变量',['技巧'],()=>{
    const y=n(2020,2025), m=n(2,12);
    const ans=`同比：${y-1}年${m}月；环比：${y}年${m-1}月`;
    return R(`${y}年${m}月的同比和环比分别是？`,ans,op(ans,[`同比：${y}年${m-1}月；环比：${y-1}年${m}月`,`同比：${y-1}年${m-1}月；环比：${y}年${m-1}月`,`同比：${y-1}年${m}月；环比：${y-1}年${m-1}月`]),'只有年月时，常见说法才是同比上一年、环比上个月。',`年月中最大单位是年，所以同比=${y-1}年${m}月；最小单位是月，所以环比=${y}年${m-1}月。`);
  });
  const ymd=Q('time_y_m_d','年月日口径变量',['技巧'],()=>{
    const y=n(2020,2025), m=n(2,11), d=n(2,27);
    const ans=`同比：${y-1}年${m}月${d}日；环比：${y}年${m}月${d-1}日`;
    return R(`${y}年${m}月${d}日的同比时间和环比时间分别是？`,ans,op(ans,[`同比：${y-1}年${m}月${d}日；环比：${y}年${m-1}月${d}日`,`同比：${y}年${m-1}月${d}日；环比：${y}年${m}月${d-1}日`,`同比：${y-1}年${m-1}月${d}日；环比：${y}年${m}月${d-1}日`]),'同比看最大时间单位，环比看最小时间单位。',`年月日中最大单位是年，所以同比是上一年同月同日；最小单位是日，所以环比是前一日。`);
  });
  const quarter=Q('time_quarter','季度口径变量',['运用'],()=>{
    const y=n(2020,2025);
    const ans=`同比：${y-1}年第一季度；环比：${y-1}年第四季度`;
    return R(`${y}年第一季度的同比时间和环比时间分别是？`,ans,op(ans,[`同比：${y-1}年第一季度；环比：${y}年第二季度`,`同比：${y}年上一季度；环比：${y-1}年第一季度`,`同比：${y-1}年第四季度；环比：${y-1}年第一季度`]),'年+季度时，环比是上一季度。',`同比看最大单位年：${y-1}年第一季度；环比看最小单位季度：${y}年第一季度的上一季度是${y-1}年第四季度。`);
  });
  const train=C('time_variable','变量时间训练',['技巧'],[month,ymd,quarter],'all');
  add(C('time_terms','同比环比与增幅｜时间口径和增长率归属',['基础'],[rateBelong,increase,train],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/06_section_growth_amount.js -----
DA3.sec('增长量｜公式、速算与误差边界');

// ----- lessons/data_analysis_speed_03/07_growth_amount_formula.js -----
(function(){
  const {n,op,R,Q,C,add,numOps,fmt}=DA3;
  const definition=Q('ga_definition','增长量定义',['基础'],()=>{
    const ans='增长量 = 现期 - 基期';
    return R('“现在比过去多了多少”对应资料分析中的哪个基本公式？',ans,op(ans,['增长率 = 现期 - 基期','基期 = 现期 - 增长率','百分点 = 现期 - 基期']),'增长量是绝对差。','增长量就是现期比基期多出的量，所以增长量=现期-基期。');
  });
  const currentFormula=Q('ga_current_formula','现期公式',['基础'],()=>{
    const ans='增长量 = 现期 ÷ (1+r) × r';
    return R('已知现期和增长率，求增长量，最常用公式是？',ans,op(ans,['增长量 = 现期 × (1+r)','增长量 = 现期 ÷ r','增长量 = 现期 ÷ 基期 - 1']),'用基期公式替换基期。','由基期=现期÷(1+r)，增长量=基期×r，所以增长量=现期÷(1+r)×r。');
  });
  const baseFormula=Q('ga_base_formula','基期公式',['基础'],()=>{
    const ans='增长量 = 基期 × r';
    return R('已知基期和增长率，求增长量，直接用哪个公式？',ans,op(ans,['增长量 = 基期 ÷ r','增长量 = 现期 ÷ (1+r)','增长量 = 基期 + r']),'基期是“原来的量”。','比基期增长 r，增长出来的部分就是基期×r。');
  });
  const unitJudge=Q('ga_unit_judge','单位判断',['基础'],()=>{
    const ans='增长量';
    return R('题目问“比上年增长约多少”，选项为 120亿元、150亿元、180亿元、210亿元。它问的是？',ans,op(ans,['增长率','百分点','同比时间']),'看选项单位。','选项带“亿元”，是绝对量，所以问增长量；增长率通常是百分号。');
  });
  const formulaTrain=Q('ga_train_formula','现期代入变量',['技巧'],()=>{
    const cur=n(800,2200), r=n(8,35);
    const ans=`${cur} ÷ (1+${r}%) × ${r}%`;
    return R(`现期为 ${cur}，同比增长 ${r}%。求增长量，正确列式是？`,ans,op(ans,[`${cur} × (1+${r}%)`,`${cur} ÷ ${r}%`,`${cur} ÷ (1+${r}%)`]),'已知现期和增长率。',`套公式：增长量=现期÷(1+r)×r，所以是 ${ans}。`);
  });
  const baseTrain=Q('ga_train_base','基期代入变量',['技巧'],()=>{
    const base=n(500,1500), r=n(5,28);
    const val=base*r/100;
    const ans=fmt(val,1);
    return R(`基期为 ${base}，增长率为 ${r}%。增长量约是多少？`,ans,numOps(val,[val+base*0.01,val-base*0.01,base*(1+r/100)],'',1),'已知基期，直接乘增长率。',`增长量=基期×r=${base}×${r}%=${fmt(val,1)}。`);
  });
  const train=C('ga_formula_variable','变量代入',['技巧'],[formulaTrain,baseTrain],'all');
  add(C('growth_amount_formula','增长量公式｜定义、三种条件与单位识别',['基础'],[definition,currentFormula,baseFormula,unitJudge,train],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/08_growth_amount_methods.js -----
(function(){
  const {n,pk,op,R,Q,C,add,fmt,numOps,fracPool}=DA3;
  const smallRule=Q('gam_small_rule','小增长率近似',['技巧'],()=>{
    const ans='选项差距大且增长率小于10%时，可先用现期×增长率估；真实值略小';
    return R('增长量=现期÷(1+r)×r。当 r 小于10%且选项差距很大时，可以怎样快速估？',ans,op(ans,['任何时候都直接忽略分母','真实值一定比现期×r大','必须反带，不能估算']),'分母1+r大于1。','若暂时拿掉分母，得到现期×r；因为原式还要除以1+r，所以真实增长量比现期×r略小。前提是选项差距足够大。');
  });
  const ratioRule=Q('gam_ratio_rule','比例法规则',['技巧'],()=>{
    const ans='增长率化成分数：基期是分母份，增长量是分子份，现期是分母+分子份';
    return R('增长量比例法的份数逻辑是？',ans,op(ans,['现期永远是分母份','增长量永远是分母+分子份','减少量不能用份数法']),'例如增长1/7。','若增长率是1/7，则基期7份、增长1份、现期8份；已知现期就用现期对应8份求1份。');
  });
  const convertRule=Q('gam_convert_rule','非契合分数转化',['技巧'],()=>{
    const ans='增长率上调多少，现期反向下调多少；增长率下调多少，现期反向上调多少';
    return R('增长率不完全契合分数时，想把增长率划线成附近分数，现期应如何配合？',ans,op(ans,['增长率上调，现期也上调','只改增长率，不管现期','现期变化方向永远与分母一致']),'乘除估算要抵消误差。','增长量公式可看成“现期×增长率÷(1+r)”。当增长率改大，为保持整体接近，现期要反向改小；反之亦然。');
  });
  const fractionSense=Q('gam_fraction_sense','常用分数数感',['技巧'],()=>{
    const ans='2/9≈22.2%，4/9≈44.4%，2/7≈28.6%';
    return R('增长量比例法和估算中，哪组常用分数数感是正确的？',ans,op(ans,['2/9≈28.6%，4/9≈40%，2/7≈22.2%','1/8≈14.3%，1/7=12.5%，2/3=60%','1/4≈20%，1/3≈25%，2/3≈33.3%']),'常用循环节要能快速反应。','常用数感包括：2/9≈22.2%，4/9≈44.4%，2/7≈28.6%，1/7≈14.3%，1/8=12.5%，1/4=25%，1/3≈33.3%，2/3≈66.7%。');
  });
  const smallTrain=Q('gam_small_train','小增长率变量',['技巧'],()=>{
    const cur=n(1800,5200), r=n(3,9); const approx=cur*r/100; const truev=approx/(1+r/100);
    const ans=fmt(truev,1);
    return R(`现期 ${cur}，增长率 ${r}%。若选项差距很大，增长量约是多少？`,ans,numOps(truev,[approx,approx*1.12,truev*0.8],'',1),'先算现期×r，再记真实值偏小。',`${cur}×${r}%=${fmt(approx,1)}；原式还要÷(1+${r}%)，所以约为 ${ans}，略小于 ${fmt(approx,1)}。`);
  });
  const ratioGrowth=Q('gam_ratio_growth','增长份数变量',['技巧'],()=>{
    const f=pk(fracPool.filter(x=>x.p<=2 && x.q<=8));
    const one=n(80,260); const cur=one*(f.q+f.p); const growth=one*f.p;
    const ans=fmt(growth,1);
    return R(`某现期量为 ${cur}，增长率约为 ${f.name}。增长量约是多少？`,ans,numOps(growth,[one,cur/f.q,cur*f.p/f.q,growth*1.2],'',1),`增长率${f.name}表示基期${f.q}份，增长${f.p}份。`,`现期=${f.q}+${f.p}=${f.q+f.p}份，对应${cur}；一份=${fmt(one,1)}，增长${f.p}份，所以增长量=${fmt(growth,1)}。`);
  });
  const ratioDecrease=Q('gam_ratio_decrease','减少份数变量',['技巧'],()=>{
    const f=pk(fracPool.filter(x=>x.p<x.q && ['1/5','1/4','1/3','1/2','2/3'].includes(x.name)));
    const one=n(120,360); const cur=one*(f.q-f.p); const dec=one*f.p;
    const ans=fmt(dec,1);
    return R(`某现期量为 ${cur}，比基期减少约 ${f.name}。减少量约是多少？`,ans,numOps(dec,[one,cur/f.q,cur*f.p/f.q,dec*0.75],'',1),`减少${f.name}：基期${f.q}份，减少${f.p}份，现期${f.q-f.p}份。`,`基期${f.q}份，减少${f.p}份，现期剩${f.q-f.p}份。现期${cur}=${f.q-f.p}份，所以减少量=${f.p}份=${fmt(dec,1)}。`);
  });
  const convertTrain=Q('gam_convert_train','转化变量',['运用'],()=>{
    const cases=[{r:13.5,name:'1/7',target:14.3,down:true,parts:8},{r:24.0,name:'1/4',target:25.0,down:true,parts:5},{r:16.0,name:'1/6',target:16.7,down:true,parts:7},{r:15.0,name:'1/7',target:14.3,down:false,parts:8}];
    const c=pk(cases); const cur=n(1000,2600);
    const adj=c.down?'下调':'上调';
    const badAdj=c.down?'上调':'下调';
    const ans=`把 ${c.r}% 看成约 ${c.name}，同时把现期约${adj}后再除以${c.parts}`;
    return R(`现期 ${cur}，增长率 ${c.r}%。若想用 ${c.name} 比例法，正确思路是？`,ans,op(ans,[`直接用 ${cur}÷${c.parts}，不调整`,`把现期约${badAdj}后除以${c.parts}`,`把 ${c.r}% 看成1/8后除以9`]),`增长率划到${c.name}，现期要反向调整。`,`${c.r}%${c.down?'小于':'大于'}${c.name}≈${c.target}%。增长率${c.down?'上调':'下调'}到目标分数，现期就要反向${adj}，再按现期份数估算。`);
  });
  const ratioRoute=C('gam_ratio_route','比例法变量',['技巧'],[ratioGrowth,ratioDecrease],'all');
  const train=C('gam_variable','变量训练',['技巧'],[smallTrain,ratioRoute,convertTrain],'all');
  add(C('growth_amount_methods','增长量速算｜小率、比例法与转化',['技巧'],[smallRule,ratioRule,convertRule,fractionSense,train],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/09_section_traps_review.js -----
DA3.sec('选项与复盘｜陷阱、反带、增长率收束');

// ----- lessons/data_analysis_speed_03/10_option_traps.js -----
(function(){
  const {n,op,R,Q,C,add,fmt,numOps}=DA3;
  const precision=Q('trap_precision_rule','选项决定精度',['运用'],()=>{
    const ans='精度由选项差距决定，不由题干数字大小决定';
    return R('为什么增长率只有0.7%时也不能一定忽略分母？',ans,op(ans,['增长率越小越不能算','题干数字越大越要精算','所有估算都绝对不可靠']),'看选项是否接近。','若选项之间只有千分之几差距，哪怕增长率很小，也不能粗估；如果选项差距很大，才可大胆估。');
  });
  const farOption=Q('trap_far_option','首位不同大胆估',['运用'],()=>{
    const ans='选项首位差异明显时，先估数量级和首位，不必精算到底';
    return R('选项首位明显不同，题目只是普通乘除估算时，正确策略是？',ans,op(ans,['必须算到小数点后三位','直接跳过材料','优先使用反带假设']),'选项本身告诉你需要的精度。','若选项首位不同，估到首位通常就能排除；若选项非常接近，才需要更精或反带。');
  });
  const lineBoundary=Q('trap_line_boundary','划线加减边界',['技巧'],()=>{
    const ans='划线法主要服务乘除估算，复杂分数加减不能机械套';
    return R('为什么“错位加减法/划线法”不能在所有分数加减里通用？',ans,op(ans,['因为乘除永远比加减简单','因为百分数不能出现小数','因为所有加减题都只能精算']),'加减会放大局部误差。','划线后单个乘除式可能很准，但两个接近结果再相减时，差值变小，误差占比会被放大，所以复杂分数加减要谨慎。');
  });
  const sumTrap=Q('trap_sum_rule','A等于B加C',['运用'],()=>{
    const ans='所求总量包含几个部分时，看选项是否有两个陷阱项相加等于总量项';
    return R('资料分析中的“反陷阱 A=B+C”适用在哪里？',ans,op(ans,['只适用于数量关系，资料分析不能用','只要看到百分号就用','只适用于平均数题']),'看所求对象是否由部分组成。','例如水产品=养殖水产品+捕捞水产品。出题人常把两个部分和总量同时放进选项。');
  });
  const reverseRule=Q('trap_reverse_rule','反带假设规则',['技巧'],()=>{
    const ans='选项极接近、正向估算分不清时，假设一个增长量，先求基期，再用基期×增长率反推';
    return R('反带假设法适合什么场景？',ans,op(ans,['选项首位完全不同','只要题目有百分号就用','题目问百分点时优先用']),'核心是选项接近。','选项很近时，正确答案范围已被压缩。任选一个近似增长量反带求基期，再用基期×增长率可唯一指向答案。');
  });
  const error=Q('trap_error_magnify','误差放大原理',['技巧'],()=>{
    const ans='加减法会放大误差，乘除法更适合划线估算';
    return R('为什么划线法适合乘除，但对复杂分数加减要谨慎？',ans,op(ans,['加减法会自动抵消所有误差','乘除法一定不能估算','只要保留三位，加减永远准确']),'两个很准的估算值相减，差值可能很小。','单个乘除估算可能只有千分误差，但两个接近数相减后，差值被缩小，误差占比会被放大。反带法正是利用加减法放大差异。');
  });
  const sumTrain=Q('trap_sum_train','总量陷阱变量',['运用'],()=>{
    const b=n(1200,3600), c=n(500,1800), a=b+c;
    const ans=`${a}`;
    return R(`某总量由甲部分和乙部分构成。估算后甲约 ${b}，乙约 ${c}。若问总量，选项里应优先锁定哪个？`,ans,op(ans,[String(b),String(c),String(a+n(80,160)),String(Math.max(1,a-n(80,160)))]),'总量=部分+部分。',`${b}+${c}=${a}。若选项中同时出现部分值与和值，和值通常就是总量答案。`);
  });
  const crossTrain=Q('trap_cross_year','跨期分段变量',['运用'],()=>{
    const a=n(180,420), b=n(150,360), total=a+b;
    const ans=String(total);
    return R(`2012比2011多约 ${a}，2011比2010多约 ${b}。若问2012比2010多多少，应选？`,ans,op(ans,[String(a),String(b),String(total+n(20,80)),String(Math.max(1,total-n(20,80)))]),'跨期增长量可拆成两段相加。',`2012-2010=(2012-2011)+(2011-2010)=${a}+${b}=${total}。`);
  });
  const reverseTrain=Q('trap_reverse_train','反带变量',['技巧'],()=>{
    const rate=[0.5,0.6,0.7,0.8,0.9,1.1][n(0,5)];
    const base=n(38000,56000); const growth=Math.round(base*rate/100); const cur=base+growth;
    const ans=String(growth);
    return R(`现期 ${cur}，增长率 ${rate}%。选项非常接近：${growth-3}、${growth}、${growth+2}、${growth+5}。用反带法应选？`,ans,op(ans,[String(growth-3),String(growth+2),String(growth+5)]),'可假设一个选项为增长量，现期-增长量≈基期。',`真实增长量约为基期×${rate}%。因为选项很近，反带任一选项都会指向 ${growth} 左右，所以选 ${growth}。`);
  });
  const sumRoute=C('trap_sum_route','A=B+C变量',['运用'],[sumTrain,crossTrain],'all');
  const train=C('trap_variable','变量训练',['运用'],[sumRoute,reverseTrain],'all');
  add(C('option_traps','选项意识与反陷阱｜精度、A=B+C、反带',['运用'],[precision,farOption,lineBoundary,sumTrap,reverseRule,error,train],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/11_growth_rate_intro.js -----
(function(){
  const {n,op,R,Q,C,add,fmt}=DA3;
  const formula1=Q('gr_formula_amount','增长率公式1',['基础'],()=>{
    const ans='增长率 = 增长量 ÷ 基期';
    return R('本节课最后开头讲到的增长率基本公式是？',ans,op(ans,['增长率 = 增长量 ÷ 现期','增长率 = 现期 ÷ 增长量','增长率 = 基期 ÷ 增长量']),'增长率描述“增长量相对于基期”。','增长率=增长量÷基期。');
  });
  const formula2=Q('gr_formula_current_base','增长率公式2',['基础'],()=>{
    const ans='增长率 = 现期 ÷ 基期 - 1';
    return R('若只给现期和基期，没有直接给增长量，增长率可以写成？',ans,op(ans,['增长率 = 基期 ÷ 现期 - 1','增长率 = 现期 + 基期 - 1','增长率 = 现期 ÷ 增长量 - 1']),'先把增长量写成现期-基期。','增长率=(现期-基期)÷基期=现期÷基期-1。');
  });
  const train=Q('gr_train_basic','增长量除基期变量',['技巧'],()=>{
    const base=n(500,1500), growth=n(50,300); const rate=growth/base*100;
    const ans=`${fmt(rate,1)}%`;
    return R(`基期 ${base}，增长量 ${growth}。增长率约为？`,ans,op(ans,[`${fmt(growth/(base+growth)*100,1)}%`,`${fmt((base+growth)/base*100,1)}%`,`${fmt(base/growth*100,1)}%`]),'增长率=增长量÷基期。',`${growth}÷${base}≈${fmt(rate,1)}%，所以增长率约为 ${ans}。`);
  });
  const train2=Q('gr_train_current_base','现基变量',['技巧'],()=>{
    const base=n(600,1400), rate=n(8,35); const cur=Math.round(base*(1+rate/100));
    const ans=`约 ${rate}%`;
    return R(`基期 ${base}，现期约 ${cur}。增长率最接近？`,ans,op(ans,[`约 ${rate+10}%`,`约 ${Math.max(1,rate-8)}%`,`约 ${Math.round(cur/base*100)}%`]),'现期÷基期-1。',`${cur}÷${base}-1≈${rate}%，所以最接近 ${ans}。`);
  });
  const variable=C('gr_variable','变量训练',['技巧'],[train,train2],'all');
  add(C('growth_rate_intro','增长率开头｜两个公式与代入',['基础'],[formula1,formula2,variable],'sequence'));
})();

// ----- lessons/data_analysis_speed_03/12_mixed_review.js -----
(function(){
  const {n,op,R,Q,C,add,pp}=DA3;
  const identify=Q('mix_identify','先识别',['运用'],()=>{
    const ans='先看问法的时间、对象、求法，再回材料找匹配数据';
    return R('综合题第一步最应该做什么？',ans,op(ans,['先把材料全文读完并计算所有数据','先找最大数字','先看哪个选项最顺眼']),'资料分析先读问法。','先看问法：时间点判断基期/现期，对象决定找哪一行，求法决定是增长量、增长率、百分点还是其他。');
  });
  const chooseMethod=Q('mix_method_choice','方法选择',['运用'],()=>{
    const ans='选项远可估算，选项近要精算或反带';
    return R('同样是增长量题，什么时候大胆估，什么时候反带？',ans,op(ans,['增长率小就永远大胆估','选项近也可以随便忽略分母','只要有单位就必须精算到底']),'看选项距离。','选项差距大时用划线、比例法、小率近似；选项极近时，估算区分不了，要考虑反带假设。');
  });
  const mixedPercent=Q('mix_percent_or_rate','百分点混合变量',['运用'],()=>{
    const a=n(16,35), b=n(4,15), d=a-b; const ans=pp(d);
    return R(`某行业增长率 ${a}%，另一行业增长率 ${b}%。前者高多少？`,ans,op(ans,[`${d}%`,`${Math.round(d/b*100)}%`,pp(d+2)]),'两个增长率比较。',`增长率都是百分数，比较时做差并读作百分点：${a}%-${b}%=${ans}。`);
  });
  const mixedBase=Q('mix_base_or_amount','基期增长量混合变量',['运用'],()=>{
    const cur=n(1200,3000), r=n(10,30); const ans='求过去量用基期公式；求多多少用增长量公式';
    return R(`现期 ${cur}，同比增长 ${r}%。若问“去年是多少”和“比去年多多少”，应分别想到什么？`,ans,op(ans,['两个都用增长率公式','两个都直接现期×增长率','去年是多少用增长量公式，多多少用基期公式']),'问法不同，公式不同。',`去年是多少是求基期：${cur}÷(1+${r}%)；多多少是求增长量：${cur}÷(1+${r}%)×${r}%。`);
  });
  const finalCheck=Q('mix_three_checks','三省吾身收束',['运用'],()=>{
    const ans='对立面、隐含考点、再循环查漏';
    return R('复盘这节课时，“三省吾身”应检查哪三类缺口？',ans,op(ans,['只检查公式背没背','只检查例题会不会','只检查有没有错别字']),'不是只背公式。','第一看对立面和衍生面；第二想出题会不会考笔记没明说的角度；第三循环上述步骤查漏。');
  });
  const cases=C('mix_cases','混合变量',['运用'],[mixedPercent,mixedBase],'all');
  add(C('mixed_review','综合复盘｜识别、公式、方法选择',['运用'],[identify,chooseMethod,cases,finalCheck],'sequence'));
})();

