// ----- lessons/data_analysis_speed_04/02_growth_basics.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('gb_four','四量关系',['基础'],()=>R('增长问题中最核心的四个量是哪四个？','现期、基期、增长量、增长率',['现期、基期、增长量、增长率','现期、末期、均值、比重','基期、环比、同比、倍数','增长量、平均数、中位数、众数'],'先把增长题拆成四个量。','增长题的基础地图是：现期、基期、增长量、增长率。')),
    Q('gb_amount','增长量公式',['基础'],()=>R('增长量等于什么？','现期 - 基期',['现期 - 基期','基期 - 现期','现期 / 基期','增长率 / 基期'],'增长量是两个时期的差。','增长量 = 现期 - 基期。')),
    Q('gb_rate','增长率公式',['基础'],()=>R('增长率的等价公式是哪一组？','增长量/基期 = 现期/基期 - 1',['增长量/基期 = 现期/基期 - 1','增长量/现期 = 基期/现期 - 1','现期/增长量 = 基期/增长量 - 1','基期/增长量 = 现期/基期 + 1'],'增长率的分母是基期。','增长率 = 增长量 / 基期 = (现期-基期)/基期 = 现期/基期 - 1。')),
    Q('gb_current','现期公式',['基础'],()=>R('已知基期和增长率 r，现期等于什么？','基期 × (1+r)',['基期 × (1+r)','基期 ÷ (1+r)','基期 × r','基期 - 增长量'],'增长后是在原基期上乘增长因子。','现期 = 基期 × (1+r)。下降时可写成 基期 × (1-r)。')),
    Q('gb_base','基期公式',['基础'],()=>R('已知现期和增长率 r，基期等于什么？','现期 ÷ (1+r)',['现期 ÷ (1+r)','现期 × (1+r)','现期 ÷ r','现期 - r'],'从现期倒推基期要除增长因子。','基期 = 现期 / (1+r)。若下降 r，则基期 = 现期/(1-r)。')),
    Q('gb_denominator','分母陷阱',['基础'],()=>R('已知现期和增长量求增长率，分母应是什么？','现期 - 增长量',['现期 - 增长量','现期','增长量','现期 + 增长量'],'增长率永远除以基期。','基期 = 现期 - 增长量，所以增长率 = 增长量/(现期-增长量)。')),
    Q('gb_compute','计算优先式',['技巧'],()=>R('实际计算增长率时，为什么常优先用“增长量/基期”？','少做减法，误差更可控',['少做减法，误差更可控','因为它永远不用除法','因为它一定比现期/基期更大','因为它能直接得到增长量'],'减法会放大估算误差。','增长量/基期通常只需要一次除法；现期/基期-1 多了减法，估算误差更容易被放大。')),
    Q('gb_compare','比较优先式',['技巧'],()=>R('比较两个增长率大小时，常比较什么即可？','现期/基期',['现期/基期','增长量/现期','基期/现期','现期-基期'],'两个增长率都要减1。','增长率 = 现期/基期 - 1。比较大小时“-1”共同存在，可直接比较现期/基期。'))
  ];
  add(C('growth_basics','增长基础｜公式与分母陷阱',['基础'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/03_question_recognition.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('qr_first','第一眼看什么',['基础'],()=>R('资料分析增长题第一眼应优先看什么？','问题时间，再看材料时间',['问题时间，再看材料时间','材料第一段，再看图例颜色','选项最长的那个','题干最后一个数字'],'时间决定现期、基期还是未来。','先看问题时间，再和材料时间对比，才能判断是现期、基期、增长还是预测。')),
    Q('qr_same','同时间',['基础'],()=>R('问题时间与材料时间相同，通常对应什么方向？','现期或增长相关',['现期或增长相关','一定是基期','一定是未来预测','一定是平均数'],'同时间不需要倒推。','问题时间等于材料时间，通常直接围绕现期量或当期增长关系提问。')),
    Q('qr_before','早于材料',['基础'],()=>R('问题时间早于材料时间，通常是什么问题？','基期问题',['基期问题','现期问题','未来预测','混合平均数'],'早于材料就是往回找。','材料给较晚时间，问题问较早时间，多数是基期量或基期比较。')),
    Q('qr_after','晚于材料',['基础'],()=>R('问题时间晚于材料时间，通常是什么问题？','未来现期问题',['未来现期问题','基期问题','已经发生的现期问题','比重差问题'],'晚于材料是往后推。','材料给当前或过去，问题问更晚时间，通常按增长率推未来现期。')),
    Q('qr_percent','百分号选项',['基础'],()=>R('选项带百分号时，通常问什么？','增长率',['增长率','增长量','具体人数','具体金额'],'百分号通常对应率。','增长率、增速、增幅等通常以百分号形式呈现。')),
    Q('qr_unit','实际单位选项',['基础'],()=>R('选项带亿元、万人、吨等实际单位时，通常问什么？','增长量或具体量',['增长量或具体量','增长率','百分比变化','百分点'],'实际单位对应量。','亿元、万人、吨等是量的单位，多数问增长量、现期量或基期量。')),
    Q('qr_speed','快慢问法',['基础'],()=>R('“增长快慢、增速、增长幅度、增长最快”对应什么？','增长率',['增长率','增长量','基期量','现期量'],'快慢是率，不是量。','这些表述本质上问的是增长率大小。')),
    Q('qr_howmuch','增长多少',['基础'],()=>R('“增长多少亿元/万人/吨”对应什么？','增长量',['增长量','增长率','增速','百分点'],'有实际单位就是量。','“增长多少”且带实际单位，问的是增长量。')),
    Q('qr_yoy','同比定义',['基础'],()=>R('同比通常是和哪个时期比较？','去年同期',['去年同期','紧邻上一周期','本年平均值','下一周期'],'同比看同一时间位置。','同比是和上一年同一时期比较，例如今年5月同比通常比去年5月；它是环比的常见对立面。')),
    Q('qr_ring','环比定义',['基础'],()=>R('环比是和哪个时期比较？','紧邻上一周期',['紧邻上一周期','去年同期','历史最高值','本年平均值'],'环就是相邻。','环比比较的是紧邻上一周期。月份比上月，季度比上季度。')),
    Q('qr_month','月环比',['基础'],()=>R('同时出现年和月时，问5月环比，一般比较哪两个时期？','5月与4月',['5月与4月','5月与去年5月','全年与上年','一季度与二季度'],'取更小时间单位。','年和月同时出现，月是更小单位。5月环比就是5月与4月比。')),
    Q('qr_quarter','季度环比',['基础'],()=>R('2015年一季度环比的上一季度是哪一个？','2014年四季度',['2014年四季度','2015年二季度','2014年一季度','2015年全年'],'一季度再往前是上一年四季度。','季度环比看紧邻上一季度，所以2015年一季度的上一季度是2014年四季度。'))
  ];
  add(C('question_recognition','问法识别｜时间与单位',['基础'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/04_section_compare_mixed.js -----
EX.sec('比较判断｜分数与混合');

// ----- lessons/data_analysis_speed_04/05_fraction_compare.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('fc_basic','基本大小',['技巧'],()=>R('两个正分数比较时，哪种情况可以直接判定左边更大？','分子更大且分母更小',['分子更大且分母更小','分子更小且分母更大','分子和分母都更大','分子和分母都更小'],'分子帮变大，分母帮变小。','正分数中，分子越大越大，分母越大越小。分子大且分母小，一定更大。')),
    Q('fc_integer','整数倍视角',['技巧'],()=>R('分数比较前，常先观察是否接近什么？','1、2、3等整数倍',['1、2、3等整数倍','材料页码','选项字数','题干年份'],'先粗定位量级。','接近1、2、3等整数倍时，可以用倍数骨架快速排除。')),
    Q('fc_direct','直除定位',['技巧'],()=>R('直除比较常看什么即可？','首位或关键位',['首位或关键位','所有小数位','单位名称','年份位数'],'资料分析追求够用。','直除不必总算到底，能用首位或关键位区分选项即可。')),
    Q('fc_match','配同法',['技巧'],()=>R('配同法的核心是什么？','把分母或分子配到接近相同',['把分母或分子配到接近相同','把所有数都约成1','只比较年份','只看选项顺序'],'配到可直接比较。','配同法是通过倍乘、划线、错位，把分母或分子调整到接近相同，再比较另一边。')),
    Q('fc_match_limit','配同边界',['技巧'],()=>R('配同法什么时候不宜使用？','配同误差过大时',['配同误差过大时','两个数完全相同时','分母可以直接相同时','选项差距很大时'],'误差大就会误判。','若配同造成的相对误差明显过大，就不能硬配，应换直除、拆分或差分。')),
    Q('fc_split_gt','拆分大于1',['技巧'],()=>R('a/b 大于1且接近1时，可拆成什么？','1 + (a-b)/b',['1 + (a-b)/b','1 - (a-b)/b','(b-a)/a - 1','a + b'],'超过1就是1加尾巴。','当 a>b 且接近时，a/b = 1 + (a-b)/b。比较尾巴即可。')),
    Q('fc_split_lt','拆分小于1',['技巧'],()=>R('a/b 小于1且接近1时，可拆成什么？','1 - (b-a)/b',['1 - (b-a)/b','1 + (b-a)/b','(a-b)/a + 1','b/a - 1'],'低于1就是1减尾巴。','当 a<b 且接近时，a/b = 1 - (b-a)/b。尾巴越大，整体越小。')),
    Q('fc_diff_condition','差分使用条件',['技巧'],()=>R('差分法主要用于哪种比较？','一个分数的分子和分母都更大',['一个分数的分子和分母都更大','一个分数分子大分母小','两个分数分母完全相同','两个分数分子完全相同'],'基础法失效时用。','当大分数的分子、分母都更大，不能直接判定大小，可用差分法。')),
    Q('fc_diff_rule','差分规则',['技巧'],()=>R('比较大分数c/d与小分数a/b时，差分分数应为？','(c-a)/(d-b)',['(c-a)/(d-b)','(c-d)/(a-b)','(a-c)/(b-d)','(a+b)/(c+d)'],'差的是分子差和分母差。','差分分数 = 两分子差 / 两分母差。拿它和小分数比较，判断大分数方向。')),
    Q('fc_diff_logic','差分本质',['技巧'],()=>R('差分法的底层本质更接近什么？','误差分析',['误差分析','随机猜测','单位换算','简单平均数'],'不是机械混合。','差分法本质是用新增部分的比例判断整体被拉高还是拉低，属于误差/增量方向分析。'))
  ];
  add(C('fraction_compare','分数比较｜方法与边界',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/06_mixed_growth.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('mg_between','整体范围',['技巧'],()=>R('整体由若干部分加总而成时，整体增长率通常位于哪里？','各部分增长率之间',['各部分增长率之间','一定大于所有部分','一定小于所有部分','与增长量最大者完全相等'],'整体是加权结果。','整体增长率是各部分增长率按基期权重形成的加权平均，因此夹在部分增长率之间。')),
    Q('mg_not_max','不能最大',['技巧'],()=>R('混合增长率中，整体增长率能否成为所有部分中的最大值？','通常不能',['通常不能','一定能','必然超过最大部分','只要现期大就能'],'平均数不超过最大。','整体增长率是加权平均，通常不能超过最大部分增长率。')),
    Q('mg_not_min','不能最小',['技巧'],()=>R('混合增长率中，整体增长率能否成为所有部分中的最小值？','通常不能',['通常不能','一定能','必然低于最小部分','只看增长量决定'],'平均数不低于最小。','整体增长率是加权平均，通常不能低于最小部分增长率。')),
    Q('mg_weight','权重偏向',['技巧'],()=>R('整体增长率更容易靠近哪一部分？','基期权重更大的部分',['基期权重更大的部分','增长率数字更长的部分','材料排在前面的部分','单位更大的部分'],'加权平均看权重。','基期规模越大，对整体增长率的拉动越强，整体越靠近它。')),
    Q('mg_eliminate','选项排除',['运用'],()=>R('混合增长率题最常用的快速排除思路是什么？','先排除超出部分增速范围的选项',['先排除超出部分增速范围的选项','先把每个增长量精确算出','先背固定答案','先按选项顺序选中间'],'整体一定在范围内。','看到整体由部分组成，先找各部分增速范围，超出范围的选项直接排除。'))
  ];
  add(C('mixed_growth','混合增长率｜范围与权重',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/07_section_avg_growth.js -----
EX.sec('年均增长｜量、率、估算');

// ----- lessons/data_analysis_speed_04/08_avg_growth_amount.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('aga_recognize','识别问法',['基础'],()=>R('“某年至某年，平均每年增长多少亿元”问的是什么？','年均增长量',['年均增长量','年均增长率','现期比重','平均增长速度'],'有实际单位，是量。','“平均每年增长多少”且带实际单位，问年均增长量。')),
    Q('aga_formula','基本公式',['基础'],()=>R('年均增长量的公式是什么？','(末期量 - 初期量) / 年份差',['(末期量 - 初期量) / 年份差','末期量 / 初期量 - 1','初期量 × 增长率','增长率 / 年份差'],'量用差，率用比。','年均增长量 = 总增长量 / 增长间隔 = (末期量 - 初期量)/年份差。')),
    Q('aga_gap','年份差',['基础'],()=>R('2015年至2018年的年份差是多少？','3',['3','4','2','5'],'年份差是末年减初年。','2018-2015=3，所以有3个增长间隔，不是4。')),
    Q('aga_prev','前一年规则',['基础'],()=>R('题问2015—2018平均每年增长，材料同时给2014，按课程规则初期优先取哪年？','2014年',['2014年','2015年','2018年','2016年'],'把2015看成第一年增长后的结果。','按时间边界规则，若题问2015—2018平均每年增长且材料给2014，用2014作初期；没有2014才用2015。')),
    Q('aga_no_prev','无前一年',['基础'],()=>R('题问2015—2018平均每年增长，但材料没有2014数据，初期取哪年？','2015年',['2015年','2014年','2018年','2016年'],'没有前一年就用题干首年。','若材料没有前一年数据，只能以题干首年2015作为初期。')),
    Q('aga_ignore_rate','忽略附带率',['运用'],()=>R('求年均增长量时，材料同时给增长率和具体量，通常优先用什么？','具体量',['具体量','增长率','百分号选项','材料标题'],'增长量题用量。','年均增长量是实际单位的量，优先用末期量和初期量作差，不要被附带增长率带偏。'))
  ];
  add(C('avg_growth_amount','年均增长量｜年份差与首年陷阱',['基础'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/09_avg_growth_rate_exact.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('agr_essence','本质',['基础'],()=>R('年均增长率的本质是什么？','每年按同一个r连续增长',['每年按同一个r连续增长','每年增长量完全相同','只看最后一年增长率','把所有增长率直接相加'],'率是乘法连续。','年均增长率假设每一年都按同一个r增长，形成连续乘法。')),
    Q('agr_positive','正增长公式',['基础'],()=>R('正增长年均增长率的精确公式骨架是什么？','(1+r)^N = 末期/初期',['(1+r)^N = 末期/初期','(1-r)^N = 末期/初期','Nr = 初期/末期','r/N = 末期/初期'],'正增长用1+r。','若每年增长r，N个间隔后，末期/初期=(1+r)^N。')),
    Q('agr_negative','负增长公式',['基础'],()=>R('年均下降率的公式骨架是什么？','(1-r)^N = 末期/初期',['(1-r)^N = 末期/初期','(1+r)^N = 末期/初期','1/(1+r)^N = 初期/末期','Nr = 末期/初期'],'下降用1-r。','每年下降r，增长因子是1-r，所以(1-r)^N=末期/初期。')),
    Q('agr_exact','精确解',['基础'],()=>R('年均增长率精确解可以写成什么？','r = (末期/初期)^(1/N) - 1',['r = (末期/初期)^(1/N) - 1','r = (末期-初期)/N','r = 初期/末期 - 1','r = 末期×初期/N'],'对(1+r)^N开N次方。','由(1+r)^N=末期/初期，得到r=(末期/初期)^(1/N)-1。')),
    Q('agr_compare','同N比较',['技巧'],()=>R('比较两个年均增长率，若年份差N相同，优先比较什么？','末期/初期',['末期/初期','末期-初期','初期-末期','年份名称'],'N相同，开方关系单调。','N相同时，(1+r)^N与r同向，直接比较末期/初期即可。')),
    Q('agr_no_need','不必硬算',['技巧'],()=>R('年均增长率题为什么很多时候不用真的解r？','可用比较、估算、划线或选项代入',['可用比较、估算、划线或选项代入','因为r一定等于增长量','因为所有题都是72法则','因为答案永远是中间项'],'资料分析重在选项判断。','精确开方很慢，实战通常用比较、二项估算、三项代入、划线法或72/115法则。'))
  ];
  add(C('avg_growth_rate_exact','年均增长率｜精确式与比较',['基础'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/10_avg_growth_rate_estimate.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('age_expand','二项展开',['技巧'],()=>R('(1+r)^N 展开的前几项是什么？','1 + Nr + C_N^2r² + ...',['1 + Nr + C_N^2r² + ...','1 - Nr - C_N^2r²','N + r + r²','1 + r/N'],'这是估算来源。','年均增长率估算来自二项展开：(1+r)^N = 1 + Nr + C_N^2r² + ...。')),
    Q('age_two','两项估算',['技巧'],()=>R('只保留前两项时，年均增长率近似为？','(末期/初期 - 1) / N',['(末期/初期 - 1) / N','(末期-初期) × N','初期/末期 / N','末期/初期 + N'],'忽略二次项后平均分摊。','令末期/初期-1为总增长率大R，保留1+Nr，得 r≈大R/N。')),
    Q('age_direction','误差方向',['技巧'],()=>R('正增长时，两项估算值通常与真实r相比如何？','偏大',['偏大','偏小','完全相等','无法比较'],'二次项被忽略了。','真实式还有正的二次项、三次项；只用Nr解释全部增长，会把r估大。')),
    Q('age_choice','选项选择',['技巧'],()=>R('正增长两项估算后，选项通常应选什么方向？','略小于估算值',['略小于估算值','略大于估算值','最大选项','最小选项'],'估算值是上方。','两项估算偏大，所以真实年均增长率通常略小于估算值。')),
    Q('age_boundary','适用边界',['技巧'],()=>R('两项估算更适合哪类情况？','r小、N不大',['r小、N不大','r很大、N很大','选项极近且增长率30%以上','负增长且不管符号'],'小量才能忽略高次项。','r越小、N越不大，高次项影响越小，两项估算越可靠。')),
    Q('age_5_10','经验边界',['技巧'],()=>R('经验边界是？','r≤5%、N≤10较适合',['r≤5%、N≤10较适合','r≥50%、N≥20较适合','只要N=1就必须用','只要有百分号就不能用'],'这是经验规则。','常用经验：r≤5%、N≤10时，两项估算通常较稳。')),
    Q('age_20','大增速慎用',['技巧'],()=>R('选项达到20%、30%以上时，两项估算应如何处理？','慎用，只能辅助排除或定位',['慎用，只能辅助排除或定位','直接选刚小于估算值','直接选最大项','完全不用看公式'],'高次项不能忽略。','大增速时二次项影响大，不能机械选刚小于估算值，只能辅助排除或定位。')),
    Q('age_upper','上界',['技巧'],()=>R('正增长两项估算即使不够精确，通常仍可作为真实r的什么？','上界',['上界','下界','精确值','单位换算值'],'偏大就是上界。','正增长中两项估算值通常大于真实r，可用于排除高于估算值的选项。')),
    Q('age_decline_sign','下降估算符号',['技巧'],()=>R('年均下降率估算时，最容易错在哪里？','把负号大小和下降幅度混淆',['把负号大小和下降幅度混淆','把年份差看成末年','把三项式系数固定为4','把环比当同比'],'下降率要看幅度，不只看代数大小。','若粗估写成-19%，真实可能是-30%左右。代数上-30%更小，但下降幅度更大；负增长题要回到(1-r)^N和保留率判断。')),
    Q('age_three','三项式通式',['技巧'],()=>R('三项式估算的核心近似是什么？','Nr + C_N^2r² ≈ 大R',['Nr + C_N^2r² ≈ 大R','Nr - C_N^2r² ≈ 大R','r/N + r² ≈ 大R','N²r ≈ 大R'],'保留到二次项。','大R=末期/初期-1，三项式保留Nr和C_N^2r²。')),
    Q('age_n5','N=5修正',['技巧'],()=>R('N=5时三项式应写成什么？','5r + 10r² ≈ 大R',['5r + 10r² ≈ 大R','5r + 4r² ≈ 大R','5r + 5r² ≈ 大R','10r + 5r² ≈ 大R'],'C_5^2=10。','N=5时二次项系数是C_5^2=10，所以是5r+10r²，不是5r+4r²。')),
    Q('age_substitute','三项式用法',['技巧'],()=>R('三项式在实战中更建议怎么用？','代入选项，不硬解方程',['代入选项，不硬解方程','必须精确求根','只背N=3','完全不用选项'],'代入更快。','资料分析选择题中，三项式主要用来代入候选项检验，而不是完整解二次方程。')),
    Q('age_bianshu','编数法',['技巧'],()=>R('编数法本质更接近什么？','把总增长粗略平均分摊',['把总增长粗略平均分摊','精确开方','十字交叉','环比比较'],'它和两项估算同源。','编数法可理解为把中间复杂增长简化掉，近似把总增长率按年份差分摊。'))
  ];
  add(C('avg_growth_rate_estimate','年均增长率｜估算与边界',['技巧'],qs,'all'));
})();

