EX.sec('通法陷阱｜划线、法则、连接');

// ----- lessons/data_analysis_speed_04/12_line_method.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('lm_use','适用对象',['技巧'],()=>R('划线体系最适合用来处理哪类题？','年均增长率大题，尤其大增速或选项接近',['年均增长率大题，尤其大增速或选项接近','只求增长量的小题','只看材料标题的题','完全没有比例关系的题'],'它处理乘方和误差。','年均增长率需要处理(1±r)^N，划线法适合估算乘方、比较候选和控制误差。')),
    Q('lm_steps','基本流程',['技巧'],()=>R('划线体系第一步通常是什么？','先列(1±r)^N = 末期/初期',['先列(1±r)^N = 末期/初期','先把选项全部相加','先求平均增长量','先看材料最后一句'],'先列骨架。','划线法先列出年均增长率骨架，再估算右侧比例，最后代入候选r比较。')),
    Q('lm_candidate','候选比较',['技巧'],()=>R('代入候选r后，若(1+r)^N算得比末期/初期偏大，真实r应怎样？','更小',['更小','更大','不变','无法判断'],'候选增长太快了。','候选r使增长因子乘方过大，说明候选r偏大，真实r应更小。')),
    Q('lm_candidate_low','候选偏小',['技巧'],()=>R('代入候选r后，若(1+r)^N算得比末期/初期偏小，真实r应怎样？','更大',['更大','更小','必为0','必为负'],'候选增长不够。','候选r乘方后达不到目标比例，说明真实r应更大。')),
    Q('lm_decline','负增长因子',['技巧'],()=>R('年均下降30%时，增长因子应写成什么？','0.7',['0.7','1.3','30','-1.3'],'下降用1-r。','下降30%表示每年保留70%，因子是1-30%=0.7。')),
    Q('lm_not_13','下降陷阱',['技巧'],()=>R('下降率题最常见的因子错误是什么？','把1-r误写成1+r',['把1-r误写成1+r','把年份差写对','先看选项','比较末期/初期'],'下降不是增加。','负增长要用1-r，不能把下降30%写成1.3。')),
    Q('lm_error','误差放大',['技巧'],()=>R('乘方估算中，多个因子的相对误差会怎样？','近似累加',['近似累加','全部抵消','只保留最后一个','变成绝对值单位'],'乘法误差会传递。','例如每个因子约1%的误差，四次方总误差可能接近4%，选项很近时必须校验。')),
    Q('lm_close','选项很近',['运用'],()=>R('年均增长率选项很接近时，划线法必须额外注意什么？','校验误差是否足以改变答案',['校验误差是否足以改变答案','直接选中间','只用72法则','忽略小数点'],'近选项怕误差翻盘。','当候选差距小，估算误差可能改变大小关系，必须检查单因子误差和幂次放大。')),
    Q('lm_bigstep','大步估算',['技巧'],()=>R('大步估算法的核心做法是什么？','总误差除以年份差，快速定位r',['总误差除以年份差，快速定位r','把所有选项相乘','只看最大年份','用末期减初期除以现期'],'先定位，再精修。','大步估算可把末期/初期相对1的总误差，粗略除以年份差，快速判断r的大概范围。')),
    Q('lm_limit','大步边界',['技巧'],()=>R('大步估算最适合承担什么作用？','快速定位，不替代精校',['快速定位，不替代精校','精确求根','完全替代材料阅读','直接得到唯一答案'],'它是粗估。','大步估算适合先锁定范围；若选项接近，仍要用划线或代入校验。'))
  ];
  add(C('line_method','划线体系｜乘方估算与误差',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/13_rules_and_multiple.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('rule72','72法则',['技巧'],()=>R('末期约为初期2倍，N年年均增长率可近似为？','72/N',['72/N','115/N','N/72','2N'],'翻倍用72。','当末期约等于2倍初期，年均增长率约为72/N。')),
    Q('rule115','115法则',['技巧'],()=>R('末期约为初期3倍，N年年均增长率可近似为？','115/N',['115/N','72/N','3N','N/115'],'三倍用115。','当末期约等于3倍初期，年均增长率约为115/N。')),
    Q('rule_above2','略大于2倍',['技巧'],()=>R('末期略大于2倍初期时，答案相对72/N应怎样？','略大于72/N',['略大于72/N','略小于72/N','等于115/N','一定为0'],'比例更大，率更大。','比2倍略大，所需年均增长率也略大于72/N。')),
    Q('rule_below2','略小于2倍',['技巧'],()=>R('末期略小于2倍初期时，答案相对72/N应怎样？','略小于72/N',['略小于72/N','略大于72/N','等于115/N','一定为负'],'比例更小，率更小。','比2倍略小，所需年均增长率也略小于72/N。')),
    Q('rule_use_limit','法则边界',['技巧'],()=>R('72/115法则最适合什么时候用？','接近2倍或3倍且选项拉开时',['接近2倍或3倍且选项拉开时','任何增长率题','选项极近时必用','负增长率题必用'],'它是粗法。','72/115法则是快速估算工具，只有接近倍数且选项差距足够时才稳。')),
    Q('mul_is','是几倍',['基础'],()=>R('“A是B的k倍”表示什么？','A/B = k',['A/B = k','(A-B)/B = k','A-B = k','B/A = k+1'],'“是”就是直接比。','A是B的k倍，直接表示A/B=k。')),
    Q('mul_increase','增长几倍',['基础'],()=>R('“A比B增长m倍”表示什么？','(A-B)/B = m',['(A-B)/B = m','A/B = m','B/A = m','A-B = m%'],'增长是多出来的部分。','增长m倍指增长部分是基期的m倍，即(A-B)/B=m，所以A/B=m+1。')),
    Q('mul_21','增长2.1倍',['基础'],()=>R('“增长2.1倍”对应末期/初期是多少？','3.1',['3.1','2.1','1.1','210'],'增长倍数要加1。','增长2.1倍表示增长率210%，末期/初期=1+2.1=3.1。')),
    Q('mul_trap','倍数陷阱',['运用'],()=>R('倍数表述最常见陷阱是什么？','混淆“是几倍”和“增长几倍”',['混淆“是几倍”和“增长几倍”','把亿元看成万人','把季度看成月份','忽略标题'],'一字之差差1倍。','“是几倍”直接是比例；“增长几倍”是增长部分，换成比例要加1。'))
  ];
  add(C('rules_multiple','72与倍数｜法则和表述陷阱',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/14_same_avg_growth.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('same_pattern','题型识别',['基础'],()=>R('“若2016—2017与2014—2015保持相同年均增速”属于什么题型？','相同年均增速首尾连接题',['相同年均增速首尾连接题','普通增长量题','混合增长率题','百分点差题'],'相同增速就是相同倍数因子。','这类题不必先求r，可直接用相同增长因子连接首尾。')),
    Q('same_no_r','不先求r',['技巧'],()=>R('相同年均增速题为什么不建议先求r？','直接连接比例更快',['直接连接比例更快','r不存在','只能用直除','题目不允许算式'],'目标是量，不是r。','若两个区间年数相同且年均增速相同，则总增长因子相同，可直接比值连接。')),
    Q('same_b2a','B²/A公式',['技巧'],()=>R('已知段初期A、末期B，目标段以B为初期且年数相同，未来末期为？','B²/A',['B²/A','A²/B','B/A²','A×B'],'由B/A = D/B推出。','设未来末期为D，相同总因子给出B/A=D/B，所以D=B²/A。')),
    Q('same_general','一般公式',['技巧'],()=>R('若目标段初期不是B，一般应如何求目标末期？','目标初期 × (已知末期/已知初期)',['目标初期 × (已知末期/已知初期)','目标初期 ÷ 已知末期','已知初期²/目标初期','只用B²/A'],'换成相同增长因子。','相同年均增速且年份差相同，目标末期=目标初期×已知总因子=目标初期×B/A。')),
    Q('same_mishear','口误纠正',['基础'],()=>R('“除以初期的平方”在该题型中应如何纠正？','应为末期平方除以初期',['应为末期平方除以初期','应为初期平方除以末期','应为末期除以初期平方','应完全不用除法'],'按等式推导。','由B/A=D/B得D=B²/A，所以是末期平方除以初期，不是除以初期平方。')),
    Q('same_integrated','综合流程',['运用'],()=>R('相同年均增速综合题的正确流程是什么？','先识别相同区间，再连比例，最后看选项',['先识别相同区间，再连比例，最后看选项','先精确开方，再背答案','先求增长量，再求平均数','先看最大选项'],'先看结构。','这类题的关键是找到两个年数相同的区间，连接总因子，而不是陷入开方。'))
  ];
  add(C('same_avg_growth','相同年均增速｜首尾连接',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_04/15_section_variable_training.js -----
EX.sec('变量训练｜必要三级路线');

// ----- lessons/data_analysis_speed_04/16_var_four_values.js -----
(function(){
  const {n,pctInt,R,Q,C,add,choose}=EX;

  const currentInc=Q('var_base_rate_current_inc','整数增长率',['技巧'],()=>{
    const base=n(80,300); const r=n(5,30); const cur=Math.round(base*(100+r)/100); const ans=String(cur);
    return R(`${base} 增长 ${r}% 后约为多少？`,ans,choose(ans,[cur+5,cur-5,base+r,base]),'现期=基期×(1+r)。',`${base}×(1+${r}%)≈${cur}。`);
  });
  const currentSmall=Q('var_base_rate_current_small','小数百分率',['技巧'],()=>{
    const base=n(200,900); const r=n(11,49)/10; const cur=Math.round(base*(1+r/100)); const ans=String(cur);
    return R(`${base} 增长 ${r}% 后约为多少？`,ans,choose(ans,[cur+3,cur-3,Math.round(base*(1-r/100)),base]),'小百分率也乘1+r。',`${base}×(1+${r}%)≈${cur}。`);
  });
  const currentDown=Q('var_base_rate_current_down','负增长',['技巧'],()=>{
    const base=n(300,900); const r=n(5,25); const cur=Math.round(base*(100-r)/100); const ans=String(cur);
    return R(`${base} 下降 ${r}% 后约为多少？`,ans,choose(ans,[Math.round(base*(100+r)/100),cur+8,cur-8,base-r]),'下降用1-r。',`${base}×(1-${r}%)≈${cur}。`);
  });
  const getCurrent=C('var_four_current','给基期和率求现期',['技巧'],[currentInc,currentSmall,currentDown],'sequence');

  const denomBase=Q('var_current_amount_rate_base','分母是基期',['技巧'],()=>{
    const base=n(100,400); const inc=n(10,90); const cur=base+inc; const rate=Math.round(inc/base*1000)/10; const ans=`${rate}%`;
    return R(`某指标现期为${cur}，比上期增加${inc}，增长率约为多少？`,ans,[ans,`${Math.round(inc/cur*1000)/10}%`,`${inc}%`,`${Math.round(cur/base*100)}%`],'先还原基期=现期-增长量。',`基期=${cur}-${inc}=${base}，增长率=${inc}/${base}≈${ans}。`);
  });
  const percentOption=Q('var_current_amount_rate_percent','百分号干扰',['运用'],()=>{
    const base=n(120,360); const inc=n(12,72); const cur=base+inc; const rate=Math.round(inc/base*1000)/10; const ans=`${rate}%`;
    return R(`现期${cur}万人，比基期多${inc}万人。下列哪个最可能是增长率？`,ans,[ans,`${inc}万人`,`${cur}万人`,`${base}万人`],'选项单位先筛。',`增长率应带百分号，且分母为基期${base}。`);
  });
  const wrongDenom=Q('var_current_amount_rate_wrong_denom','现期作分母陷阱',['运用'],()=>{
    const base=n(150,450); const inc=n(30,120); const cur=base+inc; const correct=Math.round(inc/base*1000)/10; const wrong=Math.round(inc/cur*1000)/10;
    return R(`现期${cur}亿元，增长${inc}亿元。若有人算成${inc}/${cur}≈${wrong}%，错在哪里？`,'把现期误作增长率分母',['把现期误作增长率分母','把增长量误作现期','把基期加了两次','把亿元写成万人'],'增长率分母永远是基期。',`正确分母是基期=${cur}-${inc}=${base}，不是现期${cur}。`);
  });
  const getRate=C('var_four_rate','给现期和增长量求率',['技巧'],[denomBase,percentOption,wrongDenom],'sequence');

  const baseUp=Q('var_current_rate_base_up','除以1+r',['技巧'],()=>{
    const base=n(100,500); const r=n(5,25); const cur=Math.round(base*(100+r)/100); const ans=String(Math.round(cur/(1+r/100)));
    return R(`现期约${cur}，同比增长${r}%，基期约为多少？`,ans,choose(ans,[Number(ans)+10,Number(ans)-10,cur,Math.round(cur*(1+r/100))]),'倒推基期要除以增长因子。',`基期≈${cur}/(1+${r}%)≈${ans}。`);
  });
  const baseDown=Q('var_current_rate_base_down','下降除以1-r',['技巧'],()=>{
    const base=n(200,700); const r=n(5,30); const cur=Math.round(base*(100-r)/100); const ans=String(Math.round(cur/(1-r/100)));
    return R(`现期约${cur}，同比下降${r}%，基期约为多少？`,ans,choose(ans,[Math.round(cur/(1+r/100)),Number(ans)+15,Number(ans)-15,cur]),'下降的因子是1-r。',`基期≈${cur}/(1-${r}%)≈${ans}。`);
  });
  const baseUnit=Q('var_current_rate_base_unit','选项单位干扰',['运用'],()=>{
    const base=n(50,180); const r=n(8,28); const cur=Math.round(base*(100+r)/100); const ans=`${Math.round(cur/(1+r/100))}亿元`;
    return R(`现期${cur}亿元，同比增长${r}%。基期约为？`,ans,[ans,`${r}%`,`${cur}亿元`,`${Math.round(cur*r/100)}亿元`],'题目问基期，是量。',`基期是具体量，约${ans}，不是百分号。`);
  });
  const getBase=C('var_four_base','给现期和率求基期',['技巧'],[baseUp,baseDown,baseUnit],'sequence');

  add(C('var_four_values','变量训练｜四量互推',['技巧'],[getCurrent,getRate,getBase],'all'));
})();

// ----- lessons/data_analysis_speed_04/17_var_question_time.js -----
(function(){
  const {n,R,Q,C,add}=EX;
  const early=Q('var_time_early','问题早于材料',['基础'],()=>{
    const mat=n(2018,2024); const ask=mat-n(1,4);
    return R(`材料给${mat}年，问题问${ask}年数据，通常先判断为哪类？`,'基期问题',['基期问题','现期问题','未来预测','百分点问题'],'问题时间更早。',`${ask}早于${mat}，通常是从材料时间倒推基期。`);
  });
  const same=Q('var_time_same','问题等于材料',['基础'],()=>{
    const y=n(2018,2024);
    return R(`材料和问题都问${y}年，通常优先按什么处理？`,'现期或当期增长相关',['现期或当期增长相关','基期倒推','未来预测','无关年份'],'同年不倒推。','问题时间等于材料时间，通常围绕现期量或当期增长关系。');
  });
  const late=Q('var_time_late','问题晚于材料',['基础'],()=>{
    const mat=n(2016,2021); const ask=mat+n(1,4);
    return R(`材料给${mat}年，问题问${ask}年，通常是什么方向？`,'未来现期问题',['未来现期问题','基期问题','年均增长量','差分法'],'问题时间更晚。',`${ask}晚于${mat}，通常按增长率往后推未来量。`);
  });
  const timeRoute=C('var_time_direction','时间方向判断',['基础'],[early,same,late],'sequence');

  const pct=Q('var_unit_percent','百分号选项',['基础'],()=>R('四个选项分别为12.5%、36亿元、54万人、120吨，题目大概率问什么？','增长率',['增长率','增长量','具体人数','具体产量'],'百分号对应率。','带百分号的答案形态通常对应增长率、增速或增幅。'));
  const real=Q('var_unit_real','实际单位选项',['基础'],()=>R('选项都是“亿元”，题干问“增长多少”，应优先判断为？','增长量',['增长量','增长率','增速','百分点'],'实际单位对应量。','“增长多少亿元”问增长量。'));
  const speed=Q('var_unit_speed','增长快慢问法',['基础'],()=>R('“下列哪项增长最快”通常比较什么？','增长率',['增长率','增长量','现期量','基期量'],'快慢看速度。','增长最快、增速最高、增长幅度最大，本质是比较增长率。'));
  const unitRoute=C('var_unit_route','单位与措辞判断',['基础'],[pct,real,speed],'all');

  const month=Q('var_ring_month','月份环比',['基础'],()=>{
    const m=n(2,12);
    return R(`${m}月环比增长，是与哪个月比较？`,`${m-1}月`,[`${m-1}月`,`${m}月`,`${m+1>12?1:m+1}月`,`去年${m}月`],'环比看紧邻上一期。',`${m}月环比是和${m-1}月比较。`);
  });
  const quarter=Q('var_ring_quarter','季度环比',['基础'],()=>{
    const q=n(2,4);
    return R(`${q}季度环比，是与哪个季度比较？`,`${q-1}季度`,[`${q-1}季度`,`${q}季度`,`${q+1>4?1:q+1}季度`,`去年${q}季度`],'季度环比看上一季度。',`${q}季度的上一季度是${q-1}季度。`);
  });
  const cross=Q('var_ring_cross_year','跨年上一季度',['基础'],()=>{
    const y=n(2016,2025);
    return R(`${y}年一季度环比，是与哪个时期比较？`,`${y-1}年四季度`,[`${y-1}年四季度`,`${y}年二季度`,`${y-1}年一季度`,`${y}年全年`],'一季度往前跨年。',`${y}年一季度的上一季度是${y-1}年四季度。`);
  });

  const yoy=Q('var_ring_yoy','同比训练',['基础'],()=>{
    const y=n(2018,2025); const m=n(1,12);
    return R(`${y}年${m}月同比增长，是与哪个时期比较？`,`${y-1}年${m}月`,[`${y-1}年${m}月`,`${y}年${m===1?12:m-1}月`,`${y}年${m}月`,`${y-1}年全年`],'同比看去年同期。',`同比不是紧邻上月，而是和上一年同一时期比，所以是${y-1}年${m}月。`);
  });
  const ringRoute=C('var_ring_route','环比/同比训练',['基础'],[month,quarter,cross,yoy],'sequence');

  add(C('var_question_time','变量训练｜问法识别与环比',['基础'],[timeRoute,unitRoute,ringRoute],'all'));
})();

// ----- lessons/data_analysis_speed_04/18_var_fraction_methods.js -----
(function(){
  const {n,R,Q,C,add}=EX;
  const bigSmall=Q('var_frac_basic_bigsmall','分子大分母小',['技巧'],()=>{
    const a=n(60,120), b=n(80,150); const c=a+n(10,30), d=b-n(10,30);
    return R(`比较 ${c}/${d} 与 ${a}/${b}，哪个更大？`,`${c}/${d}`,[`${c}/${d}`,`${a}/${b}`,'无法直接判断','一定相等'],'分子更大、分母更小。',`${c}>${a}且${d}<${b}，所以${c}/${d}一定更大。`);
  });
  const smallBig=Q('var_frac_basic_smallbig','分子小分母大',['技巧'],()=>{
    const a=n(80,150), b=n(60,120); const c=a-n(10,30), d=b+n(10,30);
    return R(`比较 ${c}/${d} 与 ${a}/${b}，哪个更大？`,`${a}/${b}`,[`${a}/${b}`,`${c}/${d}`,'无法判断','一定相等'],'左边分子小分母大。',`${c}<${a}且${d}>${b}，所以${c}/${d}更小，${a}/${b}更大。`);
  });
  const basic=C('var_frac_basic','基本大小',['技巧'],[bigSmall,smallBig],'all');

  const matchDen=Q('var_frac_match_den','配分母',['技巧'],()=>{
    const a=n(21,49), b=100, c=a+n(2,7), d=110; const left=a/b, right=c/d; const ans=left>right?`${a}/${b}`:`${c}/${d}`;
    return R(`用配分母思路比较 ${a}/${b} 与 ${c}/${d}，哪个更大？`,ans,[ans, ans===`${a}/${b}`?`${c}/${d}`:`${a}/${b}`,'一样大','无法比较'],'把110约配到100或把100配到110。',`可把${c}/${d}粗配到分母100，或直接比较交叉乘积：${a*d} 与 ${c*b}，答案为${ans}。`);
  });
  const matchNum=Q('var_frac_match_num','配分子',['技巧'],()=>{
    const a=n(40,80), b=n(90,160); const c=a+n(1,8), d=b+n(5,20); const ans=(a/b>c/d)?`${a}/${b}`:`${c}/${d}`;
    return R(`比较 ${a}/${b} 与 ${c}/${d}，可先把分子配近。哪个更大？`,ans,[ans, ans===`${a}/${b}`?`${c}/${d}`:`${a}/${b}`,'无法判断','必然相等'],'分子接近时看分母。',`分子很接近，分母越小分数越大；精确交叉也可验证，答案为${ans}。`);
  });
  const matchBad=Q('var_frac_match_bad','误差过大不用',['运用'],()=>R('配同法中，如果为了配同需要把一个数粗改20%以上，应如何处理？','不要硬配，换方法',['不要硬配，换方法','继续硬配','直接选分母小的','直接选分子大的'],'配同误差会误导。','配同适合误差可控的近似；误差过大时，应改用直除、交叉、拆分或差分。'));
  const match=C('var_frac_match','配同法',['技巧'],[matchDen,matchNum,matchBad],'sequence');

  const splitGt=Q('var_frac_split_gt','大于1',['技巧'],()=>{
    const b=n(80,160), tail=n(3,18), a=b+tail;
    return R(`${a}/${b} 接近1且大于1，应拆成什么？`,`1 + ${tail}/${b}`,[`1 + ${tail}/${b}`,`1 - ${tail}/${b}`,`${b}/${tail} - 1`,`${a+b}/${b}`],'超过1就是加尾巴。',`${a}/${b}=1+(${a}-${b})/${b}=1+${tail}/${b}。`);
  });
  const splitLt=Q('var_frac_split_lt','小于1',['技巧'],()=>{
    const b=n(90,180), tail=n(4,20), a=b-tail;
    return R(`${a}/${b} 接近1且小于1，应拆成什么？`,`1 - ${tail}/${b}`,[`1 - ${tail}/${b}`,`1 + ${tail}/${b}`,`${tail}/${b} - 1`,`${b}/${a} - 1`],'低于1就是减尾巴。',`${a}/${b}=1-(${b}-${a})/${b}=1-${tail}/${b}。`);
  });
  const splitTail=Q('var_frac_split_tail','尾巴方向',['技巧'],()=>R('两个小于1且都接近1的分数，拆成1-尾巴后，哪个更大？','尾巴更小的更大',['尾巴更小的更大','尾巴更大的更大','尾巴相加更大的更大','无法比较'],'从1里减得越少越大。','小于1时是1-尾巴，尾巴越大，整体越小。'));
  const split=C('var_frac_split','拆分法',['技巧'],[splitGt,splitLt,splitTail],'sequence');

  const diffUp=Q('var_frac_diff_up','差分大于小分数',['技巧'],()=>{
    const a=20, b=100, c=50, d=180; // small=.2 diff=30/80=.375, large=.277 bigger
    return R(`比较 ${c}/${d} 与 ${a}/${b}。差分为 ${(c-a)}/${(d-b)}，它大于小分数时结论是什么？`,`${c}/${d} 更大`,[`${c}/${d} 更大`,`${a}/${b} 更大`,'两者相等','不能比较'],'差分大，整体被拉高。',`小分数是${a}/${b}，差分${c-a}/${d-b}更大，所以大分数${c}/${d}被拉高，更大。`);
  });
  const diffDown=Q('var_frac_diff_down','差分小于小分数',['技巧'],()=>{
    const a=40, b=100, c=50, d=180; // small .4 diff .125, large .277 lower
    return R(`比较 ${c}/${d} 与 ${a}/${b}。差分为 ${(c-a)}/${(d-b)}，它小于小分数时结论是什么？`,`${c}/${d} 更小`,[`${c}/${d} 更小`,`${c}/${d} 更大`,'两者相等','一定无法判断'],'差分小，整体被拉低。',`新增部分比例小于原小分数，所以扩大后的${c}/${d}小于${a}/${b}。`);
  });
  const diffMis=Q('var_frac_diff_not_avg','错误理解',['运用'],()=>R('差分法中，差分分数能不能简单当作两个分数的平均数？','不能',['不能','能','只在分母相同时能','只在选项少时能'],'差分是新增部分比例。','差分分数表示新增分子/新增分母的比例，用来判断拉高还是拉低，不是两个原分数的平均数。'));
  const diff=C('var_frac_diff','差分法',['技巧'],[diffUp,diffDown,diffMis],'sequence');

  add(C('var_fraction_methods','变量训练｜分数比较方法选择',['技巧'],[basic,match,split,diff],'all'));
})();

// ----- lessons/data_analysis_speed_04/19_var_mixed_growth.js -----
(function(){
  const {n,R,Q,C,add}=EX;
  const between=Q('var_mixed_between','整体在两者之间',['技巧'],()=>{
    const a=n(3,12), b=n(15,30); const low=Math.min(a,b), high=Math.max(a,b); const ans=`${n(low+1,high-1)}%`;
    return R(`甲增长${a}%，乙增长${b}%，甲乙合计增长率最可能是？`,ans,[ans,`${high+5}%`,`${low-3}%`,`${high+10}%`],'整体在部分之间。',`合计增长率是加权平均，只能在${low}%到${high}%之间。`);
  });
  const notMax=Q('var_mixed_not_max','不能取最大',['技巧'],()=>{
    const a=n(5,10), b=n(20,35);
    return R(`A增长${a}%，B增长${b}%，整体增长率能否高于${b}%？`,'不能',['不能','一定能','只要B现期大就能','只要A增长量小就能'],'加权平均不超过最大。',`整体增长率夹在${a}%与${b}%之间，通常不能高于最大部分${b}%。`);
  });
  const notMin=Q('var_mixed_not_min','不能取最小',['技巧'],()=>{
    const a=n(5,10), b=n(20,35);
    return R(`A增长${a}%，B增长${b}%，整体增长率能否低于${a}%？`,'不能',['不能','一定能','只要A基期小就能','只看增长量决定'],'加权平均不低于最小。',`整体增长率夹在${a}%与${b}%之间，通常不能低于最小部分${a}%。`);
  });
  const range=C('var_mixed_range','范围判断',['技巧'],[between,notMax,notMin],'all');

  const bigWeight=Q('var_mixed_big_weight','大权重拉动',['技巧'],()=>R('若甲基期占90%且增长率5%，乙基期占10%且增长率40%，整体增长率更靠近谁？','甲的5%',['甲的5%','乙的40%','两者正中间22.5%','一定超过40%'],'权重大者拉动整体。','整体增长率按基期权重加权，甲权重90%，所以整体更靠近甲的5%。'));
  const smallWeight=Q('var_mixed_small_weight','小权重有限',['技巧'],()=>R('某小部分增长率很高，但基期占比很小，对整体增速影响如何？','影响有限',['影响有限','一定决定整体','一定让整体超过最大值','完全没有影响'],'权重要看基期规模。','小权重部分即使增速高，也只能有限拉动整体，不会让整体超过部分最大增速。'));
  const weight=C('var_mixed_weight','权重偏向',['技巧'],[bigWeight,smallWeight],'all');

  const extreme=Q('var_mixed_eliminate_extreme','极端值排除',['运用'],()=>R('部分增速分别为4%、9%、12%，整体增速选项中哪个必错？','15%',['15%','8%','10%','6%'],'整体不超最大不低最小。','整体增速应在4%到12%之间，15%超出范围，必错。'));
  const inRange=Q('var_mixed_eliminate_weight','范围内再结合权重',['运用'],()=>R('混合增速选项都在范围内时，下一步应看什么？','基期权重偏向',['基期权重偏向','选项字数','材料页码','年份奇偶'],'范围只能先排除。','若选项都在部分增速之间，需要看基期权重，整体更靠近权重大的部分。'));
  const eliminate=C('var_mixed_eliminate','排除选项',['运用'],[extreme,inRange],'sequence');

  add(C('var_mixed_growth','变量训练｜混合增长率',['技巧'],[range,weight,eliminate],'all'));
})();

// ----- lessons/data_analysis_speed_04/20_var_avg_growth_amount.js -----
(function(){
  const {n,R,Q,C,add,choose}=EX;
  const normal=Q('var_aga_normal','2015到2018除以3',['技巧'],()=>{
    const start=n(100,400), end=start+n(60,180); const ans=Math.round((end-start)/3);
    return R(`2015年为${start}亿元，2018年为${end}亿元，年均增长量约为多少？`,`${ans}亿元`,[`${ans}亿元`,`${Math.round((end-start)/4)}亿元`,`${end-start}亿元`,`${Math.round(end/3)}亿元`],'年份差=2018-2015=3。',`年均增长量=(${end}-${start})/3≈${ans}亿元。`);
  });
  const notCount=Q('var_aga_not_count','年份差不是年份个数',['技巧'],()=>R('2015、2016、2017、2018共4个年份，为什么年均增长量分母不是4？','增长间隔只有3个',['增长间隔只有3个','因为2018不计算','因为2015不计算','因为要除以5'],'看间隔，不看年份个数。','从2015到2018经历2015→2016、2016→2017、2017→2018，共3个增长间隔。'));
  const gap=C('var_aga_gap','普通年份差',['技巧'],[normal,notCount],'sequence');

  const hasPrev=Q('var_aga_has_prev','材料有前一年',['运用'],()=>{
    const y=n(2015,2020); const prev=y-1; const p=n(80,200), end=p+n(80,240); const ans=Math.round((end-p)/(y+3-prev));
    return R(`题问${y}—${y+3}平均每年增长，材料给${prev}年${p}亿元和${y+3}年${end}亿元。按课程规则初期取哪年？`,`${prev}年`,[`${prev}年`,`${y}年`,`${y+3}年`,`${y+1}年`],'有前一年，用前一年作初期。',`按时间边界规则，若材料给${prev}年，则把${y}看成第一年增长后的结果，初期取${prev}年。`);
  });
  const noPrev=Q('var_aga_no_prev','材料无前一年',['运用'],()=>R('题问2016—2019平均每年增长，但材料没有2015年数据，应取哪年为初期？','2016年',['2016年','2015年','2019年','2017年'],'没有前一年只能用首年。','材料没有前一年数据时，用题干首年2016作为初期。'));
  const firstGrowth=Q('var_aga_first_growth','题干首年与增长首年',['运用'],()=>R('“2015—2018平均每年增长”且给2014数据时，为什么可能用2014作初期？','把2015视作第一年增长后的结果',['把2015视作第一年增长后的结果','因为年份差必须是4','因为2015没有意义','因为2018不能作末期'],'这是课程规则的陷阱。','若材料给2014，课程规则把2015视为第一年增长后的结果，因此用2014到2018计算。'));
  const prevTrap=C('var_aga_prevtrap','前一年陷阱',['运用'],[hasPrev,noPrev,firstGrowth],'sequence');

  const yuan=Q('var_aga_unit_yuan','亿元',['基础'],()=>R('选项单位是亿元，且问平均每年增长多少，判断为？','年均增长量',['年均增长量','年均增长率','百分点','增速'],'亿元是实际单位。','带亿元、万元、吨等实际单位，是量，不是率。'));
  const wan=Q('var_aga_unit_wan','万人',['基础'],()=>R('选项单位是万人，且问平均每年增加多少，判断为？','年均增长量',['年均增长量','年均增长率','百分比','环比增速'],'万人是实际单位。','实际单位对应年均增长量。'));
  const notPct=Q('var_aga_unit_not_pct','百分号不是年均增长量',['基础'],()=>R('求年均增长量时，哪个选项形态最可疑？','12.5%',['12.5%','12.5亿元','12.5万人','12.5万吨'],'百分号是率。','年均增长量应带实际单位，百分号通常是年均增长率。'));
  const unit=C('var_aga_unit','单位识别',['基础'],[yuan,wan,notPct],'all');

  add(C('var_avg_growth_amount','变量训练｜年均增长量',['技巧'],[gap,prevTrap,unit],'all'));
})();

// ----- lessons/data_analysis_speed_04/21_var_avg_growth_rate_estimate.js -----
(function(){
  const {n,R,Q,C,add}=EX;
  const pos=Q('var_agr_exact_pos','正增长',['基础'],()=>{
    const start=n(80,180), N=n(3,6), end=start+n(30,140);
    const ans=`(1+r)^${N} = ${end}/${start}`;
    return R(`从${start}增长到约${end}，${N}年年均增长率应列什么式？`,ans,[ans,`(1-r)^${N} = ${end}/${start}`,`${N}r = ${start}/${end}`,`r/${N} = ${end}/${start}`],'正增长用1+r。',`年均增长率连续乘法，${N}个间隔列(1+r)^${N}=末/初=${end}/${start}。`);
  });
  const neg=Q('var_agr_exact_neg','负增长',['基础'],()=>{
    const start=n(120,260), N=n(2,5), end=start-n(25,80);
    const ans=`(1-r)^${N} = ${end}/${start}`;
    return R(`从${start}下降到约${end}，${N}年年均下降率应列什么式？`,ans,[ans,`(1+r)^${N} = ${end}/${start}`,`${N}r = ${end}/${start}`,`r = ${start}/${end}`],'下降用1-r。',`年均下降率的因子是1-r，所以列(1-r)^${N}=末/初=${end}/${start}。`);
  });
  const exact=C('var_agr_exact_route','精确式识别',['基础'],[pos,neg],'sequence');

  const small=Q('var_agr_two_small','小增速可用',['技巧'],()=>{
    const N=n(3,8); const Rbig=n(12,32); const approx=Math.round(Rbig/N*10)/10;
    return R(`总增长约${Rbig}%，${N}年年均增长率两项估算约为多少？`,`${approx}%`,[`${approx}%`,`${Rbig}%`,`${Math.round(Rbig*N)}%`,`${Math.round(approx*2)}%`],'总增长率除以年份差。',`两项估算r≈${Rbig}%/${N}≈${approx}%。`);
  });
  const over=Q('var_agr_two_over','估算值偏大',['技巧'],()=>R('正增长两项估算为什么通常偏大？','忽略了正的二次项和更高项',['忽略了正的二次项和更高项','因为少除了一年','因为把现期当基期','因为单位换错'],'高次项也贡献增长。','真实(1+r)^N包含Nr以外的正高次项，只用Nr解释总增长，会把r估大。'));
  const chooseSmall=Q('var_agr_two_choose','选略小',['技巧'],()=>R('正增长两项估算得到10%，选项有8.8%、9.5%、10.8%、12%，一般优先考虑哪个？','9.5%',['9.5%','10.8%','12%','8.8%'],'真实值略小于估算值。','两项估算偏大，若选项合理，真实值通常略小于10%，优先考虑9.5%。'));
  const two=C('var_agr_two','两项式估算',['技巧'],[small,over,chooseSmall],'sequence');

  const high=Q('var_agr_bound_high','20%以上慎用',['技巧'],()=>R('选项在20%、30%以上时，两项估算应如何定位？','慎用，不能机械选刚小于估算值',['慎用，不能机械选刚小于估算值','一定最精确','直接选最大','完全不看末期初期'],'高次项影响大。','增速越大，r²、r³项越不可忽略，两项估算只能辅助判断。'));
  const upper=Q('var_agr_bound_upper','只能做上界',['技巧'],()=>R('正增长两项估算为25%，以下哪个选项可直接排除？','30%',['30%','22%','20%','18%'],'估算偏大，真实更小。','正增长两项估算通常是上界，高于上界的30%可排除。'));
  const notMechanical=Q('var_agr_bound_not_mechanical','不要机械选刚小',['运用'],()=>R('两项估算得到30%，选项29%、24%、21%、18%，为什么不能必然选29%？','大增速时高次项可能让真实值远低于估算',['大增速时高次项可能让真实值远低于估算','因为29%没有百分号','因为必须选最小','因为年均增长率不能超过20%'],'估算上界不等于答案。','大增速时二次项贡献很大，真实值可能明显低于30%，不能机械选刚小的29%。'));

  const declineSign=Q('var_agr_bound_decline_sign','下降符号陷阱',['运用'],()=>{
    const rough=n(12,22), real=rough+n(5,15);
    return R(`年均下降率粗估写成 -${rough}%，若进一步校验得到 -${real}%，应怎样理解？`,`-${real}%下降幅度更大`,[`-${real}%下降幅度更大`,`-${rough}%下降幅度更大`,'两者下降幅度相同','负号越靠近0下降越大'],'负增长要看下降幅度。',`代数上-${real}%更小，但下降幅度是${real}%，比${rough}%更大。负增长题不能只按“略小”机械选。`);
  });
  const bound=C('var_agr_bound','边界题',['运用'],[high,upper,notMechanical,declineSign],'sequence');

  const n3=Q('var_agr_three_n3','N=3',['技巧'],()=>R('N=3时，三项式应近似写为？','3r+3r²≈大R',['3r+3r²≈大R','3r+6r²≈大R','3r+10r²≈大R','r+3r²≈大R'],'C_3^2=3。','三项式是Nr+C_N^2r²，N=3时为3r+3r²。'));
  const n4=Q('var_agr_three_n4','N=4',['技巧'],()=>R('N=4时，三项式应近似写为？','4r+6r²≈大R',['4r+6r²≈大R','4r+4r²≈大R','4r+10r²≈大R','6r+4r²≈大R'],'C_4^2=6。','N=4时二次项系数为6。'));
  const n5=Q('var_agr_three_n5','N=5',['技巧'],()=>R('N=5时，三项式应近似写为？','5r+10r²≈大R',['5r+10r²≈大R','5r+4r²≈大R','5r+5r²≈大R','10r+5r²≈大R'],'C_5^2=10。','N=5时二次项系数为C_5^2=10。'));
  const correct=Q('var_agr_three_not_4','口误纠正',['运用'],()=>R('若笔记写成“5r+4r²”，应如何修正？','5r+10r²',['5r+10r²','5r+4r²','4r+5r²','10r+4r²'],'组合数C_5^2=10。','三项式通式为Nr+C_N^2r²，N=5时必须是5r+10r²。'));
  const three=C('var_agr_three','三项式代入',['技巧'],[n3,n4,n5,correct],'sequence');

  add(C('var_avg_growth_rate_estimate','变量训练｜年均增长率估算',['技巧'],[exact,two,bound,three],'all'));
})();

// ----- lessons/data_analysis_speed_04/22_var_line_method.js -----
(function(){
  const {n,R,Q,C,add}=EX;
  const list=Q('var_line_pos_list','列式',['技巧'],()=>{
    const start=n(80,160), N=n(2,5), end=start+n(25,120);
    const ans=`(1+r)^${N} = ${end}/${start}`;
    return R(`从${start}到约${end}，${N}年年均增长率r，划线法第一步列什么？`,ans,[ans,`(1-r)^${N} = ${end}/${start}`,`${N}r = ${start}/${end}`,`r = ${end}-${start}`],'正增长列1+r。',`划线体系先列乘方骨架，再估右边比例：${ans}。`);
  });
  const tryR=Q('var_line_pos_try','试候选',['技巧'],()=>{
    const r=n(6,18), N=n(2,5); const factor=(1+r/100).toFixed(2).replace(/0$/,'').replace(/\.0$/,'');
    const ans=`${factor}^${N}`;
    return R(`若候选r=${r}%，则${N}年增长因子应写成什么？`,ans,[ans,`${(1-r/100).toFixed(2)}^${N}`,`${factor}`,`${r}^${N}`],'候选率先转因子。',`正增长${r}%的年增长因子是1+${r}%，即${factor}，${N}年就是${ans}。`);
  });
  const high=Q('var_line_pos_high','偏大则降',['技巧'],()=>{
    const target=n(120,180)/100, trial=(target+n(4,15)/100).toFixed(2);
    return R(`目标比例约${target.toFixed(2)}，候选r代入后得到${trial}，说明候选r怎样？`,'偏大，应降低',['偏大，应降低','偏小，应提高','刚好准确','只能改年份差'],'增长过头。',`候选乘方${trial}超过目标比例${target.toFixed(2)}，说明候选r过大，真实r更小。`);
  });
  const pos=C('var_line_pos','正增长划线',['技巧'],[list,tryR,high],'sequence');

  const useOneMinus=Q('var_line_neg_minus','用1-r',['技巧'],()=>{
    const r=n(8,35), N=n(2,5), start=n(100,300); const end=Math.round(start*Math.pow(1-r/100,N));
    const ans=`(1-r)^${N} = ${end}/${start}`;
    return R(`从${start}下降到约${end}，${N}年年均下降率r，应列什么？`,ans,[ans,`(1+r)^${N} = ${end}/${start}`,`${N}r = ${end}/${start}`,`1+r = ${end}/${start}`],'下降用保留率。',`下降r意味着每年保留1-r，所以列${ans}。`);
  });
  const downR=Q('var_line_neg_r','下降率转因子',['技巧'],()=>{
    const r=n(10,45); const factor=(1-r/100).toFixed(2).replace(/0$/,'').replace(/\.0$/,'');
    return R(`年均下降${r}%，每年因子是多少？`,factor,[factor,(1+r/100).toFixed(2),String(r),`-${factor}`],'保留1-r。',`下降${r}%就是保留${100-r}%，因子为${factor}。`);
  });
  const notPlus=Q('var_line_neg_not_plus','不要用1+r',['运用'],()=>{
    const r=n(10,40); const wrong=(1+r/100).toFixed(2), right=(1-r/100).toFixed(2).replace(/0$/,'').replace(/\.0$/,'');
    return R(`下降${r}%的题中，把因子写成${wrong}会造成什么问题？`,'把下降误当增长',['把下降误当增长','只是单位不同','答案完全不受影响','年份差少1'],'方向反了。',`${wrong}=1+${r}%代表增长${r}%，下降${r}%应写${right}=1-${r}%。`);
  });
  const neg=C('var_line_neg','负增长划线',['技巧'],[useOneMinus,downR,notPlus],'sequence');

  const single=Q('var_line_err_single','单因子误差',['技巧'],()=>{
    const e=n(1,5); const a=(1+e/100).toFixed(2).replace(/0$/,'').replace(/\.0$/,'');
    return R(`候选因子${a}相对1.00约有多大误差？`,`约${e}%`,[`约${e}%`,`约${e*10}%`,`约${Math.round(e/2)}%`,'无法估计'],'相对误差看比例。',`${a}比1.00大约${e}%。`);
  });
  const power=Q('var_line_err_power','幂次累加',['技巧'],()=>{
    const e=n(1,4), N=n(3,6); const ans=`约${e*N}%`;
    return R(`若每个因子约${e}%误差，${N}次方总误差大致可能接近？`,ans,[ans,`约${e}%`,`约${Math.round(e/N)}%`,`约${e*N*10}%`],'乘法误差近似相加。',`多因子相乘时，相对误差会近似累加，约${e}%×${N}=${e*N}%。`);
  });
  const close=Q('var_line_err_close','选项近时校验',['运用'],()=>{
    const a=n(80,120)/10, b=(a+n(1,3)/10).toFixed(1), c=(Number(b)+n(1,3)/10).toFixed(1);
    return R(`选项为${a.toFixed(1)}%、${b}%、${c}%时，划线估算后最该检查什么？`,'误差是否足以改变选项',['误差是否足以改变选项','哪个数字更顺眼','材料标题长短','年份是否偶数'],'选项太近怕误差。','选项差距很小时，必须看估算误差能否导致答案翻盘。');
  });
  const err=C('var_line_err','误差放大',['技巧'],[single,power,close],'sequence');

  const total=Q('var_line_big_total','总误差',['技巧'],()=>{
    const ratio=n(120,190)/100; const total=Math.round((ratio-1)*100);
    return R(`从1增长到约${ratio.toFixed(2)}，粗看总增长约多少？`,`${total}%`,[`${total}%`,`${Math.round(total/10)}%`,`${Math.round(ratio*100)}%`,`1.${total}%`],'相对1的增量。',`${ratio.toFixed(2)}比1多${(ratio-1).toFixed(2)}，即约${total}%总增长。`);
  });
  const divide=Q('var_line_big_divide','除以年份差',['技巧'],()=>{
    const total=n(24,72), N=n(3,8), ans=Math.round(total/N*10)/10;
    return R(`总增长约${total}%，${N}年大步估算年均约多少？`,`约${ans}%`,[`约${ans}%`,`约${total}%`,`约${Math.round(total*N)}%`,`约${Math.round(ans/2)}%`],'粗略平均分摊。',`大步估算先用总误差除以年份差，${total}%/${N}≈${ans}%。`);
  });
  const locate=Q('var_line_big_locate','只作定位',['运用'],()=>R('大步估算的结果最适合作为什么？','定位范围，再用划线校验',['定位范围，再用划线校验','唯一精确答案','替代所有公式','直接忽略选项'],'粗估不是精算。','大步估算用于快速定位，选项接近时仍需代入或划线校验。'));
  const big=C('var_line_big','大步估算',['技巧'],[total,divide,locate],'sequence');

  add(C('var_line_method','变量训练｜划线体系',['技巧'],[pos,neg,err,big],'all'));
})();

// ----- lessons/data_analysis_speed_04/23_var_rules_multiple.js -----
(function(){
  const {n,R,Q,C,add}=EX;
  const close2=Q('var_rule72_close2','接近2倍',['技巧'],()=>{
    const N=n(4,12); const ans=Math.round(72/N*10)/10;
    return R(`约${N}年翻一倍，年均增长率按72法则约为？`,`${ans}%`,[`${ans}%`,`${Math.round(115/N*10)/10}%`,`${N}%`,`${72*N}%`],'翻倍用72/N。',`72/${N}≈${ans}%。`);
  });
  const above2=Q('var_rule72_above2','略大于2倍',['技巧'],()=>R('末期是初期的2.1倍，答案相对72/N应如何？','略大于72/N',['略大于72/N','略小于72/N','等于115/N','必为负'],'比2倍多一点。','目标比例高于2倍，年均增长率应略高于72/N。'));
  const below2=Q('var_rule72_below2','略小于2倍',['技巧'],()=>R('末期是初期的1.9倍，答案相对72/N应如何？','略小于72/N',['略小于72/N','略大于72/N','等于115/N','必为0'],'比2倍少一点。','目标比例低于2倍，年均增长率应略低于72/N。'));
  const rule72=C('var_rule72','72法则',['技巧'],[close2,above2,below2],'sequence');

  const close3=Q('var_rule115_close3','接近3倍',['技巧'],()=>{
    const N=n(5,15); const ans=Math.round(115/N*10)/10;
    return R(`约${N}年增长到3倍，年均增长率按115法则约为？`,`${ans}%`,[`${ans}%`,`${Math.round(72/N*10)/10}%`,`${N}%`,`${115*N}%`],'三倍用115/N。',`115/${N}≈${ans}%。`);
  });
  const above3=Q('var_rule115_above3','略大于3倍',['技巧'],()=>R('末期是初期的3.2倍，答案相对115/N应如何？','略大于115/N',['略大于115/N','略小于115/N','等于72/N','必为0'],'比3倍更高。','目标比例高于3倍，年均增长率应略高于115/N。'));
  const below3=Q('var_rule115_below3','略小于3倍',['技巧'],()=>R('末期是初期的2.8倍，答案相对115/N应如何？','略小于115/N',['略小于115/N','略大于115/N','等于72/N','必为负'],'比3倍略低。','目标比例低于3倍，年均增长率应略低于115/N。'));
  const rule115=C('var_rule115','115法则',['技巧'],[close3,above3,below3],'sequence');

  const isTimes=Q('var_mul_is','是几倍',['基础'],()=>{
    const k=n(2,8);
    return R(`A是B的${k}倍，表示什么？`,`A/B=${k}`,[`A/B=${k}`,`(A-B)/B=${k}`,`A/B=${k+1}`,`B/A=${k}`],'“是”直接比。',`A是B的${k}倍，就是A/B=${k}。`);
  });
  const increaseTimes=Q('var_mul_increase','增长几倍',['基础'],()=>{
    const m=n(1,5); const ratio=m+1;
    return R(`A比B增长${m}倍，A/B等于多少？`,String(ratio),[String(ratio),String(m),String(ratio+1),`${m}%`],'增长部分要加回原来的1倍。',`增长${m}倍表示(A-B)/B=${m}，所以A/B=${m}+1=${ratio}。`);
  });
  const increase21=Q('var_mul_21','增长2.1倍',['基础'],()=>R('增长2.1倍，末期/初期应为多少？','3.1',['3.1','2.1','1.1','210%'],'增长倍数加1。','增长2.1倍表示多出2.1个基期，总量是1+2.1=3.1倍。'));
  const multi=C('var_multiple_words','倍数表述',['基础'],[isTimes,increaseTimes,increase21],'sequence');

  add(C('var_rules_multiple','变量训练｜72法则与倍数陷阱',['技巧'],[rule72,rule115,multi],'all'));
})();

// ----- lessons/data_analysis_speed_04/24_var_same_speed_integrated.js -----
(function(){
  const {n,R,Q,C,add,choose}=EX;
  const b2a=Q('var_same_b2a','B²/A',['技巧'],()=>{
    const A=n(80,200), factor=n(12,18)/10; const B=Math.round(A*factor); const D=Math.round(B*B/A); const ans=String(D);
    return R(`已知某指标从${A}增长到${B}。若下一等长区间保持相同年均增速，且以${B}为初期，末期约为多少？`,ans,choose(ans,[D+10,D-10,B+A,Math.round(B/A)]),'相同区间总因子相同。',`已知总因子=${B}/${A}，下一段末期D=${B}×${B}/${A}=${D}，即B²/A。`);
  });
  const targetDiff=Q('var_same_target_diff','目标初期不同',['技巧'],()=>{
    const A=100, B=140, T=200, D=280;
    return R(`已知相同年数内100变140。若另一个对象初期为200，保持相同年均增速，末期为？`,'280',['280','196','140','240'],'用相同总因子。','总因子=140/100=1.4，目标末期=200×1.4=280。');
  });
  const noR=Q('var_same_no_r','不先求r',['技巧'],()=>R('相同年均增速且年份差相同，求未来量时最佳做法是？','直接连接总比例',['直接连接总比例','先精确开方求r','先算增长量平均','直接选最大选项'],'求量不必求率。','两个等长区间年均增速相同，意味着总增长因子相同，直接连比例最快。'));
  const connect=C('var_same_connect','首尾连接',['技巧'],[b2a,targetDiff,noR],'sequence');

  const notSquare=Q('var_same_not_square','不是除以初期平方',['运用'],()=>R('由B/A = D/B推出D等于什么？','B²/A',['B²/A','B/A²','A²/B','A×B²'],'两边乘B。','B/A=D/B，两边乘B，得D=B²/A。分母是A，不是A²。'));
  const derive=Q('var_same_derive','等式推导',['运用'],()=>R('为什么“末期平方除以初期”成立？','因为两个等长区间总增长因子相同',['因为两个等长区间总增长因子相同','因为增长量相同','因为年份相加','因为选项都很大'],'相同年均增速+等长=相同总因子。','已知段因子B/A，目标段以B为初期，D/B=B/A，所以D=B²/A。'));
  const fix=C('var_same_fix','公式口误纠正',['运用'],[notSquare,derive],'sequence');

  const identify=Q('var_same_integrated_identify','先识别问法',['运用'],()=>R('综合增长题第一步仍然是什么？','识别问题时间、单位和问法',['识别问题时间、单位和问法','直接套72法则','先算所有增长量','先选中间项'],'先判断题型。','先看问的是量还是率、时间在前还是后，再决定用公式、比较、估算或连接法。'));
  const chooseFormula=Q('var_same_integrated_formula','再选公式',['运用'],()=>R('识别后发现问年均增长率，且末期约为初期2倍，选项分散，可优先考虑什么？','72法则',['72法则','增长量/现期','B²/A','差分法'],'倍增近似可用72。','接近翻倍且选项分散时，72/N可快速定位年均增长率。'));
  const optionErr=Q('var_same_integrated_error','最后看选项误差',['运用'],()=>R('估算得到约10%，选项为9.9%和10.1%，最后必须做什么？','检查估算误差',['检查估算误差','直接选10.1%','直接选9.9%','忽略小数'],'选项太近。','当选项非常接近时，估算误差可能改变答案，必须用划线或代入校验。'));
  const integrated=C('var_same_integrated','综合判断',['运用'],[identify,chooseFormula,optionErr],'sequence');

  add(C('var_same_speed_integrated','变量训练｜相同年均增速与综合陷阱',['运用'],[connect,fix,integrated],'all'));
})();

