// ----- lessons/data_analysis_speed_05/_common.js -----
(function(){
  const pk=a=>a[Math.floor(Math.random()*a.length)];
  const n=(a,b)=>a+Math.floor(Math.random()*(b-a+1));
  const uq=a=>[...new Set(a)];
  const sh=a=>a.map(v=>[Math.random(),v]).sort((x,y)=>x[0]-y[0]).map(x=>x[1]);
  const op=(a,b,l=5)=>sh([a,...sh(uq(b).filter(x=>x!==a)).slice(0,l-1)]);
  const d=(x,p=1)=>Number((Math.round(x*Math.pow(10,p))/Math.pow(10,p)).toFixed(p));
  const pct=(x,p=1)=>`${d(x,p)}%`;
  const pp=(x,p=1)=>`${d(x,p)}个百分点`;
  const yuan=(x,p=1)=>String(d(x,p));
  const sign=x=>x>0?`+${pct(x)}`:pct(x);
  const R=(q,a,pool,hint,solution,extra={})=>Object.assign({q,a,pool,hint,solution},extra);
  const cid='data_analysis_speed_05';
  const Q=(id,title,tags,mk,type)=>({id,title,t:title,type:type||tags[0],tags,mk,makeQuestion:mk});
  const C=(id,title,tags,subs,unlockMode='all')=>({id,title,t:title,type:tags[0],tags,unlockMode,subs});
  const sec=title=>Game.addLessonTopic(cid,{k:'s',t:title});
  const add=t=>Game.addLessonTopic(cid,t);
  const done=title=>Game.finishLesson(cid,title);
  const inter=(r1,r2,p=1)=>d(r1+r2+r1*r2/100,p);
  const multRate=rs=>d((rs.reduce((m,r)=>m*(1+r/100),1)-1)*100,1);
  const nearChoices=(ans,unit='%')=>{
    const base=Number(String(ans).replace('%','').replace('个百分点',''));
    const vals=[base+d(n(2,9)/10,1),base-d(n(2,9)/10,1),base+n(1,3),base-n(1,3)].map(v=>unit==='%'?pct(v):unit==='百分点'?pp(v):String(d(v,1)));
    return vals;
  };
  const makeYear=()=>n(2012,2022);
  Game.beginLesson(cid);
  window.EX={pk,n,uq,sh,op,d,pct,pp,yuan,sign,R,Q,C,sec,add,done,inter,multRate,nearChoices,makeYear};
})();

// ----- lessons/data_analysis_speed_05/00_section_main.js -----
EX.sec('资料分析速算05｜隔年增长、指数、混合与精算边界');

// ----- lessons/data_analysis_speed_05/01_concept_map.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('term_fix_base','术语修正',['基础'],()=>R(
      '易混表述里反复出现“G7”，在本课资料分析语境中应还原成什么？',
      '基期',
      ['基期','现期','增长量','百分点'],
      '它常出现在“基期×(1+增长率)=现期”的位置。',
      '“G7”是语音识别口误，应还原为“基期”。'
    )),
    Q('term_fix_current','现期修正',['基础'],()=>R(
      '易混表述里的“限期”多处实际指哪一个资料分析概念？',
      '现期',
      ['现期','基期','限期日期','截止时间'],
      '看公式位置：现期=基期+增长量。',
      '本课统一把“限期”修正为“现期”。'
    )),
    Q('term_value_added','产业增加值',['基础'],()=>R(
      '“第一产业增加值”里的“增加值”能直接当作增长量吗？',
      '不能，它是经济学统计量，不是增长量',
      ['不能，它是经济学统计量，不是增长量','能，名字里有增加二字','只能当作隔年增长量','只能当作百分点'],
      '不要被名称误导。',
      '产业增加值是统计口径下的产出指标，不是“现期-基期”的增长量，不能直接套增长量公式。'
    )),
    Q('map_main_line','主线识别',['基础'],()=>R(
      '本课主线最合理的顺序是哪一个？',
      '跨年增长→指数→混合→十字交叉→精算边界',
      ['跨年增长→指数→混合→十字交叉→精算边界','十字交叉→判断推理→利润问题→图形推理','指数→语文阅读→数量排列→申论','速算边界→定义判断→常识'],
      '围绕资料分析增长类题目展开。',
      '本课先处理隔年/多年增长，再处理指数，随后进入混合原理、严格十字交叉，最后整理选项很近时的精算方法。'
    )),
    Q('method_by_question','题型意识',['基础'],()=>R(
      '资料分析中决定方法选择的三件事是：',
      '问法、材料结构、选项精度',
      ['问法、材料结构、选项精度','字体、页码、题号','题干长短、答案位置、年份颜色','材料标题、出题省份、考试月份'],
      '训练要点：先看问法，再找结构，最后看选项。',
      '跨年、整体部分、平均分母、选项差距，都会改变方法。'
    ))
  ];
  add(C('concept_map','概念总览｜口误修正与地图',['基础'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/02_section_interyear.js -----
EX.sec('一、跨年增长｜隔年、多年、固定增长率');

// ----- lessons/data_analysis_speed_05/03_interyear_rules.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('inter_def','隔年定义',['基础'],()=>R('“2017 年比 2015 年增长多少”属于哪类问题？','隔年增长问题',['相邻增长问题','隔年增长问题','平均数问题','混合增长问题'],'中间隔着 2016 年。','不是相邻两年，中间隔了一年，所以属于隔年增长。')),
    Q('inter_two_types','两类问题',['基础'],()=>R('隔年增长问题包含哪两类？','隔年增长量和隔年增长率',['隔年增长量和隔年增长率','比重和平均数','指数和百分点','现期和选项'],'“问题”比“增长率”范围更大。','隔年增长问题包含隔年增长量与隔年增长率，本课重点是隔年增长率。')),
    Q('inter_amount','隔年增长量',['基础'],()=>R('2017 年比 2015 年多多少，本质应如何拆？','2017 比 2016 的增长量 + 2016 比 2015 的增长量',['2017 比 2016 的增长量 + 2016 比 2015 的增长量','只看 2017 比 2016 的增长量','只看 2016 比 2015 的增长量','两个增长率相加'],'问的是跨两年的总增量。','隔年增长量等于中间两段增长量相加。')),
    Q('inter_formula','公式本体',['技巧'],()=>R('若后一年增长率为 r1，前一年增长率为 r2，隔年增长率 R 等于：','r1+r2+r1r2',['r1+r2+r1r2','r1+r2','r1-r2','r1r2'],'由 (1+r1)(1+r2)-1 展开。','隔年增长率 R=(1+r1)(1+r2)-1=r1+r2+r1r2。')),
    Q('inter_years','年份选择',['基础'],()=>R('求 2017 年比 2015 年增长率，应使用哪两个年份的增长率？','2017 年增长率和 2016 年增长率',['2017 年增长率和 2016 年增长率','2016 年增长率和 2015 年增长率','2017 年增长率和 2015 年增长率','只用 2015 年增长率'],'2015 是基期，不是被相加的增长率年份。','2016 年增长率指 2016 比 2015；2017 年增长率指 2017 比 2016。')),
    Q('inter_product_positive','同正方向',['技巧'],()=>R('两个增长率都为正时，隔年增长率与 r1+r2 的关系是：','略大于 r1+r2',['略大于 r1+r2','略小于 r1+r2','一定等于 r1+r2','无法判断'],'乘积项 r1r2 为正。','R=r1+r2+r1r2，同正时乘积项为正，所以略大于两者之和。')),
    Q('inter_product_mix','一正一负方向',['技巧'],()=>R('一个增长率为正、一个为负时，r1r2 的符号是：','负数',['正数','负数','零','百分点'],'正负相乘为负。','一正一负时乘积项为负，所以隔年增长率小于前两项之和。')),
    Q('inter_product_negative','同负方向',['技巧'],()=>R('两个增长率都为负时，隔年增长率与 r1+r2 的关系是：','比 r1+r2 略大，但仍为负',['比 r1+r2 略大，但仍为负','比 r1+r2 更小','一定为正','一定等于 r1+r2'],'负负相乘为正。','R=r1+r2+r1r2，同负时乘积项为正，会把简单相加的负数往上拉一点，但两年都下降时总体仍是下降。')),
    Q('percent_vs_point','百分数与百分点',['基础'],()=>R('“同比增长 5.3%，比上年下降 1 个百分点”说明上年增长率为：','6.3%',['4.3%','5.3%','6.3%','1%'],'百分点可以直接加减增长率。','今年 5.3%，比上年低 1 个百分点，所以上年增长率为 6.3%。')),
    Q('separate_sentence','独立句陷阱',['基础'],()=>R('“同比增长 5.3%，上年同期为下降 1%”中，上一年增长率是：','-1%',['4.3%','6.3%','-1%','1 个百分点'],'没有“比上年……百分点”的连接。','“上年同期为下降 1%”是独立陈述，表示上一年增长率为 -1%，不能和 5.3% 直接加减。')),
    Q('base_back','隔年基期',['技巧'],()=>R('已知 2010 年现期量，要求 2008 年量，合理方法是：','逐年倒推或先求 2010 比 2008 的隔年增长率',['逐年倒推或先求 2010 比 2008 的隔年增长率','直接减两个增长率','只除以 2010 年增长率','只除以 2009 年增长率'],'2008 到 2010 跨了两段。','可先 2010→2009→2008，也可先合成隔年增长率再用基期公式。')),
    Q('multi_multiply','多年增长',['技巧'],()=>R('跨三年及以上时，最稳的总增长率思路是：','先把多个 (1+r) 连乘成倍数，再减 1',['先把多个 (1+r) 连乘成倍数，再减 1','所有增长率直接相加','只取最大年份增长率','只算第一个和最后一个增长率'],'多年展开太麻烦，倍数连乘更稳。','最终倍数=(1+r1)(1+r2)…，最终增长率=最终倍数-1。')),
    Q('rate_and_times','倍数关系',['基础'],()=>R('A 是 B 的 1.36 倍，A 比 B 增长了：','36%',['1.36%','36%','136%','0.36 个百分点'],'增长率=倍数-1。','1.36-1=0.36，即增长 36%。'))
  ];
  add(C('interyear_rules','隔年增长｜硬性规则',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/04_interyear_training.js -----
(function(){
  const {n,op,R,Q,C,add,pct,pp,inter,multRate,makeYear,d}=EX;
  const samePositive=Q('inter_train_same_positive','同正计算',['技巧'],()=>{
    const y=makeYear(), r1=n(5,18), r2=n(3,16), ans=pct(inter(r1,r2));
    const sum=pct(r1+r2);
    return R(`${y} 年比 ${y-1} 年增长 ${r1}%，${y-1} 年比 ${y-2} 年增长 ${r2}%。${y} 年比 ${y-2} 年增长约多少？`,ans,op(ans,[sum,pct(r1+r2+2),pct(r1+r2-1),pct(r1*r2/100)]),'同正时答案要比两者之和略大。',`隔年增长率=${r1}%+${r2}%+${r1}%×${r2}%=${ans}，比 ${sum} 略大。`);
  });
  const mixedSign=Q('inter_train_mixed_sign','一正一负',['技巧'],()=>{
    const y=makeYear(), r1=n(6,20), r2=-n(2,12), ans=pct(inter(r1,r2));
    const sum=pct(r1+r2);
    return R(`${y} 年增长 ${r1}%，${y-1} 年下降 ${-r2}%。${y} 年比 ${y-2} 年增长率约为？`,ans,op(ans,[sum,pct(r1-r2),pct(r1+r2+1),pct(r1+r2+Math.abs(r1*r2/100))]),'一正一负，乘积项为负，答案比前两项之和更小。',`R=${r1}%+(${r2}%)+${r1}%×(${r2}%)=${ans}，小于 ${sum}。`);
  });
  const bigProduct=Q('inter_train_big_product','大乘积项',['运用'],()=>{
    const y=makeYear(), r1=n(35,65), r2=n(20,45), ans=pct(inter(r1,r2));
    const prod=d(r1*r2/100,1);
    return R(`${y} 年增长 ${r1}%，${y-1} 年增长 ${r2}%。这类题最不能忽略哪一项？`,`乘积项，约 ${prod} 个百分点`,op(`乘积项，约 ${prod} 个百分点`,[`两者之和，约 ${r1+r2} 个百分点`,`年份差，约 1 年`,`基期年份，不影响答案`,`百分点单位，不需要看`]),'增长率越大，乘积项越大。',`乘积项=${r1}%×${r2}%≈${prod} 个百分点，已经不小，不能像小增长率那样忽略。`);
  });
  const formulaRoute=C('inter_formula_route','公式识别',['技巧'],[samePositive,mixedSign,bigProduct],'sequence');

  const yearPick=Q('inter_train_year_pick','年份定位',['基础'],()=>{
    const y=makeYear();
    return R(`求 ${y} 年比 ${y-2} 年增长率，应选哪两个增长率进入公式？`,`${y} 年和 ${y-1} 年`,op(`${y} 年和 ${y-1} 年`,[`${y-1} 年和 ${y-2} 年`,`${y} 年和 ${y-2} 年`,`${y-2} 年和 ${y-3} 年`]),'基期年份不直接作为增长率相加。',`${y-1} 年增长率是 ${y-1} 比 ${y-2}；${y} 年增长率是 ${y} 比 ${y-1}。`);
  });
  const baseTrap=Q('inter_train_base_trap','基期陷阱',['基础'],()=>{
    const y=makeYear();
    return R(`${y} 年比 ${y-2} 年增长，中间隔着哪一年？`,String(y-1),op(String(y-1),[String(y),String(y-2),String(y-3)]),'找中间年份。',`${y} 与 ${y-2} 不是相邻年份，中间隔着 ${y-1} 年。`);
  });
  const yearRoute=C('inter_year_route','年份定位',['基础'],[yearPick,baseTrap],'all');

  const pointDown=Q('inter_point_down','百分点下降',['基础'],()=>{
    const now=n(3,16), diff=n(1,8), ans=pct(now+diff);
    return R(`今年同比增长 ${now}%，比上年下降 ${diff} 个百分点。上年增长率是多少？`,ans,op(ans,[pct(now-diff),pct(diff),pct(-diff),pct(now)]),'“百分点”直接加减增长率。',`今年比上年低 ${diff} 个百分点，所以上年=${now}%+${diff} 个百分点=${ans}。`);
  });
  const separate=Q('inter_separate_down','为下降 x%',['基础'],()=>{
    const now=n(3,16), prev=n(1,8); const ans=pct(-prev);
    return R(`材料写：“今年同比增长 ${now}%，上年同期为下降 ${prev}%。”上年同期增长率是多少？`,ans,op(ans,[pct(now-prev),pct(now+prev),pp(prev),pct(prev)]),'“为下降”是独立句，不是“比上年下降”。',`上年同期自己就是下降 ${prev}%，即 ${ans}。`);
  });
  const pointRoute=C('inter_point_route','百分点陷阱',['基础'],[pointDown,separate],'sequence');

  const forward=Q('inter_forward_current','已知基期求现期',['技巧'],()=>{
    const base=n(800,1800), r1=n(2,9), r2=n(2,9); const ans=String(d(base*(1+r1/100)*(1+r2/100),1));
    return R(`某量 ${base}，下一年增长 ${r1}%，再下一年增长 ${r2}%。两年后约为多少？`,ans,op(ans,[String(d(base*(1+(r1+r2)/100),1)),String(d(base*(1+r1/100),1)),String(d(base*(1+r2/100),1)),String(base+r1+r2)]),'连续两年要连乘两个增长倍数。',`两年后=${base}×(1+${r1}%)×(1+${r2}%)≈${ans}。`);
  });
  const backward=Q('inter_backward_base','已知现期求基期',['技巧'],()=>{
    const base=n(600,1500), r1=n(5,18), r2=n(4,16); const cur=d(base*(1+r1/100)*(1+r2/100),1); const ans=String(base);
    return R(`某量现在约 ${cur}，前一年增长 ${r2}%，再前一年到前一年增长 ${r1}%。两年前基期约为多少？`,ans,op(ans,[String(d(cur/(1+(r1+r2)/100),0)),String(d(cur/(1+r2/100),0)),String(d(cur/(1+r1/100),0)),String(d(cur-r1-r2,0))]),'倒推要连续除以两个增长倍数。',`两年前≈${cur}÷(1+${r2}%)÷(1+${r1}%)≈${base}。`);
  });
  const baseRoute=C('inter_base_current_route','现期/基期互求',['技巧'],[forward,backward],'sequence');

  const threeYear=Q('inter_three_year','三年连乘',['运用'],()=>{
    const rs=[n(4,12),n(3,11),n(2,10)]; const ans=pct(multRate(rs));
    return R(`连续三年增长率分别为 ${rs[0]}%、${rs[1]}%、${rs[2]}%，总增长率约为？`,ans,op(ans,[pct(rs.reduce((a,b)=>a+b,0)),pct(rs[0]+rs[2]),pct(rs[0]*rs[1]/100),pct(multRate(rs)+2)]),'先连乘成倍数，再减 1。',`总倍数=(1+${rs[0]}%)(1+${rs[1]}%)(1+${rs[2]}%)，总增长率≈${ans}。`);
  });
  const timesMinus=Q('inter_times_minus','倍数减一',['基础'],()=>{
    const a=n(120,180)/100; const ans=pct((a-1)*100);
    return R(`最终量是基期的 ${a.toFixed(2)} 倍，总增长率是多少？`,ans,op(ans,[pct(a),pct(a*100),pct((a+1)*100),`${a.toFixed(2)} 倍`]),'增长率=倍数-1。',`${a.toFixed(2)}-1=${(a-1).toFixed(2)}，即 ${ans}。`);
  });
  const multiRoute=C('inter_multi_route','多年连乘路线',['运用'],[threeYear,timesMinus],'sequence');

  add(C('interyear_training','隔年增长｜变量训练',['运用'],[formulaRoute,yearRoute,pointRoute,baseRoute,multiRoute],'all'));
})();

// ----- lessons/data_analysis_speed_05/05_section_power_index.js -----
EX.sec('二、指数与比较｜指数表、增长率比较');

// ----- lessons/data_analysis_speed_05/06_power_growth_rules.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('power_formula','连续增长公式',['技巧'],()=>R('若基期为 A，连续 n 年保持增长率 r，现期应写成：','A(1+r)^n',['A(1+r)^n','A(1+nr)^n','A+r+n','A/(1+r)^n'],'每一年都乘一次 1+r。','连续 n 年保持同一增长率，现期=A(1+r)^n。')),
    Q('power_approx','二项式近似',['技巧'],()=>R('当 r 较小时，(1+r)^n 常近似为：','1+nr',['1+nr','1-rn','n+r','1+r^n'],'只保留二项式展开前两项。','(1+r)^n=1+nr+C_n^2r^2+…，小 r 时可近似为 1+nr。')),
    Q('power_direction','正增长方向',['技巧'],()=>R('r>0 时，(1+r)^n 与 1+nr 的关系是：','(1+r)^n 更大',['(1+r)^n 更大','1+nr 更大','二者一定相等','无法判断'],'后面还有正的高次项。','正增长时高次项为正，真实值大于只保留前两项的近似值。')),
    Q('power_current_bias','求现期偏差',['技巧'],()=>R('已知增长率求现期，用 1+nr 近似时，结果通常：','偏小',['偏小','偏大','恒等于真实值','没有方向'],'真实倍数更大。','(1+r)^n>1+nr，所以用 1+nr 估出的现期偏小。')),
    Q('power_avg_bias','年均反推偏差',['技巧'],()=>R('年均增长率反推中，用两项近似反推出来的增长率通常：','偏大',['偏大','偏小','正好相等','一定为负'],'这是“求增长率”场景，不是“已知增长率求现期”。','为了用较大的单项近似整个多项式，反推出来的年均增长率会偏大。')),
    Q('catch_amount','追赶题核心',['运用'],()=>R('保持正增长率不变时，后一年增长量通常比第一年：','更大',['更大','更小','一定相等','必为负'],'增长量=基期×增长率。','正增长下基期逐年变大，增长率不变，所以增长量逐年变大。')),
    Q('catch_decrease','负增长减少量',['运用'],()=>R('保持负增长率不变时，绝对减少量通常会：','逐年变小',['逐年变小','逐年变大','恒定不变','无法比较'],'基期越来越小。','下降率不变但基期变小，所以每年减少的绝对量会变小。')),
    Q('catch_guess','过两年经验',['运用'],()=>R('“保持增长率不变，哪一年超过/达到”的“过两年”属于：','猜题经验，不能替代计算',['猜题经验，不能替代计算','严格公式','百分点定义','指数定义'],'这是考场经验。','它可以辅助判断，但仍要用第一年追赶量和差距验证。'))
  ];
  add(C('power_growth_rules','固定增长率｜二项式与追赶',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/07_index_rules.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('index_not_real','指数不是实际量',['基础'],()=>R('价格指数 115 表示价格一定是 115 元吗？','不是',['是','不是','只有单位为元时是','只有增长时是'],'指数是相对值。','指数 115 表示若上年为 100，则今年为 115，不代表实际价格是 115 元。')),
    Q('index_default','默认基准',['基础'],()=>R('指数题没有特殊说明时，默认上一年等于：','100',['100','1','0','材料最大值'],'课程强调默认上年=100。','没有特殊说明时，用“指数-100”得到增长率。')),
    Q('index_rate_formula','指数转增长率',['技巧'],()=>R('默认上年=100，指数 109.9 对应增长率为：','9.9%',['109.9%','9.9%','-9.9%','0.99%'],'指数减 100 添百分号。','109.9-100=9.9，所以增长率是 9.9%。')),
    Q('index_less_actual','指数小陷阱',['基础'],()=>R('某年指数 109.9，小于另一年指数 116，能否直接说明该年实际量更小？','不能',['能','不能','只要指数过 100 就能','只要是价格指数就能'],'指数表示相对上一年的增速。','指数小只说明相对增速小，不代表实际量小。109.9 仍表示比上一年增长 9.9%。')),
    Q('index_speed','增速快慢',['基础'],()=>R('默认上年=100 时，比较哪年增长最快，可以直接比较：','指数大小',['指数大小','实际价格大小','材料字数','年份大小'],'指数越大，增长率越大。','增长率=指数-100，因此增长最快对应指数最大。')),
    Q('index_point','慢了多少',['基础'],()=>R('2012 年增速 6.6%，2011 年增速 9.9%，2012 年比 2011 年慢了多少？','3.3 个百分点',['3.3%','3.3 个百分点','16.5%','9.9%'],'增速差用百分点。','9.9%-6.6%=3.3 个百分点，不能写 3.3%。')),
    Q('index_special_base','特殊基准',['技巧'],()=>R('若题干特别说明“上年=200”，还能机械用指数-100 吗？','不能',['能','不能','只有指数小于 100 时不能','只有求增速最快时不能'],'特殊说明优先。','若指定上年=200，就应按指定基准理解，不能默认上年=100。')),
    Q('index_interyear','指数结合隔年',['技巧'],()=>R('指数转成逐年增长率后，问跨两年增长率，应使用：','隔年增长率公式',['隔年增长率公式','简单平均数','只看后一年的指数','只看前一年的指数'],'指数只是给你增长率。','先用指数得到两年的增长率，再套 R=r1+r2+r1r2。'))
  ];
  add(C('index_rules','指数问题｜硬性规则',['基础'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/08_index_training.js -----
(function(){
  const {n,op,R,Q,C,add,pct,pp,inter}=EX;
  const indexUp=Q('index_train_up','上升指数',['基础'],()=>{
    const idx=n(1030,1260)/10, ans=pct(idx-100,1);
    return R(`某年指数为 ${idx.toFixed(1)}，默认上年=100，则增长率为？`,ans,op(ans,[pct(idx,1),pct(100-idx,1),`${idx.toFixed(1)}`,pp(idx-100,1)]),'指数减 100 添百分号。',`${idx.toFixed(1)}-100=${(idx-100).toFixed(1)}，所以增长率为 ${ans}。`);
  });
  const indexDown=Q('index_train_down','下降指数',['基础'],()=>{
    const idx=n(850,995)/10, ans=pct(idx-100,1);
    return R(`某年指数为 ${idx.toFixed(1)}，默认上年=100，则增长率为？`,ans,op(ans,[pct(100-idx,1),pct(idx,1),`${idx.toFixed(1)}`,pp(100-idx,1)]),'小于 100 表示下降。',`${idx.toFixed(1)}-100=${(idx-100).toFixed(1)}，所以增长率为 ${ans}。`);
  });
  const special=Q('index_train_special','特殊基准',['技巧'],()=>{
    const base=200, idx=n(150,240), ans=idx>base?'上升':'下降';
    return R(`题干说明“上年=200”，今年指数写作 ${idx}。应判断为上升还是下降？`,ans,op(ans,['上升','下降','无法判断','一定增长 100%']),'特殊基准优先，不默认 100。',`指定上年=200，应比较 ${idx} 与 200；${idx}${idx>base?'>':'<'}200，所以为${ans}。`);
  });
  const route1=C('index_convert_route','指数转增长率',['基础'],[indexUp,indexDown,special],'all');

  const actualTrap=Q('index_train_actual_trap','指数小但仍增长',['基础'],()=>{
    const idx=n(1010,1099)/10;
    return R(`某年指数 ${idx.toFixed(1)}，比上一年指数小。能否仅据此说该年实际量低于上一年？`,'不能',op('不能',['能','指数小于 110 就能','只要增长率低就能','要看选项']), '指数表示相对上一年的增长率。',`${idx.toFixed(1)}>100，说明该年仍比上一年增长 ${(idx-100).toFixed(1)}%，不能说实际量低于上一年。`);
  });
  const speedTrap=Q('index_train_speed_trap','增速与量',['基础'],()=>R('指数较大最直接说明什么？','增速较快',['实际量一定较大','增速较快','增长量一定最大','基期一定最大'],'指数转的是增长率。','默认基准下指数越大，增长率越大，只能说明增速更快。'));
  const route2=C('index_compare_route','指数比较陷阱',['基础'],[actualTrap,speedTrap],'all');

  const indexInter=Q('index_train_interyear','指数隔年',['技巧'],()=>{
    const i1=n(1040,1160)/10, i2=n(1030,1150)/10; const r1=i1-100, r2=i2-100; const ans=pct(inter(r1,r2));
    return R(`某年指数 ${i1.toFixed(1)}，上一年指数 ${i2.toFixed(1)}。默认基准下，该年比上上年增长率约为？`,ans,op(ans,[pct(r1+r2,1),pct(r1,1),pct(r2,1),pct(i1+i2-200,1)]),'先把指数转成增长率，再用隔年公式。',`两年增长率分别为 ${r1.toFixed(1)}% 和 ${r2.toFixed(1)}%，隔年增长率=${ans}。`);
  });
  const pointText=Q('index_train_point_text','百分点表述',['基础'],()=>{
    const a=n(1040,1140)/10, b=n(1010,1035)/10; const diff=(a-b).toFixed(1); const ans=`${diff} 个百分点`;
    return R(`甲年指数 ${a.toFixed(1)}，乙年指数 ${b.toFixed(1)}。甲年增速比乙年快多少？`,ans,op(ans,[`${diff}%`,pct(a-b,1),pct(a,1),`${a.toFixed(1)}-${b.toFixed(1)}`]),'增速差写百分点。',`增速分别为 ${(a-100).toFixed(1)}% 和 ${(b-100).toFixed(1)}%，差为 ${ans}。`);
  });
  const route3=C('index_inter_route','指数隔年',['技巧'],[indexInter,pointText],'sequence');
  add(C('index_training','指数问题｜变量训练',['运用'],[route1,route2,route3],'all'));
})();

// ----- lessons/data_analysis_speed_05/09_growth_rate_compare.js -----
(function(){
  const {n,op,R,Q,C,add,d}=EX;
  const qs=[
    Q('compare_true_formula','正规公式',['基础'],()=>R('增长率的正规概念是：','增长量/基期',['增长量/基期','增长量/现期','现期/基期','基期/现期'],'定义看分母。','增长率=增长量÷基期。')),
    Q('compare_current_possible','现期比较可行',['技巧'],()=>R('只给现期和增长量，比较增长率大小时，能否用增长量/现期比较？','可以',['可以','绝对不可以','只能比较增长量','只能比较现期'],'比较方向不变。','增长量/现期越大，增长率也越大，可以用来比大小。')),
    Q('compare_derivation','推导关键',['技巧'],()=>R('增长量/现期可比的关键变形是：','基期=现期-增长量',['基期=现期-增长量','现期=基期-增长量','增长量=基期-现期','百分点=百分数-1'],'先把基期写出来。','基期=现期-增长量，进而可证明增长量/现期与增长率同向。')),
    Q('compare_inverse','倒数方向',['技巧'],()=>R('现期/增长量越大，增长率通常：','越小',['越大','越小','不变','无法比较'],'它是增长量/现期的倒数。','现期/增长量越大，增长量/现期越小，增长率也越小。')),
    Q('compare_variable','变量比较',['运用'],()=>{
      const inc1=n(20,80), cur1=n(200,600), inc2=n(20,80), cur2=n(200,600);
      const v1=inc1/cur1, v2=inc2/cur2;
      const ans=v1>v2?'甲':'乙';
      return R(`甲：增长量 ${inc1}、现期 ${cur1}；乙：增长量 ${inc2}、现期 ${cur2}。谁的增长率更大？`,ans,op(ans,['甲','乙','一样大','无法判断']),'比较增长量/现期即可。',`甲增长量/现期≈${d(v1,3)}，乙≈${d(v2,3)}，所以${ans}更大。`);
    }),
    Q('compare_not_must','方法边界',['基础'],()=>R('用增长量/现期比较增长率的态度应是：','可以用，但不一定总是最省事',['必须永远用','绝对不能用','可以用，但不一定总是最省事','只适用于负增长'],'课程说“可以，但没必要迷信”。','有时直接用现期-增长量求基期再比，会更直观。'))
  ];
  add(C('growth_compare','增长率比较｜现期分母法',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/10_section_mixed_cross.js -----
EX.sec('三、整体部分｜混合原理与严格十字交叉');

// ----- lessons/data_analysis_speed_05/11_mixed_rules.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('mixed_core','本质',['基础'],()=>R('资料分析里的“混合原理”本质上是什么？','十字交叉法',['十字交叉法','等差数列','排列组合','利润问题'],'整体由部分混合。','混合原理本质是十字交叉法，只是在资料分析里常做估算。')),
    Q('mixed_estimate','估算版',['基础'],()=>R('资料分析混合增长率常把严格分母“基期”近似成什么？','现期量',['现期量','年份','增长量','指数'],'为了快。','严格十字交叉中分母是基期；资料分析估算时常用现期量近似。')),
    Q('mixed_good','什么时候较准',['技巧'],()=>R('混合原理用现期近似通常较稳的情况是：','两部分增长率同正且分母差异不大',['一正一负且差异巨大','两部分增长率同正且分母差异不大','一个增长 80% 一个下降 60%','材料没有部分量'],'被约掉的 1+r 不要差太多。','同正时 1+r 都在 1 点几，近似影响通常不大。')),
    Q('mixed_bad','什么时候不准',['技巧'],()=>R('混合原理最需要警惕的情况是：','一正一负或增长率差异过大',['一正一负或增长率差异过大','两个部分都增长 5%','选项首位不同','题目问相邻年份'],'一正一负时 1+r 可能一个大于 1、一个小于 1。','现期近似基期会明显失真，要谨慎。')),
    Q('mixed_between','第一原则',['基础'],()=>R('混合后的增长率一定：','夹在两个部分增长率之间',['夹在两个部分增长率之间','大于两个部分增长率','小于两个部分增长率','等于两者乘积'],'整体不会跑出两端。','整体属性夹在两个部分属性之间。')),
    Q('mixed_towards','第二原则',['技巧'],()=>R('混合增长率会更偏向：','量大的部分的增长率',['量大的部分的增长率','量小的部分的增长率','年份大的部分','选项大的部分'],'偏向就是距离更近。','量越大，对整体影响越大，混合增长率离它越近。')),
    Q('mixed_distance','第三原则',['技巧'],()=>R('混合原理估算时，部分量之比与距离之比的关系是：','反比',['正比','反比','相等','无关'],'量大距离小。','部分量之比=增长率距离的反比。')),
    Q('mixed_two_ends','两端求整体',['技巧'],()=>R('已知两个部分增长率和两个部分量，要求整体增长率，常用顺序是：','夹中间→看偏向→距离反比',['夹中间→看偏向→距离反比','直接平均→四舍五入→选最大','只看增长率大的','只看量小的'],'先排除，再精算。','先用“夹在中间”排除，再看偏向，仍不够再用距离反比。')),
    Q('mixed_one_side','整体加一端求另一端',['技巧'],()=>R('已知整体增长率和一个部分增长率，求另一个部分增长率时，未知端通常在：','整体增长率的另一侧',['整体增长率的另一侧','已知部分同侧','两者正中间','必为 0'],'整体必须夹在两个部分之间。','若已知部分高于整体，则未知部分应低于整体；反之亦然。')),
    Q('mixed_positive_negative','一正一负',['运用'],()=>R('一正一负混合时，若给出的整体值几乎在两端正中间，而两部分量明显不是 1:1，应优先判断：','该说法可疑或错误',['该说法可疑或错误','一定正确','一定等于平均数','无需看部分量'],'正中间意味着两边影响接近。','量明显不等时，整体应偏向量大者，不应正好在中间附近。')),
    Q('mixed_no_overuse','第三步边界',['运用'],()=>R('混合原理做题时，是否每题都必须算“距离反比”？','不是，前两步能排除就不算',['不是，前两步能排除就不算','必须每题都算','只能算距离反比','不能看选项'],'先夹逼，再偏向，最后才精算。','课程强调不要形式主义：先用“夹在中间”和“偏向量大”排除，选项还近时才进入距离反比。')),
    Q('mixed_multi','多部分混合',['运用'],()=>R('三部分混合增长率可如何处理？','先混两部分，再与第三部分混合',['先混两部分，再与第三部分混合','三个增长率直接相乘','只取最大部分','一定不能做'],'混合可分步。','多部分混合仍是整体部分关系，可以分层混合。')),
    Q('mixed_time_span','时间段拆分',['基础'],()=>R('“1—7 月”与“1—6 月、7 月”的关系是：','1—7 月=1—6 月+7 月',['1—7 月=1—6 月+7 月','1—7 月=7 月-1—6 月','7 月=1—6 月+1—7 月','三者无关'],'累计量可以拆分。','这类题也是整体与部分混合。'))
  ];
  add(C('mixed_rules','混合原理｜硬性规则',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/12_mixed_training.js -----
(function(){
  const {n,op,R,Q,C,add,pct,d}=EX;
  const twoEndRange=Q('mixed_two_range','夹在中间',['基础'],()=>{
    const a=n(8,18), b=n(22,35); const ans=`${a}% 到 ${b}% 之间`;
    return R(`甲增长率 ${a}%，乙增长率 ${b}%。甲乙合计增长率一定在什么范围？`,ans,op(ans,[`大于 ${b}%`,`小于 ${a}%`,`等于 ${(a+b)/2}%`,`无法判断`]),'混合值夹在两个部分之间。',`整体增长率一定介于 ${a}% 和 ${b}% 之间。`);
  });
  const twoEndBias=Q('mixed_two_bias','偏向量大',['技巧'],()=>{
    const small=n(10,20), big=n(24,35), q1=n(1000,1800), q2=n(3000,5000); const ans=`更接近 ${big}%`;
    return R(`甲量 ${q1}、增长 ${small}%；乙量 ${q2}、增长 ${big}%。合计增长率更接近哪一端？`,ans,op(ans,[`更接近 ${small}%`,`正好中间`,`一定小于 ${small}%`,`更接近 ${big}%`]),'量大的部分影响更大。',`乙量更大，所以合计增长率更偏向乙的 ${big}%。`);
  });
  const distanceCalc=Q('mixed_distance_calc','距离反比换算',['技巧'],()=>{
    const low=10, high=22, ratioBig=2; const ans='18%';
    return R(`A 增长 10%，量为 1 份；B 增长 22%，量为 2 份。整体增长率约为？`,ans,op(ans,['14%','16%','18%','20%']),'量比 1:2，距离比 2:1。','两端差 12 个百分点，共 3 份，一份 4；整体离 B 的 22% 只有 1 份，所以 22%-4%=18%。');
  });
  const twoRoute=C('mixed_two_end_route','两端求整体',['技巧'],[twoEndRange,twoEndBias,distanceCalc],'sequence');

  const otherSide=Q('mixed_one_other_side','未知端方向',['技巧'],()=>{
    const known=n(12,22), whole=n(5,known-2); const ans='低于整体增长率';
    return R(`某部分增长率 ${known}%，整体增长率 ${whole}%。另一个部分增长率应在整体的哪一侧？`,ans,op(ans,['高于已知部分','低于整体增长率','等于已知部分','无法判断']),'整体要夹在两个部分之间。',`已知部分 ${known}% 高于整体 ${whole}%，另一部分必须低于整体，整体才会夹在两端之间。`);
  });
  const oneCalc=Q('mixed_one_calc','整体加一端',['技巧'],()=>{
    const smallQty=1, bigQty=9, known=13, whole=4; const ans='约 3%';
    return R(`柴油量约 1 份，增长率 13%；汽油量约 9 份，合计增长率 4%。汽油增长率约为？`,ans,op(ans,['约 3%','约 4%','约 9%','约 13%']),'量小距离远，柴油到整体的距离是 9 份。','柴油与汽油量比 1:9，距离比 9:1。13% 到 4% 差 9 个百分点，对应 9 份，1 份约 1 个百分点，汽油≈4%-1%=3%。');
  });
  const oneRoute=C('mixed_one_side_route','整体加一端求另一端',['技巧'],[otherSide,oneCalc],'sequence');

  const posNegMid=Q('mixed_pos_neg_mid','中点错误',['运用'],()=>R(
    '甲量明显大于乙量，甲增长 4%，乙下降 6%。若有人说整体约为 -1%，且 -1% 几乎在两端中间，应如何判断？',
    '可疑，整体应更偏向甲的 4%',
    ['可疑，整体应更偏向甲的 4%','一定正确，因为平均就是 -1%','一定低于 -6%','无法用混合判断'],
    '量明显不等时，整体不该在正中间。',
    '整体增长率夹在 -6% 和 4% 之间，但甲量更大，应更靠近 4%，不是几乎正中间。'
  ));
  const posNegBoundary=Q('mixed_pos_neg_boundary','现期近似边界',['运用'],()=>R(
    '混合增长中一部分增长 50%，另一部分下降 40%，为什么不能太粗地用现期量比代替基期量比？',
    '两个 1+r 分母差异太大',
    ['两个 1+r 分母差异太大','因为不能有负增长','因为选项一定相同','因为整体不在两端之间'],
    '资料分析混合近似约掉了 1+r。',
    '一边 1.50，一边 0.60，差异很大，用现期近似基期容易失真。'
  ));
  const posNegRoute=C('mixed_pos_neg_route','一正一负判断',['运用'],[posNegMid,posNegBoundary],'all');

  const timeSplit=Q('mixed_time_split','累计拆分',['基础'],()=>{
    const total=n(160,240), july=n(20,50); const first=total-july;
    return R(`1—7 月累计量 ${total}，7 月当月量 ${july}，则 1—6 月量是多少？`,String(first),op(String(first),[String(total+july),String(july),String(total),String(total-july+1)]),'累计量拆分：1—7 月=1—6 月+7 月。',`1—6 月=${total}-${july}=${first}。`);
  });
  const timeUnknown=Q('mixed_time_unknown_rate','未知段增长率',['技巧'],()=>R(
    '已知 1—7 月整体增长率和 7 月增长率，要求 1—6 月增长率，本质属于：',
    '已知整体和一个部分，求另一个部分',
    ['已知整体和一个部分，求另一个部分','隔年增长率','指数问题','百分点陷阱'],
    '1—7 月由 1—6 月和 7 月组成。',
    '累计段拆分后就是整体与两个部分的混合增长。'
  ));
  const timeRoute=C('mixed_time_route','时间段拆分',['运用'],[timeSplit,timeUnknown],'sequence');

  const identify=Q('mixed_deep_identify','识别整体部分',['基础'],()=>R('“四川+重庆固定资产投资总额”这类问法首先应识别为：','整体=两个部分相加',['整体=两个部分相加','隔年增长','指数增长','平均数除法'],'总额来自两个地区相加。','四川和重庆是两个部分，两地总额是整体。'));
  const canApprox=Q('mixed_deep_approx','能否近似',['技巧'],()=>R('若两个部分增长率都为正且相差不极端，混合原理用现期量比近似通常：','可以作为估算',['完全禁止','可以作为估算','必然精确','只能用于人数题'],'这是资料分析里的估算版十字交叉。','同正时被约掉的 1+r 差异通常不大，可以估算。'));
  const finalDistance=Q('mixed_deep_distance','最后距离',['技巧'],()=>R('量比 1:2 时，距离比应为：','2:1',['1:2','2:1','1:1','3:1'],'量大距离小。','部分量之比与距离之比成反比，所以 1:2 对应 2:1。'));
  const workflow=C('mixed_workflow_chain','判断链',['技巧'],[identify,canApprox,finalDistance],'sequence');
  const deepRoute=C('mixed_deep_route','综合路线',['运用'],[workflow],'sequence');
  add(C('mixed_training','混合原理｜变量训练',['运用'],[twoRoute,oneRoute,posNegRoute,timeRoute,deepRoute],'all'));
})();

// ----- lessons/data_analysis_speed_05/13_cross_rules.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('cross_trigger','触发特征',['基础'],()=>R('问人数/次数/个数，但材料没有直接给这些量，最应想到：','十字交叉',['十字交叉','隔年增长','指数减 100','化除为乘'],'材料常给平均值。','问分母类数量而材料只给平均值时，要想到用平均值构造十字交叉。')),
    Q('cross_average','平均值结构',['基础'],()=>R('平均用时的分母通常是：','人数',['人数','增长率','指数','百分点'],'平均=总量/个数。','平均时间=总时间/人数，因此十字交叉得到的是人数比。')),
    Q('cross_denominator','分母含义',['技巧'],()=>R('用男性平均用时、女性平均用时、整体平均用时构造十字交叉，得到的是：','男性人数与女性人数之比',['男性人数与女性人数之比','男性增长率与女性增长率之比','城镇与农村人数之比','两个指数之比'],'分组决定分母。','男女平均值的分母分别是男女人数，所以交叉得男女分母比。')),
    Q('cross_strict','严格性',['技巧'],()=>R('严格十字交叉与资料分析混合原理的关键差别是：','严格十字交叉不把分母换成现期近似',['严格十字交叉不把分母换成现期近似','严格十字交叉不能用差值','严格十字交叉只能用于指数','严格十字交叉不用整体'],'这里没有约掉分母。','严格十字交叉得到的就是实际分母比，不能随意粗化。')),
    Q('cross_49_51','49:51 边界',['运用'],()=>R('若十字交叉得到男性:女性=49:51，且总人数约 4.86 万，男性人数应：','略少于一半',['略多于一半','略少于一半','正好一半','无法判断'],'49 小于 51。','这是严格比值，男性占 49/(49+51)，略少于一半。')),
    Q('cross_group_match','分组匹配',['基础'],()=>R('题目问男性人数时，应优先使用哪组平均值？','男性/女性平均值',['男性/女性平均值','城镇/农村平均值','年份平均值','指数最大值'],'问谁，就用谁的分组。','用城镇/农村平均值会得到城镇/农村人数比，不是男女人数比。')),
    Q('cross_multi_average','多组平均值',['运用'],()=>R('材料同时给男女平均用时和城乡平均用时，选哪组取决于：','题目问法',['题目问法','哪组数字更大','哪组更靠前','哪组单位更短'],'分母要对上问法。','问男性就用男女；问城镇就用城乡。'))
  ];
  add(C('cross_rules','严格十字交叉｜人数次数个数',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/14_cross_training.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;
  const trigger=Q('cross_train_trigger','问人数识别',['基础'],()=>R(
    '题目问“受访男性居民约多少人”，材料只给整体平均用时、男性平均用时、女性平均用时。应想到什么？',
    '用平均值构造十字交叉',
    ['用平均值构造十字交叉','用隔年增长率','用指数减 100','直接平均两个选项'],
    '人数是平均值的分母。',
    '平均用时=总用时/人数，所以可通过男女平均值与整体平均值构造人数比。'
  ));
  const denom=Q('cross_train_denom','分母就是人数',['基础'],()=>R('平均时间=总时间/什么？','人数',op('人数',['增长率','百分点','年份','指数']),'平均值的分母就是要找的数量。','平均时间=总时间÷人数。'));
  const route1=C('cross_people_route','人数识别',['基础'],[trigger,denom],'all');

  const minuteConvert=Q('cross_train_minutes','时间转分钟',['技巧'],()=>{
    const h=n(3,5), m=n(5,55), ans=String(h*60+m);
    return R(`${h} 小时 ${m} 分钟等于多少分钟？`,ans,op(ans,[String(h*100+m),String(h*60),String(m*60+h),String(h+m)]),'十字交叉前先统一单位。',`${h}小时=${h*60}分钟，加 ${m} 分钟，共 ${ans} 分钟。`);
  });
  const diffRatio=Q('cross_train_diff_ratio','做差得比值',['技巧'],()=>R(
    '整体平均 264 分，男性 315 分，女性 215 分。十字交叉得到男:女应看哪组差？',
    '(264-215):(315-264)',
    ['(264-215):(315-264)','(315-264):(264-215)','(315-215):(264-215)','315:215'],
    '分母比等于对侧差。',
    '男性人数:女性人数=(整体-女性):(男性-整体)=(264-215):(315-264)=49:51。'
  ));
  const totalAllocate=Q('cross_train_allocate','总人数分配',['技巧'],()=>{
    const total=n(40000,60000), a=49, b=51; const ans='略少于一半';
    return R(`若男:女=49:51，总人数 ${total}，男性人数与一半相比？`,ans,op(ans,['略少于一半','略多于一半','正好一半','等于女性人数两倍']),'49 份少于 51 份。',`男性占 49/(49+51)=49%，所以略少于一半。`);
  });
  const route2=C('cross_construct_route','构造训练',['技巧'],[minuteConvert,diffRatio,totalAllocate],'sequence');

  const maleNotUrban=Q('cross_match_male','问男性不用城乡',['基础'],()=>R(
    '题目问男性人数，但你用城镇/农村平均值构造十字交叉，会得到什么？',
    '城镇/农村人数比，不是男女人数比',
    ['城镇/农村人数比，不是男女人数比','男女人数比','增长率之比','指数之比'],
    '分组决定分母。',
    '城镇/农村平均值的分母是城乡人数，因此不能回答男性人数。'
  ));
  const urbanNotMale=Q('cross_match_urban','问城镇不用男女',['基础'],()=>R(
    '题目问城镇居民人数时，应使用哪组平均值构造？',
    '城镇/农村平均值',
    ['男性/女性平均值','城镇/农村平均值','年份指数','增长量/现期'],
    '问法决定分组。',
    '问城镇，就要用城镇与农村这组平均值。'
  ));
  const multiDistract=Q('cross_match_distract','多平均值干扰',['运用'],()=>R(
    '材料出现多组平均值时，最优先检查什么？',
    '哪组分母对应题目所问对象',
    ['哪组分母对应题目所问对象','哪组数字最大','哪组在材料最前面','哪组小数最少'],
    '十字交叉得到的是分母比。',
    '要让分母比正好对应题目所问人数、次数或个数。'
  ));
  const route3=C('cross_match_route','分组匹配',['运用'],[maleNotUrban,urbanNotMale,multiDistract],'all');
  add(C('cross_training','严格十字交叉｜变量训练',['运用'],[route1,route2,route3],'all'));
})();

// ----- lessons/data_analysis_speed_05/15_section_calculation.js -----
EX.sec('四、精算边界｜千分位、反代、改选项');

// ----- lessons/data_analysis_speed_05/16_calculation_rules.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('calc_option_first','选项首位',['基础'],()=>R('选项首位都不一样时，优先使用：','直除看首位',['直除看首位','精确到小数点后三位','反代所有选项','完全忽略题干'],'选项差距大，不必精算。','首位不同，粗略直除即可锁定答案。')),
    Q('calc_close_option','选项千分级',['运用'],()=>R('选项只差千分之几时，能否粗暴忽略 0.4% 这类小量？','不能',['能','不能','看心情','只要题干短就能'],'选项也很近。','小量虽然小，但选项差距也小，忽略可能直接错。')),
    Q('calc_fourth_nine','第四位是 9',['技巧'],()=>R('保留三位时，如果第四位是 9，课程建议：','最好进一位',['最好进一位','永远舍去','改成 0','不看前三位'],'避免低估过多。','例如 1.029 可近似成 1.03，计算更稳。')),
    Q('calc_thousand_line','千分位划线',['技巧'],()=>R('百分位划线看第三位，千分位划线应看：','第四位',['第二位','第三位','第四位','第六位'],'位数后移一位。','0.4%=4‰，处理千分位误差时要看第四位。')),
    Q('calc_fourth_eight','第四位是 8',['技巧'],()=>R('保留三位时，如果第四位是 8，课程态度更接近：','不必强行进位，看选项和误差方向',['不必强行进位，看选项和误差方向','必须像 9 一样永远进位','必须永远舍去','与前三位无关'],'8 与 9 的稳妥程度不同。','第四位为 9 时常建议进位；第四位为 8 时不必机械处理，要结合选项差距和前后误差。')),
    Q('calc_fraction_convert','常用分数转化',['技巧'],()=>R('0.143 和 0.571 在速算中可分别联想到：','1/7 和 4/7',['1/7 和 4/7','1/6 和 3/6','1/8 和 5/8','1/9 和 2/9'],'143 是七分之一的典型小数骨架。','0.143≈1/7，0.571≈4/7；分数转化要服务于选项判断，不是单纯背表。')),
    Q('calc_div_to_mul','化除为乘',['技巧'],()=>R('A/(1+r) 在 r 较小时可近似为：','A(1-r)',['A(1-r)','A(1+r)','A/r','A-r'],'用平方差配分母。','A/(1+r)=A(1-r)/(1-r²)，忽略 r² 后约为 A(1-r)。')),
    Q('calc_square_diff','平方差来源',['技巧'],()=>R('化除为乘中被忽略的关键小量是：','r²',['r²','r','A','1+r'],'平方项更小。','分母变成 1-r²，r 小时 r² 更小，可近似忽略。')),
    Q('calc_range_r','适用范围',['基础'],()=>R('化除为乘一般在 |r| 约多少以内较稳？','10% 以内',['10% 以内','100% 以上','只在 80% 附近','与 r 无关'],'r 越小，r² 越小。','课程强调 10% 以内通常较精确。')),
    Q('calc_bias_positive','偏大偏小',['技巧'],()=>R('r>0 时，用 A(1-r) 近似 A/(1+r)，估算值通常：','偏小',['偏小','偏大','完全相等','无法判断'],'把 1-r² 当成 1，是把分母看大。','真实分母 1-r² 小于 1，直接当 1 会使结果偏小。')),
    Q('calc_reverse','反代思维',['运用'],()=>R('增长量选项极近时，可先在选项之间假设一个增长量，再：','现期减假设值得基期，基期乘增长率验证',['现期减假设值得基期，基期乘增长率验证','把所有选项平均','直接选最大','只看题号'],'这是反代。','假设增长量越接近真实值，验证越精确。')),
    Q('calc_reverse_mid','假设值位置',['技巧'],()=>R('反代时假设值最好取在：','选项之间且便于计算',['选项之间且便于计算','所有选项之外','越大越好','越小越好'],'离真实答案近。','答案一定在选项附近，取中间好算值更稳。')),
    Q('calc_change_option','改选项法',['技巧'],()=>R('改选项法的核心等式是：','a/b-K=(a-Kb)/b',['a/b-K=(a-Kb)/b','a/b+K=(a+K)/b','a/b=ab','a-Kb=b-Ka'],'把共同部分拿掉。','当选项都在 10 点几或 4 点几，可减去共同整数部分放大差异。')),
    Q('calc_subtract_error','减法放大误差',['运用'],()=>R('改选项法能让接近选项变好区分，原因是：','减法会放大内部误差',['减法会放大内部误差','乘法会消除所有误差','除法没有误差','选项越多越简单'],'拿掉共同部分后，剩余差异占比变大。','把 10 点几变成零点几或几百几，选项相对差距变大，更容易判断。'))
  ];
  add(C('calculation_rules','速算与精算边界｜硬性规则',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_05/17_calculation_training.js -----
(function(){
  const {n,op,R,Q,C,add,d}=EX;
  const thousandNoIgnore=Q('calc_train_no_ignore','0.4%不忽略',['运用'],()=>{
    const cur=n(2500,3900), perm=n(3,8); const rate=perm/10; const ans=String(d(cur/(1+rate/100),0));
    return R(`现期 ${cur}，增长率 ${rate.toFixed(1)}%。若选项只差千分级，基期约为？`,ans,op(ans,[String(cur),String(d(cur*(1-rate/100),0)),String(d(cur+perm,0)),String(d(cur-perm,0))]),'0.4% 这类小量在选项很近时不能直接丢。',`基期=${cur}÷(1+${rate.toFixed(1)}%)≈${ans}。粗暴选 ${cur} 可能错。`);
  });
  const oneSide=Q('calc_train_one_side','只动一边',['技巧'],()=>R(
    '千分位划线时，课程建议分子分母怎样处理更不容易乱？',
    '只动其中一个，别两边同时乱改',
    ['只动其中一个，别两边同时乱改','分子分母必须都改','只能改答案','完全不能估算'],
    '千分级误差本来就小，操作要稳。',
    '只调整分子或分母之一，再补偿误差，能降低混乱。'
  ));
  const compensate=Q('calc_train_compensate','补偿误差',['技巧'],()=>R(
    '把除数略看大后，直接除出的结果会怎样？',
    '偏小，需要向上补偿',
    ['偏小，需要向上补偿','偏大，需要向下补偿','完全不变','必为负'],
    '除数越大，商越小。',
    '估算时若把分母看大，初步商偏小，要根据误差方向补回。'
  ));
  const route1=C('calc_thousand_route','千分位划线',['技巧'],[thousandNoIgnore,oneSide,compensate],'sequence');

  const frac143=Q('calc_train_frac_143','143骨架',['技巧'],()=>R(
    '看到 0.143、14.3%、143/1000 这类骨架，优先联想到：',
    '1/7',
    op('1/7',['1/6','1/8','1/9','2/7']),
    '143 是七分之一的近似循环节。',
    '1÷7≈0.142857，四舍五入可记成 0.143。'
  ));
  const frac571=Q('calc_train_frac_571','571骨架',['技巧'],()=>R(
    '看到 0.571、57.1% 这类骨架，优先联想到：',
    '4/7',
    op('4/7',['3/7','5/7','4/9','1/7']),
    '571 是七分之四的近似骨架。',
    '4÷7≈0.5714，所以 0.571 常可转为 4/7 辅助估算。'
  ));
  const fracUse=Q('calc_train_frac_use','转化目的',['运用'],()=>R(
    '分数转化的目的是什么？',
    '服务选项判断，减少无意义精算',
    ['服务选项判断，减少无意义精算','背得越多越好','替代所有公式','只用于指数题'],
    '速算方法要看选项。',
    '0.143≈1/7 这类转化，是为了快速定位选项或判断大小，不是为了脱离题目背小数。'
  ));
  const routeFrac=C('calc_fraction_route','分数转化',['技巧'],[frac143,frac571,fracUse],'all');

  const divSmall=Q('calc_train_div_small','小 r 场景',['技巧'],()=>{
    const A=n(2000,5000), r=n(2,8); const ans=String(d(A*(1-r/100),0));
    return R(`${A}÷(1+${r}%) 可用化除为乘近似为多少？`,ans,op(ans,[String(d(A*(1+r/100),0)),String(d(A/(1-r/100),0)),String(A),String(d(A-r,0))]),'A/(1+r)≈A(1-r)。',`${A}×(1-${r}%)≈${ans}。`);
  });
  const divBias=Q('calc_train_div_bias','偏大偏小',['技巧'],()=>R(
    'r>0 时，A(1-r) 与 A/(1+r) 相比一般怎样？',
    'A(1-r) 略小',
    ['A(1-r) 略小','A(1-r) 略大','完全相等','无法判断'],
    '忽略的是分母里的 1-r²。',
    '真实值=A(1-r)/(1-r²)，分母小于 1，所以真实值略大，A(1-r) 略小。'
  ));
  const divLarge=Q('calc_train_div_large','大 r 边界',['运用'],()=>R(
    '如果 r=45%，还机械用 A(1-r) 近似 A/(1+r)，最大风险是：',
    'r² 不小，误差明显',
    ['r² 不小，误差明显','答案一定更精确','题目必然无解','增长率会变成百分点'],
    '45% 的平方已经不小。',
    '化除为乘依赖忽略 r²，r 大时不能放心忽略。'
  ));
  const route2=C('calc_div_route','化除为乘',['技巧'],[divSmall,divBias,divLarge],'sequence');

  const reverseNear=Q('calc_train_reverse_near','选项很近',['运用'],()=>R(
    '增长量选项为 765、771、778、785 这类很近数据时，优先考虑：',
    '反代思维',
    ['反代思维','只看首位','把增长率全忽略','直接选中间'],
    '选项近，粗算不够。',
    '可取一个夹在选项中的好算假设值，再用基期×增长率验证。'
  ));
  const reverseMid=Q('calc_train_reverse_mid','中间假设',['技巧'],()=>R(
    '反代假设增长量时，为什么不一定要取某个选项本身？',
    '只要夹在选项之间且好算，就足够接近真实值',
    ['只要夹在选项之间且好算，就足够接近真实值','必须取最大选项','必须取最小选项','不能假设'],
    '假设值用于验证方向和接近程度。',
    '答案就在选项附近，取中间好算值能让后续乘法更顺。'
  ));
  const reverseVerify=Q('calc_train_reverse_verify','基期验证',['技巧'],()=>R(
    '增长量反代的验证式是：',
    '基期×增长率≈假设增长量',
    ['基期×增长率≈假设增长量','现期×基期≈增长率','指数-100≈基期','增长率÷现期≈增长量'],
    '先用现期减假设值得基期。',
    '若基期×增长率接近假设增长量，说明假设接近答案。'
  ));
  const route3=C('calc_reverse_route','反代思维',['运用'],[reverseNear,reverseMid,reverseVerify],'sequence');

  const remove10=Q('calc_train_remove10','结果在10点几',['技巧'],()=>R(
    '若 a/b 的选项都在 10 点几，改选项可先算什么？',
    'a/b-10=(a-10b)/b',
    ['a/b-10=(a-10b)/b','a/b+10=(a+10b)/b','a/b×10','a-b/10'],
    '先拿掉共同的 10。',
    '把共同整数部分拿掉后，剩余选项差异更明显。'
  ));
  const remove4=Q('calc_train_remove4','结果在4点几',['技巧'],()=>R(
    '若 a/b 的选项都在 4 点几，改选项更适合先减：',
    '4',
    ['4','10','100','0'],
    '减掉共同整数部分。',
    '结果在 4 点几，先算 a/b-4=(a-4b)/b。'
  ));
  const observeRest=Q('calc_train_observe_rest','观察剩余选项',['技巧'],()=>R(
    '改选项后，剩余选项差距变大，接下来应：',
    '用粗算判断剩余部分，再还原原答案',
    ['用粗算判断剩余部分，再还原原答案','重新精确计算所有原式','放弃题目','只选最大值'],
    '剩余差异已经被放大。',
    '先判断剩余部分落在哪个选项，再加回被减掉的共同部分。'
  ));
  const deep=C('calc_change_deep','去掉共同整数部分',['技巧'],[remove10,remove4],'sequence');
  const route4=C('calc_change_route','改选项法',['运用'],[deep,observeRest],'sequence');
  add(C('calculation_training','速算与精算边界｜变量训练',['运用'],[route1,routeFrac,route2,route3,route4],'all'));
})();

