// ----- lessons/data_analysis_speed_06/03_precision_hard.js -----
(function(){
  const {R,Q,C,add}=EX;
  const q1=Q('precision_relative_error','相对误差',['基础'],()=>R(
    '判断选项差距“大不大”时，应主要看什么？',
    '相对误差',
    ['相对误差','绝对差','数字位数越多越小','选项字母顺序'],
    '2.7 和 2.8 不是只看差 0.1。',
    '要看差值占原数的大约比例。相对误差在 1% 以内才算较小，超过 1% 就不能当成千分级。'
  ));
  const q2=Q('precision_line_method','划线法适用',['技巧'],()=>R(
    '选项没有细到千分级时，优先可用哪类快速估算？',
    '划线法',
    ['划线法','反代法','逐位长除到底','放弃'],
    '选项差距足够大，估算误差可控。',
    '划线法把复杂数改成好算数，并记录分子分母变化造成的上升、下降误差。'
  ));
  const q3=Q('precision_reverse_when','反代适用',['技巧'],()=>R(
    '当选项前三位相同、差距只有千分级时，普通估算不够，应优先想到什么？',
    '反代思维',
    ['反代思维','随便四舍五入','只看首位','把所有选项相加'],
    '千分级选项对估算精度要求很高。',
    '普通划线估算常只有 1%左右精度；选项千分级时，应选一个夹在选项之间且方便计算的值反代验证。'
  ));
  const q4=Q('precision_first_digit','首位直除',['技巧'],()=>R(
    '选项分别是 5 开头、6 开头、1 开头、4 开头时，最快优先用什么？',
    '直除看首位',
    ['直除看首位','反代每个选项','求精确小数','先画线段'],
    '首位差距大，不需要复杂估算。',
    '选项首位不同，直接判断结果首位即可，通常无需划线到很细。'
  ));
  const q5=Q('precision_magnitude','数量级判断',['基础'],()=>R(
    '选项形同但小数点不同，例如 14 与 1.4，应该优先看什么？',
    '数量级',
    ['数量级','字母顺序','哪个更整齐','哪个更大就选哪个'],
    '这类题不是难题，而是小数点题。',
    '把百分号、小数点完整还原，看结果是一位数、两位数还是小数，不要忽略小数点。'
  ));
  const q6=Q('precision_boundary_verify','边界验证',['技巧'],()=>R(
    '划线估算值刚好位于两个选项中间时，下一步应该做什么？',
    '验证是否跨过临界值',
    ['验证是否跨过临界值','随便选左边','只看选项字母','重新照搬材料'],
    '估算值不是精确值。',
    '当估算值正好夹在两个选项中间，要验证真实值偏大还是偏小，不能直接凭开头选择。'
  ));

  const q7=Q('precision_reverse_boundary','反代边界',['技巧'],()=>R(
    '选项只是百分级差距时，是否应优先反代？',
    '不应优先反代，划线或直除更节能',
    ['不应优先反代，划线或直除更节能','必须每题反代','只能逐位精算','直接放弃'],
    '反代是为千分级服务的。',
    '选项差距较大时，反代会增加步骤；只有选项极近、普通估算精度不够时才优先反代。'
  ));
  add(C('precision_hard_card','选项精度｜算法选择',['基础'],[q1,q2,q3,q4,q5,q6,q7],'all'));
})();

// ----- lessons/data_analysis_speed_06/04_precision_variable.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;
  const q1=Q('precision_var_first_digit','首位判断',['技巧'],()=>{
    const d=n(120,780); const k=n(2,8); const rem=n(0,Math.floor(d*0.35)); const a=d*k+rem;
    const ans=`${k}开头`;
    return R(`${a} ÷ ${d} 的选项首位分别不同，结果首位大约是？`,ans,op(ans,[`${k-1}开头`,`${k+1}开头`,`${Math.max(1,k-2)}开头`]),'先看 d×几最接近 a。',`${d}×${k}=${d*k}，且余量不大，所以商是 ${k} 开头。`);
  });
  const q2=Q('precision_var_line_pick','划线选择',['技巧'],()=>{
    const base=n(230,760); const pct=n(3,8); const changed=Math.round(base*(1+pct/100));
    return R(`${base} 被看成 ${changed}，大约相当于上升多少？`,`${pct}%`,op(`${pct}%`,[`${pct+2}%`,`${Math.max(1,pct-2)}%`,`-${pct}%`]),'用变化量除以原数。',`${changed}-${base}≈${Math.round(base*pct/100)}，约为原数的 ${pct}%，所以是上升 ${pct}%。`);
  });
  const q3=Q('precision_var_reverse_use','反代场景',['技巧'],()=>{
    const start=n(260,690); const opts=[start,start+1,start+2,start+3].map(x=>`${x}.${n(1,8)}`);
    return R(`四个选项为 ${opts.join('、')}，前三位高度接近。此时最稳的估算策略是？`,'选中间方便值反代',op('选中间方便值反代',['只看首位','随便四舍五入','把分母看成 100']), '选项差距越小，越要反向验证。','选项已经接近千分级，普通划线法精度可能不够，应选夹在选项之间且方便做差的值反代。');
  });
  const q4=Q('precision_var_magnitude','数量级',['技巧'],()=>{
    const days=n(28,31); const p=(n(35,68)/10).toFixed(1); const val=days*Number(p)/100;
    const ans=val<10?'一位数':'两位数';
    return R(`${days} × ${p}% 的结果数量级最接近哪一种？`,ans,op(ans,['两位数','一位数','三位数','小于 0.1']), '百分号要变成两位小数。',`${p}%=${Number(p)/100}，${days}×${Number(p)/100}≈${val.toFixed(2)}，所以是${ans}。`);
  });
  const q5=Q('precision_var_boundary','临界验证',['技巧'],()=>{
    const d=n(103,129); const target=n(3,8); const a=d*target+n(1,9); const crit=target+1;
    const ans=a>=d*crit?`能到 ${crit}`:`到不了 ${crit}`;
    return R(`${a} ÷ ${d} 的估算值卡在 ${target} 与 ${crit} 附近。验证 ${d}×${crit}=${d*crit} 后，应判断？`,ans,op(ans,[`能到 ${target}`,`到不了 ${target}`,`必须反代全部选项`]),'把临界值移到另一边相乘。',`${a} ${a>=d*crit?'≥':'<'} ${d*crit}，所以真实商${a>=d*crit?'已经':'还没有'}达到 ${crit}。`);
  });
  const routeA=C('precision_var_route_a','方法选择｜顺序',['技巧'],[q1,q2,q3],'sequence');
  const routeB=C('precision_var_route_b','边界处理｜顺序',['技巧'],[q4,q5],'sequence');
  add(C('precision_variable_card','选项精度｜变量训练',['技巧'],[routeA,routeB],'all'));
})();

// ----- lessons/data_analysis_speed_06/05_section_growth_amount.js -----
EX.sec('增长量｜公式与分数法');

// ----- lessons/data_analysis_speed_06/06_growth_amount_hard.js -----
(function(){
  const {R,Q,C,add}=EX;
  const q1=Q('ga_base_formula','基期公式',['基础'],()=>R('已知现期量 A、增长率 r，基期量公式是？','A÷(1+r)',['A÷(1+r)','A×(1+r)','A÷r','A×r'], '增长率为正时，现期比基期多。','现期=基期×(1+r)，所以基期=A÷(1+r)。'));
  const q2=Q('ga_growth_formula','增长量公式',['基础'],()=>R('已知现期量 A、增长率 r，增长量可写成？','A×r÷(1+r)',['A×r÷(1+r)','A×(1+r)','A÷r','A×r÷(1-r)'], '增长量=现期−基期。','增长量=A−A÷(1+r)=A×r÷(1+r)。'));
  const q3=Q('ga_decrease_formula','减少量公式',['基础'],()=>R('已知现期量 A、下降率 r，减少量可写成？','A×r÷(1-r)',['A×r÷(1-r)','A×r÷(1+r)','A÷(1+r)','A×(1-r)'], '下降时现期=基期×(1−r)。','基期=A÷(1−r)，减少量=基期−现期=A×r÷(1−r)。'));
  const q4=Q('ga_unit_fraction','1/n 分数法',['技巧'],()=>R('若增长率约为 1/n，则增长量约等于现期的多少？','1/(n+1)',['1/(n+1)','1/n','1/(n-1)','n/(n+1)'], '现期比基期多一份。','基期 n 份、增长量 1 份、现期 n+1 份，所以增长量≈现期÷(n+1)。'));
  const q5=Q('ga_mn_fraction','m/n 份数法',['技巧'],()=>R('若增长率约为 m/n，则现期对应多少份？','n+m 份',['n+m 份','n-m 份','m 份','n×m 份'], '增长率=m/n 表示基期 n 份增长 m 份。','基期 n 份，增长量 m 份，现期就是 n+m 份。'));
  const q6=Q('ga_close_options','增长量近选项',['技巧'],()=>R('求增长量且选项非常接近时，普通划线法不稳，应优先用什么？','反代思维',['反代思维','只看首位','不看选项','因子特征'], '千分级选项不能粗糙估。','先从选项中间取方便值，与现期做差，再验证增长关系。'));

  const q7=Q('ga_split_multiply','凑整拆乘',['技巧'],()=>R('遇到 3084×87 这类乘法，课上推荐的快捷处理之一是？','把 87 拆成 90−3',['把 87 拆成 90−3','把 87 当成 100 不管误差','只看末位','直接跳过'], '复杂乘法可以拆成接近整十的数。','例如 3084×87=3084×(90−3)，先算 90 倍再减 3 倍，比硬乘更快。'));
  add(C('growth_amount_hard_card','增长量｜公式与分数法',['基础'],[q1,q2,q3,q4,q5,q6,q7],'all'));
})();

// ----- lessons/data_analysis_speed_06/07_growth_amount_variable.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;
  const q1=Q('ga_var_one_over_n','1/n 增长量',['技巧'],()=>{
    const den=n(4,9); const present=(den+1)*n(30,120); const ans=String(present/(den+1));
    return R(`现期量为 ${present}，增长率约为 1/${den}，增长量约是多少？`,ans,op(ans,[String(present/den),String(Math.round(present/(den+2))),String(present)]),'1/n 增长率对应现期 n+1 份。',`增长量≈现期÷(${den}+1)=${present}÷${den+1}=${ans}。`);
  });
  const q2=Q('ga_var_m_over_n','m/n 增长量',['技巧'],()=>{
    const m=2, den=7; const unit=n(20,80); const present=(den+m)*unit; const ans=String(m*unit);
    return R(`现期量为 ${present}，增长率约为 2/7，增长量约是多少？`,ans,op(ans,[String(unit),String(den*unit),String(Math.round(present/7))]),'基期 7 份，增长 2 份，现期 9 份。',`现期 ${present} 对应 9 份，每份 ${unit}，增长量 2 份=${ans}。`);
  });
  const q3=Q('ga_var_decrease','下降减少量',['技巧'],()=>{
    const den=n(5,10); const r=1/den; const present=(den-1)*n(40,110); const ans=String(Math.round(present/(den-1)));
    return R(`现期量为 ${present}，下降率约为 1/${den}，减少量约是多少？`,ans,op(ans,[String(Math.round(present/(den+1))),String(Math.round(present/den)),String(present)]),'下降时现期是基期少一份。',`下降 1/${den} 表示基期 ${den} 份，现期 ${den-1} 份；减少量 1 份=${present}÷${den-1}≈${ans}。`);
  });
  const q4=Q('ga_var_method_by_options','按选项选法',['技巧'],()=>{
    const close=n(0,1)===1; const ans=close?'反代思维':'直除或划线';
    const desc=close?'选项如 268.1、268.5、269.0、269.4，前三位接近':'选项如 400、520、670、810，首位不同';
    return R(`求增长量时，${desc}。优先策略是？`,ans,op(ans,['反代思维','直除或划线','因子特征','逐位精算到小数后六位']),'先看选项精度。',`${close?'选项接近千分级，普通估算不够，应反代。':'首位差异大，直除或划线足够。'}`);
  });
  const q5=Q('ga_var_reverse_mid','反代中间值',['技巧'],()=>{
    const lo=n(2600,3900); const vals=[lo,lo+8,lo+13,lo+21]; const mid=lo+11;
    return R(`四个增长量选项约为 ${vals.join('、')}。反代时取 ${mid} 这样的值是否必须是选项？`,'不必须，只要夹在选项间且方便算',op('不必须，只要夹在选项间且方便算',['必须等于 A 选项','必须等于最大选项','只能取整数 1000']), '反代值是工具，不是答案本身。','反代值可以不是任何选项；关键是夹在选项区间内，并让做差或乘法更方便。');
  });
  const routeA=C('ga_var_route_a','分数法｜顺序',['技巧'],[q1,q2,q3],'sequence');
  const routeB=C('ga_var_route_b','选项法｜顺序',['技巧'],[q4,q5],'sequence');
  add(C('growth_amount_variable_card','增长量｜变量训练',['技巧'],[routeA,routeB],'all'));
})();

// ----- lessons/data_analysis_speed_06/08_section_growth_rate_compare.js -----
EX.sec('增长率比较｜两种分数');

// ----- lessons/data_analysis_speed_06/09_growth_rate_compare_hard.js -----
(function(){
  const {R,Q,C,add}=EX;
  const q1=Q('gr_formula_inc_base','增长率定义',['基础'],()=>R('增长率最基本的定义是？','增长量÷基期',['增长量÷基期','增长量÷现期','现期÷增长量','基期÷现期'], '增长是相对于过去基期而言。','增长率=增长量÷基期。'));
  const q2=Q('gr_formula_current_base','现期基期式',['基础'],()=>R('增长率也可以写成哪种形式？','现期÷基期−1',['现期÷基期−1','现期÷基期+1','基期÷现期−1','增长量÷现期+1'], '现期=基期+增长量。','增长率=(现期−基期)÷基期=现期÷基期−1。'));
  const q3=Q('gr_compare_drop_one','比较可去掉 -1',['技巧'],()=>R('比较多个增长率时，若都用“现期÷基期−1”，为什么可先比较“现期÷基期”？','每项都减同一个 1，不影响大小',['每项都减同一个 1，不影响大小','因为 1 可以忽略单位','因为基期都相等','因为现期都相等'], '同减同加不改变大小关系。','增长率大小由现期÷基期的大小决定。'));
  const q4=Q('gr_inc_base_better','增长量除基期更好看',['技巧'],()=>R('有些增长率比较题，为什么先算增长量再除以基期更方便？','分子变小，分数更容易比较',['分子变小，分数更容易比较','一定能得到整数','可以不用看基期','可以消除所有选项'], '现期和基期很接近时，差值往往更简洁。','现期÷基期形式不一定好比，减出增长量后变成增长量÷基期，常更直观。'));
  const q5=Q('gr_ref_above_one','参照 1：大于 1',['技巧'],()=>R('几个分数都大于 1，把它们降到 1 时，下降越多说明原分数怎样？','原分数越大',['原分数越大','原分数越小','无法判断','一定等于 1'], '离 1 越远，原来越大。','都大于 1 时，下降越多才到 1，说明原分数一开始越高。'));
  const q6=Q('gr_ref_below_one','参照 1：小于 1',['技巧'],()=>R('几个分数都小于 1，把它们升到 1 时，上升越少说明原分数怎样？','原分数越大',['原分数越大','原分数越小','一定为负','无法比较'], '离 1 越近，原来越大。','都小于 1 时，只需上升一点点就到 1，说明原值更接近 1，也更大。'));

  const q7=Q('gr_diff_essence','差分误差法',['技巧'],()=>R('分数比大小时，差分法/分子分母误差法本质上在比较什么？','相对变化幅度',['相对变化幅度','绝对差谁大','选项字母顺序','只看分子位数'], '分子、分母同时变，不能只看差多少。','差分法的核心是看分子相对变化和分母相对变化谁更大；这和划线法中的百分误差判断是一套底层逻辑。'));
  add(C('growth_rate_compare_hard_card','增长率比较｜两种分数',['基础'],[q1,q2,q3,q4,q5,q6,q7],'all'));
})();

// ----- lessons/data_analysis_speed_06/10_growth_rate_compare_variable.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;
  const q1=Q('gr_var_current_base','现期基期比较',['技巧'],()=>{
    const b1=n(100,300), inc1=n(18,50), b2=n(120,360), inc2=n(5,16);
    const r1=inc1/b1, r2=inc2/b2; const ans=r1>r2?'甲':'乙';
    return R(`甲：基期 ${b1}、现期 ${b1+inc1}；乙：基期 ${b2}、现期 ${b2+inc2}。谁增长率更大？`,ans,op(ans,['甲','乙','一样大','无法判断']),'可比较增长量÷基期。',`甲增长率=${inc1}/${b1}≈${(r1*100).toFixed(1)}%；乙=${inc2}/${b2}≈${(r2*100).toFixed(1)}%，所以${ans}更大。`);
  });
  const q2=Q('gr_var_inc_base','增长量基期比较',['技巧'],()=>{
    const base=n(200,700); const incA=n(20,60); const incB=incA+n(5,35);
    const ans='乙';
    return R(`甲增长量 ${incA}、基期 ${base}；乙增长量 ${incB}、基期 ${base}。谁增长率更大？`,ans,op(ans,['甲','乙','一样大','无法判断']),'基期相同，看增长量。',`基期相同，增长量 ${incB}>${incA}，所以乙增长率更大。`);
  });
  const q3=Q('gr_var_ref_above','大于 1 参照',['技巧'],()=>{
    const d1=n(80,160), extra1=n(18,35), d2=n(80,160), extra2=n(5,15);
    const a1=d1+extra1, a2=d2+extra2; const ans=(extra1/d1>extra2/d2)?'甲':'乙';
    return R(`甲=${a1}/${d1}，乙=${a2}/${d2}，两个都大于 1。谁更大？`,ans,op(ans,['甲','乙','一样大','无法判断']),'都大于 1，看超过 1 的幅度。',`甲超过 1 的幅度约 ${extra1}/${d1}，乙约 ${extra2}/${d2}；幅度更大者分数更大，所以选${ans}。`);
  });
  const q4=Q('gr_var_ref_below','小于 1 参照',['技巧'],()=>{
    const d1=n(100,220), gap1=n(5,15), d2=n(100,220), gap2=n(20,40);
    const a1=d1-gap1, a2=d2-gap2; const ans=(gap1/d1<gap2/d2)?'甲':'乙';
    return R(`甲=${a1}/${d1}，乙=${a2}/${d2}，两个都小于 1。谁更大？`,ans,op(ans,['甲','乙','一样大','无法判断']),'都小于 1，离 1 越近越大。',`甲到 1 需上升约 ${gap1}/${d1}，乙需上升约 ${gap2}/${d2}；上升少者原来更大，所以选${ans}。`);
  });
  const q5=Q('gr_var_method_choose','形式选择',['技巧'],()=>{
    const cur=n(900,1500); const base=cur-n(20,80); const ans='增长量÷基期';
    return R(`比较 ${cur}/${base}−1 这类增长率时，哪种改写通常更好看？`,ans,op(ans,['现期÷基期继续硬除','增长量÷基期','现期×基期','只看现期']), '现期与基期接近，差值更小。',`${cur}/${base}−1=(${cur}-${base})/${base}，分子变小，更容易比较。`);
  });

  const q6=Q('gr_var_relative_error','相对误差比较',['技巧'],()=>{
    const top=900, bottom=1000;
    const downTop=n(80,150);
    const downBottom=downTop-n(20,50);
    const aTop=top, aBottom=bottom, bTop=top-downTop, bBottom=bottom-downBottom;
    const ans=(aTop/aBottom>bTop/bBottom)?'甲':'乙';
    return R(`甲=${aTop}/${aBottom}，乙=${bTop}/${bBottom}。从甲变到乙时，分子少 ${downTop}、分母少 ${downBottom}，谁更大？`,ans,op(ans,['甲','乙','一样大','无法判断']),'比较相对下降幅度，不只看绝对差。',`分子下降 ${downTop}/${top}，分母下降 ${downBottom}/${bottom}；分子相对下降更大，所以分数变小，原来的甲更大。`);
  });
  const routeA=C('gr_var_route_a','两种形式｜顺序',['技巧'],[q1,q2,q5],'sequence');
  const routeB=C('gr_var_route_b','参照一｜顺序',['技巧'],[q3,q4,q6],'sequence');
  add(C('growth_rate_compare_variable_card','增长率比较｜变量训练',['技巧'],[routeA,routeB],'all'));
})();

// ----- lessons/data_analysis_speed_06/11_section_mixed.js -----
EX.sec('混合原理｜基期和差与顺逆差');

// ----- lessons/data_analysis_speed_06/12_mixed_hard.js -----
(function(){
  const {R,Q,C,add}=EX;
  const q1=Q('mix_whole_parts','混合关系',['基础'],()=>R('混合原理的基本结构是？','整体=部分1+部分2',['整体=部分1+部分2','整体=部分1×部分2','整体=部分1÷部分2','整体=部分1−部分2且不可变形'], '总量由部分构成。','资料分析里的总量、进出口、收入合计等都常是整体与部分的混合关系。'));
  const q2=Q('mix_rate_between','混合增长率位置',['基础'],()=>R('混合增长率通常位于哪里？','两个部分增长率之间',['两个部分增长率之间','一定大于两个部分','一定小于两个部分','与部分量无关'], '整体由两个部分合成。','整体增长率被两个部分增长率夹住，并更靠近量大的部分。'));
  const q3=Q('mix_large_close','靠近量大者',['技巧'],()=>R('两个部分量一大一小，混合增长率更靠近谁的增长率？','量大的部分',['量大的部分','量小的部分','永远靠近较高增长率','永远靠近较低增长率'], '量大者权重更高。','混合增长率是加权结果，部分量越大，权重越大。'));
  const q4=Q('mix_base_sum','基期和步骤',['技巧'],()=>R('A/(1+r1)+B/(1+r2) 的快速思路第一步是？','先算现期和 A+B',['先算现期和 A+B','分别精算两个分数','先把增长率相乘','直接看选项字母'], '两个分数是两个部分的基期。','基期和=现期和÷(1+混合增长率)。'));
  const q5=Q('mix_base_diff','基期差步骤',['技巧'],()=>R('A/(1+r1)−B/(1+r2) 的快速思路第一步是？','先算现期差 A−B',['先算现期差 A−B','分别算到小数','把 A 和 B 相乘','忽略 B'], '减法可变形为整体−部分=另一部分。','基期差应先求对应的现期差，再估差额部分增长率。'));
  const q6=Q('mix_surplus_def','顺逆差',['基础'],()=>R('贸易顺差和逆差分别是？','顺差=出口−进口；逆差=进口−出口',['顺差=出口−进口；逆差=进口−出口','顺差=进口−出口；逆差=出口−进口','顺差=出口+进口；逆差=出口−进口','二者没有公式'], '顺差表示出口更多。','出口大于进口叫顺差，进口大于出口叫逆差。'));
  const q7=Q('mix_current_trap','现期陷阱',['技巧'],()=>R('求某部分的基期值时，选项中出现“现期和/差”，通常是什么？','陷阱项',['陷阱项','必然答案','题目无解','单位换算项'], '基期不是现期。','先算出的现期和/差只是第一步，若要求基期，还要除以 1+对应增长率。'));
  const q8=Q('mix_pos_neg_boundary','正负边界',['技巧'],()=>R('两个部分增长率一正一负时，是否应机械套口算混合？','不应机械套',['不应机械套','一定可以秒算','必须取平均数','不用看题'], '课程明确说这种情况不标准。','一正一负时快速口算混合容易失准，应改用更稳的公式、方向判断或其他方法。'));

  const q9=Q('mix_segment_to_mental','线段到口算',['技巧'],()=>R('混合增长率刚学时可画线段，熟练后考场上更应该怎样做？','直接按份数口算',['直接按份数口算','每题都完整画线段','只背例题答案','把两个增长率简单相加'], '线段法是理解支架，不是最终速度。','线段法帮助理解“量比反向切距离”；熟练后应直接口算总距离、份数和靠近哪一端。'));
  const q10=Q('mix_distance_split','距离切分',['技巧'],()=>R('两部分量之比为 3:4，两个增长率相差 3.5 个百分点。口算混合增长率时，总距离应分成几份？','7 份',['7 份','3 份','4 份','12 份'], '量比 3:4，对应总份数 7。','混合率位于两端增长率之间，总距离按 3+4=7 份切分；再根据量大者更近判断具体位置。'));
  add(C('mixed_hard_card','混合原理｜基期和差与顺逆差',['基础'],[q1,q2,q3,q4,q5,q6,q7,q8,q9,q10],'all'));
})();

// ----- lessons/data_analysis_speed_06/13_mixed_variable.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;
  const q1=Q('mix_var_rate_position','混合率位置',['技巧'],()=>{
    const r1=n(5,12), r2=n(16,25); const ans=`${r1}%到${r2}%之间`;
    return R(`部分1增长率 ${r1}%，部分2增长率 ${r2}%，整体混合增长率应在哪里？`,ans,op(ans,[`小于${r1}%`,`大于${r2}%`,`等于${r1+r2}%`]),'整体增长率被部分增长率夹住。',`混合增长率必在 ${r1}% 与 ${r2}% 之间。`);
  });
  const q2=Q('mix_var_weight_close','靠近量大者',['技巧'],()=>{
    const small=n(200,400), large=n(700,1200); const rSmall=n(5,9), rLarge=n(15,22);
    return R(`甲现期 ${small}、增长 ${rSmall}%；乙现期 ${large}、增长 ${rLarge}%。混合增长率更靠近谁？`,'乙',op('乙',['甲','二者正中间','无法判断']),'量大权重大。',`乙的量 ${large} 明显大于甲 ${small}，所以混合增长率更靠近乙的 ${rLarge}%。`);
  });
  const q3=Q('mix_var_base_sum','基期和',['技巧'],()=>{
    const A=n(3000,6000), B=n(4000,8000); const ans='先算现期和，再除以 1+混合增长率';
    return R(`${A}/(1+r1)+${B}/(1+r2) 应怎样快速处理？`,ans,op(ans,['分别精算两个分数','先算现期和，再除以 1+混合增长率','把 r1 和 r2 直接相加','只算较大的分数']),'这是两个部分的基期和。',`先算 ${A}+${B}，再估 ${A}、${B} 的混合增长率，最后除以 1+r。`);
  });
  const q4=Q('mix_var_base_diff','基期差',['技巧'],()=>{
    const A=n(7000,9500), B=n(2500,5200); const diff=A-B;
    return R(`${A}/(1+r1)−${B}/(1+r2) 的第一步现期差是多少？`,String(diff),op(String(diff),[String(A+B),String(B-A),String(Math.round(A/B))]),'基期差先算现期差。',`${A}-${B}=${diff}。后续再估差额部分增长率。`);
  });
  const q5=Q('mix_var_surplus','顺差现期',['技巧'],()=>{
    const exp=n(50,90), imp=n(20,45); const ans=String(exp-imp);
    return R(`出口 ${exp}，进口 ${imp}，现期顺差是多少？`,ans,op(ans,[String(exp+imp),String(imp-exp),String(exp)]),'顺差=出口−进口。',`${exp}-${imp}=${ans}。若题目问基期顺差，这只是第一步。`);
  });
  const q6=Q('mix_var_current_trap','现期陷阱',['技巧'],()=>{
    const cur=n(20,60); const positive=n(1,1)===1; const ans=positive?'小于现期值':'大于现期值';
    return R(`某量现期为 ${cur}，其增长率为正。若问基期值，应与 ${cur} 比较怎样？`,ans,op(ans,['大于现期值','小于现期值','等于现期值','无法判断']),'增长率为正，现期比基期大。',`基期=现期÷(1+r)，r>0 时分母大于 1，所以基期小于现期。`);
  });
  const q7=Q('mix_var_pos_neg','一正一负边界',['技巧'],()=>{
    const r1=n(4,12), r2=-n(2,8);
    return R(`两个部分增长率分别为 +${r1}% 和 ${r2}%。此时快速口算混合应如何处理？`,'不机械套，先改用稳妥判断',op('不机械套，先改用稳妥判断',['直接取平均','一定等于正数','一定等于负数']),'一正一负是边界。','课程提醒一正一负时混合口算不标准，应结合量、公式或方向稳妥判断。');
  });

  const q8=Q('mix_var_distance_split','份数切分口算',['技巧'],()=>{
    const left=n(2,5), right=n(3,7);
    const r1=n(8,13), diff=n(30,70)/10, r2=Number((r1+diff).toFixed(1));
    const mixed=Number(((left*r1+right*r2)/(left+right)).toFixed(1));
    const ans=`约${mixed.toFixed(1)}%`;
    return R(`甲乙现期量之比约为 ${left}:${right}，增长率分别为 ${r1}% 和 ${r2.toFixed(1)}%。混合增长率约为？`,ans,op(ans,[`约${((r1+r2)/2).toFixed(1)}%`,`约${r1.toFixed(1)}%`,`约${r2.toFixed(1)}%`]),'按量的权重口算，量大的增长率影响更大。',`混合率≈(${left}×${r1}+${right}×${r2.toFixed(1)})÷${left+right}≈${mixed.toFixed(1)}%，也就是把两端距离按总份数 ${left+right} 切分。`);
  });
  const routeA=C('mix_var_route_a','混合率｜顺序',['技巧'],[q1,q2,q8],'sequence');
  const routeB=C('mix_var_route_b','基期和差｜顺序',['技巧'],[q3,q4],'sequence');
  const routeC=C('mix_var_route_c','顺逆差｜顺序',['技巧'],[q5,q6,q7],'sequence');
  const familyA=C('mix_var_family_core','结构计算',['技巧'],[routeA,routeB],'all');
  add(C('mixed_variable_card','混合原理｜变量训练',['技巧'],[familyA,routeC],'all'));
})();

// ----- lessons/data_analysis_speed_06/14_section_product.js -----
EX.sec('乘积增长率｜构造与百分点');

// ----- lessons/data_analysis_speed_06/15_product_hard.js -----
(function(){
  const {R,Q,C,add}=EX;
  const q1=Q('prod_formula','乘积增长率公式',['基础'],()=>R('若 A=B×C，B 增长率 r1，C 增长率 r2，则 A 增长率为？','r1+r2+r1×r2',['r1+r2+r1×r2','r1+r2','r1×r2','r1−r2'], '把两个 1+r 相乘。','(1+rA)=(1+r1)(1+r2)，展开得 rA=r1+r2+r1r2。'));
  const q2=Q('prod_like_interval','像隔年但不是隔年',['基础'],()=>R('乘积增长率公式与隔年增长率公式关系是？','形式相同，概念不同',['形式相同，概念不同','完全同一概念','完全无关','只能用于年份'], '一个是时间连续，一个是乘积结构。','二者公式都为 r1+r2+r1r2，但乘积增长率来自 A=B×C。'));
  const q3=Q('prod_amount_price','金额模型',['基础'],()=>R('进口额、销售额这类金额常可表示为？','数量×单价',['数量×单价','数量÷单价','单价−数量','只看数量'], '总金额由多少和单价共同决定。','进口额=进口数量×进口单价，成交额=面积×单价，均可用乘积增长率。'));
  const q4=Q('prod_whole_ratio','整体比重模型',['基础'],()=>R('部分量与整体、比重的关系是？','部分量=整体量×比重',['部分量=整体量×比重','整体量=部分量×比重','比重=整体量×部分量','部分量=整体量−比重'], '比重是部分占整体的比例。','所以求部分量增长率时，可把整体增长率和比重增长率做乘积增长率。'));
  const q5=Q('prod_construct','构造乘积',['技巧'],()=>R('题干给出口增长率和“进口占出口比重”的变化，要求进口增长率，应该怎样构造？','进口=(进口/出口)×出口',['进口=(进口/出口)×出口','进口=出口−比重','进口=出口+比重','无法构造'], '把比重看成一个可参与乘积的量。','进口占出口比重就是进口/出口，所以进口=(进口/出口)×出口。'));
  const q6=Q('prod_percentage_point','百分点处理',['技巧'],()=>R('“比重下降 2 个百分点”能否直接当作 −2% 增长率代入乘积公式？','不能，要先转成比重增长率',['不能，要先转成比重增长率','可以，完全一样','只能取绝对值','不需要看基期'], '百分点是差值，不是增长率。','比重增长率=比重变化量÷基期比重，先算出该增长率，再代入乘积增长率。'));

  const q7=Q('prod_share_thinking','份数思维',['技巧'],()=>R('整体×比重型乘积增长率题，除了直接套公式，还可用哪种思路？','份数思维',['份数思维','因子特征硬选','只看现期比重','忽略乘积项'], '把基期整体设成方便份数。','可设基期整体为 100 份，根据基期比重得基期部分，再用整体增长率和现期比重求现期部分，最后比较部分量变化。'));
  add(C('product_hard_card','乘积增长率｜构造与百分点',['基础'],[q1,q2,q3,q4,q5,q6,q7],'all'));
})();

// ----- lessons/data_analysis_speed_06/16_product_variable.js -----
(function(){
  const {n,op,R,Q,C,add,pct}=EX;
  const q1=Q('prod_var_positive','正正乘积',['技巧'],()=>{
    const r1=n(4,12), r2=n(3,10); const ans=(r1+r2+r1*r2/100).toFixed(1)+'%';
    return R(`数量增长 ${r1}%，单价增长 ${r2}%，金额增长率约为？`,ans,op(ans,[`${r1+r2}%`,`${(r1+r2-r1*r2/100).toFixed(1)}%`,`${(r1*r2/100).toFixed(1)}%`]),'别漏乘积项。',`${r1}%+${r2}%+${r1}%×${r2}%=${ans}。`);
  });
  const q2=Q('prod_var_negative','正负乘积',['技巧'],()=>{
    const r1=n(8,16), r2=-n(3,9); const ans=(r1+r2+r1*r2/100).toFixed(1)+'%';
    return R(`面积增长 ${r1}%，单价下降 ${-r2}%，成交额增长率约为？`,ans,op(ans,[`${r1+r2}%`,`${(r1-r2).toFixed(1)}%`,`${(r1*r2/100).toFixed(1)}%`]),'下降率要带负号。',`r=${r1}%+(${r2}%)+${r1}%×(${r2}%)=${ans}。`);
  });
  const q3=Q('prod_var_pp_to_rate','百分点转增长率',['技巧'],()=>{
    const cur=(n(100,180)/10); const drop=(n(8,25)/10); const base=cur+drop; const rate=-(drop/base*100); const ans=rate.toFixed(1)+'%';
    return R(`某比重现期为 ${cur.toFixed(1)}%，比上年下降 ${drop.toFixed(1)} 个百分点。这个“比重本身”的增长率约为？`,ans,op(ans,[`-${drop.toFixed(1)}%`,`${drop.toFixed(1)}%`,`${(drop/cur*100).toFixed(1)}%`]),'增长率=变化量÷基期比重。',`基期比重=${cur.toFixed(1)}%+${drop.toFixed(1)}%=${base.toFixed(1)}%，增长率=-${drop.toFixed(1)}÷${base.toFixed(1)}≈${ans}。`);
  });
  const q4=Q('prod_var_whole_ratio','整体比重乘积',['技巧'],()=>{
    const rw=n(6,14); const rr=-n(5,15); const ans=(rw+rr+rw*rr/100).toFixed(1)+'%';
    return R(`整体量增长 ${rw}%，部分占整体的比重增长 ${rr}%。部分量增长率约为？`,ans,op(ans,[`${rw+rr}%`,`${rw}%`,`${rr}%`]),'部分量=整体量×比重。',`部分增长率=${rw}%+(${rr}%)+${rw}%×(${rr}%)=${ans}。`);
  });
  const q5=Q('prod_var_construct_import','构造进口',['技巧'],()=>{
    const rex=n(5,13), rshare=n(3,9); const ans=(rex+rshare+rex*rshare/100).toFixed(1)+'%';
    return R(`出口增长 ${rex}%，进口占出口比重增长 ${rshare}%。进口增长率约为？`,ans,op(ans,[`${rex+rshare}%`,`${rex}%`,`${rshare}%`]),'进口=(进口/出口)×出口。',`进口增长率=${rex}%+${rshare}%+${rex}%×${rshare}%=${ans}。`);
  });
  const routeA=C('prod_var_route_a','直接乘积｜顺序',['技巧'],[q1,q2],'sequence');
  const routeB=C('prod_var_route_b','比重构造｜顺序',['技巧'],[q3,q4,q5],'sequence');
  add(C('product_variable_card','乘积增长率｜变量训练',['技巧'],[routeA,routeB],'all'));
})();

// ----- lessons/data_analysis_speed_06/17_section_ratio.js -----
EX.sec('比重基础｜部分整体与表格坑');

// ----- lessons/data_analysis_speed_06/18_ratio_hard.js -----
(function(){
  const {R,Q,C,add}=EX;
  const q1=Q('ratio_definition','比重定义',['基础'],()=>R('比重的公式是？','部分量÷整体量×100%',['部分量÷整体量×100%','整体量÷部分量×100%','增长量÷基期','现期÷基期'], '比重就是占比。','某部分占整体的比例，就是部分量除以整体量。'));
  const q2=Q('ratio_current','现期比重',['基础'],()=>R('现期比重题中，题目问哪一年，应该用哪一年的数据？','同一年现期的部分和整体',['同一年现期的部分和整体','上一年基期数据','只用增长率','任意年份都可以'], '先读时间点。','题目问 2015 年，就找 2015 年的部分量和整体量。'));
  const q3=Q('ratio_compare','比重比大小',['技巧'],()=>R('多个地区比重最大，本质是在比较什么？','多个“部分÷整体”的分数大小',['多个“部分÷整体”的分数大小','多个增长率乘积','多个年份差','多个单位名称'], '比重就是分数。','先用分子分母、首位直除、差分或误差判断，不必全部精算。'));
  const q4=Q('ratio_pp_amount','百分点差转实际量',['技巧'],()=>R('占比高 4 个百分点，要转成实际量差，应怎样做？','百分点差×整体量',['百分点差×整体量','百分点差÷整体量','整体量÷百分点差','直接写 4'], '百分点是比例差。','实际量差=整体量×比重差。'));
  const q5=Q('ratio_part_to_total','已知部分和比重求整体',['基础'],()=>R('已知部分量和比重，求整体量，用什么公式？','整体量=部分量÷比重',['整体量=部分量÷比重','整体量=部分量×比重','整体量=比重÷部分量','整体量=部分量−比重'], '比重=部分÷整体。','整体=部分÷比重；求另一部分时可用整体−已知部分，或整体×补集比重。'));
  const q6=Q('ratio_table_unit','表格单位陷阱',['运用'],()=>R('表格中一列是金额，另一列是件数，问“总捐赠款”时能否把件数列加进去？','不能',['不能','能','只要数字大就能','单位不同也随便加'], '先看单位和对象。','总捐赠款只能加金额类捐赠款，件数不是款，不能混加。'));
  const q7=Q('ratio_factor_trait','因子特征慎用',['运用'],()=>R('资料分析中为什么不能随便用数量关系的因子特征秒选？','选项多为估算值，不一定保留精确因子',['选项多为估算值，不一定保留精确因子','资料分析没有数字','所有选项都精确','因子特征永远错误'], '资料分析选项常四舍五入。','因子特征要求精确值；资料分析即使没写“约”，选项也常是估算值。'));
  add(C('ratio_hard_card','比重基础｜部分整体与表格坑',['基础'],[q1,q2,q3,q4,q5,q6,q7],'all'));
})();

// ----- lessons/data_analysis_speed_06/19_ratio_variable.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;
  const q1=Q('ratio_var_direct','现期比重',['技巧'],()=>{
    const total=n(500,1200); const p=n(20,80); const part=Math.round(total*p/100); const ans=`约${p}%`;
    return R(`某部分量 ${part}，整体量约 ${total}，比重大约是多少？`,ans,op(ans,[`约${Math.max(1,p-10)}%`,`约${Math.min(99,p+10)}%`,`约${Math.round(part/10)}%`]),'部分÷整体。',`${part}÷${total}≈${p}%，所以比重约 ${p}%。`);
  });
  const q2=Q('ratio_var_compare','比重比大小',['技巧'],()=>{
    const totalA=n(600,1100), totalB=n(500,1000);
    const pA=n(62,82), pB=n(35,58);
    const a=Math.round(totalA*pA/100), b=Math.round(totalB*pB/100);
    const ans='甲';
    return R(`甲：部分 ${a}、整体 ${totalA}；乙：部分 ${b}、整体 ${totalB}。谁比重更大？`,ans,op(ans,['甲','乙','一样大','无法判断']),'比重是部分÷整体，不是只看部分大小。',`甲比重约 ${pA}%，乙比重约 ${pB}%，所以甲更大。`);
  });
  const q3=Q('ratio_var_pp_days','百分点转天数',['技巧'],()=>{
    const days=n(28,31); const p=(n(25,70)/10).toFixed(1); const ans=(days*Number(p)/100).toFixed(1);
    return R(`某类天数占比高 ${p} 个百分点，月份共有 ${days} 天，实际多约多少天？`,`${ans}天`,op(`${ans}天`,[`${p}天`,`${(days+Number(p)).toFixed(1)}天`,`${(Number(p)/days).toFixed(1)}天`]),'百分点差要乘整体天数。',`${days}×${p}%≈${ans}，所以约多 ${ans} 天。`);
  });
  const q4=Q('ratio_var_part_total','部分比重求整体',['技巧'],()=>{
    const p=n(15,40); const total=n(80,200); const part=Math.round(total*p/100); const ans=String(Math.round(part/(p/100)));
    return R(`某部分量 ${part}，占整体 ${p}%，整体量约是多少？`,ans,op(ans,[String(part*p),String(Math.round(part*p/100)),String(part+p)]),'整体=部分÷比重。',`${part}÷${p}%≈${ans}。`);
  });
  const q5=Q('ratio_var_complement','补集比重',['技巧'],()=>{
    const p=n(10,40); const ans=`${100-p}%`;
    return R(`网民占总人数 ${p}%，非网民占比是多少？`,ans,op(ans,[`${p}%`,`${100+p}%`,`-${p}%`]),'补集比重=1−原比重。',`非网民占比=100%-${p}%=${ans}。`);
  });
  const q6=Q('ratio_var_unit_trap','单位陷阱',['运用'],()=>{
    const money1=n(100,500), money2=n(200,700), pieces=n(1000,3000); const ans=String(money1+money2);
    return R(`表格中：现金捐款 ${money1} 万元、社会组织捐款 ${money2} 万元、物资 ${pieces} 件。总捐赠款应为？`,`${ans} 万元`,op(`${ans} 万元`,[`${money1+money2+pieces} 万元`,`${pieces} 件`,`${money2+pieces} 万元`]),'款是金额，件数不能加。',`总捐赠款只加金额：${money1}+${money2}=${ans} 万元。物资件数不是款。`);
  });
  const q7=Q('ratio_var_factor_warning','因子特征警惕',['运用'],()=>R(
    '资料分析选项是约数时，看到某个选项有“7 的倍数”特征，能否只凭因子特征秒选？',
    '不能',
    op('不能',['能','只要题干没写约就能','必须选最大倍数']),
    '资料分析选项常是四舍五入。',
    '因子特征要求精确值；资料分析多数答案是估算或近似，不能只凭整除特征。'
  ));
  const routeA=C('ratio_var_route_a','直接比重｜顺序',['技巧'],[q1,q2],'sequence');
  const routeB=C('ratio_var_route_b','比重变形｜顺序',['技巧'],[q3,q4,q5],'sequence');
  const routeC=C('ratio_var_route_c','表格陷阱｜顺序',['运用'],[q6,q7],'sequence');
  const familyA=C('ratio_var_family_calc','计算变形',['技巧'],[routeA,routeB],'all');
  add(C('ratio_variable_card','比重基础｜变量训练',['技巧'],[familyA,routeC],'all'));
})();

