// ----- lessons/data_analysis_speed_07/11_data_ratio_cards.js -----
(function(){
  const {n,op,R,Q,C,pct,add}=EX;

  const a=Q('ratio_definition','比重定义',['基础'],()=>R(
    '资料分析中“比重”的基本形式是什么？',
    '部分量 ÷ 整体量',
    ['部分量 ÷ 整体量','整体量 ÷ 部分量','现期量 ÷ 增长率','增长量 ÷ 基期量'],
    '谁占谁，就是前者除以后者。',
    '比重是部分占整体的比例，先找分子部分和分母整体。'
  ));

  const b=Q('base_ratio_formula','基期比重公式',['技巧'],()=>R(
    '基期比重的正确公式是？',
    '现期部分/现期整体 × (1+整体增长率)/(1+部分增长率)',
    ['现期部分/现期整体 × (1+整体增长率)/(1+部分增长率)','现期部分/现期整体 × (1+部分增长率)/(1+整体增长率)','现期整体/现期部分 × (1+整体增长率)/(1+部分增长率)','现期比重 × 部分增长率'],
    '交叉记忆：分子对应增长率放分母，分母对应增长率放分子。',
    '基期部分=现期部分/(1+R部)，基期整体=现期整体/(1+R整)，相除后得到现期比重×(1+R整)/(1+R部)。'
  ));

  const b2=Q('base_ratio_numeric_layout','基期比重列式',['运用'],()=>{
    const part=n(500,900), whole=n(1200,2200), rp=n(5,14), rw=rp+n(1,6);
    const ans=`${part}/${whole} × (1+${pct(rw)})/(1+${pct(rp)})`;
    return R(
      `现期部分量为${part}，现期整体量为${whole}；部分增长率${pct(rp)}，整体增长率${pct(rw)}。基期比重应列为？`,
      ans,
      op(ans,[`${part}/${whole} × (1+${pct(rp)})/(1+${pct(rw)})`,`${whole}/${part} × (1+${pct(rw)})/(1+${pct(rp)})`,`${part}/${whole} × ${pct(rw)}/${pct(rp)}`]),
      '先写现期比重，再把增长率交叉放。',
      `基期比重=现期部分/现期整体×(1+R整)/(1+R部)，所以是 ${ans}。`
    );
  });

  const b3=Q('base_ratio_direction','基期比重修正方向',['运用'],()=>{
    const part=n(600,900), whole=n(1500,2400), rp=n(10,18), rw=n(3,9);
    const ans='小于现期比重';
    return R(
      `某部分现期量${part}、整体现期量${whole}，部分增长率${pct(rp)}，整体增长率${pct(rw)}。基期比重与现期比重相比怎样？`,
      ans,
      ['大于现期比重','小于现期比重','等于现期比重','无法判断'],
      '看修正项(1+R整)/(1+R部)。',
      `R整=${pct(rw)}小于R部=${pct(rp)}，所以(1+R整)/(1+R部)<1，基期比重小于现期比重。`
    );
  });

  const c=Q('ratio_trap','现期陷阱',['技巧'],()=>R(
    '基期比重题选项差距只有千分之几时，常见考点是什么？',
    '现期比重陷阱与修正方向',
    ['现期比重陷阱与修正方向','一定要长除法','题目无解','只看最大选项'],
    '选项极近通常不是让你死算。',
    '先算或估出现期比重陷阱，再看(1+R整)/(1+R部)让答案比陷阱大还是小。'
  ));


  const c2=Q('ratio_close_trap_variable','极近选项陷阱变量',['运用'],()=>{
    const current=n(600,760)/10; const rp=n(80,130)/10; const rw=rp+n(2,8)/10;
    const delta=(rw-rp)/(100+rp)*current;
    const ans='基期比重略大于现期比重';
    return R(
      `现期比重约${current.toFixed(1)}%，部分增长率${pct(rp)}，整体增长率${pct(rw)}。若选项围绕${current.toFixed(1)}%只差千分之几，正确方向是什么？`,
      ans,
      ['基期比重略大于现期比重','基期比重略小于现期比重','必然等于现期比重','只能放弃死算'],
      '看修正项(1+R整)/(1+R部)。',
      `R整>R部，修正项>1，所以基期比重比现期比重略大；大约多${delta.toFixed(2)}个百分点。极近选项题先找陷阱方向，再看差距。`
    );
  });

  const c3=Q('ratio_permille_adjust','千分位修正',['运用'],()=>{
    const trap=n(6400,6900)/100; const plus=n(2,5); const ans=(trap + trap*plus/1000).toFixed(2)+'%';
    return R(
      `现期比重陷阱约${trap.toFixed(2)}%，修正项约多${plus}‰。基期比重大约是多少？`,
      ans,
      op(ans,[(trap-plus/100).toFixed(2)+'%',(trap+plus/10).toFixed(2)+'%',trap.toFixed(2)+'%']),
      '选项只差千分之几时，用“陷阱值 ± 千分位修正”。',
      `修正约为${trap.toFixed(2)}%×${plus}‰=${(trap*plus/1000).toFixed(2)}个百分点，所以答案约${ans}。原课用1094与109的差，说明极近选项要看千分位修正，而不是死除。`
    );
  });

  const d=Q('ratio_change_formula','比重变化公式',['技巧'],()=>R(
    '比重变化=现期比重-基期比重，可化为哪一式？',
    '现期比重 × (R部-R整)/(1+R部)',
    ['现期比重 × (R部-R整)/(1+R部)','现期比重 × (R整-R部)/(1+R整)','基期比重 × R整','现期比重 ÷ 基期比重'],
    '比重变化只做差，不做除法。',
    '比重本身是百分数，问多多少/少多少，用百分点意义下的差值。'
  ));

  const d2=Q('ratio_percentage_point','百分点表达',['基础'],()=>R(
    '某比重由5%变为6%，最规范的表述是？',
    '上升1个百分点',
    ['上升1个百分点','上升20个百分点','上升20%才是唯一正确说法','下降1个百分点'],
    '比重变化看百分数之间的差。',
    '6%-5%=1个百分点。考试有时写“上升1%”，在比重变化语境下通常就是百分点差。'
  ));

  const d3=Q('ratio_change_numeric','比重变化幅度变量',['运用'],()=>{
    const current=n(20,60); const rp=n(8,16); const rw=rp-n(2,5);
    const val=current*(rp-rw)/(100+rp);
    const ans='上升，约'+val.toFixed(1)+'个百分点';
    return R(
      `某部分现期比重为${current}%，部分增长率${pct(rp)}，整体增长率${pct(rw)}。比重变化最接近？`,
      ans,
      op(ans,[`下降，约${val.toFixed(1)}个百分点`,`上升，约${(val+1).toFixed(1)}个百分点`,`不变`]),
      '先判升降，再估幅度。',
      `R部>R整，所以上升；变化≈${current}%×(${rp}-${rw})%/(1+${rp}%)=${val.toFixed(1)}个百分点。`
    );
  });

  const e=Q('ratio_rise_fall','升降三态',['技巧'],()=>{
    const mode=n(0,2); let whole=n(5,15), part=whole, ans='不变';
    if(mode===0){part=whole+n(1,8); ans='上升';}
    if(mode===1){part=Math.max(1,whole-n(1,4)); ans='下降';}
    return R(
      `某部分增长率为${pct(part)}，整体增长率为${pct(whole)}。该部分比重如何变化？`,
      ans,
      ['上升','下降','不变','无法判断'],
      '只比较R部与R整。',
      `R部=${pct(part)}，R整=${pct(whole)}；R部${part>whole?'大于':part<whole?'小于':'等于'}R整，所以比重${ans}。`
    );
  });



  const e2=Q('ratio_negative_growth_compare','负增长率也要比较大小',['技巧'],()=>R(
    '整体增长率为-5.1%，某部分增长率为-2.9%。该部分比重如何变化？',
    '上升',
    ['上升','下降','不变','无法判断'],
    '增长率比较要带正负号。',
    '-2.9% 大于 -5.1%，即R部>R整，所以该部分比重上升。原课用国企费用例子提醒过负增长也按数轴大小比较。'
  ));

  const e3=Q('ratio_change_numeric_down','比重变化下降幅度',['运用'],()=>{
    const current=n(20,60); const rw=n(8,16); const rp=rw-n(2,5);
    const val=current*(rw-rp)/(100+rp);
    const ans='下降，约'+val.toFixed(1)+'个百分点';
    return R(
      `某部分现期比重为${current}%，部分增长率${pct(rp)}，整体增长率${pct(rw)}。比重变化最接近？`,
      ans,
      op(ans,[`上升，约${val.toFixed(1)}个百分点`,`下降，约${(val+1).toFixed(1)}个百分点`,`不变`]),
      'R部<R整，先判下降。',
      `变化=现期比重×(R部-R整)/(1+R部)，符号为负；幅度≈${current}%×(${rw}-${rp})%/(1+${rp}%)=${val.toFixed(1)}个百分点。`
    );
  });

  const f=Q('mix_growth','混合增长率',['技巧'],()=>R(
    '整体由多个部分组成，整体增长率与各部分增长率的关系是？',
    '夹在各部分增长率之间',
    ['夹在各部分增长率之间','一定等于最大值','一定小于最小值','与部分无关'],
    '整体是部分的混合。',
    '整体增长率通常夹在各部分增长率之间；真题常问最低端和最高端，便于直接判断升降。'
  ));

  const f2=Q('mix_growth_apply','混合增长率应用',['运用'],()=>{
    const low=n(1,5), high=n(10,16), mid=n(low+1,high-1);
    return R(
      `某省由甲、乙、丙三部分组成，增长率分别为${pct(low)}、${pct(mid)}、${pct(high)}。若问最低增长部分和最高增长部分占整体比重变化，能直接判断的是？`,
      '最低增长部分下降，最高增长部分上升',
      ['最低增长部分下降，最高增长部分上升','两者都上升','两者都下降','都无法判断'],
      '整体增长率夹在三者之间。',
      `整体增长率一定大于${pct(low)}且小于${pct(high)}，所以最低增长部分R部<R整，比重下降；最高增长部分R部>R整，比重上升。`
    );
  });



  const f3=Q('mix_growth_middle_boundary','混合中间项边界',['技巧'],()=>R(
    '三个部分增长率为5.3%、5.4%、10.8%，整体增长率夹在三者之间。若只问5.4%这一部分的比重升降，为什么可能不能直接秒判？',
    '整体增长率可能在5.3%和10.8%之间，未必能确定与5.4%的大小',
    ['整体增长率可能在5.3%和10.8%之间，未必能确定与5.4%的大小','因为整体增长率一定等于5.4%','因为中间部分一定下降','因为不能比较百分数'],
    '混合只能确定整体在最小和最大之间。',
    '原课强调真题常问一头一尾：最低增长部分必低于整体，最高增长部分必高于整体；中间且很接近时，不能强判，除非进一步计算。'
  ));

  const g=Q('ratio_change_bound','变化幅度边界',['技巧'],()=>R(
    '比重变化公式中，若R部为正且现期比重小于1，变化幅度通常与 |R部-R整| 有什么关系？',
    '小于 |R部-R整|',
    ['小于 |R部-R整|','一定等于 |R部-R整|','一定大于 |R部-R整|','与增长率无关'],
    '现期比重<1，且1+R部>1。',
    '比重变化=现期比重×(R部-R整)/(1+R部)。当R部为正时，前面乘的比例会让幅度小于增长率差本身；若R部为负，不能机械套这个方向。'
  ));



  const g2=Q('ratio_bound_negative_rpart','R部为负的边界',['驿站'],()=>R(
    '使用“比重变化幅度小于|R部-R整|”这个结论时，为什么要注意R部是否为正？',
    '因为R部为负时，1+R部可能小于1，分母修正方向会变',
    ['因为R部为负时，1+R部可能小于1，分母修正方向会变','因为负增长率不能计算','因为比重一定为负','因为百分点不能相减'],
    '这个边界结论依赖1+R部>1。',
    '原课提醒：R部为正时分母大于1，幅度会被压小；若R部为负，分母小于1，不能机械套同一个小于号。'
  ));

  const g3=Q('ratio_bound_positive_explicit','正增长小于差值',['技巧'],()=>{
    const rp=n(8,16), rw=rp+n(1,5);
    const ans=`下降幅度小于${(rw-rp).toFixed(1)}个百分点`;
    return R(
      `某比重变化中，R部=${pct(rp)}，R整=${pct(rw)}，且现期比重<1。变化幅度与${pct(rw-rp)}相比怎样？`,
      ans,
      op(ans,[`下降幅度大于${(rw-rp).toFixed(1)}个百分点`,`一定等于${(rw-rp).toFixed(1)}个百分点`,'无法判断升降']),
      'R部为正时，1+R部>1，即分母比一大；现期比重又小于1。',
      `幅度=现期比重×|R部-R整|/(1+R部)。前面小于1，分母也会压小结果，所以幅度小于增长率差${(rw-rp).toFixed(1)}个百分点。`
    );
  });

  const g4=Q('ratio_guess_small_value','应急猜小值',['驿站'],()=>R(
    '比重变化题已经判定“下降”，剩余两个下降选项为0.7和1.5个百分点，实在没时间时原课给的应急猜法是什么？',
    '猜数值小的0.7个百分点',
    ['猜数值小的0.7个百分点','猜数值大的1.5个百分点','改猜上升选项','直接放弃'],
    '这是应急，不替代正常估算。',
    '原课说先判断上升下降；有时间继续估算，没时间时比重变化题倾向猜数字小的，因为比重变化常比增长率差更小。'
  ));

  const h=Q('ratio_vs_multiple_boundary','比重与倍数边界',['驿站'],()=>R(
    '比重变化“小于|R部-R整|”这个经验为什么不能无脑推广到所有A/B比值题？',
    '因为倍数题的A/B可能大于1，不再是比重',
    ['因为倍数题的A/B可能大于1，不再是比重','因为增长率不能相减','因为所有比值都无公式','因为百分点不能比较'],
    '比重的现期比重小于1，倍数不一定。',
    '原课提醒：A是B的倍数或A/B比值变化时，A/B可能大于1，特殊情况下甚至会抵消成R部-R整，不能把比重边界机械套过去。'
  ));

  const route=C('ratio_variable_route','变量训练｜公式升降混合与边界',['运用'],[b,b2,b3,d,d2,d3,e,e2,e3,f,f2,f3,g,g2,g3,g4,h],'all');
  add(C('data_ratio_card','比重系统｜基期变化与陷阱',['技巧'],[a,route,c,c2,c3],'all'));
})();

// ----- lessons/data_analysis_speed_07/20_section_data_average.js -----
(function(){ EX.sec('资料分析｜平均数与基期平均数'); })();

// ----- lessons/data_analysis_speed_07/21_data_average_cards.js -----
(function(){
  const {n,op,R,Q,C,pct,add}=EX;

  const a=Q('avg_definition','平均数定义',['基础'],()=>R(
    '资料分析中“平均数”的基本形式是什么？',
    '总量 ÷ 份数',
    ['总量 ÷ 份数','部分量 ÷ 整体量','增长量 ÷ 增长率','现期 ÷ 基期'],
    '平均、均、每，先找被平均的总量和份数。',
    '平均数不是比重；它是一个总量被分成若干份后的每份水平，也就是总量除以份数。'
  ));

  const a2=Q('avg_keywords','平均数关键词',['基础'],()=>R(
    '看到“平均、均、每户、每家、亩产量、平均功率”时，优先识别为什么题型？',
    '平均数：总量 ÷ 份数',
    ['平均数：总量 ÷ 份数','比重：部分 ÷ 整体','增长率：增长量 ÷ 基期','概率：满足 ÷ 总数'],
    '这些词都在问每一份的水平。',
    '平均功率=总功率/销量，亩产量=总产量/面积，每户费用=总费用/户数。'
  ));



  const a3=Q('avg_present_no_growth','现期平均数不加修正',['基础'],()=>R(
    '材料和问法都是同一年，求“平均每家/平均每月”时，是否需要乘增长率修正项？',
    '不需要，直接总量÷份数',
    ['不需要，直接总量÷份数','必须乘(1+R份)/(1+R总)','必须乘(1+R总)/(1+R份)','只看增长率'],
    '同年就是现期平均数。',
    '只有问过去的平均数才用基期平均数修正项；问材料同年，直接按口径列出现期总量/现期份数。'
  ));

  const b=Q('avg_unit_match','单位匹配变量',['技巧'],()=>{
    const fee=n(36,96), users=n(12,48), months=[3,6,12][n(0,2)];
    const ans=`总费用 ÷ 用户数 ÷ ${months}`;
    return R(
      `某地${months}个月有线网络总费用${fee}亿元，用户${users}万户。求平均每户每月费用，应如何列式？`,
      ans,
      op(ans,[`总费用 ÷ ${months}`,`总费用 ÷ 用户数`,`用户数 ÷ 总费用 ÷ ${months}`]),
      '题目同时包含“每户/用户”和“每月”。',
      `先除以用户数得到每户${months}个月费用，再除以${months}得到每户每月费用。`
    );
  });



  const b2=Q('avg_unit_conversion','平均数单位换算',['运用'],()=>{
    const fee=n(20,96), users=n(10,60), months=[3,6,12][n(0,2)];
    const val=fee*10000/users/months;
    const ans=`约${val.toFixed(1)}元`;
    return R(
      `某地${months}个月有线网络总费用${fee}亿元，用户${users}万户。平均每户每月费用约为多少元？`,
      ans,
      op(ans,[`约${(fee/users/months).toFixed(1)}元`,`约${(fee*10000/users).toFixed(1)}元`,`约${(fee*10000/months).toFixed(1)}元`]),
      '先列总费用÷用户数÷月份，再处理“亿元/万户”的单位换算。',
      `1亿元÷1万户=10000元/户，所以平均每户每月=${fee}×10000÷${users}÷${months}=${val.toFixed(1)}元。原课在有线电视费用题中专门提醒过“单位要换算”。`
    );
  });



  const b3=Q('avg_present_numeric','现期平均数数值',['运用'],()=>{
    const total=n(1200,3600), count=n(300,900);
    const val=total/count;
    const ans=`约${val.toFixed(1)}`;
    return R(
      `某项目现期直接费用${total}万元，资助项目${count}个。平均资助强度约为多少万元/个？`,
      ans,
      op(ans,[`约${(val+0.8).toFixed(1)}`,`约${(val-0.8).toFixed(1)}`,`约${(count/total).toFixed(1)}`]),
      '现期平均数直接总量÷份数。',
      `平均资助强度=${total}÷${count}=${val.toFixed(1)}万元/个。原课在“平均资助强度”处强调先找费用和项目数，再用首位/接近度判断。`
    );
  });

  const b4=Q('avg_multiple_compare','平均数倍数比较',['运用'],()=>{
    const aTotal=n(1800,4200), aCount=n(200,700), bTotal=n(900,2600), bCount=n(300,900);
    const val=(aTotal/aCount)/(bTotal/bCount);
    const ans=`约${val.toFixed(1)}倍`;
    return R(
      `甲类总营业收入${aTotal}万元、${aCount}家；乙类总营业收入${bTotal}万元、${bCount}家。甲类平均营业收入约是乙类的多少倍？`,
      ans,
      op(ans,[`约${(val+1).toFixed(1)}倍`,`约${Math.max(0.1,val-1).toFixed(1)}倍`,`约${(aTotal/bTotal).toFixed(1)}倍`]),
      '先分别求平均，再作倍数比较。',
      `五星级和四星级饭店这类题就是平均数倍数比较。甲平均=${aTotal}/${aCount}，乙平均=${bTotal}/${bCount}；倍数=(${aTotal}/${aCount})÷(${bTotal}/${bCount})≈${val.toFixed(1)}。原课五星/四星饭店题就是平均数之后再比较倍数。`
    );
  });

  const c=Q('base_avg_formula','基期平均数公式',['技巧'],()=>R(
    '基期平均数的正确公式是？',
    '现期总量/现期份数 × (1+份数增长率)/(1+总量增长率)',
    ['现期总量/现期份数 × (1+份数增长率)/(1+总量增长率)','现期总量/现期份数 × (1+总量增长率)/(1+份数增长率)','现期份数/现期总量 × (1+份数增长率)','现期平均数 × 总量增长率'],
    '总量在分子，份数在分母；增长率交叉。',
    '基期总量=现期总量/(1+R总)，基期份数=现期份数/(1+R份)，相除后为现期平均数×(1+R份)/(1+R总)。'
  ));

  const d=Q('avg_vs_ratio','别和比重混淆',['基础'],()=>R(
    '“平均功率”应识别为哪类口径？',
    '总功率 ÷ 销量',
    ['总功率 ÷ 销量','某部分 ÷ 总功率','销量 ÷ 总功率','增长率相减'],
    '平均功率是每台/每件的功率。',
    '平均数与比重容易混，但必须不混淆。凡是“平均每个、每家、亩产量、平均功率”，先找总量和份数。'
  ));

  const e=Q('base_avg_variable','基期平均变量',['运用'],()=>{
    const total=n(2400,3600), copies=n(400,800), rt=n(6,12), rc=n(2,5);
    const ans='现期平均数 × (1+份数增速)/(1+总量增速)';
    return R(
      `现期总功率${total}，销量${copies}；总功率增速${pct(rt)}，销量增速${pct(rc)}。求基期平均功率，修正项应怎么放？`,
      ans,
      op(ans,['现期平均数 × (1+总量增速)/(1+份数增速)','现期平均数 × 总量增速/份数增速','只用现期总功率/销量']),
      '基期平均数公式要交叉。',
      `平均功率=总功率/销量，所以销量是份数，修正项为(1+${pct(rc)})/(1+${pct(rt)})。`
    );
  });

  const e2=Q('base_avg_direction','基期平均修正方向',['运用'],()=>{
    const rt=n(8,16), rs=n(1,7);
    return R(
      `某指标现期平均数为A，总量增长率${pct(rt)}，份数增长率${pct(rs)}。基期平均数相对现期平均数怎样？`,
      '更小',
      ['更小','更大','相等','无法判断'],
      '看修正项(1+R份)/(1+R总)。',
      `R份=${pct(rs)}小于R总=${pct(rt)}，所以修正项小于1，基期平均数小于现期平均数。`
    );
  });

  const f=Q('avg_denominator_pick','分母选择变量',['运用'],()=>{
    const modes=[['亩产量','播种面积或种植面积','总产量÷面积'],['平均每家市值','上市公司家数','总市值÷公司家数'],['平均功率','销量','总功率÷销量']];
    const m=modes[n(0,modes.length-1)];
    return R(
      `求“${m[0]}”时，分母应该找什么？`,
      m[1],
      op(m[1],['总人口','增长率','利润额']),
      '平均数的分母是份数。',
      `${m[0]}对应的列式是${m[2]}。`
    );
  });

  const g=Q('avg_not_ab_confusion','不混记AB',['驿站'],()=>R(
    '为什么本课把基期比重和基期平均数分开背，而不只用A/B统一记？',
    '避免实战时把部分整体、总量份数代乱',
    ['避免实战时把部分整体、总量份数代乱','因为两个公式完全无关','因为平均数没有增长率','因为比重不能计算'],
    '形式相似不等于口径相同。',
    '比重是部分/整体；平均数是总量/份数。统一字母看似省事，但容易把R部、R整、R总、R份代错。'
  ));

  const route=C('avg_variable_route','变量训练｜单位口径基期与分母',['运用'],[a2,a3,b,b2,b3,b4,c,d,e,e2,f,g],'all');
  add(C('data_average_card','平均数系统｜口径与基期',['技巧'],[a,route],'all'));
})();

// ----- lessons/data_analysis_speed_07/30_section_estimation.js -----
(function(){ EX.sec('资料分析｜估算、划线与边界'); })();

// ----- lessons/data_analysis_speed_07/31_estimation_cards.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;

  const a=Q('estimate_first_digit','首位法',['技巧'],()=>R(
    '列式后发现选项分别是3开头、4开头、5开头、6开头，应优先采用什么策略？',
    '首位判断，不必精算',
    ['首位判断，不必精算','完整长除法','随机猜一个','先算到小数点后三位'],
    '选项差距决定计算精度。',
    '首位不同，判断数量级和首位即可；不需要把每个数算完。'
  ));

  const b=Q('estimate_line','划线法变量',['技巧'],()=>{
    const real=n(21,29), easy=real+1, numerator=easy*n(20,30), base=numerator/easy;
    return R(
      `把分母${real}临时估成${easy}后，基准结果为${base}；真实分母${real}比${easy}小，真实结果应怎样？`,
      `比${base}大`,
      op(`比${base}大`,[`比${base}小`,`刚好${base}`,'无法比较']),
      '分母变小，商变大。',
      '估算不是只算基准，还要判断修正方向和大致误差。'
    );
  });

  const c=Q('estimate_error_cancel','误差抵消',['技巧'],()=>R(
    '资料分析中把一个因子估大、另一个因子估小，可能带来什么好处？',
    '误差抵消',
    ['误差抵消','误差必然翻倍','答案必错','不能估算'],
    '估算要看方向。',
    '一个上调、一个下调时，方向相反的误差可能互相抵消，使结果足够接近选项。'
  ));

  const c2=Q('estimate_option_precision','选项决定精度',['技巧'],()=>R(
    '同一道式子，选项相差很大和选项相差千分之几，计算策略应怎样？',
    '前者首位估算，后者查陷阱或细估',
    ['前者首位估算，后者查陷阱或细估','两者都必须算到底','两者都直接猜','只看材料标题'],
    '计算精度由选项决定。',
    '课程多次强调列式后先瞄选项：差距大就省算，差距极近往往有现期/基期等陷阱。'
  ));

  const c3=Q('estimate_three_not_look','三不看式骨架',['技巧'],()=>R(
    '类似156、1101这类数据，课程估算时强调先抓什么？',
    '抓好算骨架和误差方向',
    ['抓好算骨架和误差方向','所有数字逐位长除','完全忽略误差','只看单位名称'],
    '例如156可看成15，1101可联想到1/9附近。',
    '所谓“三不看”式处理，本质不是乱丢数字，而是先抓可心算的数字骨架，再用上升/下降几个百分点修正误差。'
  ));

  const c4=Q('estimate_156_to_15','典型好算数',['技巧'],()=>R(
    '估算 7.10 ÷ 15.61 这类式子时，把15.61先看成15，主要目的是什么？',
    '得到好算骨架，再判断误差',
    ['得到好算骨架，再判断误差','保证答案完全精确','让结果必然变大100%','避免看选项'],
    '15、1/9、1/4等都是常用好算骨架。',
    '课程示范中会把156类数据改成15附近，再看改动导致上升或下降多少，并结合其他因子抵消误差。'
  ));

  const c4b=Q('estimate_factor_nine','九因子与好约数',['技巧'],()=>R(
    '遇到1885、12这类不顺眼的数据时，课程示范把1885近似成1800，主要是为了什么？',
    '制造9因子或整百骨架，便于约分后再修正误差',
    ['制造9因子或整百骨架，便于约分后再修正误差','让答案必然精确','完全忽略用户数','把所有数都变小'],
    '估算不是随意改数，而是主动改成好约分结构。',
    '原课有线电视费用题中，把1885看成1800附近，是为了约掉9因子；也示范过把相关数改成480、20等好算骨架，再用误差方向修正。'
  ));



  const c5=Q('estimate_near_integer','更接近几倍',['技巧'],()=>{
    const den=n(400,900), mult=n(2,4), num=den*mult-n(10,80);
    const ans=`更接近${mult}倍`;
    return R(
      `估算${num}÷${den}，商是${mult-1}开头还是更接近${mult}？`,
      ans,
      op(ans,[`更接近${mult-1}倍`,`无法估计`,`一定超过${mult+1}倍`]),
      '先看分母的整数倍靠近哪里。',
      `${den}×${mult}=${den*mult}，而${num}只比它少一点，所以商接近${mult}。原课平均资助强度题就是看二开头但更接近三，直接选更近的选项。`
    );
  });

  const c6=Q('estimate_no_good_multiple','没有倍数就直除',['技巧'],()=>R(
    '资料分析估算时，如果看不出明显倍数或好算关系，最稳的处理是什么？',
    '化成单个数据后一位数直除',
    ['化成单个数据后一位数直除','继续硬找复杂技巧','直接放弃','只看题干关键词'],
    '技巧服务于计算，不要为技巧而技巧。',
    '原课小麦亩产量题最后强调：没有倍数概念或直接倍数，就不要硬找，直接写成单个数据，用一位数直除即可。'
  ));

  const d=Q('guess_limit','猜题边界',['驿站'],()=>R(
    '比重变化题判断出上升/下降后，没时间精算时可猜数值小的。这个方法应如何定位？',
    '应急猜题，不替代正常估算',
    ['应急猜题，不替代正常估算','任何时候都优先用','比公式更可靠','只能靠猜题'],
    '课程说“没到必要时不要乱用猜题法”。',
    '先用R部与R整判断升降；有时间就估算，实在没时间再用数值小的作应急策略。'
  ));

  add(C('estimation_card','计算节能｜首位划线误差',['技巧'],[a,b,c,c2,c3,c4,c4b,c5,c6,d],'all'));
})();

// ----- lessons/data_analysis_speed_07/40_section_station.js -----
(function(){ EX.sec('驿站｜术语修正与边界'); })();

// ----- lessons/data_analysis_speed_07/41_station_data_cleanup.js -----
(function(){
  const {R,Q,C,add}=EX;
  const a=Q('station_data_terms','驿站｜资料术语修正',['驿站'],()=>R(
    '易混表述中“机器/G7、限期”在资料分析语境中应还原为什么？',
    '基期、现期',
    ['基期、现期','机器、限期','基数、限额','过去量、总量'],
    '按资料分析语境修正易混术语。',
    '“机器/G7”是基期，“限期”是现期；公式中要区分现期量、基期量与增长率。'
  ));
  const b=Q('station_data_not_covered','驿站｜后续边界',['驿站'],()=>R(
    '本段课程最后提到但未正式展开的资料分析内容有哪些？',
    '平均数变化、拉动增长、比重做差进阶刷题',
    ['平均数变化、拉动增长、比重做差进阶刷题','基期比重、现期比重','比重升降判断','平均数口径匹配'],
    '预告不等于已经讲完。',
    '本07课只训练已讲的比重、比重变化、平均数、基期平均数和估算；后续预告内容不放入主训练。'
  ));

  const c=Q('station_ratio_difference_future','驿站｜比重差边界',['驿站'],()=>R(
    '原课中“比重差/比重做差进阶”应放在本课主训练里吗？',
    '不放主训练，只作为后续刷题边界提醒',
    ['不放主训练，只作为后续刷题边界提醒','必须和基期比重混成一个题','完全删除不提','当作平均数变化来练'],
    '题面说后面刷题再讲比重做差的进阶方法。',
    '本课已经训练“比重变化=现期比重-基期比重”的基本概念；题面说比重差进阶、平均数变化、拉动增长属于后续内容，因此只放驿站边界，不硬塞主训练。'
  ));
  add(C('station_data_cleanup_card','驿站｜术语修正与边界',['驿站'],[a,b,c],'all'));
})();

