    Q('avg_words','平均数关键词',['基础'],()=>R('下列哪一个最容易识别为平均数题？','单位GDP能耗',['贡献率','拉动增长','单位GDP能耗','百分点'],'单位、人均、户均、每人次都是信号。','单位GDP能耗=能耗/GDP，是平均数结构。')),
    Q('annual_confuse','年均混淆',['基础'],()=>R('“平均数增长率”和“年均增长率”是否是同一个题型？','不是',['是','不是','只在国考中是','只在比重题中是'],'一个是总量/份数的平均数变化，一个是时间平均。','平均数增长率=(R总-R份)/(1+R份)；年均增长率是跨期增长速度问题。'))
