// ----- lessons/data_analysis_speed_08/09_base_share.js -----
(function(){
  const {R,Q,C,add}=EX;
  const subs=[
    Q('base_share_formula','基期比重公式',['基础'],()=>R(
      '基期比重应写成哪一个公式？',
      '现期比重×(1+R整)/(1+R部)',
      ['现期比重×(1+R整)/(1+R部)','现期比重×(1+R部)/(1+R整)','现期平均数×(1+R份)/(1+R总)','现期比重×(R部-R整)/(1+R部)'],
      '比重=部分÷整体，基期倒推时增长率交叉。',
      '基期比重=现期比重×(1+整体增长率)/(1+部分增长率)。'
    )),
    Q('base_share_cross','交叉对应',['技巧'],()=>R(
      '基期比重公式中，为什么(1+R整)在分子？',
      '整体在原比重分母，倒推时交叉到分子',
      ['整体在原比重分母，倒推时交叉到分子','整体永远写在分子','部分增长率没有用','因为平均数公式也这样'],
      '比重=部分/整体。',
      '基期部分=现期部分/(1+R部)，基期整体=现期整体/(1+R整)，相除后得到(1+R整)/(1+R部)。'
    )),
    Q('base_share_vs_avg','和基期平均数区分',['基础'],()=>R(
      '基期比重与基期平均数的共同点和区别是什么？',
      '都交叉倒推，但名称必须按本题对象替换',
      ['都交叉倒推，但名称必须按本题对象替换','公式完全相同不用区分','基期比重没有增长率','基期平均数只能做差'],
      '一个是部分/整体，一个是总量/份数。',
      '基期比重用(1+R整)/(1+R部)；基期平均数用(1+R份)/(1+R总)。'
    )),
    Q('four_formulas_memory','四公式硬背',['基础'],()=>R(
      '哪些公式不要只靠相似关系临场推？',
      '基期比重、比重变化、基期平均数、平均数变化',
      ['基期比重、比重变化、基期平均数、平均数变化','翻番、贡献率、混合、年均','乘法、除法、加法、减法','百分点、百分数、单位、表头'],
      '这些公式长得像，紧张时容易把字母写乱。',
      '这四组公式需要直接记牢，再按题目对象替换部/整或总/份。'
    ))
  ];
  add(C('base_share_card','基期比重｜交叉对应',['基础'],subs,'all'));
})();

// ----- lessons/data_analysis_speed_08/10_share_change.js -----
(function(){
  const {R,Q,C,add}=EX;
  const subs=[
    Q('share_def','比重结构',['基础'],()=>R('比重的一般结构是什么？','部分÷整体',['部分÷整体','总量÷份数','增长量÷基期量','A增长量÷B增长量'],'比重看某部分占整体多少。','比重=部分/整体。')),
    Q('share_change_formula','变化公式',['基础'],()=>R('比重变化公式是？','现期比重×(R部-R整)/(1+R部)',['现期比重×(R部-R整)/(1+R部)','现期平均数×(R总-R份)/(1+R总)','(R总-R份)/(1+R份)','A增长量/B基期量'],'比重变化是相对量做差。','比重变化=现期比重×(R部-R整)/(1+R部)。')),
    Q('share_denominator','分母位置',['技巧'],()=>R('比重变化公式的分母是？','1+R部',['1+R部','1+R整','1+R总','1+R份'],'和平均数公式区分。','比重变化公式分母是1+部分增长率。')),
    Q('share_rise','比重上升',['基础'],()=>R('什么时候比重上升？','R部>R整',['R部>R整','R部<R整','R总>R份','A增长量>B增长量'],'部分长得比整体快，占比提高。','部分增长率大于整体增长率，比重上升。')),
    Q('share_down','比重下降',['基础'],()=>R('什么时候比重下降？','R部<R整',['R部<R整','R部>R整','R部=R整且现期大','只要部分量下降'],'部分增长慢于整体。','部分增长率小于整体增长率，比重下降。'))
  ];
  add(C('share_change_card','比重变化｜公式与升降',['基础'],subs,'all'));
})();

// ----- lessons/data_analysis_speed_08/11_share_max_training.js -----
(function(){
  const {n,pct,op,R,Q,C,add}=EX;
  const chain=C('share_chain_route','相邻年份升降链',['技巧'],[
    Q('share_next_year','后年更大吗',['技巧'],()=>{
      const rp=n(6,20), rw=rp-n(1,5); const ans='后一年比重大';
      return R(`某年部分增长${pct(rp)}，整体增长${pct(rw)}。与上一年相比，该年比重如何？`,ans,op(ans,['后一年比重大','后一年比重小','无法判断','一定不变']), '比较R部和R整。',`R部=${pct(rp)}>R整=${pct(rw)}，比重上升。`);
    }),
    Q('share_candidate','锁定候选',['运用'],()=>{
      const ans='只保留升降链最终峰值候选';
      return R('连续多年比重最大值题，若能通过R部与R整判断每年相对上一年升降，第一步应做什么？',ans,op(ans,['每年比重全算','只保留升降链最终峰值候选','直接选最后一年','直接选第一年']), '最大最小题可以先用趋势排除。',`先判断相邻年份比重升降，排除不可能成为最大值的年份，再对候选精算。`);
    })
  ],'sequence');
  const calc=C('share_candidate_calc','先排除再计算',['运用'],[
    Q('two_segments','两段趋势',['运用'],()=>{
      const ans='两个局部峰值';
      return R('若前半段比重先降后升，后半段连续上升，通常最后需要比较哪些年份？',ans,op(ans,['全部年份','两个局部峰值','只比第一年和第二年','只看增长率最大年']), '趋势链只能排除，不一定直接给最终答案。',`每段趋势留下局部峰值，最后比较这些候选即可。`);
    }),
    Q('candidate_only','只算候选',['技巧'],()=>{
      const a=n(3000,8000), b=n(9000,18000); const ans='只计算候选年份比重';
      return R(`已排除大部分年份，只剩两年候选。接下来应如何求最大比重？`,ans,op(ans,['从头全算','只计算候选年份比重','继续只看标题','改算贡献率']), '排除后不要返工。',`趋势判断只是锁定候选，最终需要对候选的部分/整体进行比较或估算。`);
    })
  ],'sequence');
  add(C('share_max_training_card','比重最大最小｜变量训练',['运用'],[chain,calc],'all'));
})();

