// ----- lessons/data_analysis_speed_08/26_annual_monthly.js -----
(function(){
  const {R,Q,C,add,n,op}=EX;
  const subs=[
    Q('annual_amount','年均增长量',['基础'],()=>{ const a=n(100,300), years=n(3,8), b=a+n(20,60)*years; const ans=(b-a)/years; return R(`初期${a}，${years}年后为${b}，年均增长量是多少？`,String(ans),op(ans,[ans+1,ans-1,b-a]),'末期减初期，再除以年份差。',`(${b}-${a})/${years}=${ans}。`); }),
    Q('monthly_amount','月均增长量',['基础'],()=>{ const a=n(80,200), months=n(4,10), inc=n(5,20), b=a+inc*months; return R(`初月${a}，${months}个月后为${b}，月均增长量是多少？`,String(inc),op(inc,[inc+1,inc-1,b-a]),'末期减初期，再除以月份差。',`(${b}-${a})/${months}=${inc}。`); }),
    Q('month_boundary','月份基点',['技巧'],()=>R('问“7月至次年3月月平均增量”，材料给6月、7月、3月数据，通常应以哪个月作初始量？','6月',['6月','7月','3月','任选'],'7月的增量相对于6月产生。','若计算7月到3月每月增量，需要用3月量-6月量，再除以9个月。')),
    Q('annual_not_avg_rate','不要混同',['基础'],()=>R('年均/月均增长量与平均数增长率是否同一类公式？','不是',['是','不是','只差一个百分号','只在月份题相同'],'一个按时间平均，一个按总量/份数变化。','年均/月均增长量=(末期-初期)/时间差；平均数增长率=(R总-R份)/(1+R份)。'))
  ];
  add(C('annual_monthly_card','年均月均｜增长量边界',['基础'],subs,'all'));
})();

// ----- lessons/data_analysis_speed_08/27_data_reading_boundaries.js -----
(function(){
  const {R,Q,C,add,n,op}=EX;
  const subs=[
    Q('time_current_base','时间定位',['基础'],()=>R(
      '材料给2017年数据，题目问2016年，通常先判断为哪类问题？',
      '基期问题',
      ['现期问题','基期问题','翻番问题','贡献率问题'],
      '题目年份早于材料年份。',
      '材料年=题目年通常按现期处理；题目问上一年或更早年份，通常要由现期倒推基期。'
    )),
    Q('increase_decrease_back','增减量倒推',['技巧'],()=>{
      const base=n(80,180), inc=n(5,30), cur=base+inc;
      return R(`某地现期出生人口${cur}，比上年增加${inc}。上年是多少？`,String(base),op(base,[cur,cur+inc,base-inc]),'增加多少，就从现期中减回去。',`${cur}-${inc}=${base}。若题干说“减少x”，则基期=现期+x。`);
    }),
    Q('higher_lower_point','高于低于百分点',['基础'],()=>R(
      '浙江增速5%，高于全国2.8个百分点，则全国增速是多少？',
      '2.2%',
      ['2.2%','7.8%','5%','2.8%'],
      '“高于”说明浙江=全国+2.8个百分点。',
      '全国增速=5%-2.8%=2.2%。若A低于B x个百分点，则B=A+x个百分点。'
    )),
    Q('given_share_add','表头占比直接加',['技巧'],()=>R(
      '表格两列已经给出“金融证券类占比12.4%”“支付交易类占比87.3%”，求二者合计占比，应怎么做？',
      '直接相加',
      ['直接相加','先除以总量','先求增长率','先转成基期量'],
      '表头已经说明数据是占比。',
      '二者占同一个总量的比重，合计占比=12.4%+87.3%=99.7%，不必再除以总量。'
    )),
    Q('given_current_share','现期比重已给',['技巧'],()=>R(
      '若题目已直接给出现期比重41%，求“较上年提高多少”，现期部分应如何处理？',
      '直接用41%减基期比重',
      ['直接用41%减基期比重','重新用现期部分量除整体量','用41%乘增长率','改算贡献率'],
      '已给的数据不要重复计算。',
      '比重变化=现期比重-基期比重；现期比重已给时，重点求基期比重即可。'
    )),
    Q('read_question_max_min','问法审题',['基础'],()=>R(
      '题干问“最大是多少”，审题上最不能犯的错误是什么？',
      '把最大看成最小',
      ['把最大看成最小','先找分母','先看单位','先写公式'],
      '审题方向必须先确认。',
      '方法再快也要先看清问法：最大、最小、多、少、上升、下降，方向错了就不是计算问题。'
    )),
    Q('same_year_current','材料同年现期',['基础'],()=>R(
      '材料和题目都指向同一年，例如材料是2010年、题目也问2010年，通常按什么量处理？',
      '现期量',
      ['现期量','基期量','增长量','番数'],
      '年份一致时通常不需要倒推。',
      '题问年份与材料年份一致，先按现期量找数；题问上年或过去年份，才考虑基期倒推。'
    ))
  ];
  add(C('data_reading_boundaries_card','读题定位｜时间、表头与百分点',['基础'],subs,'all'));
})();

// ----- lessons/data_analysis_speed_08/28_option_strategy.js -----
(function(){
  const {R,Q,C,add}=EX;
  const subs=[
    Q('wide_options','差距大估算',['运用'],()=>R('选项差距很大时，最节能的策略是什么？','大胆划线估算',['逐位精算','大胆划线估算','只看题干年份','直接猜最大'],'估算误差小于选项差距即可。','差距大时，抓骨架和数量级即可。')),
    Q('close_options_precise','千分级精算',['技巧'],()=>R('选项差距只有千分之几时，能否随意划线？','不能',['能','不能','只要题目短就能','只要百分号小就能'],'误差可能超过选项差。','应改用代入、拆分或更精确计算。')),
    Q('multiply_split','乘法拆分',['技巧'],()=>R('多位数乘法且选项很接近时，推荐什么方法？','拆分法',['拆分法','随意划线','只看首位','贡献率法'],'拆分没有估算误差。','如382=400-20+2，分别乘再合并。')),
    Q('growth_substitute','增长量代入',['技巧'],()=>R('已知现期量和增长率，问增长量且选项很接近，常用什么方法？','代入法',['代入法','翻番法','比重变化公式','拉动增长公式'],'选项接近，不宜粗估。','用现期量-候选增长量得到基期，再乘增长率验证。')),
    Q('two_groups','两组选项',['运用'],()=>R('若选项分成两组，组内接近、组间差距大，应怎么做？','先粗估分组，再组内代入',['直接代入中间值','先粗估分组，再组内代入','只选最小','只选最大'],'先排除远的一组。','粗估判断答案落在哪组，再在组内精算。')),
    Q('line_core','划线法核心',['技巧'],()=>R('划线法的核心不是把数算准，而是先控制什么？','误差小于选项差距',['误差小于选项差距','每一步都无误差','只看首位','只看最大数'],'估算服务于选项。','能划到什么程度，取决于选项间距；误差压在选项差距内即可。')),
    Q('error_cancel','误差抵消',['技巧'],()=>R('估算时一个数被调大、另一个相关因素被调小，可能出现什么效果？','误差互相抵消',['误差互相抵消','误差必然翻倍','答案一定变大','答案一定变小'],'估算中常用“上调/下调”控制误差。','划线估算不只看单个数，还要看分子分母、乘除关系中的误差方向。')),

    Q('division_split_second_digit','除法拆分',['技巧'],()=>R('A÷B 且选项第二位不同，除了划线法，还可用哪种稳定方法？','拆分法',['拆分法','翻番法','贡献率法','直接选最大'],'第二位不同，拆出整数倍后看余数很快。','例如先看B的2倍、3倍还剩多少，再把余数继续除以B，得到首两位判断选项。'))
  ];
  add(C('option_strategy_card','选项意识｜估算还是精算',['运用'],subs,'all'));
  add(Q('foundation_first','驿站｜基础先行',['驿站'],()=>R('为什么不能一开始就模仿“只看选项不写误差”的高手做法？','基础不牢会失控',['基础不牢会失控','因为选项没有用','因为所有题都要精算','因为公式不用背'],'灵活来自熟练，不是跳过基础。','先会判断误差和公式，再逐步减少书写；否则容易把估算变成乱猜。')));
})();

// ----- lessons/data_analysis_speed_08/29_comprehensive_training.js -----
(function(){
  const {n,pct,op,R,Q,C,add}=EX;
  const identify=C('identify_route','先识别题型',['运用'],[
    Q('random_type','随机识别',['运用'],()=>{ const items=[['人均收入同比增长百分之几','平均数增长率'],['某项占比提高多少','比重变化'],['A拉动B增长多少百分点','拉动增长'],['A对B增长的贡献率','贡献率'],['A比B多多少倍','多几倍']]; const it=EX.pk(items); return R(`题干问：“${it[0]}”。应识别为哪类？`,it[1],op(it[1],items.map(x=>x[1])),'抓关键词。',`关键词对应题型：${it[0]} → ${it[1]}。`); }),
    Q('diff_or_ratio','做差做比',['运用'],()=>R('“比重较上年提高多少”应优先做差还是做比？','做差',['做差','做比','先翻番','先求贡献率'],'比重是相对量。','相对量比较高低，优先现期比重-基期比重。'))
  ],'sequence');
  const formula=C('formula_route','再选公式',['技巧'],[
    Q('formula_blank','公式填空',['技巧'],()=>R('平均数增长率公式应填哪个分母： (R总-R份)/( ? )','1+R份',['1+R份','1+R总','1+R部','B基期量'],'增长率公式不带现期平均数。','平均数增长率=(R总-R份)/(1+R份)。')),
    Q('denominator_random','分母随机辨析',['技巧'],()=>{ const list=[['平均数增长量','1+R总'],['平均数增长率','1+R份'],['比重变化','1+R部'],['基期比重倒推','1+R部'],['基期平均数倒推','1+R总'],['拉动增长','B基期量'],['贡献率','B增长量']]; const it=EX.pk(list); return R(`${it[0]}的关键分母是什么？`,it[1],op(it[1],list.map(x=>x[1])),'不同题型分母不同。',`${it[0]}对应分母：${it[1]}。`); }),
    Q('four_formula_random','四公式随机辨析',['技巧'],()=>{ const list=[['基期比重','现期比重×(1+R整)/(1+R部)'],['比重变化','现期比重×(R部-R整)/(1+R部)'],['基期平均数','现期平均数×(1+R份)/(1+R总)'],['平均数增长率','(R总-R份)/(1+R份)']]; const it=EX.pk(list); return R(`${it[0]}应匹配哪个公式？`,it[1],op(it[1],list.map(x=>x[1])),'这是一组高相似公式，必须准确区分。',`${it[0]}：${it[1]}。`); })
  ],'sequence');
  const method=C('method_route','最后选算法',['运用'],[
    Q('method_pick','算法选择',['运用'],()=>{ const list=[['选项差距很大','划线估算'],['选项千分级接近','拆分或代入'],['增长率约为1/7求增长量','份数法'],['问增长量且候选接近','代入法']]; const it=EX.pk(list); return R(`${it[0]}时，优先选择什么方法？`,it[1],op(it[1],list.map(x=>x[1])),'方法服务于误差边界。',`${it[0]} → ${it[1]}。`); }),
    Q('need_precise','精算边界',['运用'],()=>R('估算是否足够，最终取决于什么？','估算误差是否小于选项差距',['估算误差是否小于选项差距','题目数字是否好看','题干是否很长','是否出现百分号'],'不是为了炫技，是为了节能正确。','选项差距大，估算足够；选项极近，必须控制误差或精算。'))
  ],'sequence');
  add(C('comprehensive_training_card','综合判定｜变量训练',['运用'],[identify,formula,method],'all'));
})();

// ----- lessons/data_analysis_speed_08/30_original_edges_variable_expansion.js -----
(function(){
  const {pk,n,pct,op,R,Q,C,add,approx}=EX;

  const edgeSubs=[
    Q('max_min_reading','最大最小审题',['基础'],()=>R(
      '题目问“最大是多少”，考场上最不能犯的错误是什么？',
      '看成求最小或反向处理',
      ['看成求最小或反向处理','先看单位','画线估算','找表头'],
      '这个坑必须优先防住。',
      '求最大、求最小属于问法方向问题，方向读反，后面公式和估算都救不回来。'
    )),
    Q('ten_percent_phrase','十以内增长率',['技巧'],()=>R(
      '增长率在10%以内、现期又较大时，增长量可优先怎样估？',
      '按100增加多少、1000增加多少来估',
      ['按100增加多少、1000增加多少来估','必须用贡献率','必须先求基期比重','直接减1'],
      '这是小增长率增长量的速算入口。',
      '如增长7.9%，100增加约7.9，1000增加约79，再看现期有几个百、几个千。'
    )),
    Q('mixed_principle_name','混合原理名称',['基础'],()=>R(
      '“整体增长率夹在两个部分增长率之间，且更靠近量大的部分”对应哪个思想？',
      '混合原理',
      ['混合原理','翻番公式','基期平均数','拉动增长'],
      '这是后文基期做差、未知部分增长率反推的底层。',
      '混合原理：整体增长率在部分增长率之间；距离关系与部分量大小成反比。'
    ))
  ];

  const contexts=[
    ['出口额','出口量','平均价格'],
    ['总薪酬','人数','人均薪酬'],
    ['能耗','GDP','单位GDP能耗'],
    ['总产量','面积','单位面积产量'],
    ['旅客周转量','客运量','每人次运输距离']
  ];
  const avgRoute=C('scene_avg_route','平均数场景迁移',['技巧'],[
    Q('scene_avg_identify','随机场景识别',['技巧'],()=>{
      const [tot,den,avg]=pk(contexts);
      return R(`“${avg}”应理解为哪两个量相除？`,`${tot}÷${den}`,op(`${tot}÷${den}`,[`${den}÷${tot}`,`${tot}+${den}`,`${tot}-${den}`]),'先找总量和份数。',`${avg}是平均数结构，应为${tot}除以${den}。`);
    }),
    Q('scene_avg_rate','随机场景增长率',['技巧'],()=>{
      const [tot,den,avg]=pk(contexts); let rt=n(4,28), rd=n(-4,18); if(rt===rd) rt+=3;
      const val=(rt-rd)/(100+rd)*100, ans=approx(val,1)+'%';
      return R(`${avg}=${tot}÷${den}，${tot}增长${pct(rt)}，${den}增长${pct(rd)}，${avg}增长率约为？`,ans,op(ans,[approx(rt-rd,1)+'%',approx(val+1,1)+'%',approx(val-1,1)+'%']),'平均数增长率分母用1+R份。',`(${rt}-${rd})/(100+${rd})≈${ans}。`);
    })
  ],'sequence');

  const shareRoute=C('scene_share_route','比重场景迁移',['技巧'],[
    Q('scene_share_or_avg','比重还是平均数',['基础'],()=>{
      const part=pk(['第三产业增加值','夏粮产量','广告收入','面上项目数']);
      const whole=pk(['GDP','粮食总产量','广电总收入','总资助项目数']);
      return R(`${part}占${whole}的比重，本质结构是什么？`,`${part}÷${whole}`,op(`${part}÷${whole}`,[`${whole}÷${part}`,`${part}+${whole}`,'R总-R份']),'“占……比重”是部分除以整体。',`部分是${part}，整体是${whole}，所以比重=${part}÷${whole}。`);
    }),
    Q('scene_share_change','随机比重变化',['技巧'],()=>{
      let rb=n(-3,24), rw=n(-2,20); if(rb===rw) rw+=2; const now=n(15,65); const val=now*(rb-rw)/(100+rb); const ans=approx(val,1)+'个百分点';
      return R(`现期比重${pct(now)}，R部=${pct(rb)}，R整=${pct(rw)}，比重变化约为？`,ans,op(ans,[approx(now*(rb-rw)/(100+rw),1)+'个百分点',approx(rb-rw,1)+'个百分点',approx(val+2,1)+'个百分点']),'比重变化=现期比重×(R部-R整)/(1+R部)。',`${now}%×(${rb}-${rw})/(100+${rb})≈${ans}。`);
    })
  ],'sequence');

  const wordingRoute=C('scene_wording_route','问法变量迁移',['运用'],[
    Q('wording_amount_rate','多少与快慢',['基础'],()=>{
      const a=pk(['上涨最多','增加最多','多多少']); const b=pk(['增长最快','增速最高','同比百分之几']);
      return R(`问“${a}”与问“${b}”分别优先对应什么？`,'前者看量，后者看率',op('前者看量，后者看率',['前者看率，后者看量','二者都看贡献率','二者都看翻番']),'“多少”看量，“快慢”看率。',`“${a}”是量的大小；“${b}”是率或速度。`);
    }),
    Q('wording_point_restore','高低百分点还原',['技巧'],()=>{
      const a=n(4,18), d=n(1,6); const high=Math.random()<0.5; const ans=pct(high?a-d:a+d);
      return R(`A增长${pct(a)}，且A增速${high?'高于':'低于'}B ${d}个百分点，则B增长率是多少？`,ans,op(ans,[pct(a+d),pct(a-d),pct(d)]),'“高于”说明A=B+d；“低于”说明A=B-d。',high?`A高于B ${d}个百分点，所以B=${a}-${d}=${ans}。`:`A低于B ${d}个百分点，所以B=${a}+${d}=${ans}。`);
    })
  ],'sequence');

  add(C('original_edges_card','易错边界｜细节提醒',['基础'],edgeSubs,'all'));
  add(Q('side_quantity_guessing','驿站｜跨模块猜题提醒',['驿站'],()=>R(
    '“反陷阱、偏移法、求最大猜次大、求最小猜次小”这类提醒应如何处理？',
    '作为审题与应急猜题提醒，不并入资料分析主公式',
    ['作为审题与应急猜题提醒，不并入资料分析主公式','作为平均数增长率公式','作为贡献率公式','完全删除不看'],
    '它们来自数量关系侧的复习提醒。',
    '这类方法说明考试中要防问法陷阱，没时间时可应急；但本课资料分析主线仍是平均数、比重、增长量、拉动增长、贡献率等。'
  )));
  add(Q('jiangsu_training','驿站｜江苏题训练意义',['驿站'],()=>R(
    '复杂资料分析题主要考查什么？',
    '复杂题要靠结构识别和估算思维，不能只死算',
    ['复杂题要靠结构识别和估算思维，不能只死算','江苏题只能放弃','所有题都必须直除','选项不用看'],
    '结合后文三数做比、比重最大值等题看。',
    '这些题不一定数据最难，而是考你能否看出结构：选两个对象、用增长率判断升降、结合选项估算。'
  )));
  add(Q('method_not_only','驿站｜方法不唯一',['驿站'],()=>R(
    '“方法不唯一”的正确理解是？',
    '掌握底层结构后，可选择最省力算法',
    ['掌握底层结构后，可选择最省力算法','只能照搬一种划线方法','所有题都必须精算','不用判断结构'],
    '划线法、拆分、代入、份数法可以并存。',
    '资料分析不是背一种机械步骤，而是先识别对象和问法，再根据选项精度选择划线、拆分、代入或精算。'
  )));
  add(C('variable_expansion_card','场景迁移｜随机变量强化',['运用'],[avgRoute,shareRoute,wordingRoute],'all'));
})();

// ----- lessons/data_analysis_speed_08/31_point12_final_audit_expansion.js -----
(function(){
  const {pk,n,pct,approx,op,R,Q,C,add}=EX;

  const fidelitySubs=[
    Q('diff_first_exception','做差优先与例外',['基础'],()=>R(
      '相对量比大小时，什么时候才考虑“做比”？',
      '做差没有答案时才考虑做比',
      ['做差没有答案时才考虑做比','一看到百分号就做比','一律做比','题干有同比就做比'],
      '处理顺序：做差为主。',
      '比重、率等相对量比大小优先直接做差；如果做差结果没有对应选项，再考虑做比。'
    )),
    Q('share_not_growth_amount','比重不能叫增长量',['基础'],()=>R(
      '为什么“比重做差”一般不叫“比重增长量”？',
      '增长量是绝对量，比重做差仍是百分点/百分数差',
      ['增长量是绝对量，比重做差仍是百分点/百分数差','因为比重不能做差','因为比重一定做比','因为增长量必须是负数'],
      '注意“变化”和“增长量”的命名边界。',
      '平均数是绝对量，做差可叫平均数增长量；比重是相对量，做差结果叫比重变化或百分点变化。'
    )),
    Q('percent_written_point_spoken','百分号与百分点表达',['基础'],()=>R(
      '选项写“20%”而解析读“20个百分点”时，最稳妥的判断是什么？',
      '看题型本质，不只看符号',
      ['看题型本质，不只看符号','百分号一定表示做比','百分点一定不能选','直接排除百分号选项'],
      '选项可能写成百分号形式。',
      '相对量做差的结果书面上可能仍写%，口头或规范表达常读作百分点；核心仍是先看题型。'
    )),
    Q('original_number_option_trap','题干原数选项警惕',['技巧'],()=>R(
      '选项中出现题干原始数据时，应怎样处理？',
      '警惕它是未加工数据，不能直接选',
      ['警惕它是未加工数据，不能直接选','一定就是答案','只要最大就选','只要最小就选'],
      '题干原数往往还没经过基期、增长量、比重等处理。',
      '例如题目要求基期或进出口总额，现期原数直接出现在选项中时，要先判断是否还需除以1+r、相加或做差。'
    )),
    Q('guess_small_one_reason','相差一选小的理由',['技巧'],()=>R(
      '“A比B多多少倍”的选项里若两个选项相差1，为什么小的常是答案？',
      '因为误算成“A是B的几倍”会多1',
      ['因为误算成“A是B的几倍”会多1','因为小数一定正确','因为增长率一定小','因为翻番要减1'],
      '“是几倍”和“多几倍”差一个1。',
      'A是B的几倍=A/B；A比B多几倍=A/B-1，所以陷阱选项往往比答案大1。'
    )),
    Q('direction_first_before_formula','方向先于公式',['基础'],()=>R(
      '为什么“求最大/求最小”不能看反？',
      '方向读反会导致后面所有计算都服务于错误目标',
      ['方向读反会导致后面所有计算都服务于错误目标','因为公式会自动纠错','因为最大题都不用算','因为最小题都选次小'],
      '审题方向是进入公式前的第一关。',
      '资料分析里“最大、最小、最多、最少、上升、下降”必须先确认方向，方向错了，估算再快也错。'
    )),
    Q('estimate_requires_gap','划线估算的条件',['技巧'],()=>R(
      '划线法能大胆使用的前提是什么？',
      '估算误差小于选项差距',
      ['估算误差小于选项差距','所有数字都能随便改','选项越接近越要粗估','不需要看选项'],
      '估算必须结合选项。',
      '选项差距大，允许粗估；选项千分级接近时，必须代入、拆分或精算，不能乱划线。'
    ))
  ];

  const relativeVar=C('relative_expression_random','相对量表达扰动',['技巧'],[
    Q('random_diff_vs_ratio','做差做比扰动',['技巧'],()=>{
      const a=n(24,72), b=a-n(3,18); const diff=a-b; const ratio=approx((a-b)/b*100,1)+'%'; const ans=`${diff}个百分点`;
      return R(`甲比重${pct(a)}，乙比重${pct(b)}。问“甲比乙高多少”，优先结果是？`,ans,op(ans,[ratio,`${a/b}倍`,`${a+b}%`]),'两个比重比大小，先做差。',`${a}%-${b}%=${diff}个百分点；${ratio}是做比后的结果，不是优先答案。`);
    }),
    Q('random_name_boundary','命名边界扰动',['技巧'],()=>{
      const isAvg=Math.random()<0.5; const obj=isAvg?'人均收入':'某行业占比'; const ans=isAvg?'增长量':'比重变化';
      return R(`${obj}今年与去年直接相减，结果更适合叫作什么？`,ans,op(ans,['增长量','比重变化','贡献率','拉动增长']),'看对象是绝对量还是相对量。',isAvg?'人均收入是平均数，属于绝对量，做差可叫增长量。':'占比是相对量，做差叫比重变化或百分点变化，不叫增长量。');
    })
  ],'sequence');

  const wordingVar=C('wording_random_upgrade','问法与选项扰动',['运用'],[
    Q('random_multiple_wording','倍数问法扰动',['技巧'],()=>{
      const b=n(80,300); const k=n(2,7); const a=b*k; const more=Math.random()<0.5; const ans=more?`${k-1}倍`:`${k}倍`;
      return R(`A=${a}，B=${b}。题目问“A${more?'比B多多少倍':'是B的多少倍'}”，答案是？`,ans,op(ans,[`${k}倍`,`${k-1}倍`,`${k+1}倍`,`${Math.max(1,k-2)}倍`]),'先看有没有“多”。',more?`A/B=${k}，问多多少倍要减1，所以是${k-1}倍。`:`A/B=${k}，问是多少倍不减1。`);
    }),
    Q('random_raw_option_trap','题干原数陷阱扰动',['技巧'],()=>{
      const cur=n(800,5000), r=n(5,25); const base=Math.round(cur/(1+r/100)); const ans='不能直接选现期原数';
      return R(`现期量为${cur}，同比增长${pct(r)}。若题目问基期量，选项里出现${cur}，应怎样判断？`,ans,op(ans,[`基期约${base}`,ans,'直接选现期原数','用现期量加增长率']), '问基期，需要现期除以1+r。',`基期约为${cur}/(1+${r}%)≈${base}，所以${cur}只是现期原数，不能直接选。`);
    })
  ],'sequence');

  const sceneVar=C('scene_random_upgrade','跨场景随机迁移',['运用'],[
    Q('random_algorithm_choice','算法选择扰动',['运用'],()=>{
      const close=Math.random()<0.5; const ans=close?'代入或拆分精算':'划线估算即可';
      const opts=close?'201.1、201.4、201.7、202.0':'18、24、39、61';
      return R(`某题计算式较复杂，选项为：${opts}。优先策略是什么？`,ans,op(ans,['划线估算即可','代入或拆分精算','直接猜最大','一定求贡献率']),'看选项差距。',close?'选项极接近，粗估风险大，应代入、拆分或精算。':'选项差距大，可先用划线法快速定位。');
    }),
    Q('random_high_low_point','高低百分点扰动',['技巧'],()=>{
      const known=n(6,30), d=n(2,8); const type=pk(['高于','低于']); const ans= type==='高于'?pct(known-d):pct(known+d);
      return R(`某省增长${pct(known)}，${type}全国${d}个百分点。全国增长率是？`,ans,op(ans,[pct(known+d),pct(known-d),pct(d),pct(known)]),'把“高于/低于”还原成等式。',type==='高于'?`某省=全国+${d}，所以全国=${known}-${d}=${ans}。`:`某省=全国-${d}，所以全国=${known}+${d}=${ans}。`);
    })
  ],'sequence');

  add(C('fidelity_point12_card','易错细节｜边界提醒',['基础'],fidelitySubs,'all'));
  add(Q('method_choice_not_showoff','驿站｜方法选择不是炫技',['驿站'],()=>R(
    '“不要为了快而快”的正确理解是？',
    '基础公式和误差意识稳了，再选择省力方法',
    ['基础公式和误差意识稳了，再选择省力方法','永远不用速算','只用一种方法','所有题都靠猜'],
    '基础不牢时不能直接跳到只看选项。',
    '速算是建立在识别对象、公式正确、误差可控上的；否则会把技巧变成乱猜。'
  )));
  add(C('variable_point12_card','综合训练｜问法与选项扰动',['运用'],[relativeVar,wordingVar,sceneVar],'all'));
})();

// ----- lessons/data_analysis_speed_08/32_calculation_line_method_expansion.js -----
(function(){
  const {pk,n,pct,approx,op,R,Q,C,add}=EX;

  const exactSubs=[
    Q('exact_tail_sum','精算不是全算',['技巧'],()=>R(
      '多位数加总题需要“精算”时，优先指什么？',
      '用尾数法排除选项',
      ['用尾数法排除选项','每个数完整竖式相加','直接看最大项','把所有数都估成整数'],
      '精算也要省力。',
      '多位数加法常先看末位；若两个选项尾数相同，再看倒数第二位，不必把每个大数完整加完。'
    )),
    Q('exact_vs_estimate','精算估算分工',['基础'],()=>R(
      '“精算”和“估算”的分工是什么？',
      '加总类常用尾数精算，乘除类常用估算',
      ['加总类常用尾数精算，乘除类常用估算','所有题都直除','所有题都只猜','比重题不能估算'],
      '先看运算结构。',
      '求多个数据之和时，尾数法很稳；乘除式则更适合分数转化、划线法、拆分或代入。'
    )),
    Q('fraction_transform_role','分数转化地位',['技巧'],()=>R(
      '资料分析速算主要靠哪两类方法打底？',
      '分数转化和划线法',
      ['分数转化和划线法','只靠直除','只靠贡献率','只靠翻番'],
      '这出现在划线法正式讲解前。',
      '分数转化用于把常见小数或百分数转成好算分数；划线法用于主动改造不好看的A÷B。'
    )),
    Q('fraction_table_need','常见分数敏感',['技巧'],()=>R(
      '看到14.2%、16.7%、12.5%、11.1%这类数，应形成什么敏感性？',
      '能快速联想到1/7、1/6、1/8、1/9',
      ['能快速联想到1/7、1/6、1/8、1/9','一律直除','一律看成10%','只判断大小不计算'],
      '分数转化靠熟练。',
      '常见分数能把除法变成乘法或份数法，是后面增长量、A÷B估算的基础。'
    ))
  ];

  const lineRuleSubs=[
    Q('line_three_digit_diff','截三位做差',['技巧'],()=>R(
      '划线法速算误差的第一步是什么？',
      '截三位做差',
      ['截三位做差','四舍五入到整数','完整计算相对误差','只看个位'],
      '注意：“截”不是四舍五入。',
      '例如1034看成1000，先看103到100，差3，再转成约3%的误差。'
    )),
    Q('line_pad_three_digits','不足三位补零',['技巧'],()=>R(
      '2345想看成24时，做三位误差应怎样处理24？',
      '把24看成240再做差',
      ['把24看成240再做差','直接用234-24','直接算2345÷24','不用管误差'],
      '所有参与比较的数都要统一成三位。',
      '234变到240，差6；再用首两位估差值占原数的百分比。'
    )),
    Q('line_more_means_permille','“多”表示什么',['技巧'],()=>R(
      '“2%多”“7%多”里的“多”主要表示什么？',
      '千分级的小尾巴，通常不必精确算完',
      ['千分级的小尾巴，通常不必精确算完','必须再算十位数','说明答案一定错','说明不能估算'],
      '“多”是误差意识，不是随便糊弄。',
      '多数资料分析选项不会卡到千分级；若选项极近，再把这个“多”进一步配回去。'
    )),
    Q('line_denominator_direction','分母误差方向',['基础'],()=>R(
      'A÷B中，若只把分母B调小3%，算出的初值C应怎样修正？',
      'C也调小约3%',
      ['C也调小约3%','C调大约3%','不用修正','改成贡献率'],
      '修正方向跟分母相同。',
      '分母被调小会让估算值偏大，所以要把C按同方向调小约3%。'
    )),
    Q('line_numerator_direction','分子误差方向',['基础'],()=>R(
      'A÷B中，若只把分子A调大2%，算出的初值C应怎样修正？',
      'C调小约2%',
      ['C调小约2%','C调大约2%','C不变','把2%加到分母'],
      '分子方向与结果修正相反。',
      '分子被调大使估算值偏大，所以最终要反向调小。'
    )),
    Q('line_same_direction_cancel','同向抵消',['技巧'],()=>R(
      'A÷B中，分子下降3%、分母下降2%，误差应怎样合并？',
      '同向抵消，大减小，剩分子下降1%',
      ['同向抵消，大减小，剩分子下降1%','异向叠加，变5%','直接忽略','只看分母2%'],
      '分子和分母都同向改动，先抵消。',
      '分子剩余下降1%，修正结果时跟分子相反，所以C应上调约1%。'
    )),
    Q('line_opposite_direction_stack','异向叠加',['技巧'],()=>R(
      'A÷B中，分子上升3%、分母下降2%，误差应怎样合并？',
      '异向叠加，约5%',
      ['异向叠加，约5%','同向抵消成1%','只保留3%','一定不能算'],
      '两个变化都让估算值同向偏大。',
      '分子上升使值偏大，分母下降也使值偏大，因此要合并成约5%的修正量。'
    )),
    Q('line_error_under_ten','误差别超过十',['技巧'],()=>R(
      '划线法改数时，单次误差最好控制在什么范围？',
      '尽量不要超过10%',
      ['尽量不要超过10%','越大越好','必须超过20%','只要好算就无限改'],
      '误差太大就不好配回去。',
      '划线是主动改数，但不是乱改；误差越小，越容易结合选项或快速修正。'
    )),
    Q('line_active_not_passive','主动改数',['基础'],()=>R(
      '划线法区别于传统拆分法的关键心法是什么？',
      '以自己的口算目标主动改造数据',
      ['以自己的口算目标主动改造数据','完全被题目原数牵着走','永远不能改分母','只改最后一位'],
      '这是划线法的“主动性”。',
      '看到不好看的分母或分子，可以主动改成好约分、好转分数的数，再用误差修正。'
    ))
  ];

  const variableSubs=[
    Q('random_fraction_transform','分数转化随机',['技巧'],()=>{
      const list=[
        ['14.2%','1/7'],['16.7%','1/6'],['12.5%','1/8'],['11.1%','1/9'],
        ['33.3%','1/3'],['25%','1/4'],['75%','3/4']
      ];
      const it=pk(list);
      return R(`看到${it[0]}，优先联想到哪个分数？`,it[1],op(it[1],list.map(x=>x[1])),'先建立常见百分数和分数的对应。',`${it[0]}约等于${it[1]}，可用于份数法或除法转化。`);
    }),
    Q('random_three_digit_error','三位误差随机',['技巧'],()=>{
      const base=n(120,980);
      const target=Math.round(base/n(8,12))*n(8,12);
      const diff=Math.abs(base-target);
      const ans=diff===0?'约0%':`约${Math.max(1,Math.round(diff/(base/10)))}%`;
      return R(`把${base}看成${target}，按“截三位做差”的误差约为？`,ans,op(ans,[`约${Math.max(0,Math.round(diff/(base/10))+2)}%`,`约${Math.max(0,Math.round(diff/(base/10))-2)}%`,'不用看误差']),'差值除以原数首两位，口算百分级误差。',`差${diff}，${base}的10%约${Math.round(base/10)}，所以误差约为${ans}。`);
    }),
    Q('random_ab_error_direction','A÷B误差方向随机',['运用'],()=>{
      const numUp=Math.random()<0.5;
      const denUp=Math.random()<0.5;
      const a=n(1,6), b=n(1,6);
      let ans, detail;
      if(numUp===denUp){
        const left=Math.abs(a-b);
        if(a===b){ ans='基本抵消'; detail='分子分母同向且幅度相同，误差近似抵消。'; }
        else if(a>b){ ans=`按分子剩${left}%反向修正`; detail=`同向抵消后，分子剩${left}%，结果修正跟分子相反。`; }
        else { ans=`按分母剩${left}%同向修正`; detail=`同向抵消后，分母剩${left}%，结果修正跟分母相同。`; }
      }else{
        ans=`异向叠加约${a+b}%`;
        detail='分子和分母的改动让结果偏向同一边，先叠加再修正。';
      }
      return R(`A÷B估算中，分子${numUp?'上升':'下降'}${a}%，分母${denUp?'上升':'下降'}${b}%，误差合并应先判断什么？`,ans,op(ans,['基本抵消',`异向叠加约${a+b}%`,`按分子剩${Math.abs(a-b)}%反向修正`,`按分母剩${Math.abs(a-b)}%同向修正`]),'同向先抵消，异向先叠加；再看剩余在分子还是分母。',detail);
    }),
    Q('random_tail_exact','尾数法随机',['技巧'],()=>{
      const nums=[n(1200,9800),n(1200,9800),n(1200,9800)];
      const tail=nums.reduce((s,x)=>s+x,0)%10;
      const ans=`尾数为${tail}`;
      return R(`若只需先排除选项，${nums.join('+')} 的和应先看什么？`,ans,op(ans,[`尾数为${(tail+1)%10}`,`尾数为${(tail+5)%10}`,'直接完整相加']),'多位数加总先看尾数。',`末位相加取个位，得到${tail}；选项尾数不同即可快速排除。`);
    })
  ];

  add(C('calculation_original_fidelity','计算方法｜精算与转化',['技巧'],exactSubs,'all'));
  add(C('line_method_original_fidelity','A÷B划线法｜误差规则',['技巧'],lineRuleSubs,'all'));
  add(Q('line_daily_training','驿站｜误差训练方式',['驿站'],()=>R(
    '课后怎样训练划线法的底层能力？',
    '随手看数字，练三秒内判断能变成谁、误差多少',
    ['随手看数字，练三秒内判断能变成谁、误差多少','每天完整直除100题','只背答案','完全不练口算'],
    '可以用车牌号、商品价格等随机数字训练。',
    '核心不是机械记步骤，而是训练数字敏感：这个数能看成几，误差约多少，能否和另一个误差抵消。'
  )));
  add(C('line_method_variable_upgrade','划线法训练｜误差扰动',['运用'],variableSubs,'all'));
})();

// ----- lessons/data_analysis_speed_08/33_process_data_reading_expansion.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const processSubs=[
    Q('material_five_questions','材料与五题结构',['基础'],()=>R(
      '资料分析通常怎样组织材料和题目？',
      '一篇材料配五道选择题',
      ['一篇材料配五道选择题','一段材料只配一道问答题','没有材料只给公式','每题都不看选项'],
      '这是进入资料分析的基本场景。',
      '资料分析先给文字、表格或图形材料，再围绕材料设置选择题；常见是一篇材料后附五道题。'
    )),
    Q('first_four_must_score','前四题优先拿分',['基础'],()=>R(
      '资料分析前四道题应怎样处理？',
      '前四题通常各考一个知识点，必须尽量拿分',
      ['前四题通常各考一个知识点，必须尽量拿分','前四题都靠猜','前四题都比第五题难','前四题不用读材料'],
      '前四题多是单公式、单概念或单计算。',
      '前四题的考点相对集中，是稳定得分来源；第五题常是综合判断，耗时结构不同。'
    )),
    Q('fifth_comprehensive_strategy','第五题综合策略',['技巧'],()=>R(
      '第五题常问“下列说法正确/错误的是”，为什么不能像前四题一样逐项硬做？',
      '它相当于把四个小判断合在一道题里，逐项硬算太耗时',
      ['它相当于把四个小判断合在一道题里，逐项硬算太耗时','因为第五题一定放弃','因为第五题没有选项','因为第五题只考单位'],
      '第五题往往要借助选项策略节省时间。',
      '综合题应结合选项差异、明显错误项、题干原数陷阱、最大最小方向等策略，不能机械把ABCD全部精算到底。'
    )),
    Q('read_question_first','先读问法',['基础'],()=>R(
      '资料分析作答第一步为什么要先读问法？',
      '先判断考什么概念或公式',
      ['先判断考什么概念或公式','先把材料全文精读','先算所有数字','先看哪个选项最长'],
      '作答时要先读最后的问法。',
      '问增长量、增长率、比重、平均数、拉动、贡献率，对应的数据和公式都不同；先读问法才能知道去材料里找什么。'
    )),
    Q('three_part_ability','三部分能力',['基础'],()=>R(
      '资料分析能力可以拆成哪三部分？',
      '概念公式、找数据、计算',
      ['概念公式、找数据、计算','背范文、写作文、听力','只背公式、只猜题、只看图','单位、颜色、标题'],
      '这是整课的总框架。',
      '先用概念公式识别题型，再到材料中定位数据，最后把数据代入并用合适算法选答案。'
    ))
  ];

  const dataReadingSubs=[
    Q('targeted_data_search','带着目标找数据',['技巧'],()=>R(
      '找数据时，为什么不能一上来把材料每句话都精读？',
      '应根据问法知道要找什么，再对无关段落略读',
      ['应根据问法知道要找什么，再对无关段落略读','所有段落都必须逐字精读','只看第一段','只看最大数字'],
      '找数要服务于题目目标。',
      '例如题目求小麦增长量，读到玉米段可快速略过；出现小麦相关行时再精读定位现期量和增长率。'
    )),
    Q('intensive_extensive_reading','精读略读边界',['技巧'],()=>R(
      '“精读略读”在找数据中分别对应什么？',
      '无关信息略读，目标信息精读',
      ['无关信息略读，目标信息精读','全文都略读','全文都精读','只读选项不读材料'],
      '找数据要有精略读意识。',
      '速度不是乱扫，而是在知道目标后对无关内容快速过滤，对命中对象、时间、单位、表头、增长率等细节仔细确认。'
    ))
  ];

  const randomSubs=[
    Q('random_question_to_data','问法定位随机',['技巧'],()=>{
      const list=[
        ['2019年小麦增长量','小麦的现期量和增长率'],
        ['第三产业占GDP比重','第三产业增加值和GDP'],
        ['人均薪酬增长率','总薪酬增长率和人数增长率'],
        ['A拉动B增长多少百分点','A的增长量和B的基期量'],
        ['A对B增长的贡献率','A的增长量和B的增长量']
      ];
      const it=pk(list);
      return R(`题目问“${it[0]}”，读完问法后应优先去材料找什么？`,it[1],op(it[1],list.map(x=>x[1])),'先由问法反推数据位置。',`“${it[0]}”对应的数据需求是：${it[1]}。`);
    }),
    Q('random_relevant_paragraph','精略读随机',['技巧'],()=>{
      const target=pk(['小麦','铁路客运量','第三产业','研究与试验发展经费']);
      const other=pk(['玉米','公路货运量','第一产业','普通高校招生人数']);
      return R(`题目要求${target}相关指标，材料第一段主要讲${other}，第二段出现${target}。应怎样读？`,'第一段略读，第二段精读',['第一段略读，第二段精读','第一段精读，第二段略读','两段都不读','只看选项'],'目标对象决定精读位置。',`${other}不是目标对象，可快速扫过；${target}命中题目对象，应仔细看时间、单位、现期量和增长率。`);
    }),
    Q('random_fifth_option_strategy','综合题随机策略',['运用'],()=>{
      const clue=pk(['选项含题干原数','选项问最大最小','选项差距很大','选项涉及比重变化']);
      const map={
        '选项含题干原数':'先判断是否为未加工数据陷阱',
        '选项问最大最小':'先确认方向，再挑候选',
        '选项差距很大':'先估算排除明显错误项',
        '选项涉及比重变化':'先看R部与R整判断升降'
      };
      return R(`第五题综合判断中，若发现“${clue}”，优先策略是什么？`,map[clue],op(map[clue],Object.values(map)),'第五题要用选项意识节省时间。',`${clue}时，优先${map[clue]}，不必一开始就四个选项全部精算。`);
    })
  ];

  add(C('process_original_fidelity','作答流程｜先问法再材料',['基础'],processSubs,'all'));
  add(C('data_search_original_fidelity','找数据｜精读略读',['技巧'],dataReadingSubs,'all'));
  add(Q('data_search_training','驿站｜找数据训练方式',['驿站'],()=>R(
    '没时间完整刷题时，也可以怎样训练找数据能力？',
    '打开材料不动笔，练习快速找到题目需要的数据',
    ['打开材料不动笔，练习快速找到题目需要的数据','只背答案','完全不看材料','只练数量关系'],
    '找数据靠熟能生巧。',
    '即使不完整做题，也可以每天看材料和题问，练“我要找哪个对象、哪个年份、哪个指标”。'
  )));
  add(C('process_variable_upgrade','作答流程｜定位训练',['运用'],randomSubs,'all'));
})();

// ----- lessons/data_analysis_speed_08/34_fraction_transform_deepening.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const memorySubs=[
    Q('fraction_memory_limit','分数只背到1/11',['基础'],()=>R(
      '分数转化常用表背到哪里基本够用？',
      '背到1/11',
      ['背到1/11','必须背到1/19','只背1/2','完全不背'],
      '不需要背一大张表。',
      '常用分数转化重在熟练和迁移，背到1/11即可覆盖多数入口，后面靠三不看、1/7循环和误差处理扩展。'
    )),
    Q('three_ignore_items','三不看原则内容',['技巧'],()=>R(
      '分数转化中的“三不看原则”具体不看什么？',
      '零、小数点、百分号',
      ['零、小数点、百分号','年份、单位、标题','分子、分母、选项','最大、最小、平均'],
      '这是分数转化的核心技巧。',
      '在乘除转化时，零、小数点、百分号常只是数量级或表达形式；先看数字形状，再按需要补回数量级。'
    )),
    Q('nine_eleven_reciprocal','9和11倒数关系',['技巧'],()=>R(
      '按三不看原则，1/9≈0.111、1/11≈0.09 可以形成什么快速关系？',
      '9和11可看作倒数转换入口',
      ['9和11可看作倒数转换入口','9和11完全相等','9只能做加法','11只能做减法'],
      '小数点和零先不看。',
      '1/9看成111，1/11看成09；在乘除中可快速把除以9、除以11转为乘相应近似数。'
    )),
    Q('seven_cycle_base','1/7必须背142857',['基础'],()=>R(
      '为什么要把1/7=0.142857背成完整六位循环？',
      '因为后面要推出1/7到6/7',
      ['因为后面要推出1/7到6/7','因为只能考1/7','因为142857没有用','因为所有分数都六位'],
      '不要只记143。',
      '考场近似可用143，但训练时要背142857，才能用循环位移快速识别2/7到6/7。'
    )),
    Q('fraction_fail_to_line','匹配不出就转划线',['技巧'],()=>R(
      '当一个A÷B题匹配不出好用分数转化时，下一步转向什么方法？',
      '划线法',
      ['划线法','继续硬凑分数','直接放弃','只看单位'],
      '分数转化不是万能钥匙。',
      '若内部数字不像常见分数，或硬凑导致误差过大、式子更复杂，就改用A÷B划线法主动改数。'
    ))
  ];

  const sevenRoute=C('seven_cycle_route','1/7循环训练',['技巧'],[
    Q('seven_cycle_start_rule','开头规律',['技巧'],()=>R(
      '1/7到6/7的开头数如何快速判断？',
      '1、2开头看分子；3、4开头为分子+1；5、6开头为分子+2',
      ['1、2开头看分子；3、4开头为分子+1；5、6开头为分子+2','全部都以分子开头','全部都以分子+1开头','只能直除'],
      '六个七分数可以分成三组。',
      '1/7、2/7分别以1、2开头；3/7、4/7以4、5开头；5/7、6/7以7、8开头。'
    )),
    Q('seven_cycle_random','循环位移随机',['技巧'],()=>{
      const list=[
        ['1/7','142857'],['2/7','285714'],['3/7','428571'],
        ['4/7','571428'],['5/7','714285'],['6/7','857142']
      ];
      const it=pk(list);
      return R(`${it[0]} 的六位循环应匹配哪一组？`,it[1],op(it[1],list.map(x=>x[1])),'都来自142857，只是开头位置不同。',`${it[0]}=${it[1]}循环。`);
    }),
    Q('seven_reverse_random','反向识别随机',['运用'],()=>{
      const list=[
        ['142','1/7'],['285','2/7'],['428','3/7'],
        ['571','4/7'],['714','5/7'],['857','6/7']
      ];
      const it=pk(list);
      return R(`分母中出现约${it[0]}的形状，优先联想到哪个七分数？`,it[1],op(it[1],list.map(x=>x[1])),'考试常是从数字反推分数。',`${it[0]}是${it[1]}循环小数的开头，可优先尝试分数转化。`);
    })
  ],'sequence');

  const packagingRoute=C('fraction_packaging_route','包装型分数转化',['运用'],[
    Q('decimal_point_split','小数点拆包装',['技巧'],()=>R(
      '2167 这类数中，若167像1/6，怎样用三不看原则拆开？',
      '点成2.167，看作2+0.167',
      ['点成2.167，看作2+0.167','直接当成1/6','直接删除2','只能直除'],
      '小数点可以帮助把外层整数和内部熟悉分数分开。',
      '2167可先看成2.167，其中0.167≈1/6，所以整体近似2+1/6。'
    )),
    Q('packaged_fraction_random','包装识别随机',['运用'],()=>{
      const list=[
        ['1713','1+5/7','12/7'],
        ['2167','2+1/6','13/6'],
        ['2135','2+1/7','15/7'],
        ['0875','7/8','7/8']
      ];
      const it=pk(list);
      return R(`分母形如${it[0]}，用三不看/内部识别，优先可看成什么？`,it[1],op(it[1],list.map(x=>x[1])),'先把熟悉的小数块拆出来。',`${it[0]}可近似处理为${it[1]}，必要时再化成${it[2]}倒上去乘。`);
    }),
    Q('fraction_error_boundary','分数硬凑边界',['技巧'],()=>R(
      '为什么不能把差得较远的数字硬凑成某个七分数？',
      '误差可能超过选项允许范围',
      ['误差可能超过选项允许范围','因为七分数不能用','因为小数点不能动','因为只能背1/3'],
      '硬凑分数可能把简单题复杂化甚至做错。',
      '分数转化要和误差意识配合：第三位小差通常可忽略，差到百分级甚至更大时，要改用划线法或其他算法。'
    ))
  ],'sequence');

  add(C('fraction_memory_card','分数转化｜记忆边界',['技巧'],memorySubs,'all'));
  add(C('fraction_variable_card','分数转化｜随机迁移强化',['运用'],[sevenRoute,packagingRoute],'all'));
})();

