// ----- lessons/data_analysis_speed_09/01_station_terms.js -----
(function(){
  const {R,Q,add,op,pk}=EX;
  add(Q('station_terms','驿站｜语音术语修正',['驿站'],()=>{
    const pairs=[['限期','现期'],['机器比重','基期比重'],['计息比重','基期比重'],['极其比重','基期比重'],['支出','直除'],['守位法','首位法']];
    const [raw,ans]=pk(pairs);
    return R(
      `语音转文字里出现“${raw}”，复原到资料分析术语应是什么？`,
      ans,
      op(ans,['现期比重','基期比重','直除','首位法','增长量']),
      '先判断它在语境中指时间、除法还是选项首位。',
      `“${raw}”在本课语境中应还原为“${ans}”。这些术语只作识别，不增加新题型。`
    );
  }));
})();

// ----- lessons/data_analysis_speed_09/02_overview_core.js -----
(function(){
  const {R,Q,C,add,op,pk,n}=EX;

  const q1=Q('core_time','时间先行',['基础'],()=>{
    const mat=n(2008,2020);
    const ask=mat-1;
    const ans='基期';
    return R(
      `材料给的是 ${mat} 年，题目问 ${ask} 年的指标。第一判断应是？`,
      ans,
      op(ans,['现期','基期','隔年','年均']),
      '先读问法里的时间点，再与材料时间比较。',
      `${ask} 年早于材料的 ${mat} 年，所以问的是过去值，即基期。`
    );
  });

  const q2=Q('core_object','对象后置',['基础'],()=>{
    const ans='先问求谁，再列式';
    return R(
      '资料分析读题时，时间判断之后，最节能的下一步是什么？',
      ans,
      op(ans,['直接计算所有数据','先问求谁，再列式','只看最大数字','跳过材料']),
      '时间解决“现期/基期”，对象解决“分子分母是谁”。',
      '先明确求谁的值、谁的比重、谁的平均数，再去材料中找对应量。'
    );
  });

  const q3=Q('core_structure','结构识别',['基础'],()=>{
    const items=[
      ['平均每家接待人数','总量÷份数'],
      ['某项占总额比例','部分÷整体'],
      ['贸易顺差','出口-进口'],
      ['同比增长率','增长量÷基期量'],
      ['增长量','现期量-基期量']
    ];
    const [stem,ans]=pk(items);
    return R(
      `题干出现“${stem}”，优先识别为哪种结构？`,
      ans,
      op(ans,items.map(x=>x[1])),
      '不要被材料数字牵着走，先把问法翻译成数学结构。',
      `“${stem}”对应结构是 ${ans}。`
    );
  });

  const q4=Q('core_options','选项定精度',['运用'],()=>{
    const ans='先看选项差距，再决定估算或精算';
    return R(
      '同样一道资料分析题，为什么有人能不完整计算也能选出答案？',
      ans,
      op(ans,['永远只直除','先看选项差距，再决定估算或精算','所有题都用拆分法','只背固定答案']),
      '选项决定你需要精确到首位、百分位，还是千分位。',
      '选项差距大时估到首位即可；选项极近时才需要拆分、直除或精算。'
    );
  });

  add(C('core_card','做题总纲｜时间对象题型',['基础'],[q1,q2,q3,q4],'sequence'));
})();

// ----- lessons/data_analysis_speed_09/03_section_avg_ratio.js -----
(function(){ EX.sec('平均数与比重'); })();

// ----- lessons/data_analysis_speed_09/04_average.js -----
(function(){
  const {R,Q,C,add,op,n,r1}=EX;

  const q1=Q('avg_basic','普通平均数',['基础'],()=>{
    const total=n(3200,9600), cnt=n(20,80);
    const ans='总量÷份数';
    return R(
      `某类机构接待 ${total} 万人次，共 ${cnt} 家。平均每家接待人数的基本列式是什么？`,
      ans,
      op(ans,['份数÷总量','总量÷份数','部分÷整体','增长量÷基期']),
      '“平均每家”就是把总量分摊到家数上。',
      `平均数本质是总量除以份数，即 ${total}÷${cnt}。`
    );
  });

  const q2=Q('avg_share_cancel','占比约分',['技巧'],()=>{
    const a=n(55,88), b=100-a, c=n(30,55), d=100-c;
    const ans=`${a}/${b} × ${d}/${c}`;
    return R(
      `甲接待量占 ${a}%，机构数占 ${c}%；乙为剩余部分。甲平均数是乙平均数的多少倍，应先化成哪种骨架？`,
      ans,
      op(ans,[`${a}/${c} × ${b}/${d}`,`${c}/${d} × ${b}/${a}`,`${a}/${b} × ${c}/${d}`]),
      '平均数倍数 = 甲总量/甲份数 ÷ 乙总量/乙份数。公共总量和公共机构数可约掉。',
      `乙接待量占 ${b}%，乙机构数占 ${d}%。所以是 (${a}/${c})÷(${b}/${d})=${a}/${b}×${d}/${c}。`
    );
  });

  const q3=Q('avg_growth_formula','增长率公式',['基础'],()=>{
    const rt=n(12,28), rc=n(2,11);
    const ans=`(${rt}%-${rc}%)/(1+${rc}%)`;
    return R(
      `总成交额增长 ${rt}%，合同项数增长 ${rc}%。平均每项成交额增长率应列为？`,
      ans,
      op(ans,[`(${rt}%-${rc}%)/(1+${rt}%)`,`(${rc}%-${rt}%)/(1+${rc}%)`,`${rt}%-${rc}%`]),
      '平均数=总量÷份数，增长率用“总减份，除以1+份”。',
      `平均数增长率 = (r总-r份)/(1+r份)，所以列式为 ${ans}。`
    );
  });

  const q4=Q('avg_growth_trend','趋势判断',['运用'],()=>{
    const rt=n(5,18), rc=rt+n(1,8);
    const ans='下降';
    return R(
      `总量增长 ${rt}%，份数增长 ${rc}%。平均数变化方向是？`,
      ans,
      op(ans,['上升','下降','不变','无法判断']),
      '平均数增长率看 r总-r份 的符号。',
      `${rt}%<${rc}%，总量追不上份数，平均数下降。`
    );
  });

  add(C('average_card','平均数｜公式与倍数',['基础'],[q1,q2,q3,q4],'all'));
})();

// ----- lessons/data_analysis_speed_09/05_ratio.js -----
(function(){
  const {R,Q,C,add,op,n,r1}=EX;

  const q1=Q('ratio_current','现期比重',['基础'],()=>{
    const part=n(1200,4800), whole=part+n(800,5200);
    const ans='部分÷整体';
    return R(
      `现期部分量为 ${part}，整体量为 ${whole}。现期比重的基本结构是？`,
      ans,
      op(ans,['整体÷部分','部分÷整体','增长量÷现期','现期÷基期']),
      '“占”字前面通常是部分，后面是整体。',
      `现期比重=${part}÷${whole}，即部分÷整体。`
    );
  });

  const q2=Q('ratio_base_formula','基期比重公式',['技巧'],()=>{
    const rp=n(10,25), rw=n(4,15);
    const ans=`现期比重×(1+${rw}%)/(1+${rp}%)`;
    return R(
      `部分增长率 ${rp}%，整体增长率 ${rw}%。基期比重应如何由现期比重修正？`,
      ans,
      op(ans,[`现期比重×(1+${rp}%)/(1+${rw}%)`,`现期比重×(${rp}%-${rw}%)`,`现期比重÷(1+${rw}%)`]),
      '基期比重=现期比重×整体增长因子÷部分增长因子。记作交叉对应。',
      `基期比重=现期比重×(1+r整体)/(1+r部分)，所以为 ${ans}。`
    );
  });

  const q3=Q('ratio_size','基期现期大小',['运用'],()=>{
    const rw=n(6,12), rp=rw+n(2,10);
    const ans='现期比重大于基期比重';
    return R(
      `部分增长率 ${rp}%，整体增长率 ${rw}%。现期比重与基期比重谁大？`,
      ans,
      op(ans,['现期比重大于基期比重','现期比重小于基期比重','二者一定相等','无法判断']),
      '部分涨得比整体快，份额会提高。',
      `${rp}%>${rw}%，部分增长更快，所以现期比重更大，基期比重更小。`
    );
  });

  const q4=Q('ratio_pp','百分点',['基础'],()=>{
    const a=n(40,60), b=a+n(2,8);
    const ans=`增加 ${b-a} 个百分点`;
    return R(
      `某比重由 ${a}% 变为 ${b}%。应表述为？`,
      ans,
      op(ans,[`增加 ${b-a}%`,`增加 ${r1((b-a)/a*100)}%`,`增加 ${b} 个百分点`]),
      '两个百分数直接相减，单位是百分点。',
      `${b}%-${a}%=${b-a} 个百分点，不是“增长 ${b-a}%”。`
    );
  });

  const q5=Q('ratio_trap','现期陷阱',['运用'],()=>{
    const ans='现期比重陷阱';
    return R(
      '题目问基期比重，选项里常出现“直接用现期部分÷现期整体”的结果。这个选项通常是什么？',
      ans,
      op(ans,['现期比重陷阱','平均数陷阱','隔年增长陷阱','顺差陷阱']),
      '求过去，却直接用现在的数据，通常就是干扰项。',
      '基期比重必须乘增长率修正项；只算现期比重常是出题人设置的陷阱。'
    );
  });


  const q6=Q('ratio_correction_gap','修正项定位',['技巧'],()=>{
    const rw=n(8,14), rp=rw+n(1,4);
    const gap=rp-rw;
    const ans='看增长因子修正项与现期陷阱的距离';
    return R(
      `求基期比重时，部分增长 ${rp}%，整体增长 ${rw}%，选项里有一个现期比重陷阱。近选项判断应重点看什么？`,
      ans,
      op(ans,['看增长因子修正项与现期陷阱的距离','只看材料第一句','只看部分量大小','直接选最大的比重']),
      '基期比重=现期比重×(1+r整体)/(1+r部分)，答案与现期陷阱的差距来自修正项。',
      `这里部分增速比整体高约 ${gap} 个百分点，现期比重通常比基期比重大一点；近选项可用这个修正差距定位答案。`
    );
  });


  add(C('ratio_card','比重｜现期基期变化',['基础'],[q1,q2,q3,q4,q5,q6],'all'));
})();

// ----- lessons/data_analysis_speed_09/06_section_fraction_mix.js -----
(function(){ EX.sec('分数加减与混合'); })();

// ----- lessons/data_analysis_speed_09/07_fraction.js -----
(function(){
  const {R,Q,C,add,op,n,r1}=EX;

  const q1=Q('frac_common_den','普通分母通分',['技巧'],()=>{
    const den1=n(720,860), up=n(20,45), den2=den1-up;
    const num2=n(220,330);
    const pct=r1(up/den2*100);
    const ans=`把 ${den2} 调到 ${den1}，分子同步上升约 ${pct}%`;
    return R(
      `遇到 a/${den1} - ${num2}/${den2}，两个分母接近。优先怎么处理第二个分数？`,
      ans,
      op(ans,[`直接把两个分母都看成 1000`,`把 ${den2} 调到 ${den1}，分子不变`,`把 ${den1} 调到 ${den2}，只改分母`]),
      '通分时分母怎么变，分子也要同步按比例变。',
      `${den2} 到 ${den1} 上升约 ${pct}%，所以第二个分子的等价值也要同步上升约 ${pct}%。`
    );
  });

  const q2=Q('frac_growth_den','1+r分母',['技巧'],()=>{
    const ans='优先转混合原理';
    return R(
      '两个分数做和或做差，分母都是 1+r 形式，且增长率差距不大。优先用什么思路？',
      ans,
      op(ans,['优先转混合原理','一律拆成二分之一','只看分母大小','直接放弃']),
      '1+r 分母对应“由现期回基期”，可看成整体和部分的混合增长。',
      '当增长率同号且差距不大时，混合原理能快速估出等价增长率，再排选项。'
    );
  });

  const q3=Q('frac_error_amplify','误差放大',['基础'],()=>{
    const ans='加减法会放大误差';
    return R(
      '为什么两个分数做差时，单个分数估得很准，最终答案仍可能偏很多？',
      ans,
      op(ans,['加减法会放大误差','乘法一定无误差','分母越大越不准','百分号不能估算']),
      '差值可能很小，局部误差相减后占整体比例变大。',
      '分数加减尤其是做差，会把原来千分级的局部误差放大成几个百分点的整体误差。'
    );
  });

  const q4=Q('frac_split_when','拆分法场景',['技巧'],()=>{
    const ans='分数加减且选项很近';
    return R(
      '拆分法最应该留给哪类资料分析计算？',
      ans,
      op(ans,['单个 A/B 且选项很远','分数加减且选项很近','所有比重题','所有混合题']),
      '单个 A/B 往往划线更快；加减法才更容易放大误差。',
      '当 A/B±C/D 且选项差距在 1%—5%以内时，拆分或直除更稳。'
    );
  });

  const q5=Q('frac_single_ab','单个分数',['运用'],()=>{
    const ans='划线或首位估算更节能';
    return R(
      '单独一个 A/B，且选项差距明显时，课程更推荐什么？',
      ans,
      op(ans,['划线或首位估算更节能','必须拆分到四位','必须通分','必须用混合原理']),
      '拆分法不是为了炫技，只有在必要时才用。',
      '单个分数没有加减放大误差，通常用划线、首位或直除即可。'
    );
  });

  add(C('fraction_card','分数加减｜通分拆分边界',['技巧'],[q1,q2,q3,q4,q5],'all'));
})();

// ----- lessons/data_analysis_speed_09/07a_denominator_strategy.js -----
(function(){
  const {R,Q,C,add,op,n,pk,r1}=EX;

  const q1=Q('den_to_one_growth','普通分母转1开头',['技巧'],()=>{
    const d=n(720,890), k=n(6,8);
    const scaled=r1(d/(k*100));
    const ans='可以转，但通常不是首选';
    return R(
      `普通分母 ${d} 若分子分母同除以 ${k*100}，分母可变成约 ${scaled}，看成 1 附近的增长因子。这个思路应如何定位？`,
      ans,
      op(ans,['可以转，但通常不是首选','必须所有题都这样转','这种转化一定错误','只改分母不用改分子']),
      '题面说普通分母也能转成混合原理，但步骤更绕。',
      `把普通分母变成 1 开头，可以借混合原理理解；但要同步处理分子分母，且操作偏麻烦，所以实战常优先通分或拆分。`
    );
  });

  const q2=Q('den_scale_close','先放缩接近',['技巧'],()=>{
    const small=n(210,260), big=small*2+n(8,24);
    const ans=`先把 ${small} 放大 2 倍接近 ${big}`;
    return R(
      `两个分数分母约为 ${small} 和 ${big}，直接通分不顺。第一步更节能的是？`,
      ans,
      op(ans,[`直接把两者都看成 400`,`只把 ${big} 删掉一位`,`分母不变直接分子相减`]),
      '分母差距较大但有倍数关系时，先放缩到接近，再通分。',
      `${small}×2=${small*2}，已经接近 ${big}。同步把对应分子也乘 2 后，两个分母就适合再做通分比较。`
    );
  });

  const q3=Q('den_no_double_rough','不要双粗改',['运用'],()=>{
    const ans='不要把两个分母都粗暴改成同一个整百数';
    return R(
      '两个分数做差时，为什么不建议直接把 421 和 452 都粗暴看成 400？',
      ans,
      op(ans,['不要把两个分母都粗暴改成同一个整百数','这样一定会完全精确','因为400不能做分母','因为分数做差不能估算']),
      '两个分数做差会放大误差，粗暴双改更危险。',
      '更稳的是先让一个分母变成另一个分母，或先倍数放缩接近；同时分子也按同一比例变化。'
    );
  });

  const q4=Q('den_direction_good_factor','通分方向看好算',['技巧'],()=>{
    const ans='优先改向更好算、有好因子的分母';
    return R(
      '两个分母都可以互相调整时，题面为什么倾向把 421 调到 452，而不是反过来？',
      ans,
      op(ans,['优先改向更好算、有好因子的分母','只能把小数改成大数','只能把大数改成小数','方向完全随机不用考虑']),
      '452 可进一步看作 45 附近，45 有 5×9 的好算骨架。',
      '通分方向不只是升或降的个人习惯，还要看目标数是否方便后续心算，例如是否接近 45、125、11 等好数骨架。'
    );
  });

  const q5=Q('den_sync_num','放缩必须同步分子',['基础'],()=>{
    const m=n(2,3), num=n(260,360), den=n(180,260);
    const ans=`分子也乘 ${m}`;
    return R(
      `把分数 ${num}/${den} 的分母乘 ${m}，准备与另一个分母接近。为了等价，分子应怎样？`,
      ans,
      op(ans,[`分子也乘 ${m}`,'分子保持不变',`分子除以 ${m}`,'分子加上分母']),
      '分数等价变形，分子分母同乘或同除。',
      `分母乘 ${m} 后，分子也必须乘 ${m}，否则数值被改坏。`
    );
  });

  add(C('denominator_strategy_card','分母处理｜转化放缩通分',['技巧'],[q1,q2,q3,q4,q5],'all'));
})();

// ----- lessons/data_analysis_speed_09/07b_split_integer_cancel.js -----
(function(){
  const {R,Q,C,add}=EX;

  const q1=Q('split_integer_cancel_scene','整数抵消场景',['技巧'],()=>{
    return R(
      '当两个分数做差，且两个分数都略大于 1，例如 564/421 - 596/452，拆分法最节能的一步是什么？',
      '两个分数都先拆出 1，让 1-1 抵消',
      ['两个分数都先拆出 1，让 1-1 抵消','把两个分母都看成400','只拆较大的分数','把减号改成加号'],
      '都大于1时，整数部分相同，可先消掉。',
      '564/421=1+143/421，596/452=1+144/452，做差时 1-1 抵消，只剩 143/421-144/452，计算量更小。'
    );
  });

  const q2=Q('split_integer_cancel_result','余数表达式',['技巧'],()=>{
    return R(
      '把 564/421 - 596/452 拆出整数后，正确的余数表达式是哪一个？',
      '143/421 - 144/452',
      ['143/421 - 144/452','421/143 - 452/144','564/143 - 596/144','1/421 - 1/452'],
      '分子减分母得到余数。',
      '564=421+143，596=452+144，所以两个分数分别是 1+143/421、1+144/452。'
    );
  });

  const q3=Q('split_integer_cancel_boundary','整数抵消边界',['基础'],()=>{
    return R(
      '整数抵消拆分适合什么时候使用？',
      '两个分数有相同或接近的整数部分时',
      ['两个分数有相同或接近的整数部分时','任意两个分数都必须用','只要分母含百分号就用','选项首位不同也必须用'],
      '拆分是为了减少差值计算量，不是固定仪式。',
      '如果两个分数都在 1 点几，拆出 1 很划算；若单个 A/B 选项差距大，仍然首位或划线更节能。'
    );
  });

  add(C('split_integer_cancel_card','拆分法｜整数抵消',['技巧'],[q1,q2,q3],'all'));
})();

// ----- lessons/data_analysis_speed_09/08_mixing.js -----
(function(){
  const {R,Q,C,add,op,n,r1}=EX;

  const q1=Q('mix_between','夹逼',['基础'],()=>{
    const a=n(12,18), b=a+n(4,9), mix=n(a+1,b-1);
    const ans=`在 ${a}% 与 ${b}% 之间`;
    return R(
      `两个部分增长率分别为 ${a}% 和 ${b}%，整体混合增长率应在哪里？`,
      ans,
      op(ans,[`大于 ${b}%`,`小于 ${a}%`,`在 ${a}% 与 ${b}% 之间`]),
      '整体由两个部分组成，混合值不会跑到两端之外。',
      `混合增长率一定夹在两个部分增长率之间，即 ${a}% 到 ${b}% 之间。`
    );
  });

  const q2=Q('mix_lean','偏向量大',['运用'],()=>{
    const smallRate=n(8,14), bigRate=smallRate+n(5,10);
    const ans=`更靠近 ${smallRate}%`;
    return R(
      `甲增长 ${smallRate}% 且量更大，乙增长 ${bigRate}% 且量更小。混合增长率更靠近谁？`,
      ans,
      op(ans,[`更靠近 ${smallRate}%`,`更靠近 ${bigRate}%`,`刚好在正中间`,`无法判断`]),
      '混合值偏向量大的那一边。',
      `甲的量更大，所以整体增长率更靠近甲的 ${smallRate}%。`
    );
  });

  const q3=Q('mix_three','三者混合',['技巧'],()=>{
    const ans='先混量接近、比例好算的两项';
    return R(
      '三者混合增长率题中，最节能的第一步通常是什么？',
      ans,
      op(ans,['先混量接近、比例好算的两项','三个增长率直接平均','先找最大增长率','只看最小量']),
      '三者混合可以降维成两次两者混合。',
      '先把容易混的两项合成一个临时整体，再与第三项混合。'
    );
  });

  const q4=Q('mix_boundary','混合边界',['运用'],()=>{
    const ans='极端一正一负时不要硬用近似混合';
    return R(
      '如果分数做差转混合后，等价增长率可能是 -100% 以上，而另一个增长率是正的十几二十。此时应怎么处理？',
      ans,
      op(ans,['极端一正一负时不要硬用近似混合','继续无脑十字交叉','直接取两个增长率平均','答案一定为负']),
      '课程中的顺差题就是这个边界：混合近似会失真。',
      '增长率一正一负且负值极端时，改用划线估算、直除或拆分，别硬套混合。'
    );
  });

  add(C('mix_card','混合原理｜夹逼偏向',['技巧'],[q1,q2,q3,q4],'all'));
})();

// ----- lessons/data_analysis_speed_09/08a_mixing_identity.js -----
(function(){
  const {R,Q,C,add,op,n,pk}=EX;

  const q1=Q('mix_identity_cumulative','累计就是混合',['基础'],()=>{
    const end=n(3,12);
    const month=n(2,end);
    const ans=`1-${end}月累计是混合，${month}月是部分`;
    return R(
      `材料给“1-${end}月累计增长率”和“${month}月当月增长率”。谁是混合值，谁是部分值？`,
      ans,
      op(ans,[`${month}月是混合，1-${end}月累计是部分`,'二者都是混合值','二者都是部分值']),
      '累计包含多个期间，当月只是其中一个部分。',
      `1-${end}月累计由若干月份合成，所以累计增长率是混合值；${month}月当月是其中一个部分。`
    );
  });

  const q2=Q('mix_unknown_other_side','求另一部分位置',['基础'],()=>{
    const rMix=n(12,19), rKnown=rMix+n(2,7);
    const ans=`未知部分增长率应小于 ${rMix}%`;
    return R(
      `整体混合增长率为 ${rMix}%，已知一个部分为 ${rKnown}%。求另一个部分时，未知值大致在哪一侧？`,
      ans,
      op(ans,[`未知部分增长率应大于 ${rKnown}%`,`未知部分增长率应小于 ${rMix}%`,`未知部分一定等于 ${rMix}%`]),
      '混合值夹在两个部分之间。已知部分在混合值上方，另一部分就应在混合值下方。',
      `${rMix}% 是混合值，${rKnown}% 是一个部分且高于混合值，所以另一个部分必须低于 ${rMix}%。`
    );
  });

  const q3=Q('mix_distance_lean','距离偏向',['技巧'],()=>{
    const ans='混合值到量大部分的距离更小';
    return R(
      '混合值“偏向量大的部分”，落实到选项距离上是什么意思？',
      ans,
      op(ans,['混合值到量大部分的距离更小','混合值一定等于量大部分','量大部分一定增长率更高','距离与量无关']),
      '偏向不是直接选量大的增长率，而是看混合值离哪边更近。',
      '量大的部分权重更大，整体混合值被拉向它，所以混合值到量大部分的距离更小。'
    );
  });

  const q4=Q('mix_need_estimate_ratio','两原理不够再估量比',['运用'],()=>{
    const ans='再估两部分量之比';
    return R(
      '如果混合第一原理“夹逼”和第二原理“偏向量大者”仍不能唯一排除选项，下一步应做什么？',
      ans,
      op(ans,['再估两部分量之比','直接平均两个增长率','直接选最大项','放弃混合原理']),
      '讲法中先用夹逼和偏向；还不够，再看量比。',
      '量比决定混合值离两端的距离比例。先定范围和方向，仍不够时再估量比，不必一上来精算。'
    );
  });

  add(C('mix_identity_card','混合识别｜整体与部分',['基础'],[q1,q2,q3,q4],'all'));
})();

