// ----- lessons/data_analysis_speed_10_EX/04_monotone_training.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;

  const under=C('mono_train_under','三倍以内',['技巧'],[
    Q('mono_diff_level1','一级差',['技巧'],()=>{
      const a=n(3,12), d=n(2,8); const arr=[a,a+d,a+2*d,a+3*d]; const ans=String(a+4*d);
      return R(
        `数列 ${arr.join('，')}，下一项是多少？`, ans,
        op(ans,[String(a+5*d),String(a+4*d+1),String(a+3*d)]),
        '单调且倍数不大，先做差。',
        `相邻差都是 ${d}，所以下一项是 ${arr[3]}+${d}=${ans}。`
      );
    }),
    Q('mono_diff_level2','二级差',['技巧'],()=>{
      const a=n(2,8), d1=n(2,5), inc=n(2,4);
      const x1=a, x2=x1+d1, x3=x2+d1+inc, x4=x3+d1+2*inc; const next=x4+d1+3*inc;
      return R(
        `数列 ${x1}，${x2}，${x3}，${x4}，下一项是多少？`, String(next),
        op(next,[next+inc,next-inc,x4+d1]),
        '一级差再看差。',
        `一级差为 ${d1}，${d1+inc}，${d1+2*inc}，下一差为 ${d1+3*inc}，所以下一项 ${next}。`
      );
    })
  ],'all');

  const over=C('mono_train_over','三倍以上',['技巧'],[
    Q('mono_multi_seq','倍数序列',['技巧'],()=>{
      const a=n(1,4), m=n(3,5); const arr=[a,a*m,a*m*m]; const ans=String(a*m*m*m);
      return R(
        `数列 ${arr.join('，')}，下一项是多少？`, ans,
        op(ans,[String(a*m*m+a),String(a*m*m*(m+1)),String(a*m)]),
        '相邻倍数都较大，先看倍数。',
        `每次乘 ${m}，所以下一项是 ${arr[2]}×${m}=${ans}。`
      );
    }),
    Q('mono_power_seq','平方识别',['技巧'],()=>{
      const k=n(3,7); const arr=[(k-2)**2,(k-1)**2,k**2]; const ans=String((k+1)**2);
      return R(
        `数列 ${arr.join('，')}，下一项最可能是多少？`, ans,
        op(ans,[String((k+1)**2+1),String((k+2)**2),String(k**2+1)]),
        '接近平方数时看次方。',
        `这是连续平方数：${k-2}²，${k-1}²，${k}²，下一项为 ${k+1}²=${ans}。`
      );
    })
  ],'all');

  const edge=C('mono_train_edge','边界判断',['运用'],[
    Q('mono_edge_one','个别超三倍',['运用'],()=>R(
      '一个单调数列大多相邻倍数在三倍内，只有一组约 3.1 倍。优先路线是什么？','仍先和差分析',
      ['仍先和差分析','直接次方','直接奇偶猜','不能做'],
      '个别略超可忽略。',
      '口诀是经验入口，整体仍像三倍以内，就先做和差。'
    )),
    Q('mono_edge_two','多处超三倍',['运用'],()=>R(
      '一个单调数列中连续多组相邻倍数都超过三倍，应切换到什么路线？','倍数或次方',
      ['倍数或次方','只做一级差','只做和','看单位'],
      '多处超三倍不再是个别。',
      '此时优先怀疑乘法放大或幂次结构。'
    ))
  ],'all');

  add(C('monotone_training','单调变量训练｜做差与倍数切换',['技巧'],[under,over,edge],'all'));
})();

// ----- lessons/data_analysis_speed_10_EX/04a_monotone_diff_extra.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;

  const direct=[
    Q('mono_sum_diff_meaning','和差分析含义',['基础'],()=>R(
      '课程说“和差分析”时，最常用、最先试的一步是什么？','做差',
      ['做差','画地图','看单位','查表头'],
      '和差里做差出现更频繁。',
      '单调且三倍以内，优先做差；做和可作为备选，但不要一开始乱试很多路。'
    )),
    Q('mono_sum_later_boundary','做和顺序边界',['技巧'],()=>R(
      '做差后能构造网络时，还需要马上改去做和吗？','不需要',
      ['不需要','必须马上做和','必须做到四级差','直接奇偶猜'],
      '按节能顺序来。',
      '课程强调：第一步通常做差；做差后若构造网络能出答案，就不必再做和。构造不出时，做和可以作为备选。'
    )),
    Q('mono_diff_not_forever','不要无限做差',['基础'],()=>R(
      '一级差、二级差都不顺时，是否应该一路做到四级、五级差？','不应该',
      ['不应该','应该','必须做到十级','只要选项多就继续'],
      '差到后面数据太少，容易硬造。',
      '课程边界是最多三级差；无规律就转构造网络。'
    ))
  ];

  const chain=C('mono_diff_chain_training','差值倍数链',['技巧'],[
    Q('mono_diff_multiplier_chain','一级差倍数链',['技巧'],()=>{
      const a=n(3,9), d=n(2,5); const diffs=[d,d*2,d*3,d*4];
      const arr=[a]; for(const x of diffs){arr.push(arr[arr.length-1]+x);} const next=arr[arr.length-1]+d*5;
      return R(
        `数列 ${arr.join('，')}，若一级差为 ${diffs.join('，')}，下一项是多少？`, String(next),
        op(next,[next+d,next-d,arr[arr.length-1]*2]),
        '先看一级差本身。',
        `一级差是 ${d}×1，${d}×2，${d}×3，${d}×4，下一差为 ${d}×5=${d*5}，所以下一项是 ${next}。`
      );
    }),
    Q('mono_diff_power_after','差值转次方',['技巧'],()=>{
      const a=n(1,5), k=n(2,4); const diffs=[1,4,9].map(x=>x*k); const arr=[a]; for(const x of diffs) arr.push(arr[arr.length-1]+x); const next=arr[3]+16*k;
      return R(
        `数列 ${arr.join('，')}，一级差为 ${diffs.join('，')}，下一项最可能是多少？`, String(next),
        op(next,[next+k,next-3*k,arr[3]+25*k]),
        '差值本身可能是平方结构。',
        `差值为 ${k}×1²，${k}×2²，${k}×3²，下一差为 ${k}×4²=${16*k}，下一项 ${next}。`
      );
    })
  ],'sequence');

  add(C('monotone_diff_extra','单调数列补全｜和差与差值链',['技巧'],[...direct,chain],'all'));
})();

