// ----- lessons/data_analysis_speed_10_EX/09a_fraction_zigzag_training.js -----
(function(){
  const {n,op,R,Q,C,add}=EX;

  const frac=C('frac_variable_training','分数数列变量训练',['技巧'],[
    Q('frac_num_den_arith_var','分子分母分别看',['技巧'],()=>{
      const a=n(1,4), d=n(1,3), b=n(5,10), e=n(2,4);
      const f1=`${a}/${b}`, f2=`${a+d}/${b+e}`, f3=`${a+2*d}/${b+2*e}`; const ans=`${a+3*d}/${b+3*e}`;
      return R(
        `分数数列 ${f1}，${f2}，${f3}，下一项最可能是？`, ans,
        op(ans,[`${a+3*d}/${b+2*e}`,`${a+2*d}/${b+3*e}`,`${a+4*d}/${b+4*e}`]),
        '分子看分子，分母看分母。',
        `分子每次 +${d}，分母每次 +${e}，所以下一项是 ${ans}。`
      );
    }),
    Q('frac_scale_var','同倍放缩变量',['技巧'],()=>{
      const k=n(2,5); const ans='同倍放缩';
      return R(
        `若分数 ${2*k}/${3*k} 看不出规律，但可化为 2/3，应使用什么思路？`, ans,
        ['同倍放缩','只改分子','只改分母','把分数改成整数'],
        '分子分母同除不改变数值。',
        `${2*k}/${3*k} 同除以 ${k} 得 2/3，可让分子或分母进入清楚规律。`
      );
    })
  ],'all');

  const zig=C('zigzag_variable_training','忽大忽小变量训练',['技巧'],[
    Q('zig_interval_sequence_var','间隔差变量',['技巧'],()=>{
      const a=n(2,8), b=n(20,40), da=n(2,5), db=n(3,7);
      const arr=[a,b,a+da,b+db,a+2*da,b+2*db]; const ans=String(a+3*da);
      return R(
        `数列 ${arr.join('，')}，下一项是多少？`, ans,
        op(ans,[String(b+3*db),String(a+2*da+db),String(arr[5]+da)]),
        '忽大忽小时先隔项看。',
        `奇数位：${a}，${a+da}，${a+2*da}，下一项为 ${a+3*da}。`
      );
    }),
    Q('zig_direct_after_fail','优先法失败后退路',['运用'],()=>R(
      '忽大忽小数列优先间隔差，但间隔差无规律时，下一步可以怎样？','退回直接做差或构造网络',
      ['退回直接做差或构造网络','永远不能做差','只能奇偶猜','直接放弃'],
      '优先法不是唯一法。',
      '非单调并不等于不能直接做差；间隔差失败后，可以看相邻差、做和或构造网络。'
    ))
  ],'all');

  add(C('fraction_zigzag_training','分数与忽大忽小变量训练｜放缩与间隔',['技巧'],[frac,zig],'all'));
})();

// ----- lessons/data_analysis_speed_10_EX/09b_priority_boundary_extra.js -----
(function(){
  const {R,Q,C,add}=EX;
  const qs=[
    Q('num_priority_not_only','优先法不是唯一法',['基础'],()=>R(
      '数字推理里“优先考虑间隔差/做差”是什么意思？','先看，不代表一定有规律',
      ['先看，不代表一定有规律','一定就是答案','不能再换方法','只用于猜题'],
      '优先是节能顺序，不是保证命中。',
      '原课反复强调：优先方法只是先瞄一眼，没规律就退回直接做差、构造网络或其他路线。'
    )),
    Q('num_operation_after_fail','优先失败后的动作',['技巧'],()=>R(
      '忽大忽小数列间隔差后没有规律，下一步更合理的是？','换路线，不硬认规律',
      ['换路线，不硬认规律','硬把差值凑成规律','立刻乱猜','只看第一个数'],
      '不要为了套口诀而套口诀。',
      '间隔差只是优先路线；若没有连续规律，可以回到直接做差、做和或构造网络。'
    ))
  ];
  add(C('priority_boundary_extra','路线边界补全｜优先不等于唯一',['技巧'],qs,'all'));
})();

// ----- lessons/data_analysis_speed_10_EX/09c_fraction_zigzag_random_enrichment.js -----
(function(){
  const {n,op,R,Q,C,add,pk}=EX;

  const frac=C('fraction_ops_random','分数四则变量',['技巧'],[
    Q('fraction_four_ops_random','前项分子分母四则随机',['技巧'],()=>{
      const a=n(1,8), b=n(2,9); const mode=pk(['和','差','积']);
      const val=mode==='和'?a+b:mode==='差'?Math.abs(a-b):a*b;
      return R(
        `某分数项为 ${a}/${b}。若规律是“前一项分子分母${mode}得到后一项某部位”，该部位应填多少？`, String(val),
        op(val,[a+b+1,Math.max(0,Math.abs(a-b)-1),a*b+1]),
        '分数多时，除分子分母分别看，还要看同一分数内的四则组合。',
        mode==='和'?`${a}+${b}=${val}。`:mode==='差'?`|${a}-${b}|=${val}。`:`${a}×${b}=${val}。`
      );
    }),
    Q('fraction_denominator_multiple_random','分母倍数通分随机',['技巧'],()=>{
      const d=n(3,8), m=pk([2,3,4]); const ans='考虑通分做差';
      return R(
        `分数数列中相邻分母出现 ${d}、${d*m}、${d*m*2} 这类明显倍数关系，优先考虑什么？`, ans,
        ['考虑通分做差','只看奇偶','直接猜最大','永远分子分母分别看'],
        '分母倍数明显时，通分会变得省力。',
        '这是原课分数数列的第三条优先路线：分母呈明显倍数关系，则考虑通分做差。'
      );
    })
  ],'all');

  const zig=C('zigzag_sum_random','间隔和变量',['技巧'],[
    Q('zigzag_interval_sum_random','间隔和备选随机',['技巧'],()=>{
      const a=n(2,9), b=n(10,20); const ans=String(a+b);
      return R(
        `忽大忽小数列优先间隔差；若题目设置成第1项 ${a} 与第3项 ${b} 的间隔“和”成规律，则第1、3项和是多少？`, ans,
        op(ans,[b-a,a*b,Math.abs(b-a)]),
        '间隔差更常见，但间隔和也可能出现。',
        `间隔和就是隔一项相加：${a}+${b}=${ans}。优先法失败时要允许换路。`
      );
    }),
    Q('zigzag_fallback_random','间隔失败后退路随机',['技巧'],()=>R(
      '忽大忽小题先试间隔差，但间隔差没有规律。下一步更符合课程路线的是？','退回直接做差并构造网络',
      ['退回直接做差并构造网络','继续硬做间隔差','马上做四级差','只猜奇偶'],
      '优先不等于唯一。',
      '间隔差只是优先路线；无规律时退回直接做差，再看能否构造网络。'
    ))
  ],'all');

  add(C('fraction_zigzag_random_enrichment','分数忽大忽小升华｜四则、通分与退路变量',['技巧'],[frac,zig],'all'));
})();

