// ----- lessons/data_analysis_speed_11/_common.js -----
(function(){
  const pk=a=>a[Math.floor(Math.random()*a.length)];
  const n=(a,b)=>a+Math.floor(Math.random()*(b-a+1));
  const uq=a=>[...new Set(a)];
  const sh=a=>a.map(v=>[Math.random(),v]).sort((x,y)=>x[0]-y[0]).map(x=>x[1]);
  const op=(a,b,l=4)=>sh([a,...sh(uq(b).filter(x=>x!==a)).slice(0,l-1)]);
  const R=(q,a,pool,hint,solution,extra={})=>Object.assign({q,a,pool,hint,solution},extra);
  const pct=x=>`${x}%`;
  const signed=x=>(x>0?`+${x}%`:`${x}%`);
  const cid='data_analysis_speed_11';
  const Q=(id,title,tags,mk,type)=>({id,title,t:title,type:type||tags[0],tags,mk,makeQuestion:mk});
  const C=(id,title,tags,subs,unlockMode='all')=>({id,title,t:title,type:tags[0],tags,unlockMode,subs});
  const sec=title=>Game.addLessonTopic(cid,{k:'s',t:title});
  const add=t=>Game.addLessonTopic(cid,t);
  const done=title=>Game.finishLesson(cid,title);
  Game.beginLesson(cid);
  window.EX={pk,n,uq,sh,op,R,Q,C,sec,add,done,pct,signed};
})();

// ----- lessons/data_analysis_speed_11/00_section_position.js -----
EX.sec('资料分析｜定位与问法');

// ----- lessons/data_analysis_speed_11/01_position_question.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('da_read_order','三步定位',['基础'],()=>R(
    '资料分析拿到题，最省力的首要顺序是什么？',
    '时间点→对象→问法',
    op('时间点→对象→问法',['对象→选项→公式','先列式→再找材料','只看关键词','先看选项均衡']),
    '先判断现期、基期或隔年，再确认对象完整限定，最后看问什么。',
    '课程反复强调先看时间点，再看对象，再看问法；这能避免拿错年份、对象和分母。'
  ));

  const q2=Q('da_time_identity','时间身份',['基础'],()=>{
    const y=n(2014,2024);
    const ask=pk([y,y-1,y-2]);
    const ans=ask===y?'现期':(ask===y-1?'基期':'隔年基期');
    return R(
      `材料给的是 ${y} 年数据，题目问 ${ask} 年。这个题首先应识别为？`,
      ans,
      op(ans,['现期','基期','隔年基期','平均数升降']),
      '材料年份和问题年份相同是现期，差一年是基期，差两年是隔年。',
      `材料 ${y} 年，问题 ${ask} 年，所以是${ans}问题。`
    );
  });

  const q3=Q('da_object_limit','对象限定',['基础'],()=>{
    const cases=[
      ['东北地区民间固定资产投资','固定资产投资','民间固定资产投资','全国固定资产投资'],
      ['非养殖水产品产量','养殖水产品产量','水产品出口额','水产品进口量'],
      ['批发和零售业直接投资金额','直接投资总额','新设立企业数','房地产直接投资额']
    ];
    const c=pk(cases);
    return R(
      `题干完整对象是“${c[0]}”。找材料时最不能只抓哪个残缺对象？`,
      c[1],
      op(c[1],c.slice(2).concat([c[0]])),
      '对象限定词不能丢，尤其地区、民间、非、行业、金额/数量。',
      `“${c[1]}”少了关键限定，容易把全国或其他口径的数据拿来误用。`
    );
  });

  const q4=Q('da_ask_type','问法翻译',['基础'],()=>{
    const item=pk([
      ['增幅为多少','增长率'],
      ['增加了多少','增长量'],
      ['平均每家','平均数'],
      ['占比为多少','比重'],
      ['贸易状态','顺差或逆差']
    ]);
    return R(
      `题目问“${item[0]}”，本质上先归类为？`,
      item[1],
      op(item[1],['增长率','增长量','平均数','比重','顺差或逆差']),
      '先把中文问法翻译成模型。',
      `“${item[0]}”对应${item[1]}，之后才选择公式或估算方法。`
    );
  });

  add(C('da_reading_card','审题定位｜时间对象问法',['基础'],[q1,q2,q3,q4],'all'));
})();

// ----- lessons/data_analysis_speed_11/02_section_growth.js -----
EX.sec('资料分析｜增长、降幅与百分点');

// ----- lessons/data_analysis_speed_11/03_growth_core.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const f1=Q('da_base_formula','基期公式',['技巧'],()=>R(
    '已知现期量 A 和增长率 r，求基期量的标准式是什么？',
    'A÷(1+r)',
    op('A÷(1+r)',['A×(1+r)','A÷r','A×r÷(1+r)']),
    '基期是把现期倒推回上一期。',
    '增长时：现期=基期×(1+r)，所以基期=A÷(1+r)。下降时就是 A÷(1-r)。'
  ));

  const f2=Q('da_growth_amount_formula','增长量公式',['技巧'],()=>R(
    '已知现期量 A 和增长率 r，求增长量的常用式是什么？',
    'A×r÷(1+r)',
    op('A×r÷(1+r)',['A÷(1+r)','A×(1+r)','A÷r']),
    '增长量=现期-基期。',
    '基期=A÷(1+r)，增长量=A-A÷(1+r)=A×r÷(1+r)。'
  ));

  const v1=Q('da_base_drill','倒推基期',['技巧'],()=>{
    const base=n(80,240)*10;
    const r=pk([5,8,10,12,20]);
    const now=Math.round(base*(100+r)/100);
    const ans=`约 ${base}`;
    return R(
      `某指标现期约为 ${now}，同比增长 ${r}%。基期约为多少？`,
      ans,
      op(ans,[`约 ${now}`,`约 ${Math.round(now*(100+r)/100)}`,`约 ${base+r*10}`]),
      '增长后倒推：现期除以 1+增长率。',
      `${now}÷(1+${r}%)≈${base}，所以基期约为 ${base}。`
    );
  });

  const v2=Q('da_down_base_drill','下降倒推',['技巧'],()=>{
    const base=n(90,260)*10;
    const r=pk([6,9,12,20,25]);
    const now=Math.round(base*(100-r)/100);
    const ans=`约 ${base}`;
    return R(
      `某指标现期约为 ${now}，同比下降 ${r}%。基期约为多少？`,
      ans,
      op(ans,[`约 ${now}`,`约 ${Math.round(now*(100-r)/100)}`,`约 ${base-r*10}`]),
      '下降后倒推：现期除以 1-降幅。',
      `${now}÷(1-${r}%)≈${base}，所以基期约为 ${base}。`
    );
  });

  const v3=Q('da_fraction_growth','份数增长量',['技巧'],()=>{
    const pairs=[[20,6],[25,5],[12.5,9],[11.1,10],[10,11]];
    const [r,den]=pk(pairs);
    const now=n(12,80)*den;
    const ans=`约 ${Math.round(now/den)}`;
    return R(
      `现期量约为 ${now}，同比增长约 ${r}%。用份数思维估增长量。`,
      ans,
      op(ans,[`约 ${Math.round(now/(den-1))}`,`约 ${Math.round(now/(den+1))}`,`约 ${now}`]),
      `把 ${r}% 看成常见分数，增长量≈现期除以“现期份数”。`,
      `${r}% 对应现期约 ${den} 份，增长 1 份，所以增长量≈${now}÷${den}=${Math.round(now/den)}。`
    );
  });

  const v4=Q('da_small_rate_100','100增加多少',['技巧'],()=>{
    const r=pk([3.2,4.6,5.8,6.4,8.5]);
    const base=pk([300,500,800,1000,1200]);
    const ans=`约 ${Math.round(base*r/100)}`;
    return R(
      `${base} 同比增长 ${r}%，用“100 增加多少”估增长量。`,
      ans,
      op(ans,[`约 ${Math.round(base*r/100)+10}`,`约 ${Math.max(1,Math.round(base*r/100)-10)}`,`约 ${base}`]),
      '增长率在 10% 以内，100 增加 r，base 增加 base×r%。',
      `${base}×${r}%≈${Math.round(base*r/100)}，所以增长量约为 ${Math.round(base*r/100)}。`
    );
  });

  const drill=C('da_growth_variable_route','变量训练',['技巧'],[v1,v2,v3,v4],'sequence');
  add(C('da_growth_card','增长核心｜基期与增长量',['技巧'],[f1,f2,drill],'all'));
})();

// ----- lessons/data_analysis_speed_11/04_rate_drop.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const r1=Q('da_rate_word','增幅含义',['基础'],()=>R(
    '资料分析中“增幅”通常等价于什么？',
    '增长率',
    op('增长率',['增长量','比重','平均数']),
    '“幅”在这里是增长的幅度，不是具体增加量。',
    '增幅就是增长率；若材料说高出多少个百分点，就对增长率做加减。'
  ));

  const r2=Q('da_decline_abs','降幅比较',['基础'],()=>R(
    '增长率 -3.2% 和 -5.6%，如果问“降幅更大”，应选哪个？',
    '-5.6%',
    op('-5.6%',['-3.2%','两者一样','无法判断']),
    '问增长率大小看正负号，问降幅大小看下降绝对值。',
    '-3.2% 的增长率更大，但 -5.6% 的下降幅度更大。'
  ));

  const r3=Q('da_point_change','百分点修正',['技巧'],()=>{
    const now=n(6,18);
    const diff=n(1,5);
    const mode=pk(['高出','低于']);
    const ans=mode==='高出'?`${now-diff}%`:`${now+diff}%`;
    return R(
      `某部分同比增长 ${now}%，${mode}整体增幅 ${diff} 个百分点。整体增幅是多少？`,
      ans,
      op(ans,[`${now+diff}%`,`${diff}%`,`${now}%`]),
      '高出整体，就用部分减百分点；低于整体，就用部分加百分点。',
      `${mode==='高出'?`${now}-${diff}`:`${now}+${diff}`}=${ans.replace('%','')}，整体增幅为 ${ans}。`
    );
  });

  const r4=Q('da_decline_widen','降幅扩大收窄',['技巧'],()=>{
    const now=n(8,30);
    const d=n(1,4);
    const mode=pk(['扩大','收窄']);
    const prev=mode==='扩大'?now-d:now+d;
    const ans=`-${prev}%`;
    return R(
      `今年同比下降 ${now}%，降幅比上年${mode} ${d} 个百分点。上年增长率是多少？`,
      ans,
      op(ans,[`-${now+d}%`,`-${now-d}%`,`+${prev}%`]),
      '扩大：今年降得更多；收窄：今年降得更少。',
      `${mode==='扩大'?'今年更负，所以上年少降':'今年少降，所以上年多降'}，上年为 -${prev}%。`
    );
  });

  const drill=C('da_rate_variable_route','变量训练',['技巧'],[r3,r4],'sequence');
  add(C('da_rate_card','增幅降幅｜百分点与正负',['基础'],[r1,r2,drill],'all'));
})();

// ----- lessons/data_analysis_speed_11/05_section_structure.js -----
EX.sec('资料分析｜混合、平均、比重');

// ----- lessons/data_analysis_speed_11/06_mix_avg_share.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const m1=Q('da_mix_rule','混合夹逼',['基础'],()=>R(
    '整体由 A、B 两部分构成时，整体增长率与两部分增长率的关系是？',
    '夹在两部分增长率之间',
    op('夹在两部分增长率之间',['一定大于两部分','一定小于两部分','等于两部分相加']),
    '整体是加权混合结果。',
    '整体增长率不会跑到两个部分增长率之外；这是混合原理。'
  ));

  const m2=Q('da_mix_direction','未知部分方向',['技巧'],()=>{
    const whole=n(2,8);
    const part=whole+n(1,5);
    const ans=`小于 ${whole}%`;
    return R(
      `整体增长率为 ${whole}%，已知 A 部分增长率为 ${part}%。B 部分增长率应在什么方向？`,
      ans,
      op(ans,[`大于 ${part}%`,`等于 ${whole}%`,`一定为负数`]),
      '整体必须夹在 A、B 之间。',
      `A 已经高于整体，要把整体拉回 ${whole}%，B 必须小于 ${whole}%。`
    );
  });

  const a1=Q('da_avg_direction_rule','平均数升降',['基础'],()=>R(
    '平均数=总量÷份数。判断平均数升降，只比较哪两个增长率？',
    '总量增长率与份数增长率',
    op('总量增长率与份数增长率',['现期量与基期量','部分量与整体量','出口额与进口额']),
    '平均数的分子是总量，分母是份数。',
    'R总>R份，平均数上升；R总<R份，平均数下降。'
  ));

  const a2=Q('da_avg_direction_drill','升降判断',['技巧'],()=>{
    const rt=n(-5,12);
    let rf=n(-4,13);
    if(rf===rt) rf+=2;
    const ans=rt>rf?'上升':'下降';
    return R(
      `某平均数=金额÷数量。金额增长率 ${rt}%，数量增长率 ${rf}%。平均数如何变化？`,
      ans,
      op(ans,['上升','下降','不变','无法判断']),
      '比较分子增长率和分母增长率。',
      `${rt}% ${rt>rf?'大于':'小于'} ${rf}%，所以平均数${ans}。`
    );
  });

  const b1=Q('da_ratio_formula','比重公式',['基础'],()=>R(
    '比重、占比、比例的基本结构是什么？',
    '部分÷整体',
    op('部分÷整体',['整体÷部分','增长量÷现期','基期÷现期']),
    '先确认部分和整体是否同口径。',
    '比重=部分÷整体；用比重求部分，就是整体×比重。'
  ));

  const b2=Q('da_ratio_transfer','比例迁移',['技巧'],()=>{
    const total=n(400,900);
    const whole=n(70,99)*100;
    const part=Math.round(whole*n(6,15)/100);
    const ans=`约 ${Math.round(total*part/whole)}`;
    return R(
      `甲类总量 ${total}，其行业分布比例与总体相同。总体中某行业 ${part}、总体总量 ${whole}。甲类该行业约多少？`,
      ans,
      op(ans,[`约 ${part}`,`约 ${total}`,`约 ${Math.round(total*whole/part)}`]),
      '先算总体行业占比，再乘甲类总量。',
      `甲类该行业≈${total}×${part}/${whole}≈${Math.round(total*part/whole)}。`
    );
  });

  const avg=C('da_avg_route','平均数',['技巧'],[a1,a2],'sequence');
  const ratio=C('da_ratio_route','比重比例',['技巧'],[b1,b2],'sequence');
  add(C('da_structure_card','结构关系｜混合平均比重',['技巧'],[m1,m2,avg,ratio],'all'));
})();

// ----- lessons/data_analysis_speed_11/07_scope_consistency.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const c1=Q('da_count_from_share','占比换人数',['技巧'],()=>{
    const total=pk([1000,1500,2000,3000]);
    const diff=pk([6.5,10.5,15.3,22.4]);
    const ans=`约 ${Math.round(total*diff/100)}`;
    return R(
      `总人数 ${total}，两个选择的占比相差 ${diff} 个百分点。实际人数相差约多少？`,
      ans,
      op(ans,[`约 ${diff}`,`约 ${Math.round(total/diff)}`,`约 ${Math.round(total*(100-diff)/100)}`]),
      '占比差要乘总人数，不能把百分点当人数。',
      `${total}×${diff}%≈${Math.round(total*diff/100)}，所以人数差约为 ${Math.round(total*diff/100)}。`
    );
  });

  const c2=Q('da_denominator_shift','分母换范围',['技巧'],()=>{
    const plane=n(30,50);
    const factor=n(4,12);
    const ans=`${Math.round(factor/plane*100)}%`;
    return R(
      `总人群中，飞机用户占 ${plane}%，考虑积分奖励的人占 ${factor}%。且只有飞机有积分奖励。在飞机用户中，考虑积分奖励者占比约为？`,
      ans,
      op(ans,[`${factor}%`,`${plane}%`,`${Math.round((plane-factor)/plane*100)}%`]),
      '题目问“在飞机用户中”，分母要换成飞机用户。',
      `占比=${factor}%÷${plane}%≈${Math.round(factor/plane*100)}%。`
    );
  });

  const c3=Q('da_containment','包含关系',['基础'],()=>R(
    '题干说“火车包含高铁、动车、普通列车”，求火车总占比时应怎么做？',
    '三项占比相加',
    op('三项占比相加',['只看高铁','只看普通列车','用飞机占比替代']),
    '包含关系常藏在文字里。',
    '火车不是单独一栏时，要把其包含的交通方式合并。'
  ));

  const d1=Q('da_plane_train_reverse','反向占比',['技巧'],()=>{
    const total=2000;
    const people=pk([600,750,840,920]);
    const plane=Math.round(people/total*1000)/10;
    const rail=Math.round((100-plane)*10)/10;
    const ans=`约 ${rail}%`;
    return R(
      `共有 ${total} 人，只能选飞机或高铁。若选飞机约 ${people} 人，则选高铁占比约多少？`,
      ans,
      op(ans,[`约 ${plane}%`,`约 ${Math.round(people/20)}%`,`约 ${Math.round((people/total)*100)}%`]),
      '先人数转占比，再用 100% 减。',
      `飞机占比=${people}÷${total}=${plane}%，高铁占比≈100%-${plane}%=${rail}%。`
    );
  });

  const d2=Q('da_not_in_range','范围内不考虑',['技巧'],()=>{
    const inRange=pk([62,68,75,80]);
    const consider=n(35,inRange-5);
    const ans=`约 ${Math.round((inRange-consider)/inRange*100)}%`;
    return R(
      `总人群中，飞机或高铁用户占 ${inRange}%，考虑行程总耗时的人占 ${consider}%，且这些考虑者均在飞机或高铁用户中。问在飞机或高铁用户中“不考虑”的占比。`,
      ans,
      op(ans,[`${100-consider}%`,`${inRange-consider}%`,`${consider}%`]),
      '先限定分母，再在这个范围内做差。',
      `范围内不考虑占比=(${inRange}%-${consider}%)÷${inRange}%≈${Math.round((inRange-consider)/inRange*100)}%。`
    );
  });

  const inner=C('da_range_complex_inner','范围陷阱',['运用'],[d1,d2],'sequence');
  const outer=C('da_range_scenarios','变量场景',['技巧'],[c1,c2,inner],'sequence');
  add(C('da_range_card','范围一致｜占比人数与包含',['运用'],[c3,outer],'all'));
})();

// ----- lessons/data_analysis_speed_11/08_section_estimation.js -----
EX.sec('资料分析｜估算、比较、综合判断');

// ----- lessons/data_analysis_speed_11/09_estimation_compare.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const e1=Q('da_first_digit_fraction','分数首位比较',['技巧'],()=>{
    const target=n(20,39)/10;
    const goodDen=n(160,240);
    const goodNum=Math.round(target*goodDen);
    const ans=`${goodNum}÷${goodDen}`;
    const bad1=`${n(400,600)}÷${n(80,130)}`;
    const bad2=`${n(80,150)}÷${n(150,250)}`;
    const bad3=`${n(700,900)}÷${n(90,150)}`;
    return R(
      `整体平均水平约为 ${target.toFixed(1)}。下列哪个分数最接近整体？`,
      ans,
      op(ans,[bad1,bad2,bad3]),
      '先看首位和数量级，行测不必每项精除。',
      `${ans}≈${target.toFixed(1)}，其首位与整体最接近。`
    );
  });

  const e2=Q('da_peak_valley','削峰填谷',['技巧'],()=>{
    const base=pk([80,90,100]);
    const count=pk([5,8,10]);
    const offsets=[];
    for(let i=0;i<count;i++) offsets.push(n(-5,4));
    const sum=offsets.reduce((a,b)=>a+b,0);
    const avg=Math.round((base+sum/count)*10)/10;
    const nums=offsets.map(x=>base+x).join('、');
    const ans=String(avg);
    return R(
      `一组数据为 ${nums}，都接近 ${base}。用削峰填谷求平均数约为？`,
      ans,
      op(ans,[String(base),String(Math.round((base+sum)*10)/10),String(Math.round((base-sum/count)*10)/10)]),
      '把每个数与参照值比较，算总偏差再除以个数。',
      `总偏差=${sum}，平均数=${base}+${sum}/${count}≈${avg}。`
    );
  });

  const e3=Q('da_weight_score','权重计算',['技巧'],()=>{
    const a=n(70,95), b=n(70,100), c=n(70,100);
    const score=Math.round((a*0.2+b*0.4+c*0.4)*10)/10;
    const ans=String(score);
    return R(
      `某项目三项得分分别为 ${a}、${b}、${c}，权重为 20%、40%、40%。综合得分约为？`,
      ans,
      op(ans,[String(Math.round((a+b+c)/3*10)/10),String(Math.round((a*0.4+b*0.4+c*0.2)*10)/10),String(a+b+c)]),
      '权重不是简单平均，要各自乘权重后相加。',
      `综合得分=${a}×20%+${b}×40%+${c}×40%≈${score}。`
    );
  });

  const e4=Q('da_quantity_order','数量级意识',['技巧'],()=>R(
    '增长额之差一正一负时，若问“两者增长额之差约为多少”，应特别注意什么？',
    '符号与数量级',
    op('符号与数量级',['只看绝对量最大','只看增长率最大','把百分号去掉直接相加']),
    '负增长的增长额为负；作差时可能变成相加。',
    '还要确认单位和小数位，避免把 8.9 看成 89 或 890。'
  ));

  const drill=C('da_estimate_variable_route','变量训练',['技巧'],[e1,e2,e3],'all');
  add(C('da_estimate_card','估算比较｜首位削峰权重',['技巧'],[drill,e4],'all'));
})();

// ----- lessons/data_analysis_speed_11/10_integrated_strategy.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const s1=Q('da_trade_balance','顺差逆差',['基础'],()=>{
    const exp=n(60,150);
    const imp=n(20,120);
    const ans=exp>imp?'顺差':'逆差';
    return R(
      `出口额 ${exp}，进口额 ${imp}。贸易状态是什么？`,
      ans,
      op(ans,['顺差','逆差','无法判断','增长率']),
      '顺差看出口额大于进口额，逆差相反。',
      `${exp}${exp>imp?'>':'<'}${imp}，所以是${ans}。注意看“额”，不是看“量”。`
    );
  });

  const s2=Q('da_fast_than_whole','快于整体',['基础'],()=>{
    const whole=n(5,12);
    const x=whole+n(1,10);
    const y=whole-n(1,4);
    return R(
      `整体增速 ${whole}%。甲行业 ${x}%，乙行业 ${y}%。谁快于整体？`,
      '甲行业',
      op('甲行业',['乙行业','两者都快','两者都不快']),
      '快于整体就是增长率大于整体。',
      `${x}%>${whole}%，所以甲行业快于整体；${y}%<${whole}%，乙不快于整体。`
    );
  });

  const s3=Q('da_decline_faster','降幅快于整体',['基础'],()=>{
    const whole=n(6,12);
    const more=whole+n(2,10);
    const less=whole-n(1,4);
    return R(
      `整体下降 ${whole}%。甲下降 ${more}%，乙下降 ${less}%。谁的降幅快于整体？`,
      '甲',
      op('甲',['乙','两者都是','两者都不是']),
      '降幅快于整体，就是下降绝对值更大。',
      `${more}% 的下降幅度大于 ${whole}%，所以甲快于整体。`
    );
  });

  const s4=Q('da_option_balance','综合题策略',['运用'],()=>R(
    '综合判断题没时间时可以参考选项均衡，但有时间应怎样做？',
    '优先验证容易判断的选项',
    op('优先验证容易判断的选项',['完全只按均衡猜','从 A 到 D 全部精算','先忽略题干']),
    '选项均衡只是应急，不是定理。',
    '课程中多次强调：没时间可猜，有时间要验证，尤其 A、C、D 等可疑或易判选项。'
  ));

  const s5=Q('da_same_diff_option','同存异',['运用'],()=>R(
    '组合选项中，多个选项共同出现的元素与唯一缺失的元素，通常可以怎么用？',
    '先用同存异排除或优先验证',
    op('先用同存异排除或优先验证',['直接全部相加','只看第一个词','一定选唯一项']),
    '同存异是省时间的选项意识。',
    '多个选项都有的内容更可能是稳定项；少数独有或缺失项适合先查验，但不能当作必然规律。'
  ));

  add(C('da_comprehensive_card','综合判断｜贸易比较与选项意识',['运用'],[s1,s2,s3,s4,s5],'all'));
})();

// ----- lessons/data_analysis_speed_11/11_section_advanced_formula.js -----
EX.sec('资料分析｜隐含考法与边界');

// ----- lessons/data_analysis_speed_11/12_advanced_formula_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const l1=Q('da_line_awareness','划线意识',['技巧'],()=>R(
    '资料分析里“划线法/划线意识”的本质是什么？',
    '用接近关系和误差范围快速锁定量级',
    op('用接近关系和误差范围快速锁定量级',['把所有数精确相除','只看最大数字','把百分号全部去掉']),
    '课程强调：学了划线，不一定真的要划线，而是形成“略大、略小、误差不大”的意识。',
    '当 744 与 781 很接近时，744/781 略小于 1；再乘一个总量，结果也只是略小，不会小到差几个数量级。'
  ));

  const l2=Q('da_line_drill','接近比例',['技巧'],()=>{
    const total=pk([420,526,680,840]);
    const denom=n(720,960);
    const num=denom-n(20,70);
    const exact=Math.round(total*num/denom);
    const ans=`略小于 ${total}`;
    return R(
      `某比例为 ${num}/${denom}，要求 ${total}×${num}/${denom}。不精算时最合理的判断是？`,
      ans,
      op(ans,[`远大于 ${total*2}`,`约为 ${Math.round(total/2)}`,`接近 0`]),
      '分子比分母小一点，所以比例略小于 1。',
      `${num}/${denom} 略小于 1，所以结果约为 ${exact}，应判断为略小于 ${total}。`
    );
  });

  const y1=Q('da_two_year_rate','隔年增长率',['技巧'],()=>{
    const r1=pk([-20,-15,-10,8,12]);
    const r2=pk([-12,-8,10,15]);
    const val=(r1+r2+r1*r2/100).toFixed(1).replace('.0','');
    const ans=`约 ${val}%`;
    return R(
      `某指标第一年增长率 ${r1}%，第二年增长率 ${r2}%。隔年增长率约为？`,
      ans,
      op(ans,[`约 ${r1+r2}%`,`约 ${r1*r2}%`,`约 ${r1-r2}%`]),
      '隔年增长率不能只简单相加，还要加乘积项。',
      `隔年增长率=${r1}%+${r2}%+${r1}%×${r2}%≈${val}%。`
    );
  });

  const y2=Q('da_two_year_base','连续倒推',['技巧'],()=>{
    const base=n(80,180)*10;
    const r1=pk([10,12,20]);
    const r2=pk([5,8,10]);
    const now=Math.round(base*(1+r1/100)*(1+r2/100));
    const ans=`约 ${base}`;
    return R(
      `2014 年为未知，2015 年增长 ${r1}%，2016 年又增长 ${r2}%，2016 年现期约 ${now}。2014 年约为？`,
      ans,
      op(ans,[`约 ${now}`,`约 ${Math.round(now/(1+r2/100))}`,`约 ${Math.round(now*(1+r1/100))}`]),
      '隔年基期也可以连续除两次。',
      `${now}÷(1+${r2}%)÷(1+${r1}%)≈${base}。`
    );
  });

  const b1=Q('da_base_share_general','基期比重通式',['技巧'],()=>{
    const cur=n(20,70);
    const part=pk([8,12,15,20]);
    const whole=pk([3,5,10]);
    const v=Math.round(cur*(100+whole)/(100+part));
    const ans=`约 ${v}%`;
    return R(
      `现期比重 ${cur}%，部分增长率 ${part}%，整体增长率 ${whole}%。基期比重约为？`,
      ans,
      op(ans,[`${cur}%`,`约 ${Math.round(cur*(100+part)/(100+whole))}%`,`约 ${cur+part-whole}%`]),
      '基期比重不是直接加减增长率。',
      `基期比重=现期比重×(1+整体增长率)/(1+部分增长率)≈${v}%。`
    );
  });

  const b2=Q('da_avg_rate_general','平均数增长率',['技巧'],()=>{
    const totalR=n(8,20);
    const countR=n(1,totalR-2);
    const v=Math.round((totalR-countR)/(100+countR)*10000)/100;
    const ans=`约 ${v}%`;
    return R(
      `总量增长 ${totalR}%，份数增长 ${countR}%。若题目问平均数增长率，约为？`,
      ans,
      op(ans,[`${totalR-countR}%`,`${totalR}%`,`${countR}%`]),
      '升降只看大小；若问具体增长率，要除以 1+份数增长率。',
      `平均数增长率=(${totalR}%-${countR}%)/(1+${countR}%)≈${v}%。`
    );
  });

  const e1=Q('da_month_stable','累计不等于月度',['运用'],()=>R(
    '材料只说“1—12 月累计增速与 1—11 月持平”，能否推出每个月增速都平稳？',
    '不能',
    op('不能',['能','只能推出 12 月最快','只能推出 1 月最快']),
    '累计增速是混合结果，不等于每个月都一样。',
    '课程强调：“月增速平稳”指每个月增长率差不多；累计区间持平只能说明整体混合结果持平，不能推出每个月平稳。'
  ));

  const e2=Q('da_main_force','主力影响判断',['运用'],()=>{
    const east=n(12,20)*10000;
    const mid=n(3,8)*10000;
    const eastR=n(5,9);
    const midR=n(1,6);
    return R(
      `东部基数 ${east}，增速 ${eastR}%；中部基数 ${mid}，增速 ${midR}%。判断总增长主力更可能是谁？`,
      '东部',
      op('东部',['中部','无法比较','一定是增速低者']),
      '主力影响看“基数×增速”，不是只看增速。',
      `东部基数明显更大，且增速不低，增长贡献通常更大，所以更可能是主力。`
    );
  });

  const e3=Q('da_threshold_no_detail','不到超过判断',['技巧'],()=>{
    const now=n(1100,1500);
    const r=n(30,45);
    const base=Math.round(now/(1+r/100));
    const ans=base<1000?'不到1000':'超过1000';
    return R(
      `现期 ${now}，增长率 ${r}%。基期约 ${now}÷(1+${r}%)，判断是否不到 1000。`,
      ans,
      op(ans,['不到1000','超过1000','一定等于1000','无法判断']),
      '只问阈值时，不必精算所有小数位。',
      `约为 ${base}，所以${ans}。这就是“够判断即可”的三不看/阈值意识。`
    );
  });

  const line=C('da_line_route','划线估算',['技巧'],[l1,l2],'sequence');
  const formula=C('da_formula_extend_route','公式补足',['技巧'],[y1,y2,b1,b2],'all');
  const boundary=C('da_boundary_route','边界判断',['运用'],[e1,e2,e3],'all');
  add(C('da_completion_card','隐含考法｜公式与边界',['运用'],[line,formula,boundary],'all'));
})();

// ----- lessons/data_analysis_speed_11/13_section_chart_option.js -----
EX.sec('资料分析｜图表判断与选项意识');

// ----- lessons/data_analysis_speed_11/14_chart_option_edges.js -----

(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const z1=Q('da_zero_option_emergency','选项含零',['运用'],()=>R(
    '技巧提示中提到“选项出现 0”时，没时间可以怎么处理？',
    '作为应急拆零线索，但不能当定理',
    op('作为应急拆零线索，但不能当定理',['一定选择含 0 选项','永远排除含 0 选项','直接跳过题干']),
    '这是考场应急意识，不是硬公式。',
    '原课说没时间时可以“拆零”，本质是利用选项特征做应急判断；有时间仍要回到题干验证。'
  ));

  const z2=Q('da_first_question_para','首题首段',['基础'],()=>R(
    '资料分析一篇材料的第一小题，定位时有什么经验性提示？',
    '常优先在第一段找，但仍要以对象为准',
    op('常优先在第一段找，但仍要以对象为准',['一定只看最后一段','不用看对象','直接看综合判断']),
    '这是定位效率经验，不是绝对规律。',
    '原课说“一般来讲第一题就在第一段”，但也反复强调完整对象不能丢。'
  ));

  const z3=Q('da_trade_total_export','总额推出进口额',['技巧'],()=>{
    const exp=n(60,130);
    const imp=n(20,80);
    const total=exp+imp;
    const ans=`进口额 ${imp}`;
    return R(
      `水产品进出口总额 ${total}，出口额 ${exp}。进口额是多少？`,
      ans,
      op(ans,[`进口额 ${total}`,`进口额 ${exp}`,`进口额 ${Math.abs(exp-imp)}`]),
      '总额=出口额+进口额。',
      `进口额=${total}-${exp}=${imp}。之后再比较出口额和进口额判断顺差或逆差。`
    );
  });

  const z4=Q('da_share_point_direct','比重百分点直推',['技巧'],()=>{
    const cur=n(35,75);
    const pp=n(2,6);
    const mode=pk(['降低','提高']);
    const prev=mode==='降低'?cur+pp:cur-pp;
    const ans=`${prev}%`;
    return R(
      `今年比重为 ${cur}%，比上年${mode} ${pp} 个百分点。上年比重为多少？`,
      ans,
      op(ans,[`${cur}%`,`${cur+pp}%`,`${cur-pp}%`]),
      '直接给百分点变化时，比重不用套复杂公式。',
      `${mode==='降低'?'今年低于上年':'今年高于上年'} ${pp} 个百分点，所以上年为 ${ans}。`
    );
  });

  const z5=Q('da_two_metric_fast','同时快于两个整体',['技巧'],()=>{
    const a=n(5,12), b=n(8,18);
    const x1=a+n(1,8), x2=b+n(1,8);
    const y1=a+n(1,8), y2=b-n(1,5);
    const z1v=a-n(1,4), z2=b+n(1,8);
    const ans='甲';
    return R(
      `全国整体两项增速分别为 ${a}%、${b}%。甲为 ${x1}%、${x2}%；乙为 ${y1}%、${y2}%；丙为 ${z1v}%、${z2}%。哪个同时快于全国两项整体？`,
      ans,
      op(ans,['乙','丙','甲乙丙都满足']),
      '“同时”意味着两个条件都要大于整体。',
      `甲两项都大于 ${a}% 和 ${b}%；乙第二项不满足，丙第一项不满足，所以选甲。`
    );
  });

  const z6=Q('da_opposite_rate_sum','一正一负不能抵消',['运用'],()=>R(
    '两个行业现期量相加，其中一个增长 +9.3%，另一个增长 -9.3%。能否据此判断它们基期和等于现期和？',
    '不能',
    op('不能',['能','只要增长率绝对值相同就能','只要现期量相同就必然能']),
    '增长率相反不等于增长量相反。',
    '基期要分别除以 1+9.3% 和 1-9.3%，不能用正负增长率直接抵消。'
  ));

  const z7=Q('da_change_amplitude_abs','变幅最大',['基础'],()=>{
    const vals=[n(5,12),-n(13,25),n(8,18),-n(26,40)];
    const labels=['甲','乙','丙','丁'];
    const idx=vals.map(Math.abs).indexOf(Math.max(...vals.map(Math.abs)));
    const ans=labels[idx];
    return R(
      `四个行业变动率分别为：甲 ${vals[0]}%，乙 ${vals[1]}%，丙 ${vals[2]}%，丁 ${vals[3]}%。若问“变幅最大”，选谁？`,
      ans,
      op(ans,labels),
      '变幅看变化幅度，通常看绝对值。',
      `绝对值最大的是 ${labels[idx]} 的 ${Math.abs(vals[idx])}%，所以选${ans}。`
    );
  });

  const z8=Q('da_visual_total_score','多指标总分最高',['技巧'],()=>R(
    '表格中问“综合得分最高”，如果某城市在每个分项都明显靠前，最省力的判断是什么？',
    '优先锁定该城市，再必要时验证',
    op('优先锁定该城市，再必要时验证',['必须把所有城市全加一遍','只看第一列即可','只看最低分']),
    '多指标都高时，总分通常也高。',
    '原课对冰雪旅游题的处理就是先观察各分项都高的城市，避免无谓全量精算。'
  ));

  const z9=Q('da_direct_difference','相差最大直接做差',['技巧'],()=>{
    const a=n(75,95), b=a-n(1,4);
    const c=n(75,95), d=c-n(8,15);
    const ans='乙';
    return R(
      `甲两项得分 ${a}、${b}；乙两项得分 ${c}、${d}。若问两项相差最大，谁更可能？`,
      ans,
      op(ans,['甲','两者一样','无法判断']),
      '问相差最大，本质直接做差。',
      `甲差 ${Math.abs(a-b)}，乙差 ${Math.abs(c-d)}，乙更大。`
    );
  });

  const z10=Q('da_group_sum_compare','地区合计比较',['技巧'],()=>{
    const h=[n(80,100),n(80,100),n(80,100)];
    const j=[n(60,85),n(60,85),n(60,85)];
    const hs=h.reduce((a,b)=>a+b,0), js=j.reduce((a,b)=>a+b,0);
    const ans=hs>js?'黑龙江':'吉林';
    return R(
      `黑龙江三个事件声量为 ${h.join('、')}；吉林三个事件声量为 ${j.join('、')}。合计谁更高？`,
      ans,
      op(ans,['黑龙江','吉林','无法比较','两者相等']),
      '同一地区多个对象比较，先合计同口径数据。',
      `黑龙江合计 ${hs}，吉林合计 ${js}，所以${ans}更高。`
    );
  });

  const locate=C('da_original_locate_edges','定位与应急',['运用'],[z1,z2,z3,z4],'all');
  const compare=C('da_original_compare_edges','比较与判断',['技巧'],[z5,z6,z7],'all');
  const chart=C('da_original_chart_edges','图表综合',['技巧'],[z8,z9,z10],'all');
  add(C('da_original_edges_card','路线边界｜迁移与应急',['运用'],[locate,compare,chart],'all'));
})();

// ----- lessons/data_analysis_speed_11/15_station.js -----
(function(){
  const {R,Q,add}=EX;
  add(Q('da_station_terms','驿站｜术语说明',['驿站'],()=>R(
    '这组知识中“现期/基期/隔年/百分点”属于什么用途？',
    '术语翻译，帮助快速选模型',
    ['术语翻译，帮助快速选模型','独立公式题','选项均衡定理','必须精算的信号'],
    '驿站用于轻量整理，不承担主训练。',
    '这些词的价值在于把题干语言翻译成模型：现期、基期、隔年、比重、平均数、增长量等。'
  )));
  add(Q('da_station_practice','驿站｜学习提示',['驿站'],()=>R(
    '资料分析训练最该避免的坏习惯是什么？',
    '每题都精算到底',
    ['每题都精算到底','先看时间点','确认对象限定','用选项差距估算'],
    '行测是效率型考试。',
    '课程反复提醒：能用方向、首位、范围、数量级排除时，不必每项精算。'
  )));
})();

// ----- lessons/data_analysis_speed_11/16_section_scope_strategy.js -----
EX.sec('读题口径｜范围与策略');

// ----- lessons/data_analysis_speed_11/17_scope_strategy_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const a1=Q('da_positive_not_decline','正增长不算降幅',['基础'],()=>{
    const pos=n(8,35), d1=n(5,12), d2=n(13,28);
    const ans=`-${d2}%`;
    return R(
      `三个地区同比变化分别为 +${pos}%、-${d1}%、-${d2}%。若问“降幅最大”，应选哪个变化率？`,
      ans,
      op(ans,[`+${pos}%`,`-${d1}%`,`+${Math.max(pos,d2)}%`]),
      '降幅必须先有“降”，正增长不是降幅候选。',
      `+${pos}% 是增长，不属于降幅；两个下降中 ${d2}% 的绝对值更大，所以选 ${ans}。`
    );
  });

  const a2=Q('da_far_options_range','选项差距大先判范围',['技巧'],()=>{
    const total=pk([426,526,680,840]);
    const num=n(720,780), den=n(790,860);
    const close=Math.round(total*num/den);
    const ans=`接近且小于 ${total}`;
    return R(
      `需要估算 ${total}×${num}/${den}。选项中有 ${Math.round(total/2)}、${close}、${total*2}。优先怎样判断？`,
      ans,
      op(ans,[`约为 ${Math.round(total/2)}`,`远大于 ${total*2}`,`无法估算`]),
      '选项距离很大时，不必精算，先用比例范围。',
      `${num}/${den} 略小于 1，所以结果应接近且小于 ${total}，约 ${close}。`
    );
  });

  const a3=Q('da_growth_amount_diff_sign','增长额之差的正负',['技巧'],()=>{
    const inc=n(40,90), dec=n(8,25);
    const ans=String(inc+dec);
    return R(
      `甲行业增长额约 +${inc}，乙行业增长额约 -${dec}。若问两者增长额之差的绝对距离，约为多少？`,
      ans,
      op(ans,[String(inc-dec),String(dec),String(inc)]),
      '一个正增长、一个负增长，差距是正数减负数。',
      `增长额差距=|${inc}-(-${dec})|=${inc+dec}，不是 ${inc}-${dec}。`
    );
  });

  const a4=Q('da_scope_language_first','语言理解优先',['运用'],()=>R(
    '课程中多次说有些资料分析不是难在估算，而是难在什么？',
    '读懂限定范围和题干语言',
    op('读懂限定范围和题干语言',['背更多复杂公式','把所有数字精确除完','只看选项均衡']),
    '图表调查类、范围类题尤其如此。',
    '例如“所有考虑行程总耗时的人均选择飞机或高铁”会改变分子归属；“在飞机或高铁用户中”会改变分母范围。'
  ));

  const a5=Q('da_people_to_share_to_complement','人数占比互转路径',['技巧'],()=>{
    const total=pk([1000,1600,2000,2400]);
    const people=Math.round(total*pk([0.25,0.3,0.375,0.4]));
    const plane=Math.round(people/total*1000)/10;
    const train=Math.round((100-plane)*10)/10;
    const ans=`高铁约 ${train}%`;
    return R(
      `共有 ${total} 人，优先选飞机的约 ${people} 人。若图中给的是“优先选高铁占比”，应先匹配哪个值？`,
      ans,
      op(ans,[`飞机约 ${plane}%`,`高铁约 ${plane}%`,`总人数约 ${people}%`]),
      '人数题遇到占比图，先人数÷总人数，再做互补。',
      `飞机占比=${people}/${total}=${plane}%，所以高铁占比约 100%-${plane}%=${train}%。`
    );
  });

  const a6=Q('da_composite_priority_not_rule','综合题策略不是定理',['运用'],()=>R(
    '“综合题 A 概率低、C/D 常见、可先看 D”应如何使用？',
    '只作没时间或验证顺序的策略',
    op('只作没时间或验证顺序的策略',['直接当正确答案规律','完全不用读材料','看到 D 就必选 D']),
    '这是考场节能策略，不是知识公式。',
    '原课说“猜题归猜题”，有时间仍要验证；这些经验只用于没时间或决定先查哪个选项。'
  ));

  const a7=Q('da_subset_condition_belongs','条件建立子集',['技巧'],()=>{
    const all=n(1200,3000);
    const factor=n(5,15);
    const group=n(25,50);
    const ans=`${factor}% 属于该小范围，但在小范围内占比还要除以 ${group}%`;
    return R(
      `总人数中 ${factor}% 考虑某因素。题干说“只有 A 类有这个因素”，A 类占总人数 ${group}%。正确理解是？`,
      ans,
      op(ans,[`${factor}% 就是 A 类内部占比`,`应直接 1-${factor}%`,`这个因素与 A 类无关`]),
      '“只有 A 类有”说明分子属于 A 类，但原占比仍可能是总人数占比。',
      `分子可放入 A 类范围内，但若问 A 类内部占比，应计算 ${factor}%/${group}%。`
    );
  });

  const a8=Q('da_daily_practice_rhythm','驿站｜训练节奏',['驿站'],()=>R(
    '资料分析课后训练的最低节奏是什么？',
    '每天至少四篇资料分析，并复盘读材料和估算方法',
    ['每天至少四篇资料分析，并复盘读材料和估算方法','只背公式不做题','只刷数字推理','完全依靠选项均衡'],
    '这是学习提示，不是计算题。',
    '原课结尾强调资料分析要坚持每天四篇，训练读材料能力和划线/估算能力。'
  ));

  const tone=C('da_final_wording_edges','表达口径',['基础'],[a1,a4,a6],'all');
  const calc=C('da_final_variable_edges','变量升华',['技巧'],[a2,a3,a5,a7],'all');
  const station=C('da_final_station','驿站',['驿站'],[a8],'all');
  add(C('da_final_audit_card','读题口径｜范围与策略',['运用'],[tone,calc,station],'all'));
})();

// ----- lessons/data_analysis_speed_11/18_section_position_detail.js -----
EX.sec('定位细节｜口径与迁移');

// ----- lessons/data_analysis_speed_11/19_position_detail_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('da_object_missing_total_part','对象未直给',['基础'],()=>{
    const total=n(2400,5200), part=n(900,2200); const other=total-part;
    const obj=pk(['非养殖水产品','非东部地区投资','非铁路出行人数','非公立机构数量']);
    return R(
      `材料只直接给出“总量 ${total}”和“已知部分 ${part}”，题目问“${obj}”。第一反应是什么？`,
      '先用总量与已知部分推出未知部分',
      op('先用总量与已知部分推出未知部分',['直接说材料没有无法做','只拿已知部分当答案','只看选项均衡']),
      '对象没直给时，先看它是否是整体中的剩余部分。',
      `未知部分=${total}-${part}=${other}。增长率类还可进一步用混合原理判断方向。`
    );
  });

  const q2=Q('da_first_para_priority_boundary','首段优先边界',['基础'],()=>R(
    '“第一题一般在第一段”应该如何使用？',
    '先看第一段，但对象不在第一段就继续往下找',
    op('先看第一段，但对象不在第一段就继续往下找',['第一段没有就跳题','永远只用第一段数据','第一题一定不用看对象限定']),
    '首段优先是节能顺序，不是材料范围规则。',
    '原课说第一题一般在第一段，是为了提升定位效率；真正做题仍以时间、对象、问法为准。'
  ));

  const q3=Q('da_trade_money_not_volume','贸易看额不看量',['基础'],()=>{
    const expAmt=n(70,130), impAmt=n(20,60); const expQty=n(80,160), impQty=n(170,260);
    return R(
      `某产品出口额 ${expAmt} 亿元、进口额 ${impAmt} 亿元；出口量 ${expQty} 万吨、进口量 ${impQty} 万吨。若问“贸易顺逆差”，看哪组数据？`,
      '看出口额和进口额',
      op('看出口额和进口额',['看出口量和进口量','看出口增长率','看进口增长率']),
      '顺差、逆差是金额口径。',
      `贸易状态看钱：${expAmt}>${impAmt}，所以是顺差；数量口径不能替代金额口径。`
    );
  });

  const q4=Q('da_lowest_share_most_not_choose','最低占比推出多数不选',['运用'],()=>{
    const small=n(4,9), total=100; const not=total-small;
    const item=pk(['超过8小时高铁行程','某冷门营销事件','某低频出行因素','某少数行业']);
    return R(
      `图表显示选择“${item}”的占比只有 ${small}%，且为最低项。若选项说“绝大部分被调查者不选择它”，应如何判断？`,
      '可以支持，约有绝大部分不选择',
      op('可以支持，约有绝大部分不选择',['不能判断，因为必须精确人数','一定错误，因为最低不等于少','只能说明一半人不选择']),
      '占比很低时，其互补占比很高。',
      `不选择比例约为 ${not}%，可理解为绝大部分不选择。注意这是由占比互补推出的。`
    );
  });

  const q5=Q('da_point_not_percent_multiply','百分点不是乘法',['基础'],()=>{
    const cur=n(45,70), diff=n(2,6); const ans=cur+diff;
    return R(
      `现期比重为 ${cur}%，比上年降低 ${diff} 个百分点。上年比重是多少？`,
      `${ans}%`,
      op(`${ans}%`,[`${Math.round(cur*(1+diff/100))}%`,`${cur-diff}%`,`${diff}%`]),
      '百分点变化是直接加减，不是乘以百分比。',
      `降低 ${diff} 个百分点，说明上年更高，直接 ${cur}+${diff}=${ans}%。`
    );
  });

  const q6=Q('da_training_ability_target','驿站｜训练目标',['驿站'],()=>R(
    '每天四篇资料分析，主要练的不是背题，而是什么能力？',
    '读数据、读材料、划线法、估算法和做题技巧熟练度',
    ['读数据、读材料、划线法、估算法和做题技巧熟练度','只记住每道例题答案','只练蒙题概率','只背顺差逆差定义'],
    '这是训练目标节点。',
    '训练要点强调每天四篇是为了保持读材料能力、读数据能力、划线法、估算法和技巧熟练度。'
  ));

  const locate=C('da_round3_locate_edges','定位细口径',['基础'],[q1,q2,q3],'all');
  const judge=C('da_round3_judge_edges','判断细口径',['技巧'],[q4,q5],'all');
  const station=C('da_round3_training_station','驿站',['驿站'],[q6],'all');
  add(C('da_round3_audit_card','定位细节｜口径与迁移',['运用'],[locate,judge,station],'all'));
})();

// ----- lessons/data_analysis_speed_11/20_section_estimate_weight.js -----
EX.sec('估算边界｜权重与极值');

// ----- lessons/data_analysis_speed_11/21_estimate_weight_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('da_decline_reverse_float','下降倒推近似上浮',['技巧'],()=>{
    const base=n(260,520); const r=pk([6,8,9,10]);
    const now=Math.round(base*(100-r)/100);
    const rough=now+Math.round(now*r/100);
    const ans='比现期大，约等于现期上浮一点';
    return R(
      `现期 ${now}，同比下降 ${r}%。求基期时，第一反应应是什么？`,
      ans,
      op(ans,['比现期小，直接减去下降率','等于现期，不用倒推','一定是现期的两倍']),
      '下降后倒推是除以 1-降幅，基期一定比现期大。',
      `基期=${now}÷(1-${r}%)，一定大于 ${now}。粗估可理解为现期上浮约 ${r}% 左右，约 ${rough} 附近，不是再减一次。`
    );
  });

  const q2=Q('da_mix_weight_distance','混合距离看基数',['技巧'],()=>{
    const big=n(6,12)*100; const small=n(1,4)*100;
    const rBig=n(5,10), rSmall=n(-4,2);
    const whole=Math.round((big*rBig+small*rSmall)/(big+small)*10)/10;
    const ans=`更接近 ${rBig}%`;
    return R(
      `A 部分量 ${big}、增长率 ${rBig}%；B 部分量 ${small}、增长率 ${rSmall}%。整体增长率约 ${whole}%。它应更接近谁？`,
      ans,
      op(ans,[`更接近 ${rSmall}%`,'一定在两者正中间','一定等于两者相加']),
      '混合率不只夹在两者之间，还会更靠近基数大的部分。',
      `A 的基数明显更大，所以整体增长率虽然夹在 ${rSmall}% 和 ${rBig}% 之间，但更靠近 A 的 ${rBig}%。这能排除过于极端的选项。`
    );
  });

  const q3=Q('da_rough_preserve_lead_digit','粗估保首位',['技巧'],()=>{
    const now=pk([2164,26575,13411]);
    const approx=Math.round(now/10)*10;
    const ans='不影响首位或选项档位时，可以用整百整十近似';
    return R(
      `考场估算中，${now} 近似看成 ${approx}。这种处理什么时候合理？`,
      ans,
      op(ans,['任何题都必须精确到个位','只要近似就一定错','只有没有选项时才允许近似']),
      '看选项差距和问题所需精度。',
      '原课多次用 197≈200、2164≈2160 这类处理。若只判断“三开头/二开头”或选项差距很大，保住首位和量级即可。'
    );
  });

  const q4=Q('da_small_rate_digit_expand','十以内四位估增长量',['技巧'],()=>{
    const r=pk([4.6,5.8,6.4,8.2]);
    const thousands=n(1,5); const hundreds=n(1,8);
    const val=thousands*1000+hundreds*100+n(0,9)*10;
    const ans=`约 ${Math.round(val*r/100)}`;
    return R(
      `${val} 增长 ${r}%。用“100/1000 增加多少”估增长量。`,
      ans,
      op(ans,[`约 ${Math.round(val*r/100)+20}`,`约 ${Math.max(1,Math.round(val*r/100)-20)}`,`约 ${val}`]),
      '增长率在 10% 以内时，四位数可拆成几个 1000、几个 100 来估。',
      `1000 增加 ${r*10}，100 增加 ${r}，所以 ${val}×${r}%≈${Math.round(val*r/100)}。位数越大，保留千百位估算更稳。`
    );
  });

  const q5=Q('da_rate_method_switch','十以内超十切换',['基础'],()=>{
    const r=pk([18.3,24.4,29.7,35.4]);
    return R(
      `增长率/降幅达到 ${r}% 左右时，还应优先用“100 增加多少”的小增长率法吗？`,
      '不应优先，应改用份数法、划线法或公式估算',
      op('不应优先，应改用份数法、划线法或公式估算',['应该，所有百分数都这样估','直接忽略增长率','只看尾数即可']),
      '原课把 10% 以内的小增长率法和 20%—30% 的划线/份数法分开。',
      `${r}% 已经不小，继续用“100 增加多少”容易乱数量级；应换成份数、划线或公式倒推。`
    );
  });

  const q6=Q('da_weight_delta_compare','权重差额比较',['技巧'],()=>{
    const w1=pk([20,30]); const w2=100-w1;
    const a1=n(78,88), a2=n(88,96);
    const b1=a1+n(5,10), b2=a2-n(1,5);
    const A=a1*w1+a2*w2; const B=b1*w1+b2*w2;
    const ans=A>B?'甲更高':'乙更高';
    return R(
      `综合分=指标1×${w1}%+指标2×${w2}%。甲为(${a1},${a2})，乙为(${b1},${b2})。不用全算，谁更高？`,
      ans,
      op(ans,['二者必然相等','只看指标1即可','只看指标2即可']),
      '比较加权差额：一项多多少乘权重，另一项少多少乘权重。',
      `甲-乙=(${a1}-${b1})×${w1}+(${a2}-${b2})×${w2}=${A-B}，所以${ans}。这就是原课权重题“看差额不必全算”的升华。`
    );
  });

  const q7=Q('da_table_extreme_then_growth','先找极值再算增长额',['技巧'],()=>{
    const maxNow=n(1000,1800), minNow=n(100,280);
    const rMax=pk([4.6,5.8,6.4]); const rMin=pk([-35.4,-29.7,-24.4]);
    const ans='先找绝对量最大和最小，再分别估增长额/减少额';
    return R(
      `表格题问“绝对量最大和最小的行业，增长额之差”。已知最大 ${maxNow}、增速 ${rMax}%，最小 ${minNow}、增速 ${rMin}%。第一步是什么？`,
      ans,
      op(ans,['直接把两个现期量相减','只比较增长率大小','只看最大行业即可']),
      '题干先限定对象，再限定计算。',
      '原课这类题先在表中找绝对量最大/最小的行业，再分别估增长额；如果一个为负增长，差值还要注意正负号。'
    );
  });

  const q8=Q('da_review_resources_station','驿站｜复习资源',['驿站'],()=>R(
    '结课后如果方法生疏，原课给出的恢复路径是什么？',
    '复习笔记与复盘材料，继续刷题，有问题交流复盘',
    ['复习笔记与复盘材料，继续刷题，有问题交流复盘','只看最终答案','放弃资料分析','只背选项均衡性'],
    '这是训练保障，不是计算题。',
    '最后要强调继续复习巩固笔记与复盘材料，训练读材料、读数据、划线法、估算法；有问题可讨论复盘。'
  ));

  const est=C('da_exhaustive_estimate_edges','估算边界',['技巧'],[q1,q3,q4,q5],'all');
  const structure=C('da_exhaustive_structure_edges','结构与权重',['技巧'],[q2,q6,q7],'all');
  const station=C('da_exhaustive_station','驿站',['驿站'],[q8],'all');
  add(C('da_exhaustive_audit_card','估算边界｜权重与极值',['运用'],[est,structure,station],'all'));
})();

// ----- lessons/data_analysis_speed_11/22_section_time_average.js -----
EX.sec('时间口径｜平均与比例细节');

// ----- lessons/data_analysis_speed_11/23_time_average_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('da_time_range_not_year_only','时间不只看年份',['基础'],()=>{
    const now=pk(['上半年','1—6月']); const asked=pk(['1—4月','1—5月']);
    return R(
      `材料给的是2015年${now}，题目问2015年${asked}增速。判断时间口径时，只看年份够吗？`,
      '不够，还要看累计区间或月份范围',
      op('不够，还要看累计区间或月份范围',['够，只要年份相同就是现期','直接按全年处理','只看对象不看时间']),
      '资料分析里的时间点包含年份，也包含上半年、1—4月、1—5月等范围。',
      `2015年${now}和2015年${asked}不是同一个累计区间。原课中“上半年降幅比1—4月扩大”就要用百分点修正，而不是只说年份相同。`
    );
  });

  const q2=Q('da_average_unit_identify','平均数由单位识别',['基础'],()=>{
    const money=n(80,150), tons=n(20,60);
    return R(
      `题目问“平均每吨出口价格”。材料同时给出口额 ${money} 亿元、出口量 ${tons} 万吨。平均数分子应选什么？`,
      '出口额',
      op('出口额',['出口量','出口额和出口量相加','同比增长率']),
      '平均每吨价格的单位是“钱/吨”，分子必须是钱。',
      `平均每吨价格=出口额÷出口量。原课专门提醒出口价格看“额”的增长率，出口量看“量”的增长率。`
    );
  });

  const q3=Q('da_ratio_bias_after_first_digit','首位后看偏向',['技巧'],()=>{
    const denom=n(360,420); const numer=n(65,85);
    const val=numer/denom;
    const ans=val>0.18?'接近20%':'接近18%';
    return R(
      `估算 ${numer}÷${denom}，首位判断为一成多后，还应进一步看什么？`,
      '看它更靠近18%还是20%等选项档位',
      op('看它更靠近18%还是20%等选项档位',['首位一开头就停止','直接看成1%','只比较分子尾数']),
      '首位只能排除大范围；选项接近时要看偏向。',
      `${numer}/${denom}≈${(val*100).toFixed(1)}%，${ans}。原课 71÷388 就是先看一开头，再判断更接近二成。`
    );
  });

  const q4=Q('da_opposite_rate_not_same_sum','正负同幅不等于合计不变',['技巧'],()=>{
    const a=n(80,160), b=n(60,140), r=pk([6,8,9,12]);
    return R(
      `甲现期 ${a}、同比下降 ${r}%；乙现期 ${b}、同比增长 ${r}%。能否直接认为“甲乙现期和与上年同期和相同”？`,
      '不能，基期分母不同，不能直接抵消',
      op('不能，基期分母不同，不能直接抵消',['能，增长率一正一负同幅必抵消','只要两个现期相同才不能抵消','只看百分点即可']),
      '现期合计与基期合计比较，要分别倒推，不能只看增长率符号。',
      `甲基期=${a}÷(1-${r}%)，乙基期=${b}÷(1+${r}%)；两个分母不同，且基数也可能不同，不能凭 +${r}% 和 -${r}% 判断合计不变。`
    );
  });

  const q5=Q('da_base_threshold_by_denominator','基期阈值看分母',['技巧'],()=>{
    const now=n(1200,1600); const r=pk([30,33,36]);
    const ans='小于现期，且可能低于1000要看分母是否超过约1.2—1.6';
    return R(
      `现期 ${now}，同比增长 ${r}%。判断上年是否不到1000时，第一眼看什么？`,
      ans,
      op(ans,['一定大于现期','直接把增长率加到现期上','只看现期尾数']),
      '正增长倒推基期，分母是 1+r，基期小于现期。',
      `基期=${now}÷1.${r}，先用分母大小判断是否跌破阈值。原课“不到1000家”就是用分母大于1来快速判断。`
    );
  });

  const q6=Q('da_share_difference_times_total','占比差乘总数',['技巧'],()=>{
    const total=pk([1000,1500,2000,3000]); const p1=n(45,65); const p2=n(20,40);
    const diff=p1-p2; const ans=String(Math.round(total*diff/100));
    return R(
      `总人数 ${total}，A 占 ${p1}%，B 占 ${p2}%。问 A 比 B 多多少人，应怎样算？`,
      ans,
      op(ans,[String(diff),String(total*p1/100),String(total*p2/100)]),
      '先求占比差，再乘总人数。',
      `占比差=${p1}%-${p2}%=${diff}%，人数差=${total}×${diff}%=${ans}。原课火车与飞机人数差就是这个模型。`
    );
  });

  const q7=Q('da_first_segment_not_material_whole','定位不是通读全篇',['运用'],()=>R(
    '资料分析定位时，是否每题都必须从材料第一字读到最后一字？',
    '不需要，先用题干关键词定位，但对象不匹配时继续往下找',
    op('不需要，先用题干关键词定位，但对象不匹配时继续往下找',['必须逐字通读完整材料','只看第一句话即可','只看图表标题即可']),
    '课程强调效率：先看问法、时间、对象，再找关键词；但不能错过后文限定。',
    '第一题常在第一段只是经验，真正动作是关键词定位。若前面出现“固定资产投资”但没有“东北地区”，就要继续找东北地区数据。'
  ));


  const time=C('da_round1_time_edges','时间与定位',['基础'],[q1,q7],'all');
  const avg=C('da_round1_average_edges','平均与比例',['技巧'],[q2,q3,q6],'all');
  const base=C('da_round1_base_edges','基期与合计',['技巧'],[q4,q5],'all');
  add(C('da_audit_round1_card','时间口径｜平均与比例细节',['运用'],[time,avg,base],'all'));
})();

