// ----- lessons/data_analysis_speed_11_EX/_common.js -----
(function(){
  const pk=a=>a[Math.floor(Math.random()*a.length)];
  const n=(a,b)=>a+Math.floor(Math.random()*(b-a+1));
  const uq=a=>[...new Set(a)];
  const sh=a=>a.map(v=>[Math.random(),v]).sort((x,y)=>x[0]-y[0]).map(x=>x[1]);
  const op=(a,b,l=4)=>sh([a,...sh(uq(b).filter(x=>x!==a)).slice(0,l-1)]);
  const R=(q,a,pool,hint,solution,extra={})=>Object.assign({q,a,pool,hint,solution},extra);
  const cid='data_analysis_speed_11_EX';
  const Q=(id,title,tags,mk,type)=>({id,title,t:title,type:type||tags[0],tags,mk,makeQuestion:mk});
  const C=(id,title,tags,subs,unlockMode='all')=>({id,title,t:title,type:tags[0],tags,unlockMode,subs});
  const sec=title=>Game.addLessonTopic(cid,{k:'s',t:title});
  const add=t=>Game.addLessonTopic(cid,t);
  const done=title=>Game.finishLesson(cid,title);
  Game.beginLesson(cid);
  window.EX={pk,n,uq,sh,op,R,Q,C,sec,add,done};
})();

// ----- lessons/data_analysis_speed_11_EX/00_section_route.js -----
EX.sec('数字推理｜总路线与一眼识别');

// ----- lessons/data_analysis_speed_11_EX/01_route.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('ns_route_three_times','三倍以内',['基础'],()=>R(
    '单调数列，且相邻项大多在三倍以内，优先考虑什么？',
    '和差分析',
    op('和差分析',['数字拆分','矩阵行列','分数通分']),
    '单调+三倍以内，是做差、做和、二级差的入口。',
    '课程口诀：单调数列三倍以内，优先和差分析，最常用是做差。'
  ));

  const q2=Q('ns_route_big_multiple','多处三倍以上',['基础'],()=>R(
    '数列中多处相邻项超过三倍，或明显成倍数，优先考虑什么？',
    '倍数或次方',
    op('倍数或次方',['削峰填谷','顺差逆差','百分点修正']),
    '超过三倍说明变化强烈，和差往往不是第一方向。',
    '若数据本身或附近像 8、27、64、125 等，优先次方；若倍数清楚，优先倍数。'
  ));

  const q3=Q('ns_route_up_down','忽大忽小',['基础'],()=>R(
    '数列忽大忽小、上下跳动时，优先考虑什么？',
    '间隔分组',
    op('间隔分组',['直接精算增长率','权重计算','顺差逆差']),
    '忽大忽小常是奇数项、偶数项各自成规律。',
    '间隔分组就是把第1、3、5项和第2、4、6项分开看。'
  ));

  const q4=Q('ns_route_many_terms','七项及以上',['基础'],()=>R(
    '数列项数达到七项及以上，必须提高警惕优先考虑什么？',
    '分组数列',
    op('分组数列',['贸易差额','平均数升降','基期比重']),
    '项数多时，分组能减少观察对象。',
    '分组包括间隔分组、两两分组、三三分组。'
  ));

  const q5=Q('ns_route_secondary','常规无规律',['基础'],()=>R(
    '做差、倍数、次方、分组都试不出规律时，下一步常考虑什么？',
    '数字拆分等二级考点',
    op('数字拆分等二级考点',['继续盲目做差','只按选项均衡','把题目放弃但不记录']),
    '二级考点通常更特殊，但不是第一反应。',
    '广东题中数字拆分较常见，尤其三位数、四位数以上。'
  ));

  add(C('ns_route_card','总路线｜趋势倍数项数',['基础'],[q1,q2,q3,q4,q5],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/02_difference.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const r1=Q('ns_diff_identify','入口识别',['基础'],()=>R(
    '和差分析最常用、最先试的一步是什么？',
    '做差',
    op('做差',['通分','查顺差','算权重']),
    '单调三倍以内时，先看相邻差。',
    '做差后可能是一阶等差、二级等差、倍数差或递推关系。'
  ));

  const d1=Q('ns_first_diff_constant','一级差常数',['技巧'],()=>{
    const a=n(1,30), d=n(2,15);
    const arr=[a,a+d,a+2*d,a+3*d];
    const ans=String(a+4*d);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(a+5*d),String(a+3*d+d+1),String(a+4*d-1)]),
      '相邻差相同，下一项继续加同一个差。',
      `差值都是 ${d}，所以下一项是 ${arr[3]}+${d}=${ans}。`
    );
  });

  const d2=Q('ns_second_diff','二级差',['技巧'],()=>{
    const a=n(5,30), d1v=n(1,6), step=n(2,5);
    const arr=[a];
    let diff=d1v;
    for(let i=0;i<4;i++){arr.push(arr[arr.length-1]+diff); diff+=step;}
    const ans=String(arr[4]+diff);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(Number(ans)+step),String(arr[4]+d1v),String(arr[4]*2)]),
      '先做一级差，若一级差成等差，再回带。',
      `一级差为 ${d1v}、${d1v+step}、${d1v+2*step}、${d1v+3*step}，下一差为 ${diff}，答案 ${arr[4]}+${diff}=${ans}。`
    );
  });

  const d3=Q('ns_recursive_sum','递推和',['技巧'],()=>{
    const a=n(1,6), b=n(2,9);
    const arr=[a,b,a+b,a+2*b,2*a+3*b];
    const ans=String(arr[3]+arr[4]);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(arr[4]+1),String(arr[4]*2),String(arr[2]+arr[4])]),
      '观察前两项能否相加得到后一项。',
      `${arr[0]}+${arr[1]}=${arr[2]}，${arr[1]}+${arr[2]}=${arr[3]}，${arr[2]}+${arr[3]}=${arr[4]}，所以下一项 ${arr[3]}+${arr[4]}=${ans}。`
    );
  });

  const drill=C('ns_diff_variable_route','变量训练',['技巧'],[d1,d2,d3],'sequence');
  add(C('ns_diff_card','和差分析｜做差与递推',['技巧'],[r1,drill],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/03_multiple_power.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const b1=Q('ns_multiple_rule','倍数入口',['基础'],()=>R(
    '什么时候优先考虑倍数或次方，而不是先做差？',
    '多处相邻项超过三倍或倍数明显',
    op('多处相邻项超过三倍或倍数明显',['只有一个局部超过三倍','题干出现百分号','选项有零']),
    '个别超过三倍不一定改方向，多处才更像倍数次方。',
    '课程强调：只有个别超过三倍时仍可先和差；多处超过三倍才优先倍数或次方。'
  ));

  const b2=Q('ns_multiple_drill','倍数变化',['技巧'],()=>{
    const a=n(1,5);
    const ms=pk([[2,2,2,2],[4,3,2,1],[1,2,4,8]]);
    const arr=[a];
    ms.forEach(m=>arr.push(arr[arr.length-1]*m));
    const nextM=ms[0]===4?5:(ms[0]===1?16:2);
    const ans=String(arr[arr.length-1]*nextM);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(arr[arr.length-1]+nextM),String(arr[arr.length-1]*2),String(arr[arr.length-1]*nextM+nextM)]),
      '先看相邻倍数是否有固定或变化规律。',
      `相邻倍数为 ${ms.join('、')}，下一倍数为 ${nextM}，答案 ${arr[arr.length-1]}×${nextM}=${ans}。`
    );
  });

  const p1=Q('ns_power_identify','次方识别',['基础'],()=>R(
    '数据本身或附近出现 8、27、64、125 等，应优先想到什么？',
    '次方数列',
    op('次方数列',['顺差逆差','削峰填谷','百分点']),
    '这些数是立方或平方的典型锚点。',
    '若数据是次方数±1，也可按次方数边上拆。'
  ));

  const p2=Q('ns_power_plus_one','次方数加一',['技巧'],()=>{
    const add=pk([-1,1]);
    const start=n(1,3);
    const arr=[];
    for(let i=start;i<start+4;i++) arr.push(i*i*i+add);
    const ans=String((start+4)*(start+4)*(start+4)+add);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String((start+4)*(start+4)*(start+4)),String((start+5)*(start+5)*(start+5)+add),String(Number(ans)+2)]),
      `把每项看成连续立方数${add>0?'+1':'-1'}。`,
      `规律为 ${start}³${add>0?'+1':'-1'} 到 ${start+3}³${add>0?'+1':'-1'}，下一项是 ${start+4}³${add>0?'+1':'-1'}=${ans}。`
    );
  });

  const drill=C('ns_multiple_power_route','变量训练',['技巧'],[b2,p2],'sequence');
  add(C('ns_multiple_power_card','倍数次方｜强变化数列',['技巧'],[b1,p1,drill],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/04_section_grouping.js -----
EX.sec('数字推理｜分组数列');

// ----- lessons/data_analysis_speed_11_EX/05_grouping.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const g1=Q('ns_group_trigger','分组触发',['基础'],()=>R(
    '数列七项及以上时，优先进入哪个大方向？',
    '分组数列',
    op('分组数列',['贸易顺差','基期比重','权重平均']),
    '项数多，直接全局找规律效率低。',
    '分组可以减少观察对象，包括间隔、两两、三三。'
  ));

  const i1=Q('ns_interval_rule','间隔规则',['基础'],()=>R(
    '间隔分组本质是把哪些项分开看？',
    '奇数项和偶数项',
    op('奇数项和偶数项',['最大项和最小项','整数和小数','分子和分母']),
    '忽大忽小尤其适合这样看。',
    '第1、3、5项单独成规律，第2、4、6项单独成规律。'
  ));

  const i2=Q('ns_interval_drill','忽大忽小',['技巧'],()=>{
    const a=n(20,40), b=n(20,40), d=n(1,4), e=n(1,4);
    const arr=[a,b,a-d,b+e,a-2*d,b+2*e];
    const ans=String(a-3*d);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(b+3*e),String(a+d),String(b-e)]),
      '奇数项递减，偶数项递增。',
      `奇数项 ${a}、${a-d}、${a-2*d}，下一奇数项为 ${a-3*d}。`
    );
  });

  const t1=Q('ns_pair_type','两两类型',['基础'],()=>R(
    '两两分组有哪两类？',
    '独立型和交叉型',
    op('独立型和交叉型',['现期型和基期型','顺差型和逆差型','整数型和百分型']),
    '独立型不重叠，交叉型相邻两项重叠。',
    '偶数项较多可先独立分；奇数项两两分组常要交叉。'
  ));

  const t2=Q('ns_pair_independent','独立两两',['技巧'],()=>{
    const starts=[n(1,10),n(1,10),n(1,10)];
    const sums=[10,14,18];
    const arr=[];
    for(let i=0;i<3;i++){arr.push(starts[i]);arr.push(sums[i]-starts[i]);}
    const x=n(1,10), nextSum=22;
    arr.push(x);
    const ans=String(nextSum-x);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(x+nextSum),String(nextSum),String(Math.abs(x-ans))]),
      '两个两个独立成组，看每组内部和。',
      `每组和为 10、14、18、22，最后一组已有 ${x}，所以答案 ${nextSum}-${x}=${ans}。`
    );
  });

  const t3=Q('ns_pair_cross','交叉两两',['技巧'],()=>{
    const a=n(2,8), b=n(3,9);
    const arr=[a,b];
    for(let i=0;i<4;i++) arr.push(arr[i]+arr[i+1]);
    const ans=String(arr[4]+arr[5]);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(arr[5]+1),String(arr[4]*arr[5]),String(arr[5]-arr[4])]),
      '交叉两两看，相邻两项相加得到后面的某项。',
      `从第3项起，每项等于前两项之和，下一项=${arr[4]}+${arr[5]}=${ans}。`
    );
  });

  const h1=Q('ns_triple_cross','交叉三三',['技巧'],()=>{
    const arr=[n(1,5),n(1,5),n(1,5),n(1,5),n(1,5)];
    const s1=arr[0]+arr[1]+arr[2];
    const s2=arr[1]+arr[2]+arr[3];
    const s3=arr[2]+arr[3]+arr[4];
    const step=n(2,5);
    const target=s3+step;
    const ans=String(target-arr[3]-arr[4]);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(Number(ans)+step),String(target),String(arr[4]+step)]),
      '三三交叉分组，看每组三项和的变化。',
      `前三组三项和为 ${s1}、${s2}、${s3}。设下一组和延续到 ${target}，则答案=${target}-${arr[3]}-${arr[4]}=${ans}。`
    );
  });

  const interval=C('ns_interval_branch','间隔',['技巧'],[i1,i2],'sequence');
  const pair=C('ns_pair_branch','两两',['技巧'],[t1,t2,t3],'sequence');
  const triple=C('ns_triple_branch','三三',['技巧'],[h1],'all');
  const drill=C('ns_group_variable_route','变量训练',['技巧'],[interval,pair,triple],'all');
  add(C('ns_group_card','分组数列｜间隔两两三三',['技巧'],[g1,drill],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/06_section_special.js -----
EX.sec('数字推理｜拆分、分数、小数、矩阵');

// ----- lessons/data_analysis_speed_11_EX/07_split_fraction_decimal_matrix.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const s1=Q('ns_split_trigger','拆分触发',['基础'],()=>R(
    '常规做差、倍数、次方、分组都无规律，且每项多为三位数以上，优先考虑什么？',
    '数字拆分',
    op('数字拆分',['顺差逆差','平均数升降','基期比重']),
    '拆分属于二级考点，不是第一反应。',
    '三位数、四位数以上尤其常见，可从中间或按位拆。'
  ));

  const s2=Q('ns_split_drill','两段拆分',['技巧'],()=>{
    const a=n(12,20), step=n(1,3);
    const b=n(20,40), bstep=n(2,5);
    const arr=[];
    for(let i=0;i<4;i++) arr.push(String(a+i*step)+String(b+i*bstep));
    const ans=String(a+4*step)+String(b+4*bstep);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(a+4*step)+String(b+3*bstep),String(a+3*step)+String(b+4*bstep),String((a+4*step)*(b+4*bstep))]),
      '把四位数从中间拆成前两位和后两位。',
      `前两位为 ${a}、${a+step}、${a+2*step}、${a+3*step}，后两位为 ${b}、${b+bstep}、${b+2*bstep}、${b+3*bstep}，下一项为 ${ans}。`
    );
  });

  const f1=Q('ns_fraction_trigger','分数入口',['基础'],()=>R(
    '分数项多于整数项时，第一步通常先做什么？',
    '化简，再看分子分母',
    op('化简，再看分子分母',['直接通分所有项','只看整数项','按顺差判断']),
    '分数可能被包装过。',
    '化简后，分子单独看、分母单独看；若分母倍数明显，再考虑通分做差。'
  ));

  const f2=Q('ns_fraction_drill','分子分母',['技巧'],()=>{
    const top=n(1,4);
    const start=n(2,5);
    const arr=[`${top}/${start}`,`${top}/${start+1}`,`${top}/${start+2}`,`${top}/${start+3}`];
    const ans=`${top}/${start+4}`;
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[`${top+1}/${start+4}`,`${top}/${start+3}`,`${top+start}/${start+4}`]),
      '分子不变，分母等差增加。',
      `分母为 ${start}、${start+1}、${start+2}、${start+3}，下一项为 ${ans}。`
    );
  });

  const d1=Q('ns_decimal_rule','小数规则',['基础'],()=>R(
    '小数数列和分数数列相似，小数点相当于什么？',
    '分数线',
    op('分数线',['增长率','权重','顺差线']),
    '小数点前后可分开看。',
    '整数部分对应分子思路，小数部分对应分母思路；也可用前一项整数部分和小数部分运算推出后项。'
  ));

  const d2=Q('ns_decimal_drill','整数小数拆看',['技巧'],()=>{
    const a=n(1,4), b=n(1,5), c=n(1,4), e=n(1,4);
    const ints=[a,b,a+b,a+2*b,2*a+3*b];
    const decs=[c,e,c+e,c+2*e,2*c+3*e];
    const arr=ints.slice(0,4).map((v,i)=>`${v}.${decs[i]}`);
    const ans=`${ints[4]}.${decs[4]}`;
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[`${ints[3]}.${decs[3]}`,`${ints[4]}.${decs[3]}`,`${ints[3]}.${decs[4]}`]),
      '整数部分、小数部分分别按递推和看。',
      `整数部分 ${ints.slice(0,4).join('、')}，下一项为 ${ints[4]}；小数部分 ${decs.slice(0,4).join('、')}，下一项为 ${decs[4]}，所以答案 ${ans}。`
    );
  });

  const m1=Q('ns_matrix_rule','矩阵看法',['基础'],()=>R(
    '方框/矩阵型数字推理，优先从哪里看？',
    '从数据少的一边按行或列看',
    op('从数据少的一边按行或列看',['只看最大数','按资料分析公式','先猜选项均衡']),
    '方框只是排版，规律仍是加减乘除。',
    '一行三个数时，优先看前两个数如何通过四则运算得到第三个数；不行再看列。'
  ));

  const m2=Q('ns_matrix_drill','行内关系',['技巧'],()=>{
    const x=n(1,9), y=n(2,9), add=n(-2,2);
    const ans=String(x*y+add);
    return R(
      `某一行前两个数是 ${x}、${y}，本矩阵规则为“前两数相乘后${add>=0?'加':'减'} ${Math.abs(add)} 得第三数”。第三数应为？`,
      ans,
      op(ans,[String(x+y+add),String(x*y),String(x*y-add)]),
      '方框题本质仍是行列内的四则关系。',
      `${x}×${y}${add>=0?'+':'-'}${Math.abs(add)}=${ans}。`
    );
  });

  const split=C('ns_split_branch','拆分',['技巧'],[s1,s2],'sequence');
  const frac=C('ns_fraction_branch','分数',['技巧'],[f1,f2],'sequence');
  const dec=C('ns_decimal_branch','小数',['技巧'],[d1,d2],'sequence');
  const mat=C('ns_matrix_branch','矩阵',['技巧'],[m1,m2],'sequence');
  add(C('ns_special_card','特殊数列｜拆分分数小数矩阵',['技巧'],[split,frac,dec,mat],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/08_section_strategy.js -----
EX.sec('数字推理｜严密性与考场策略');

// ----- lessons/data_analysis_speed_11_EX/09_rigor_strategy.js -----
(function(){
  const {R,Q,C,add}=EX;

  const q1=Q('ns_rigor_three_to_four','三组推一组',['运用'],()=>R(
    '数字推理中，更严密的规律通常至少应满足什么？',
    '三组关系成立再推下一组',
    ['三组关系成立再推下一组','两组关系就一定正确','只要选项有就永远正确','越复杂越正确'],
    '严密性决定哪个规律更优先。',
    '课程强调：两组推第三组不一定错，但不够稳；若有三组推第四组的规律，应优先选更严密的。'
  ));

  const q2=Q('ns_not_overfit','避免硬凑',['运用'],()=>R(
    '遇到一个勉强能套但不严密的规律，正确策略是什么？',
    '先找是否有更严密规律',
    ['先找是否有更严密规律','立刻放弃整套题','一定选最复杂规律','只看尾数'],
    '行测要快，但不能盲目硬凑。',
    '如果常规路线已有稳定规律，就不用采用更牵强的规律；若都做不出，有选项时可作为考场应急。'
  ));

  const q3=Q('ns_give_up','个别难题',['运用'],()=>R(
    '数字推理遇到个别特别偏、特别不严密的题，最节能的处理是？',
    '合理放掉，不拖累整套题',
    ['合理放掉，不拖累整套题','无限计算到最后','把所有题都按拆分做','完全不复盘'],
    '数字推理是小模块，时间不能失控。',
    '课程结尾也提醒：把高频口诀掌握，个别偏题可以放掉。'
  ));

  add(C('ns_strategy_card','严密策略｜不硬凑不恋战',['运用'],[q1,q2,q3],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/10_section_special_completion.js -----
EX.sec('数字推理｜拆分分组与特殊关系');

// ----- lessons/data_analysis_speed_11_EX/11_special_completion_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  function twoDigitWithSum(s){
    const a=Math.max(1,Math.min(9,n(Math.max(1,s-9),Math.min(9,s-1))));
    return String(a)+String(s-a);
  }

  const t1=Q('ns_two_digit_split_sum','两位拆分求和',['技巧'],()=>{
    const s1=n(5,8), s2=s1+n(3,5), s3=s2+n(3,5);
    const arr=[twoDigitWithSum(s1),twoDigitWithSum(s1),twoDigitWithSum(s2),twoDigitWithSum(s2),twoDigitWithSum(s3)];
    const ans=twoDigitWithSum(s3);
    return R(
      `${arr.join('，')}，？。若按“数字拆开后位数和两项一组重复”看，下一项可选哪一个？`,
      ans,
      op(ans,[twoDigitWithSum(s1),twoDigitWithSum(s2),twoDigitWithSum(Math.max(3,s3-2))]),
      '两位数拆成十位和个位，先看位数和。',
      `前两项位数和为 ${s1}，中间两项为 ${s2}，后面应连续两项位数和为 ${s3}，所以选 ${ans}。`
    );
  });

  const t2=Q('ns_four_digit_split_review','多位数拆分方向',['基础'],()=>R(
    '三位数、四位数数列常规方法无规律时，拆分优先怎么想？',
    '按位或从中间拆开看',
    op('按位或从中间拆开看',['直接当资料分析做','只比较大小','只看最后一项']),
    '多位数是拆分高发信号。',
    '四位数常可拆成前两位和后两位；三位数可拆成首位/后两位或前两位/个位。'
  ));

  const f1=Q('ns_fraction_cross_relation','前后分子分母关系',['技巧'],()=>R(
    '1/2，3/5，8/13，？ 若每一项的分子分母相加依次参与后一项，下一项应为？',
    '21/34',
    op('21/34',['13/21','11/18','8/21']),
    '不要只会分子、分母各自看，也要看前一个分数内部与后一项的关系。',
    '1+2=3，2+3=5；3+5=8，5+8=13；所以下一项是 8+13=21，13+21=34。'
  ));

  const f2=Q('ns_fraction_common_denominator','通分做差',['技巧'],()=>R(
    '1/3，5/12，1/2，？ 若通分为十二分母后看分子等差，下一项应为？',
    '7/12',
    op('7/12',['2/3','1/4','5/6']),
    '分母存在明显倍数时，可以通分后做差。',
    '1/3=4/12，5/12=5/12，1/2=6/12，分子 4、5、6，下一项为 7/12。'
  ));

  const d1=Q('ns_decimal_internal_relation','小数内部运算',['技巧'],()=>R(
    '小数数列除了“整数部分、小数部分分别成规律”，还要注意哪条路线？',
    '前一项整数部分和小数部分加减乘除后影响后一项',
    op('前一项整数部分和小数部分加减乘除后影响后一项',['只看小数点个数','直接全部去掉小数点','按顺差逆差判断']),
    '小数点像分数线，点前点后既可分开看，也可内部运算。',
    '例如 3.4 的 3 和 4 可以相加、相减、相乘后，与后一项的整数部分或小数部分形成关系。'
  ));

  const d2=Q('ns_decimal_recursive_sum','小数递推和',['技巧'],()=>R(
    '2.0，0.2，2.2，2.4，？ 按前两项相加看，下一项为？',
    '4.6',
    op('4.6',['2.6','4.4','3.6']),
    '小数也可以按普通数列做递推和。',
    '2.0+0.2=2.2，0.2+2.2=2.4，所以 2.2+2.4=4.6。'
  ));

  const g1=Q('ns_triple_independent','独立三三分组',['技巧'],()=>{
    const s1=n(12,20), step=n(3,6);
    const a=n(2,5), b=n(2,5), c=s1-a-b;
    const d=n(3,7), e=n(3,7), f=s1+step-d-e;
    const g=n(4,8), h=n(4,8), ansNum=s1+2*step-g-h;
    const ans=String(ansNum);
    return R(
      `${a}，${b}，${c}，${d}，${e}，${f}，${g}，${h}，？。按三三独立分组求和，？为多少？`,
      ans,
      op(ans,[String(ansNum+1),String(ansNum-1),String(ansNum+step)]),
      '三三分组不只有交叉型，也有独立型。',
      `前三项和 ${s1}，中三项和 ${s1+step}，后三项和应为 ${s1+2*step}，所以 ?=${s1+2*step}-${g}-${h}=${ansNum}。`
    );
  });

  const g2=Q('ns_group_reduce_terms','分组的目的',['基础'],()=>R(
    '七项及以上为什么常考虑分组？',
    '把长数列压缩成更少的观察对象',
    op('把长数列压缩成更少的观察对象',['让题目必然变成等差','消除所有负数','保证答案唯一为 A']),
    '分组不是为了形式，而是为了降复杂度。',
    '两两或三三分组后，原本很多项会变成少量组，再看每组内部或组间规律。'
  ));

  const m1=Q('ns_matrix_four_terms','矩阵四项关系',['技巧'],()=>{
    const a=n(1,9), b=n(1,9), c=n(1,9);
    const ans=String(a+b+c);
    return R(
      `某矩阵每行四个数，规则为前三个数相加得第四个数。若一行为 ${a}、${b}、${c}、？则？为多少？`,
      ans,
      op(ans,[String(a*b+c),String(a+b),String(a+c)]),
      '矩阵题一行若有四项，可看前三项如何推出第四项。',
      `${a}+${b}+${c}=${ans}。行内不行再考虑列内。`
    );
  });

  const split=C('ns_split_completion_route','拆分补足',['技巧'],[t1,t2],'sequence');
  const fraction=C('ns_fraction_completion_route','分数补足',['技巧'],[f1,f2],'sequence');
  const decimal=C('ns_decimal_completion_route','小数补足',['技巧'],[d1,d2],'sequence');
  const grouping=C('ns_group_completion_route','分组补足',['技巧'],[g1,g2],'sequence');
  const matrix=C('ns_matrix_completion_route','矩阵补足',['技巧'],[m1],'all');
  add(C('ns_completion_card','特殊关系｜拆分分组与边界',['运用'],[split,fraction,decimal,grouping,matrix],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/12_section_route_migration.js -----
EX.sec('数字推理｜路线边界与迁移');

// ----- lessons/data_analysis_speed_11_EX/13_route_migration_edges.js -----

(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const t1=Q('ns_tail_digit','尾数锁定',['技巧'],()=>{
    const a=n(10,60), d=pk([12,22,32]);
    const arr=[a,a+d,a+2*d,a+3*d];
    const ans=String(a+4*d);
    const tail=ans.slice(-1);
    return R(
      `${arr.join('，')}，？。若已判断下一步应加 ${d}，答案尾数应为？`,
      tail,
      op(tail,[String((Number(tail)+1)%10),String((Number(tail)+3)%10),String((Number(tail)+5)%10)]),
      '数字推理算出大致规律后，可用尾数快速锁选项。',
      `下一项=${arr[3]}+${d}=${ans}，尾数为 ${tail}。`
    );
  });

  const t2=Q('ns_construct_network','构造网络',['基础'],()=>R(
    '一级做差后差值本身没有明显规律，课程提示还要看什么？',
    '差值与原数列能否构造关系',
    op('差值与原数列能否构造关系',['出口额是否大于进口额','比重是否降低三个百分点','是否属于资料分析']),
    '不要只盯着差值序列本身。',
    '原课路线是：做差无规律后，看差值和原数列有没有网络关系；还不行再考虑二级差或特殊考点。'
  ));

  const t3=Q('ns_descending_diff','单调递减也和差',['技巧'],()=>{
    const last=n(10,50), d=n(3,12);
    const arr=[last+4*d,last+3*d,last+2*d,last+d,last];
    const ans=String(last-d);
    return R(
      `${arr.join('，')}，？`,
      ans,
      op(ans,[String(last+d),String(last-2*d),String(last*d)]),
      '单调递减且三倍以内，也可做差看规律。',
      `每次减少 ${d}，所以下一项是 ${last}-${d}=${ans}。`
    );
  });

  const t4=Q('ns_nonmonotone_not_diff_first','非单调别机械做差',['运用'],()=>R(
    '1，2，2，4，8，？ 这种不严格单调的数列，为什么不应机械先做差？',
    '整体有更明显的前两项相乘得后一项',
    op('整体有更明显的前两项相乘得后一项',['因为所有数都超过三倍','因为只能用拆分','因为必须通分']),
    '和差分析的优先入口是单调三倍以内。',
    '这里 1×2=2，2×2=4，2×4=8，所以下一项 4×8=32，比硬做差更稳。'
  ));

  const p1=Q('ns_pair_difference_route','两两分组做差',['技巧'],()=>{
    const starts=[n(20,40),n(20,40),n(20,40),n(20,40)];
    const diffs=[1,3,5,7];
    const arr=[];
    for(let i=0;i<3;i++){arr.push(starts[i]);arr.push(starts[i]+diffs[i]);}
    arr.push(starts[3]);
    const ans=String(starts[3]+diffs[3]);
    return R(
      `${arr.join('，')}，？。按两两独立分组做差，？为多少？`,
      ans,
      op(ans,[String(starts[3]+diffs[2]),String(starts[3]-diffs[3]),String(starts[3]+diffs[3]+2)]),
      '两两分组不只看和，也常看差。',
      `每组差为 1、3、5、7，最后一组已有 ${starts[3]}，所以答案 ${starts[3]}+7=${ans}。`
    );
  });

  const p2=Q('ns_power_anchor_choice','次方锚点选择',['基础'],()=>R(
    '64 既可看成 8² 又可看成 4³。遇到多种拆法时，课程建议先找什么项做锚点？',
    '拆法更唯一、更简单的项',
    op('拆法更唯一、更简单的项',['最大项','最小项','选项里的第一个数']),
    '锚点稳定，规律才不容易跑偏。',
    '原课用 9 只能稳定看成 3² 这一类简单锚点，再反推其他项该怎么拆。'
  ));

  const f1=Q('ns_fraction_packaging','分数包装化简',['技巧'],()=>R(
    '6/6，4/6，3/6，2/5，？ 这类分数题第一步为什么要化简？',
    '去掉包装，露出分子分母规律',
    op('去掉包装，露出分子分母规律',['让所有分数变成整数','直接按小数做','判断顺差逆差']),
    '分数数列常把简单规律包装起来。',
    '6/6=1，4/6=2/3，3/6=1/2；化简后更容易看成 2/2、2/3、2/4、2/5。'
  ));

  const f2=Q('ns_no_province_wall','省份规律迁移',['驿站'],()=>R(
    '不要迷信“某省只考某省规律”，更合理的训练态度是什么？',
    '把见过的规律迁移到各类考试',
    ['把见过的规律迁移到各类考试','只练本省原题答案','完全不看外省题','每省都背一套互不相干公式'],
    '这是学习策略驿站，不是计算题。',
    '原课说题库会互相借鉴，见过的规律要能迁移；不要把规律人为限制在某个省份。'
  ));

  const f3=Q('ns_loose_pattern_emergency','不严密规律应急',['运用'],()=>R(
    '数字推理中两组关系推第三组不够严密，但所有常规方法都卡住且选项有对应答案时，考场上可以怎样处理？',
    '可作为应急选择，但复盘时要标记不严密',
    op('可作为应急选择，但复盘时要标记不严密',['永远不能选','以后所有题都这样凑','必须花十分钟证明']),
    '速度与严密性要平衡。',
    '原课多次说：三组推第四组更严密；但考场上若没有更好路线，有选项时可以先走，不要无限恋战。'
  ));

  const route=C('ns_original_route_edges','路线边界',['运用'],[t1,t2,t3,t4],'all');
  const methods=C('ns_original_method_edges','方法细节',['技巧'],[p1,p2,f1],'all');
  const strategy=C('ns_original_strategy_edges','迁移与应急',['运用'],[f2,f3],'all');
  add(C('ns_original_edges_card','路线边界｜迁移与应急',['运用'],[route,methods,strategy],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/14_station.js -----
(function(){
  const {R,Q,add}=EX;
  add(Q('ns_station_terms','驿站｜术语说明',['驿站'],()=>R(
    '“间隔分组、两两分组、三三分组”共同属于哪类思路？',
    '分组数列',
    ['分组数列','贸易状态','平均数公式','比重迁移'],
    '驿站只做术语归位。',
    '项数多时，分组可以把长数列压缩成更少的观察对象。'
  )));
  add(Q('ns_station_tip','驿站｜学习提示',['驿站'],()=>R(
    '数字推理最省力的训练目标是什么？',
    '先按口诀选方向，再变量练熟',
    ['先按口诀选方向，再变量练熟','每题都从倍数开始','只背原题答案','只看省份标签'],
    '口诀用于指路，变量题用于迁移。',
    '课程多次强调不要被原题表面牵着走，应按趋势、倍数范围、项数和特殊形态选方法。'
  )));
})();

// ----- lessons/data_analysis_speed_11_EX/15_section_boundary_training.js -----
EX.sec('口诀边界｜分组与特殊考点');

// ----- lessons/data_analysis_speed_11_EX/16_boundary_training_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const r1=Q('ns_one_outlier_three_times','个别超三倍',['基础'],()=>R(
    '单调数列中只有个别相邻项超过三倍，其他大多在三倍以内，第一方向通常仍是什么？',
    '先按三倍以内走和差分析',
    op('先按三倍以内走和差分析',['立刻判定倍数次方','直接做矩阵','必须拆成分数']),
    '课程说个别在三倍外，其他在三倍内，仍可按三倍以内理解。',
    '不要被一个异常跳变带跑；先看整体多数关系，做差、做和或二级差。'
  ));

  const r2=Q('ns_route_order_after_diff','做差后的路线',['技巧'],()=>R(
    '单调三倍以内数列做差后，差值本身暂时无规律，合理的后续顺序是什么？',
    '看构造网络，再看二级差或特殊考点',
    op('看构造网络，再看二级差或特殊考点',['马上放弃','直接省份专项套公式','只看最大数']),
    '做差只是第一步，不是唯一出口。',
    '原课路线是：做差→看差值与原数列能否构造网络→必要时二级差→还不行再考虑拆分等二级考点。'
  ));

  const r3=Q('ns_simple_question_confidence','简单题自信',['驿站'],()=>R(
    '事业单位数字推理里遇到“一眼两倍、一级差等差”这类简单题，应保持什么态度？',
    '简单题要自信，不能被反复追问动摇',
    ['简单题要自信，不能被反复追问动摇','必须找第二套复杂规律','越简单越不能选','一定先放弃'],
    '这是考试节奏提示。',
    '原课说简单题不要掉分，数字推理基本题要迅速拿下，把时间留给更难的部分。'
  ));

  const g1=Q('ns_group_choose_by_terms','分组类型看项数',['技巧'],()=>R(
    '两两分组时，什么时候优先考虑交叉型？',
    '项数为奇数或独立分组会多出一项时',
    op('项数为奇数或独立分组会多出一项时',['项数越少越要独立分组','只要有七项就永远独立分组','看到小数才交叉分组']),
    '分组方式要服务于能否完整覆盖数列。',
    '原课说七项时两两独立会多出一项，所以往往考虑交叉两两；偶数项且项数多时可先试独立分组。'
  ));

  const g2=Q('ns_triple_group_sum_variable','三三分组求和变量',['技巧'],()=>{
    const a=n(1,5), b=n(1,5), c=n(1,5), d=n(6,12);
    const s1=a+b+c, s2=s1+d, s3=s2+d;
    const x=s2-b-c; const y=s3-c-x;
    const ans=String(y);
    return R(
      `交叉三三分组：(${a}+${b}+${c})=${s1}，(${b}+${c}+${x})=${s2}，(${c}+${x}+?)=${s3}。？是多少？`,
      ans,
      op(ans,[String(y+1),String(Math.max(0,y-1)),String(y+d)]),
      '三三交叉常看每组三项和是否成规律。',
      `第三组需满足 ${c}+${x}+?=${s3}，所以 ?=${s3}-${c}-${x}=${y}。`
    );
  });

  const s1=Q('ns_split_after_fail_not_first','拆分不是第一反应',['基础'],()=>R(
    '数字拆分虽然广东常考，但它在方法层级中属于什么位置？',
    '常规方法无规律后的二级考点',
    op('常规方法无规律后的二级考点',['所有题第一步都拆分','只用于资料分析','只看选项均衡']),
    '拆分重要，但不能抢在基本口诀前面。',
    '原课说一级考点是常规口诀；和差、倍数、次方、分组等都无规律时，再考虑拆分。'
  ));

  const s2=Q('ns_fraction_decimal_same_logic','分数小数同源',['基础'],()=>R(
    '小数数列为什么可以借用分数数列思路？',
    '小数点像分数线，把数分成两部分',
    op('小数点像分数线，把数分成两部分',['小数一定要通分','小数都按百分比做','小数只能做乘法']),
    '这是原课对小数考点的底层解释。',
    '分数看分子/分母，小数看整数部分/小数部分；还可看前一项两部分运算与后一项关系。'
  ));

  const s3=Q('ns_matrix_shorter_side_first','矩阵先看数据少的一边',['技巧'],()=>R(
    '方框/矩阵题中，一行 3 个数、一列 4 个数时，优先从哪里看？',
    '先看一行三个数的关系',
    op('先看一行三个数的关系',['先看一列四个数','直接拆分每个数','只看中间数']),
    '从数据少的一边更容易建立等号关系。',
    '原课说一行三个数比一列四个数更容易看“前两个如何得到第三个”；不行再看列。'
  ));

  const st1=Q('ns_practice_migration_rhythm','驿站｜迁移训练',['驿站'],()=>R(
    '数字推理复习时，原课反复强调的核心不是背省份标签，而是什么？',
    '掌握口诀路线并迁移真题规律',
    ['掌握口诀路线并迁移真题规律','只背广东答案','只看题号','把所有外省题排除'],
    '这是学习提示。',
    '课程选了广东真题，但也强调题库规律会互相迁移；掌握路线比记省份标签更重要。'
  ));

  const route=C('ns_final_route_edges','口诀边界',['基础'],[r1,r2,r3],'all');
  const group=C('ns_final_group_edges','分组边界',['技巧'],[g1,g2],'all');
  const special=C('ns_final_special_edges','特殊考点边界',['技巧'],[s1,s2,s3],'all');
  const station=C('ns_final_station','驿站',['驿站'],[st1],'all');
  add(C('ns_final_audit_card','口诀边界｜分组与特殊考点',['运用'],[route,group,special,station],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/17_section_matrix_decimal.js -----
EX.sec('口诀细节｜矩阵小数与分组');

// ----- lessons/data_analysis_speed_11_EX/18_matrix_decimal_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('ns_interval_direction_detail','间隔分组看方向',['技巧'],()=>{
    const start=n(20,40), step=pk([1,2,3]);
    const evenStart=n(30,60), evenStep=pk([1,2,3]);
    const a1=start, a3=start-step, a5=start-2*step, ans=start-3*step;
    return R(
      `数列奇数项为 ${a1}, ${a3}, ${a5}, ?；偶数项另成一组。奇数项下一项是多少？`,
      String(ans),
      op(String(ans),[String(a5+step),String(a5),String(evenStart+evenStep)]),
      '间隔分组后还要看方向，是递增还是递减。',
      `奇数项每次减少 ${step}，所以 ${a5}-${step}=${ans}。不能只看“忽大忽小”而忽略方向。`
    );
  });

  const q2=Q('ns_interval_operations_variety','间隔不只做差',['基础'],()=>R(
    '原课说“间隔看”包含哪些可能操作？',
    '做差、做和、做乘积、做除法都可能，但更多是做差',
    op('做差、做和、做乘积、做除法都可能，但更多是做差',['只能做差','只能做乘法','只能看尾数']),
    '间隔是一种分组视角，不限定唯一运算。',
    '先分奇偶或隔项，再在组内尝试最简单稳定的加减乘除关系。'
  ));

  const q3=Q('ns_group_operation_not_single','分组运算不单一',['技巧'],()=>{
    const a=n(2,8), b=n(2,8), c=a+b, d=a*b;
    const mode=pk(['和','积']);
    const ans=mode==='和'?c:d;
    return R(
      `两两分组内部可以看不同运算。若一组是 (${a}, ${b})，题目当前规律要求看“${mode}”，本组结果是多少？`,
      String(ans),
      op(String(ans),[String(Math.abs(a-b)),String(c+d),String(Math.max(a,b))]),
      '两两/三三分组后，组内可做加减乘除，不只一种。',
      `${mode==='和'?`${a}+${b}=${c}`:`${a}×${b}=${d}`}。分组只是把项捆成整体，内部运算再看规律。`
    );
  });

  const q4=Q('ns_matrix_constant_correction','矩阵常数修正',['技巧'],()=>{
    const a=n(1,5), b=n(2,6), k1=n(-2,2); const c=a*b+k1;
    const d=n(2,6), e=n(2,7), k2=k1+1; const f=d*e+k2;
    const g=n(2,7), h=n(2,7), k3=k2+1; const ans=g*h+k3;
    return R(
      `矩阵每行前两数推出第三数：${a},${b}→${c}；${d},${e}→${f}。若修正常数依次为 ${k1}, ${k2}, ${k3}，则 ${g},${h}→？`,
      String(ans),
      op(String(ans),[String(g+h+k3),String(g*h+k2),String(g*h-k3)]),
      '行内关系可能是乘法再加一个按规律变化的常数。',
      `本行按 ${g}×${h}+${k3}=${ans}。原课矩阵题中就用过“相乘再加修正数”的思路。`
    );
  });

  const q5=Q('ns_decimal_no_common_denominator','小数没有通分',['基础'],()=>R(
    '分数数列可能通分做差；小数数列对应的注意点是什么？',
    '小数没有通分，主要看整数部分和小数部分',
    op('小数没有通分，主要看整数部分和小数部分',['所有小数都先通分','小数只能转百分数','小数不能拆分']),
    '小数点像分数线，但小数没有“分母通分”这一步。',
    '小数数列主要两路：整数/小数部分分别成规律；或前一项两部分四则运算推出后一项。'
  ));

  const q6=Q('ns_true_questions_fluency_station','驿站｜熟练度与真题',['驿站'],()=>R(
    '结课后数字推理/数量相关训练，训练方向是什么？',
    '继续刷真题，提高口诀路线熟练度，有问题复盘交流',
    ['继续刷真题，提高口诀路线熟练度，有问题复盘交流','只背本节课选项','只看省份名称','完全不复盘'],
    '这是训练节奏，不是计算规则。',
    '训练要点强调数字推理内容就是这些口诀，后期关键是熟练度；数量关系尽量多刷真题，有问题讨论复盘。'
  ));

  const route=C('ns_round3_route_edges','分组与方向',['技巧'],[q1,q2,q3],'all');
  const special=C('ns_round3_special_edges','矩阵小数细节',['技巧'],[q4,q5],'all');
  const station=C('ns_round3_training_station','驿站',['驿站'],[q6],'all');
  add(C('ns_round3_audit_card','口诀细节｜矩阵小数与分组',['运用'],[route,special,station],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/19_section_review_boundaries.js -----
EX.sec('口诀边界｜特殊细节与复盘');

// ----- lessons/data_analysis_speed_11_EX/20_review_boundaries_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('ns_three_times_equal_boundary','三倍及以上边界',['基础'],()=>R(
    '数字推理里，多个相邻项达到“三倍及以上”时，路线通常怎么选？',
    '优先考虑倍数或次方，而不是机械做差',
    op('优先考虑倍数或次方，而不是机械做差',['一定先间隔分组','一定先数字拆分','直接放弃'] ),
    '原课把“个别超三倍”和“多个三倍及以上”分开。',
    '如果只是个别超三倍，仍可和差；如果多处达到三倍及以上，倍数/次方优先级上升。'
  ));

  const q2=Q('ns_diff_geometric_down','差值等比递减',['技巧'],()=>{
    const start=n(80,160); const d1=pk([32,48,64]);
    const arr=[start,start+d1,start+d1+d1/2,start+d1+d1/2+d1/4].map(x=>Math.round(x));
    const ans=String(Math.round(arr[3]+d1/8));
    return R(
      `${arr.join('，')}，？。做差后差值依次约为 ${d1}, ${d1/2}, ${d1/4}，下一项是？`,
      ans,
      op(ans,[String(arr[3]+d1/4),String(arr[3]+d1/2),String(arr[3]-d1/8)]),
      '和差分析不只看等差，也可能差值等比。',
      `差值每次减半，下一差值 ${d1/8}，所以答案 ${arr[3]}+${d1/8}≈${ans}。`
    );
  });

  const q3=Q('ns_group_reduce_terms_reason','分组压缩项数',['基础'],()=>R(
    '七项及以上为什么常考虑分组？',
    '把很多项捆成较少整体，降低观察复杂度',
    op('把很多项捆成较少整体，降低观察复杂度',['因为七项以上不能做差','因为分组一定比做差简单','因为所有长数列都是两两乘法']),
    '分组不是装饰，是降维。',
    '原课说两两分组后，本来很多项会变成几组整体，类似把对象捆绑起来再看组内规律。'
  ));

  const q4=Q('ns_matrix_switch_row_column','矩阵行列切换',['技巧'],()=>R(
    '方框/矩阵题如果按行看不出稳定关系，下一步应怎样？',
    '再按列看，仍是加减乘除或前三推后一的关系',
    op('再按列看，仍是加减乘除或前三推后一的关系',['立即判定无规律','只看最大数','只做尾数法']),
    '矩阵只是排列形式变化，本质仍是找行列关系。',
    '原课强调先从数据少的一边看；行不行，再列一列看，仍围绕加减乘除和修正常数。'
  ));

  const q5=Q('ns_square_power_nearby','次方附近数',['技巧'],()=>{
    const k=n(3,7); const mode=pk(['+1','-1']);
    const ans=mode==='+1'?k*k+1:k*k-1;
    return R(
      `某项靠近平方数 ${k}²=${k*k}，若本列规律是“平方数${mode}”，该项应为多少？`,
      String(ans),
      op(String(ans),[String(k*k),String((k+1)*(k+1)),String(k*k+(mode==='+1'?2:-2))]),
      '次方题不一定刚好是次方，也常是次方数附近。',
      `${k}²${mode}=${ans}。原课中 28、65 这类数就是靠近 27、64 的次方附近数。`
    );
  });

  const q6=Q('ns_fraction_answer_simplify','分数答案化简',['技巧'],()=>{
    const d=pk([6,8,10,12]); const num=d/2;
    return R(
      `按分子分母规律得到下一项为 ${num}/${d}。选项中可能写成什么？`,
      '1/2',
      op('1/2',[`${num}/${d}`,'2/1','无法化简']),
      '分数数列先拆包装，答案也常要化成最简形式匹配选项。',
      `${num}/${d} 化简为 1/2。原课分数题先把 6/6、4/6 等包装拆掉，本质也是这个意识。`
    );
  });

  const q7=Q('ns_review_resources_station','驿站｜复习资源',['驿站'],()=>R(
    '数字推理结课后，最重要的复盘方式是什么？',
    '按口诀路线刷真题，错题复盘，必要时回看录屏和笔记',
    ['按口诀路线刷真题，错题复盘，必要时回看录屏和笔记','只背广东题答案','只看题目年份','不再复习'],
    '这是训练保障。',
    '最后要强调数字推理内容就是这些口诀，关键是熟练度；真题、笔记与复盘材料和问题交流都服务于复盘。'
  ));

  const route=C('ns_exhaustive_route_edges','口诀边界',['技巧'],[q1,q2,q3],'all');
  const special=C('ns_exhaustive_special_edges','特殊细节',['技巧'],[q4,q5,q6],'all');
  const station=C('ns_exhaustive_station','驿站',['驿站'],[q7],'all');
  add(C('ns_exhaustive_audit_card','口诀边界｜特殊细节与复盘',['运用'],[route,special,station],'all'));
})();

// ----- lessons/data_analysis_speed_11_EX/21_section_rigor_tail.js -----
EX.sec('做差严密性｜尾数与路线切换');

// ----- lessons/data_analysis_speed_11_EX/22_rigor_tail_edges.js -----
(function(){
  const {pk,n,op,R,Q,C,add}=EX;

  const q1=Q('ns_diff_big_minus_small','做差可大减小',['技巧'],()=>{
    const arr=[n(80,120), n(50,70), n(20,40)];
    const d1=arr[0]-arr[1], d2=arr[1]-arr[2];
    return R(
      `单调递减数列 ${arr.join('，')}。做差时为了看正差，可怎样处理？`,
      '用前项减后项，保持差值为正',
      op('用前项减后项，保持差值为正',['必须后项减前项','不能做差','只看尾数']),
      '单调递减也可以和差分析，差值方向可以统一。',
      `用大减小可得 ${d1}, ${d2}，便于继续看等差、等比或二级差。原课提醒“大减小也可以”。`
    );
  });

  const q2=Q('ns_two_relations_weak','两组关系不够严密',['基础'],()=>R(
    '数字推理中，只有两组关系成立就推出下一项，严密吗？',
    '不够严密，优先寻找三组关系推第四组',
    op('不够严密，优先寻找三组关系推第四组',['非常严密，必然正确','永远不能用作应急','只要选项有就一定是唯一答案']),
    '原课多次强调三项成规律推第四项更稳。',
    '两组关系推第三组可以作为考场应急，但若存在三组成立的规律，应选更严密的那条。'
  ));

  const q3=Q('ns_center_symmetry_weak','中心对称规律慎用',['运用'],()=>R(
    '看到差值类似 14，41，41，14，这类“中心对称”能否直接当强规律？',
    '要谨慎，它可能不够严密，只能在无更好方法且有选项时应急',
    op('要谨慎，它可能不够严密，只能在无更好方法且有选项时应急',['一定是最优规律','一定不能选','只适用于分数数列']),
    '对称样子好看，但不一定符合三组推第四组的严密性。',
    '原课明确说这种规律“答案对也不严密”，考场有选项可走，但不要当作优先路线。'
  ));

  const q4=Q('ns_tail_digit_large_power','大数幂尾数锁定',['技巧'],()=>{
    const base=pk([6,7,8,9]); const exp=pk([4,5]);
    const val=Math.pow(base,exp); const ans=String(val%10);
    return R(
      `若数字推理推出下一项为 ${base}^${exp}，但选项很大，最快可先看什么？`,
      `尾数 ${ans}`,
      op(`尾数 ${ans}`,[`尾数 ${(Number(ans)+1)%10}`,`首位 ${base}`,`项数 ${exp}`]),
      '大数幂或大乘积常用尾数先锁定选项。',
      `${base}^${exp}=${val}，尾数为 ${ans}。原课多次用“尾数为几”快速选项。`
    );
  });

  const q5=Q('ns_obvious_multiply_even_not_monotone','非单调先看整体乘积',['技巧'],()=>{
    const a=pk([1,2,3]); const b=pk([2,3,4]); const c=a*b; const d=b*c; const e=c*d;
    return R(
      `${a}，${b}，${c}，${d}，？。数列不严格单调时，若整体看出前两项乘积递推，下一项是？`,
      String(e),
      op(String(e),[String(d+c),String(d*2),String(c*2)]),
      '非单调时不要机械做差，先看整体特殊关系。',
      `${a}×${b}=${c}，${b}×${c}=${d}，所以下一项=${c}×${d}=${e}。这对应原课 1,2,2,4,8,32 的思路。`
    );
  });

  const q6=Q('ns_group_try_order_flexible','分组方式可切换',['基础'],()=>R(
    '七项及以上考虑分组时，是否只能固定一种分法？',
    '不是，可在间隔、两两、三三之间切换试探',
    op('不是，可在间隔、两两、三三之间切换试探',['只能间隔分组','只能两两独立分组','只能三三交叉分组']),
    '分组是路线集合，不是一条死流程。',
    '原课同一道题会提到间隔、两两、三三都可能；若一种不稳，就换另一种。'
  ));

  const q7=Q('ns_fraction_count_after_simplify','化简后再数分数个数',['技巧'],()=>R(
    '分数数列判断“分数个数多于整数”时，应在化简前还是化简后判断？',
    '化简后判断，因为包装会伪装成分数或整数',
    op('化简后判断，因为包装会伪装成分数或整数',['必须化简前判断','只看分母大小','只看第一个数']),
    '先拆包装，再套分数数列口诀。',
    '原课把 6/6 化成 1，再看分数个数多于整数，说明判断入口要在化简之后。'
  ));

  const q8=Q('ns_exam_difficulty_station','驿站｜难度差异',['驿站'],()=>R(
    '原课提到广东事业单位数字推理整体难度与公务员题相比怎样？',
    '事业单位相对简单，但仍要按口诀路线做，不要轻敌',
    ['事业单位相对简单，但仍要按口诀路线做，不要轻敌','事业单位一定没有数字推理','公务员题一定全靠猜','难度差异与训练无关'],
    '这是学习节奏提示，不是具体公式。',
    '训练中多次强调事业单位题明显简单，但仍通过真题训练口诀熟练度。'
  ));

  const diff=C('ns_round1_diff_edges','做差与严密性',['技巧'],[q1,q2,q3],'all');
  const route=C('ns_round1_route_edges','路线切换',['技巧'],[q5,q6,q7],'all');
  const tail=C('ns_round1_tail_edges','尾数与应急',['技巧'],[q4],'all');
  const station=C('ns_round1_station','驿站',['驿站'],[q8],'all');
  add(C('ns_audit_round1_card','做差严密性｜尾数与路线切换',['运用'],[diff,route,tail,station],'all'));
})();

